gameforge.collect_quest_lv92._050_say_title = "سيون-بيونغ: "
gameforge.collect_quest_lv92._060_say = "يا أيها المحارب الشجاع! لقد وصلت في الوقت[ENTER]المناسب. أنا أبحث عن نوع خاص من المجوهرات للبحث[ENTER]الخاص بسلاحي. هل يمكنك أن تساعدني؟ تمتلك بعض[ENTER]المخلوقات في كهف اللعنة هذه المجوهرات. ولكنني شخص[ENTER]مهم جداً و لا يمكنني أن أخاطر بحياتي في مثل هذا[ENTER]المكان الخطير. "
gameforge.collect_quest_lv92._070_say = "أنا بحاجة حالياً إلى بعض من مجوهرات الخبث الخالية[ENTER]من أي عيب - هذه الأحجار الكريمة الجميلة تنمو فقط[ENTER]في أعماق الجبال. إنها مجوهرات خاصة تعرضت لسنوات[ENTER]لقوى بيران-سيتاو الشريرة و استوعبت جزء ضئيل من[ENTER]طاقته الشريرة. أحتاج لـ10 من هذه المجوهرات[ENTER]الخالية من أي عيب. حظا سعيدا و إلى اللقاء. "
gameforge.collect_quest_lv92._080_say_title = "جواهر لسيون-بيونغ "
gameforge.collect_quest_lv92._090_say = "يحتاج حداد الأسلحة و العالم سيون-بيونغ لـ10 من[ENTER]مجوهرات الخبث لإكمال بحثه حول الأسلحة. أحضر له[ENTER]الواحدة تلو الأخرى، حتى يتسنى له دراسة كل واحدة[ENTER]منها على حدة. يمكنك الحصول عليها من تمثال الجليد[ENTER]من الجحيم و رجل الجليد من الجحيم. "
gameforge.collect_quest_lv92._100_sayReward = "لقد قمت بتسليم %s مجوهرات حتى الآن. "
gameforge.collect_quest_lv92._110_say = "لا يمكنك استعمال إكسير العالم بعد. "
