gameforge.collect_quest_lv92._140_send_letter = "قد وجدت الجوهرة "
gameforge.collect_quest_lv92._145_npcChat = "جوهرة الاستياء (92) "
gameforge.collect_quest_lv92._150_say = "أنت هنا؟ عذراً ولكنني لم أنتهي من دراسة الأخيرة[ENTER]بعد. عد لاحقاً من فضلك! "
gameforge.collect_quest_lv92._160_say = "لم تجد واحدة بعد؟ عذراً، ولكن لماذا أنت هنا إذاً؟[ENTER]اذهب و لا تعد قبل أن تحضر بعض المجوهرات! "
gameforge.collect_quest_lv92._170_say = "لقد وجدت جوهرة؟ هذا رائع! أعطني لحظة لأتحقق... "
gameforge.collect_quest_lv92._180_say = "هذا رائع! إنها من دون أدنى شك من أجمل المجوهرات[ENTER]التي رأيتها بحياتي. شكراً جزيلاً! "
gameforge.collect_quest_lv92._190_say = "ولكن كما تعلم، ما زلت أحتاج إلى %s قطعة أخرى و[ENTER]بنفس الجودة العالية. أعطني يوما حتى أقوم بفحص هذه[ENTER]القطعة بشكل معمق. ثم يمكنك أن تجلب لي بعد ذلك[ENTER]قطعة جديدة أخرى. "
