gameforge.collect_quest_lv92._210_say = "هذه كانت الجوهرة الأخيرة، لقد جمعت المجوهرات[ENTER]العشر. أنا ممتن للغاية... و لن أكون بخيل[ENTER]بمكافأتي. اختر الآن! "
