gameforge.couple_ring._160_say = "عندما انصرفت عنك المرأة العجوز، لاحظت أنها تحمل[ENTER]في يدها شيئاً ما. لقد كان شيئاً لامعاً. ربما حجر[ENTER]ثمين وقيم. "
gameforge.couple_ring._170_select = "سأكرر المحاولة. "
