gameforge.couple_ring._60_say = "هذا قرار حسن ومشرف![ENTER]لا تنسى، يجب عليك قتل 30 جن-هي.[ENTER]ولكن احذر، فهم يستطيعون الخداع والاختباء[ENTER]جيداً! "
gameforge.couple_ring._70_say = "هذا قرار مؤسف، ولكن من حقك أيضاً. لا شك أن[ENTER]الشجاعة الطائشة تؤدي سريعاً إلى الموت. انتبه[ENTER]لنفسك جيداً! "
