gameforge.dragon_soul._040_say = "إنها شظية من حجر التنين، وهي عبارة عن بلور شديد[ENTER]الندرة، قيمته لا تُقدّر بثمن وقوته خارقة. يُحكى[ENTER]أنه من روح أحد التنانين. يا للرّوعة! هل تشعر[ENTER]بقوته تغمُر جسدك بمجرّد الإمساك به؟ أحضر لي تسعة[ENTER]أحجار إضافية بمجموع عشر شظايا، لأحوّلها لك إلى[ENTER]حجر تنين كامل. "
gameforge.dragon_soul._050_npcChat = "تحويل حجر التنين "
gameforge.dragon_soul._060_say = "اصبر صبرًا جميلاً. لا يُمكنني أن أُحوّل لك[ENTER]الشظايا إلى حجر التنين إلاّ بعد إحضار عشرة شظايا.[ENTER]تابع البحث! "
gameforge.dragon_soul._070_say = "آه، ممتاز! لقد أحضرت عشر شظايا من حجر التنين.[ENTER]رائع، انتظر لبعض الوقت.[ENTER]...[ENTER]تمت العملية بنجاح! يا للرّوعة... لقد تكون أثناء[ENTER]العملية ما يُطلق عليه اسم كور داركونيس. إنه قلب[ENTER]تنين من البلور، بداخله حجر التنين.[ENTER]قُم بكسره لتكشف عن نوع الحجر الذي بداخله. سينتقل[ENTER]تلقائيًا إلى قائمة جرد كيمياء حجر التنين.[ENTER]هل تعلم أنه بإمكانك رفع أداء حجر التنين بصقله؟ "
gameforge.dragon_soul._080_say = "هل ترغب في الحصول على كور دراكونيس إضافي؟ آه ثم[ENTER]آه، ظهري تقوس ولم أعد من الشباب اليافع. وقد أصبحت[ENTER]عملية تحويل مثل هذه البنود المُعقّدة تُرهقني بشكل[ENTER]كبير.[ENTER]لكنّي سأحاول جُهدي من أجل إرضاءك. لا يمكنني[ENTER]بتاتًا أن أحول لك أكثر من عشر قطع في اليوم! "
gameforge.dragon_soul._090_say = "لا مجال لأية إضافة اليوم. لا يمكنني بتاتًا أن[ENTER]أحول لك أكثر من عشر قطع من كور دراكونيس في اليوم.[ENTER]لقد أصبحت عملية تحويل مثل هذه البنود المُعقّدة[ENTER]تُرهقني بشكل كبير. أحتاج الآن لبعض الراحة، عُد من[ENTER]جديد غدًا. "
gameforge.dragon_soul._100_npcChat = "افتح متجرًا "
gameforge.dragon_soul._1010_sendLetter = "وصول شظايا حجر التنين "
gameforge.dragon_soul._1020_say = "إن العالم الكيميائي، الذي يلم بجميع أسرار معادن[ENTER]القارة، يبحث عنك منذ مدة. أسرع إليه! "
gameforge.dragon_soul._1030_npcChat = "شظايا حجر التنين؟ "
gameforge.dragon_soul._1040_say = "آه، ها أنت ذا! لقد اكتشفت شيئًا مُذهلاً: شظية حجر[ENTER]تنين! إن حجر التنين بلور نادر جدًّا، وقيمته لا[ENTER]تقدر بثمن لإنه يملك قوة خارقة. يُحكى أنه روح[ENTER]تنين. يا لجماله وروعته! سأمنحك قوة عين التنين،[ENTER]لكي تتمكن من العثور على شظايا روح التنين. أحضر لي[ENTER]عشرة من شظايا التنين، لكي أحوّلها لك إلى حجر ضخم. "
gameforge.dragon_soul._1050_sendLetter = "قُم بجمع بعض شظايا حجر التنين "
gameforge.dragon_soul._1060_say = "احضر للكيميائي 10 من شظايا حجر التنين. "
gameforge.dragon_soul._1070_say = "آه ممتاز! لقد عثرت على شظايا حجر التنين. انتظر[ENTER]لحظة من فضلك.[ENTER]...[ENTER]يا للعجب! لقد نتج عن عملية التحويل كور دراكونيس،[ENTER]قلب بلّوري، يحوي ويحمي بداخله حجر التنين.[ENTER]إذا كسّرته فإن حجر التنين بداخله سيودع مباشرة في[ENTER]قائمة جرد كيمياء حجر التنين. ستحتاج للعثور على[ENTER]شظايا حجر التنين إلى قوة عين التنين. بإمكاني أن[ENTER]أمنحك إيّاها، كل ما عليك فعله هو زيارتي يوميّا.[ENTER]سيكون عندها بإمكانك تحويل حجر التنين بنفسك! لقد[ENTER]حوّلت لك اليوم حجرًا واحدًا، سيكون بإمكانك تحويل[ENTER]3 الباقية بنفسك. "
gameforge.dragon_soul._1080_say = "يا هذا، لا تُضيع الوقت! اذهب وابحث عن شظايا حجر[ENTER]التنين! "
gameforge.dragon_soul._1090_sendLetter = "قوة عين التنين "
gameforge.dragon_soul._1100_say = "الوقت المتبقي لقوة عين التنين: %d "
gameforge.dragon_soul._110_say = "اختر. "
gameforge.dragon_soul._1110_notice = "نفذت شظايا حجر التنين. "
gameforge.dragon_soul._1120_npcChat = "أعطني قوة عين التنين "
gameforge.dragon_soul._1130_say = "أهلاً بك! لقد سبق لك أن حصلت اليوم على قوة عين[ENTER]التنين. إن العملية تُرهقني بشكل كبير، لذا فلا[ENTER]يمكنني مساعدتك إلاّ مرة وحيدة في اليوم. عُد غدًا[ENTER]من جديد! "
gameforge.dragon_soul._1140_say = "أهلاً! أنت بالتأكيد تبحث عن عين التنين. أليس[ENTER]كذلك؟ طيب، خُذ ها هي. حظ سعيد في البحث! أرجوا أن[ENTER]تجد ما يكفي من الشظايا للحصول على عشرة من أحجار[ENTER]التنين! "
gameforge.dragon_soul._1150_sendLetter = "نقصان قوة عين التنين "
gameforge.dragon_soul._1160_say = "لقد غادرتك قوة عين التنين. "
gameforge.dragon_soul._1170_say = "عُد من جديد إلى الكيميائي للحصول على قوة عين[ENTER]التنين! "
gameforge.dragon_soul._1180_say = "اذهب لزيارة الكيميائي لتحصل من عنده على قوة عين[ENTER]التنين! "
gameforge.dragon_soul._1190_say = "لا يمكنك استخدام كيمياء حجر التنين بعد،[ENTER]لأنك لم تصل إلى المستوى 30. "
gameforge.dragon_soul_daily_gift = {}
gameforge.dragon_soul_daily_gift._010_npcChat = "كور دراكونيس كهديّة "
gameforge.dragon_soul_daily_gift._020_say = "ليس بالسهل التحكم في قوة عين التنين. فقدرة التحكم[ENTER]فيها لا يملكها سوى المقاتلون ذوي الخبرة العالية.[ENTER]تابع تداريبك القتالية وعُد من جديد عند وصولك[ENTER]المستوى 50 على الأقل. "
gameforge.dragon_soul_daily_gift._030_say = "ستحتاج لقدرة التحكم في قوة عين التنين، إذا كنت[ENTER]ترغب في استخدام كور دراكونيس. عُد لاحقًا إذا توفر[ENTER]فيك هذا الشرط! "
gameforge.dragon_soul_daily_gift._040_say = "آه، إنّي أشعر بقوة عين التنين بداخلك. سأهديك كور[ENTER]دراكونيس هذا كتعبير لاحترامي وإعجابي العميقين.[ENTER]حجر وحيد في اليوم الواحد، هذا كل ما أستطيع منحك[ENTER]إياه. "
gameforge.dragon_soul_daily_gift._050_say = "تفضّل ها هو كور دراكونيس لك. "
gameforge.dragon_soul_daily_gift._060_say = "آسف، لكن لا يمكنني منحك أكثر من واحد في اليوم[ENTER]الواحد. عُد غدًا، لعلك تجد عندي كور دراكونيس[ENTER]جديد. "
