gameforge.dragon_soul_refine._020_say = "هل ترغب في صقل حجر التنين؟ هيّا اقترب. لكن اعلم[ENTER]أولاً أن عملية الصقل قد تفشل. لقد أخبرني أحدهم[ENTER]بأن ما يُسمّى بحبوب التنين ترفع من فُرص نجاح[ENTER]العملية.[ENTER]يُمكن الحصول عليها وراء القطعة النقدية التي تدور. "
gameforge.energy_system = {}
gameforge.energy_system._001_npcChat = "تقنية جديدة! "
gameforge.energy_system._010_say = "لقد نجحت! تمكنت أخيراً من تطوير تقنية جديدة،[ENTER]ستمكنني من تحويل الأشياء واستخراج طاقة خالصة[ENTER]منها. عمل مُدهش! "
gameforge.energy_system._020_say = "إذا أقدمت على تكسير شيء ما باستعمال تقنيتي فإنك[ENTER]ستحصل على شظايا الطاقة. إذا جمعت 30 من هذه[ENTER]الشظايا وحولتها فإنك ستحصل على بلور الطاقة. بلور[ENTER]خالص يخفي في داخله طاقة خالصة، تنعكس على جميع[ENTER]دروعك وأسلحتك. ما قولُك؟ عملية رهيبة أليس كذلك.[ENTER]هل ترغب في تجريبها؟ "
gameforge.energy_system._030_say = "أحضر لي كل ما تعثر عليه أثناء صيدك من عتاد وأدوات[ENTER]كالأسلحة، الحلي والملابس. سأحولها إلى شظايا[ENTER]الطاقة. مستقبل وأمل إمبراطوريتنا يرتبط بهذه[ENTER]التقنية. سنُصبح قوة لا تُقهر! "
gameforge.energy_system._035_npcChat = "استخراج شظايا الطاقة "
gameforge.energy_system._040_say = "هل نجحت العملية؟ هل حصلت على شظايا الطاقة؟ أحضر[ENTER]لي الأشياء وسأقوم بكسرها باستعمال الكيمياء. إن[ENTER]تقنيتي ما زالت في مرحلة تجريبية. لذا لا يمكنني أن[ENTER]أضمن لك عدد الشظايا التي ستحصل عليها. "
gameforge.energy_system._050_say = "هناك شرط واحد: يجب أن لا يقل مستواك ومستوى[ENTER]الأشياء عن 35. همم دعني أرى... "
gameforge.energy_system._060_say = "إنك لا تزال ضعيفاً! عُد لاحقاً عند وصولك المستوى[ENTER]35. "
gameforge.energy_system._070_say = "آه، روعة، ممتاز! إنك قوي وغني بالتجارب. أعطني[ENTER]الشيء الذي ترغب في تحوليه. "
gameforge.energy_system._080_say = "إنك لا تزال ضعيفاً لتحمل شظايا الطاقة أو التحكم[ENTER]بها. عُد لاحقاً عند وصولك للمستوى 35. "
gameforge.energy_system._090_say = "إن هذا البند غير صالح لتقنيتي. أحضر لي شيئاً آخر. "
gameforge.energy_system._100_say = "إن هذا الشيء لا يملك ما يكفي من الطاقة. أحضر لي[ENTER]شيئاً لا يقل مستواه عن 35. لا يمكنني استخراج[ENTER]الطاقة من شيء يقل مستواه عن ذلك. "
gameforge.energy_system._110_say = "هل ترغب في أن أدمر هذا الشيء؟ "
gameforge.energy_system._120_select = "نعم! "
gameforge.energy_system._130_select = "لا، ليس الآن! "
gameforge.energy_system._140_say = "لقد فشلت، لم أنجح مع الأسف في استخراج شظايا[ENTER]الطاقة. ربما نجحت في المحاولة المُقبلة. "
gameforge.energy_system._150_say = "يا للروعة! لقد نجحت في العثور على %d من شظايا[ENTER]الطاقة. تفضل. "
gameforge.energy_system._160_npcChat = "صُنع بلور الطاقة "
gameforge.energy_system._170_say = "هل استهلكت كل مذخراتك من الطاقة؟ لا تُحول حياتك[ENTER]لجحيم من شدة العمل، ولا تغامر بها في المجهول.[ENTER]سأحتاج لصُنع بلور الطاقة لـ%d من شظايا الطاقة. "
gameforge.energy_system._180_say = "إنك لم تُحصّل بعد ما يكفي من شظايا الطاقة. لا[ENTER]يمكنني أن أصنع لك من هذا العدد القليل بلور[ENTER]الطاقة. عُد لاحقاً، عند حصولك على %d من الشظايا. "
gameforge.energy_system._190_say = "ممتاز، لقد أحضرت الشظايا %d اللازمة. بإمكاني الآن[ENTER]صُنع بلور الطاقة. انتظر للحظة. سأنفذ العملية لكني[ENTER]لا أضمن لك نجاحها. "
gameforge.energy_system._200_say = "كل شيء حاضر لتذويب الشظايا وتحويلها إلى بلور[ENTER]الطاقة. لكن من أين لي بغذائي وتكاليف أدواتي. لذا[ENTER]فإني أطلب من صاحب الطلب تعوضاً بسيطاً بقيمة %d[ENTER]يانغ. هل أنت مستعد لدفعه؟ "
gameforge.energy_system._210_select = "طبعاً! "
gameforge.energy_system._220_select = "لا، ليس الآن. "
gameforge.energy_system._230_say = "موافق، سأحترم قرارك. عُد لاحقاً إذا غيرت رأيك[ENTER]واحتجت لبلور الطاقة. "
gameforge.energy_system._240_say = "آسف كل الأسف، عليك أولاً أن تدفع. إني لا أدير[ENTER]مؤسسة خيرية هنا. العملية بكل بساطة هكذا: أعطني[ENTER]المال وسأباشر العمل. "
gameforge.energy_system._250_say = "خُذ، ها هو بلور الطاقة الخاص بك. تذكر بأن النجاح[ENTER]مضمون لأول محاولة فقط. فالكيمياء يعتبر عِلم مليء[ENTER]بالمفاجآت، وبالتالي فإن تغييرات بسيطة يمكنها أن[ENTER]تُفشل العملية! احتمالات بسيطة في نوعها لكنها[ENTER]ترافق كل عملية وتجعلها عُرضة لاحتمال الفشل. "
gameforge.energy_system._260_say = "لقد فشلت العملية. لم أنجح مع الأسف في صُنع بلور[ENTER]الطاقة. إن تقنيتي رائعة، لكن العملية بحد ذاتها[ENTER]تكون دائماً مليئة بالأخطار. مما يتسبب في فشل[ENTER]الخطة. أظن أننا سنُوفق في المحاولة المُقبلة! "
gameforge.energy_system._270_say = "لقد تنبأت بهذا! لا مثيل لتقنيتي![ENTER]خذ ها هو بلور الطاقة.[ENTER]إنها حقّا تُحفة! هل تشعر بالقوة؟ "
