gameforge.find_squareguard._140_say = "أهلا بك أيها المغامر الشجاع! آه، لقد أرسلك حارس[ENTER]ساحة القرية؟ إنه بحاجة إلى جرعة حمراء؟ سأعطيك[ENTER]فوراً5 جرعات. خُذ، ها هي. إنها تعيد نقاط الحياة[ENTER]وطعمها لذيذ عذب. "
gameforge.find_squareguard._150_say = "صحيح انك جديد في هذا المكان، ولكني متأكدة من أنك[ENTER]ستصبح زبوناً مألوفاً. لهذا السبب سأعطيك الجرع[ENTER]بدون مقابل. عُد من جديد! "
gameforge.find_squareguard._160_sayReward = "حصلت من تاجرة البضائع المختلفة على 5 جرع حمراء. "
gameforge.find_squareguard._170_sayReward = "تساعدة الجرعة الحمراء في استعادة نقاط الحياة (HP). "
gameforge.find_squareguard._180_sendLetter = "العودة إلى حارس القرية "
gameforge.find_squareguard._190_sayReward = "عد إلى حارس القرية واعطيه جرعة حمراء. "
gameforge.find_squareguard._200_say = "ألم تحضر الجرعة الحمراء ؟[ENTER]ياللأسف! يبدو أنك تحب أنك حذر في استخدام المال[ENTER]شكراً لجهودك.وبالمناسة الأساتذة يبحثون عنك،[ENTER]اذهب إليهم. "
gameforge.find_squareguard._20_sayReward = "إذهب إلى القرية وتحدث إلى حارس القرية. ستحصل منه[ENTER]على أول مهمة. ستجده وسط ساحة القرية. "
gameforge.find_squareguard._210_say = "أشكرك جزيلا لإحضارك للجرعة! لقد مكنني هذا من[ENTER]البقاء هنا في القرية والقيام بعملي. هل تريد معرفة[ENTER]ماهي المهام التي أقوم بها؟ عملي يكمن على العموم[ENTER]في الإعلان عن معلومات مفيدة. كما أني أقوم بعرض[ENTER]مساعدتي لأولئك الذين يحتاجون لمساعدة. إنني مسؤول[ENTER]أيضاً وعلى الخصوص على نظام إنشاء الروابط. إذا كان[ENTER]الأمر يهمك في يوم من الأيام، فلا تتردد في التحدث[ENTER]إلي. "
gameforge.find_squareguard._220_say = "بالمناسبة، يبحث عن المعلمين اذهب اليهم لتري [ENTER]كيف يُمكنك مساعدتهم! "
gameforge.find_squareguard._30_sayTitle = "حارس ساحة القرية: "
gameforge.find_squareguard._40_say = "أهلاً بك في قريتنا أيها المغامر! سأكون لك من[ENTER]الشاكرين إن أسديت لي خدمة. إذا أعطيتك 200 يانغ،[ENTER]هل تستطيع أن تشتري لي جرعة حمراء؟ يمكنك شراؤها من[ENTER]تاجرة البضائع المختلفة. أنا حالياً في الخدمة ولا[ENTER]يمكنني مغادرة ساحة القرية. "
gameforge.find_squareguard._50_select = "نعم "
gameforge.find_squareguard._60_sayReward = "حصلت من الحارس على 200 يانغ. يمكنك بهذا المبلغ أن[ENTER]تزود نفسك بالعديد من البنود من المتاجر أو أن[ENTER]تحصل على خدمة من الحرفي. ويمكنك الحصول على الجرعة[ENTER]الحمراء من تاجرة البضائع المختلفة. "
