gameforge.fortune_telling._180_say = "هل أنت ذاهب؟ معك حق ربما. الحياة لا تخلو من الألم[ENTER]والمعاناة. أتمنى لك حياة سعيدة. عد ثانيةً في حال[ENTER]غيرت رأيك. "
gameforge.fortune_telling._20_say = "تخبرني عينك أنك ما زلت شابا ولم يمضي وقت طويلا[ENTER]على وجودك في هذا العالم. لما ترغب في معرفة مصيرك[ENTER]مبكرا؟ هل هناك سبب معين؟ إن مصيرك يخفي لك بعض[ENTER]الأحداث المثيرة. عد لاحقا. "
gameforge.fortune_telling._30_say = "هل تريد عيش حياتك كما جاء في تكهن المنجمة؟ عليك[ENTER]أن لا تأخذ هذه الأشياء بجدية تامة. المهم حقيقةً[ENTER]هو شخصيتك وأسلوب تعاملك مع الناس. إذا كان هذا[ENTER]إيجابياً فلن تواجهك أي صعوبات. إذا كنت لا زلت[ENTER]ترغب في معرفة مستقبلك، فعد غداً من[ENTER]جديد. "
gameforge.fortune_telling._40_sayTitle = "امرأة عجوز: "
gameforge.fortune_telling._50_say = "كما سبق الذكر، فإن التنبؤ بالنسبة لك اليوم هو[ENTER]كالتالي: "
gameforge.fortune_telling._60_say = "سيصيبك سوء الحظ، وإنك لم تشتر التعويذة لتجنب الشر[ENTER]بعد. هل ترغب في شراء تعويذة الثراء التي أملكها؟ "
gameforge.fortune_telling._70_select = "نعم، سأشتريه. "
gameforge.fortune_telling._80_select = "لا، لست بحاجة إليها. "
gameforge.fortune_telling._90_say = "صحيح أني لطيف معك، ولكني لا استطيع أن أهديك[ENTER]تعويذة. إذا أردت أن تتجنب سوء الحظ والنحس فعليك[ENTER]أن تدفع الثمن. "
