gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "شبح السورا: "
gameforge.ghost_story._020_npcChat = "هل أنت شبح؟ "
gameforge.ghost_story._030_say = "لا، أنا جدّتُك العجوز... بطبيعة الحال شبح! هل أنت[ENTER]مُدمن على مخدرات أم ماذا؟ "
gameforge.ghost_story._040_npcChat = "النجدة، شبح! "
gameforge.ghost_story._050_say = "يا لها من مهزلة، إنه فعلاً محارب باسل! هاها!! "
gameforge.ghost_story._060_npcChat = "من أنت؟ "
gameforge.ghost_story._070_say = "اسمي أكوما. لقد كنت في يوم من الأيام محارباً[ENTER]عظيماً، بل يحكى أنني كنت أعظم المحاربين. حتى أنا[ENTER]- نعم، خاصة أنا! - صدقت هذه الخرافة. انظر إلي وما[ENTER]تبقى مني، بعد أن عثرت على الكهف... لألقى بعدها[ENTER]هلاكي. "
gameforge.ghost_story._080_npcChat = "هل تعرف قصة هذا المكان؟ "
gameforge.ghost_story._090_say = "نعم إني على علم بما حصل آنذاك. لقد قمت في حياتي[ENTER]بأبحاث متعمقة، محاولاً الكشف عن الأسرار المحيطة[ENTER]بالكهف والعثور على مكانه. الآن وبعد وفاتي توفر لي[ENTER]وقت كافٍ للتأمل في تلك الفترة. هيا أخبرني ما الذي[ENTER]ترغب في معرفته؟ "
gameforge.ghost_story._100_npcChat = "ما طبيعة هذه البوابة؟ "
gameforge.ghost_story._110_say = "إن هذه البوابة تقودك إلى جحر التنين الظلامي،[ENTER]الملاك الضحية، بيران-سيتاو. يمكن تفعيله بمفتاح[ENTER]رمزي سحري، لا يحصل عليه سوى زعماء قوات[ENTER]بيران-سيتاو... "
gameforge.ghost_story._120_npcChat = "الملوك الثلاث "
gameforge.ghost_story._130_say = "فيما مضى كوَّن الملوك الثلاث الركيزة الأساسية[ENTER]للكون. كانت باهار-تاراجي، ملاك الخلق، أصغرهم[ENTER]سِنّاً. مهمتها كانت تقتصر على خلق الجديد - ترى[ENTER]الورود تزدهر أينما ذهبت، والحياة تنبعث من جديد[ENTER]أينما مرّت. "
gameforge.ghost_story._140_say = "سم أخيهم الأكبر هو بيران-سيتاو. مهمته ترتكز على[ENTER]التصفية والإنهاء. كلما اقترب شوط من أشواط الحياة[ENTER]من الانتهاء، قام بفصل الجسد عن الروح وإرسال هذه[ENTER]الأخيرة إلى ما وراء الزمن. الشيء الذي ضمِن توفر[ENTER]كون وفناء منتظمين غير مُنقطعين، عنصرين أساسيين في[ENTER]تكوين كل حياة. "
gameforge.ghost_story._150_say = "وأخيراً كان أخوهما الأوسط بالجيت-إلفُدين، يسهر[ENTER]على بسط التوازن، والتوسط بين أخيه وأخته من أجل[ENTER]ضمان استمرار حلقة الحياة. فلقد كان مثلاً مسؤولاً[ENTER]عن تعاقب الفصول الأربعة. "
gameforge.ghost_story._160_npcChat = "النزاع "
gameforge.ghost_story._170_say = "توجه الناس إلى الملائكة الثلاث طالبين منهم الخير[ENTER]والمساعدة خاصة في الأوقات الصعبة. لكنهم كانوا[ENTER]يخافون بيران-سيتاو ويُكنون له الحقد، جهلاً منهم[ENTER]أنه يُمثل الكفة الموازنة للخلق، وأن الاستغناء عنه[ENTER]مستحيل، كاستحالة استغناء الضوء عن الظل. "
gameforge.ghost_story._180_say = "تجاهل الملاك الأمر لمدة طويلة، لكن ومع مرور[ENTER]السنين، تكون لديه شيئاً فشيء حسدٌ كبير ليتحول إلى[ENTER]حقد وخبث كبيرين. قام في بداية الأمر بتوجيه حقده[ENTER]هذا على البشر في شكل حروب وأمراض. لكن هذا زاد من[ENTER]حقدهم له، ودفع بهم إلى التوجه إلى باهار-تاراجي،[ENTER]ملاك الحياة المُنبعثة. كانت هذه بداية الحلقة[ENTER]المفرغة، التي تؤدي إلى الهلاك. "
gameforge.ghost_story._190_say = "لمّا زاد غضب وحقد الملاك بشكل تعذر عليه تملُّكه،[ENTER]حدثت الكارثة: أقدم على قتل أخته المحبوبة لدى[ENTER]الشعب. لم يكن لفعلته هذه بحاجة لأي تحضير خاص أو[ENTER]خطة محبوكة، لأنها كانت تثق به ثقة عمياء، لتلتقيه[ENTER]في ذلك اليوم المشؤوم بنفس الثقة والأمان. أكيد أنه[ENTER]وجه نظرته الأخيرة إلى عيناها البريئتان قبل أن[ENTER]يُوجه لها ضربته القاضية. "
gameforge.ghost_story._200_npcChat = "العواقب "
gameforge.ghost_story._210_say = "لقد كان لمقتل باهار-تاراجي عواقب وخيمة، ليس فقط[ENTER]في عالم الملوك بل أيضا في عالم البشر: شتاء طويل،[ENTER]بارد وموحش دفع العديد من البشر في البر والبحر[ENTER]ثمنه غالياً. موجة من البرد الصاقع نتج عنها تجمد[ENTER]كبير للأرض، أدّى إلى انكسار الأحجار، واقتلاع أقوى[ENTER]وأقدم الأشجار. "
gameforge.ghost_story._220_say = "مات العديد من الشباب والحيوانات، ولمّا بدأ الطقس[ENTER]في الاعتدال وارتفاع درجة الحرارة، كانت نسبة[ENTER]الولادة آنذاك منخفضة إلى أقصى حد. منتوج الأرض كان[ENTER]منخفضاً إلى درجة أنه لم يُوفر ما يكفي من الغذاء[ENTER]للسكان، عساك أبنائهم. مما أدّى إلى موت الأمل.[ENTER]وضعٌ كلّف الاثنين وقتاً طويلاً قبل أن يعود إلى[ENTER]الوضع العادي. "
gameforge.ghost_story._230_say = "أصاب الألم الملاك أيضاً، رغم أن وقتهم كان يمرُّ[ENTER]بسرعة أقل من سرعة مرور وقت البشر. كان بيران-سيتاو[ENTER]معتزلاً بنفسه في مكان آن، عندما وعِي بفِعلته.[ENTER]غمره عندها ندم مارٌّ دخل في جوفه في صراع مع إحساس[ENTER]بواجب الكفّارة، واستمر الوضع هكذا إلى أن تجلّد[ENTER]قلبه بعد انتصار واجب الكفّارة. ليتحول من ملاك[ENTER]التصفية إلى ملاك الجليد والبرد القاصع، وملاك[ENTER]الحقد والرُّعب. "
gameforge.ghost_story._240_npcChat = "المعركة "
gameforge.ghost_story._250_say = "حزن ملاك الحماية، بالجيت-إلفُدين، لموت أخته لمدة[ENTER]طويلة. لمّا خفت مخالب الحزن قبضتها عنه، رحل[ENTER]باحثاً عن أخيه. أنار التعقل والذكاء طريقه، ليدرك[ENTER]أن الحياة تستحيل في ظل عدم توفر التوازن الطبيعي. "
gameforge.ghost_story._260_say = "اتبع آثار أخيه وعثر عليه بعد مرور سنين عديدة،[ENTER]منكمشاً في كهف ثلجي مليء بالحقد والوحدانية،[ENTER]بعيداً عن الحياة. قام بالجيت-إلفُدين بفعل ما يجب[ENTER]عمله ولو أن الأمر زاد من حزنه وأضاف جرحاً عميقاً[ENTER]في قلبه. حيث أنه طلب من أخيه مبارزته، ولحماقته لم[ENTER]يتردد هذا الأخير ولو للحظة في قبول التحدي... "
gameforge.ghost_story._270_say = "ُحكى أن عنف المعركة فاق كل تصور وخيال. الفوز في[ENTER]آخر المطاف كان لبالجيت-إلفُدين. لكن واحتراماً منه[ENTER]لأخلاق وآداب القرابة لم يقم بقتله بل سحب منه قوته[ENTER]وسجنه في الكهف. هذه هي قصة بيران-سيتاو وكيف أودت[ENTER]به الظروف إلى هذا الكهف حيث يعيش معاً مع[ENTER]المخلوقات التي خلقها مع مرور القرون... "
gameforge.ghost_story._280_npcChat = "لقد استمعتُ لما يكفي الآن. "
gameforge.ghost_story._290_say = "أتمنى أن يلقاك قدرٌ مغاير لقدري. أتمنى لك حظّاً[ENTER]سعيداً! "
gameforge.ghost_story._300_sayTitle = "شبح أحد المحاربين: "
gameforge.ghost_story._310_npcChat = "لما أنت شفّاف؟ "
gameforge.ghost_story._320_say = "ما الذي تظنه يا هذا؟ أنا شبح، سجين الصخور منذ[ENTER]آلاف السنين... "
gameforge.ghost_story._330_say = "النجدة، شبح! "
gameforge.ghost_story._340_say = "نعم، شبح. هيّا أطلق العنان لقدميك وإلا افترستُك! "
gameforge.ghost_story._350_npcChat = "من أنت؟ "
gameforge.ghost_story._360_say = "لقد كنت في يوم من الأيام جندياً عادياً، ينتمي إلى[ENTER]المرتزقة. من أب فلاّح وأم بسيطة. نظراً لأنني لم[ENTER]أرغب في العمل في الفلاحة وتقفي آثار أبي، قررت[ENTER]الذهاب إلى الجيش. لم يكن الأمر سهلاً، لقد كان عكس[ENTER]ذلك صعباً ومُدمياً، لكنني استفدت الكثير. مللت بعد[ENTER]مدة الوضع وكرهت حُكم مجموعة من النبلاء[ENTER]المتغطرسين، مما دفع بي إلى هجر الجيش. يرجع الفضل[ENTER]في كوني هنا في هذا المكان الظلامي إلى إحدى الصدف[ENTER]الغريبة. "
gameforge.ghost_story._370_npcChat = "هل تعرف قصة الكهف؟ "
gameforge.ghost_story._380_say = "ا لست أدري، لقد كان سوء حظ فقط. كنت أود بعد هجري[ENTER]للجيش الفرار إلى الجبال لكي أختفي هناك، فعثرت على[ENTER]هذا الكهف. لم أرتح لأول وهلة لشكلها، لكن موقعها[ENTER]كان مناسباً، كما أنها بدت لي مهجورة. كنت فيها بعد[ENTER]أيام قليلة فقط شاهداً -بل وضحية أيضاً- على معركة[ENTER]فريدة من نوعها. سأحكي لك التفاصيل إذا أحببت. "
gameforge.ghost_story._390_npcChat = "بداية المعركة "
gameforge.ghost_story._400_say = "في يوم من الأيام - ذهبت لجمع بعض الجذور من سفوح[ENTER]الجبال - نزل وبدون أي سابق إنذار تنين فضي من[ENTER]السماء. ظننت فوراً أنها نهايتي، لكنه لم ينظر إلي،[ENTER]بل ارتكزت نظراته على مدخل الكهف فقط، حيث توجه[ENTER]إليه طائراً في الواد وبدون تخفيض سرعته. "
gameforge.ghost_story._410_say = "عم المكان لمدة قليلة هدوء غريب ومُروع، كنت خلالها[ENTER]حائراً لا أدري ما العمل. كانت جميع دروعي بالكهف،[ENTER]ولم أكن أبداً مستعداً أو راغباً في لقاء تنين![ENTER]بدأت الأرض بعد حين في الاهتزاز، وطلع من عمق الجبل[ENTER]صوت صراخ مُزعج - لم يكن صوت واحداً بل صوتين[ENTER]مُختلفين! طلع من الكهف بعد وهلت من الزمن تنينين،[ENTER]الأول فضي والثاني أزرق اللون. "
gameforge.ghost_story._420_say = "اندلعت بين الاثنين معركة شرسة، يصعب بالفعل وصفها.[ENTER]قاما باقتلاع أجنحة بعضهما البعض بمخالبهما الحادة،[ENTER]وغرس أنيابهما الثاقبة في عنقي بعضهما البعض....[ENTER]لقد أمطرت الدنيا دماً... لم يتراجع أيهما ولو[ENTER]للحظة فقط عن موقعه. "
gameforge.ghost_story._430_npcChat = "نهاية المعركة "
gameforge.ghost_story._440_say = "تدحرجا أثناء قتالهما بين الجبال كعاصفة رعدية[ENTER]قوية، مُتسببين في انكسار قممها. اسود مِنقار[ENTER]التنين الأزرق من جراء البرق، وغطّت ثقاب عميقة[ENTER]ناتجة عن سقوط كريات البَرد أجنحة التنين الفضي.[ENTER]تسبب حرُّ المعركة في ذوبان الغطاء الثلجي الذي كان[ENTER]يُغطّي الأرض لقرون عديدة، مُخلّفاً ورائه غطاءً من[ENTER]الوحل. انكمشت من شدة الرعب والهلع جامداً كالصنم[ENTER]وراء صخرة ضخمة، غير قادراً على كفِّ نظري عن[ENTER]المعركة الملحمية. "
gameforge.ghost_story._450_say = "لم تبدو علامات الإنهاك تظهر عليهما إلاّ بعد ساعات[ENTER]عديدة من القتال الضار. انطلقتُ مباشرة بعدها نحو[ENTER]الكهف مستغلاًّ الفرصة لاستخراج دروعي من الكهف،[ENTER]مما أضاف لقدري الرعب والرهب. شاهدت في طريق العودة[ENTER]من الكهف التنينين طائرين نحو الكهف مُغادرين[ENTER]الجبل، أولهم كان التنين الأزرق، الذي كان يقطر[ENTER]دماً من شدة الجراح العميقة. "
gameforge.ghost_story._460_say = "قبل أن يختفي هذا الأخير في الكهف تمكن التنين[ENTER]الفضي من الالتحاق به. حصل عندها شيء غريب وعجيب:[ENTER]أنار ضوء قوي المكان، ليتحول بعدها إلى ريح قوي[ENTER]وعاصفة من الطاقة؛ أحاطت بالتنين الأزرق لترتفع[ENTER]صيحاته من شدة الألم والغضب عالياً... تقلص حجمه،[ENTER]وانخفض صراخه وضعفت قوته، وفقدت حراشفه بريقها[ENTER]وحدتها وكذا لونها... "
gameforge.ghost_story._470_say = "ترك التنين الفضي بعدها التنين الآخر وسمح له[ENTER]بالانسحاب إلى داخل الكهف. سحب التنين المُنهزم[ENTER]جسده المُنهك بآخر ما لديه من قوة ليختفي في ظلام[ENTER]الكهف. قام التنين الفضي بعدها بإصدار عاصفة سحرية[ENTER]قوية، نتج عنها حاجز طاقي وضعه على مدخل الكهف، كما[ENTER]أنه أسقط جزءاً من الجبل على المدخل. أصبحت أنا[ENTER]والتنين الأزرق سجناء. ملعونين ومحكوم علينا الموت[ENTER]جوعاً شيء فشيء... "
gameforge.ghost_story._480_npcChat = "لقد استمعت لما يكفي الآن. "
gameforge.ghost_story._490_say = "شكراً لإصغائك. لقد كانت الوحدانية رفيقتي الوفية[ENTER]خلال الألف سنة الأخيرة... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Bevor ich dem Schwarzwind entkommen bin, konnte[ENTER]ich herausfinden, wo sie ihr Gold verstecken. Und[ENTER]da lagerte ein ganzer Stapel Goldbarren! Sie[ENTER]würden es noch nicht mal bemerken, wenn welche[ENTER]fehlen. Für gute Bezahlung würde ich das Wagnis[ENTER]auf mich nehmen und dir Goldbarren besorgen. Ich[ENTER]kann allerdings nicht mehr als einen Barren auf[ENTER]einmal zurückbringen. "
gameforge.goldbar._104_say = "Zeit "
gameforge.goldbar._108_say = "Minute(n) "
gameforge.goldbar._10_npcChat = "Ein Opfer der Schwarzwindbande "
gameforge.goldbar._110_say = "Es dauert ungefنhr %s %s, einen Goldbarren[ENTER]zurückzubringen. "
gameforge.goldbar._120_say = "Sag bescheid, wenn du interessiert bist. "
gameforge.goldbar._130_say = "Wirklich? Dann kommen wir ins Geschنft?[ENTER]Du musst es nur sagen und ich werde losziehen,[ENTER]um dir ein Exemplar zu besorgen! "
