gameforge.goldbar._300_say = "Wenn du den Goldbarren zurückbringen willst, "
gameforge.goldbar._30_say = "Was? Ein Opfer der Schwarzwindbande? Ha, du bist[ENTER]ja noch ein Kind. Wo hast du das gehِrt?[ENTER]Geh und spiel lieber mit den Wildhunden! "
gameforge.goldbar._310_say = "wirst du ungefنhr %s %s warten müssen. "
gameforge.goldbar._320_say = "Ich sehe, du besitzt keine Goldbarren.[ENTER]Wenn du mir welche bringst, werde[ENTER]ich dir gute Yang dafür geben. "
gameforge.goldbar._330_say = "Was? Du willst deinen Goldbarren zurückgeben?[ENTER]Warum in aller Welt hast du ihn dann überhaupt[ENTER]gekauft? Aber gut, wenn das dein Wunsch ist, so[ENTER]soll es mir recht sein. Die Schwarzwindbande[ENTER]bewacht ihre Schنtze نuكerst gut, es ist mir[ENTER]daher nicht oft mِglich. Bist du dir also ganz[ENTER]sicher, dass du ihn zurückgeben willst? "
