gameforge.goldbar._360_say = "Hier sind deine Yang.[ENTER]Verdammnis, nun muss ich ihn zurückbringen! "
gameforge.goldbar._370_say = "Hast du überhaupt Goldbarren bei dir?[ENTER]Ich bin sehr beschنftigt. Komm also nicht her,[ENTER]wenn du keine Geschنfte machen willst! "
