gameforge.heavens_cave_keyquest._335_say = "Ein leises Flüstern schwingt im Wind:[ENTER]Geh zu einem sicheren Ort... Hier kِnnen wir[ENTER]nicht reden...[ENTER]Klicke auf die Questrolle, um mit dem Geist zu[ENTER]sprechen. "
gameforge.heavens_cave_keyquest._340_say = "Im Wind erklingt die Stimme der erschlagenen[ENTER]Gِttin Bahar-Taraji... "
gameforge.heavens_cave_keyquest._350_say = "Die Trنnen meines Bruders... so sehr trauerte er[ENTER]um mich. Aber dennoch konnte er Beran-Setaou[ENTER]nicht für seine Tat bestrafen. "
gameforge.heavens_cave_keyquest._360_say = "Er konnte sich nicht gegen seinen Bruder stellen[ENTER]- gegen Beran-Setaou, den Zerstِrer. Ihn fürchtet[ENTER]ihr Menschen. "
gameforge.heavens_cave_keyquest._370_say = "Aber du... Wer bist du? Du bist anders! Du[ENTER]fürchtest ihn nicht. Im Gegenteil, ich sehe, dass[ENTER]du den Kampf suchst. "
gameforge.heavens_cave_keyquest._380_say = "%s! Nimm diesen Tropfen meines Blutes. Forme[ENTER]daraus einen Blutstein und lass Beran-Setaou für[ENTER]seine Tat bezahlen. Der Weg in die Grotte der[ENTER]Verbannung ist nicht mehr weit. "
gameforge.heavens_cave_keyquest._390_say = "Im Wind erklingt die Stimme der erschlagenen[ENTER]Gِttin Bahar-Taraji... "
gameforge.heavens_cave_keyquest._400_say = "%s! Ich erkenne dich! "
gameforge.heavens_cave_keyquest._410_say = "Du bringst meines Bruders Trنnen zu meinem Trost[ENTER]und sollst dafür mein Blut erhalten, damit du[ENTER]weiter kنmpfen kannst. "
gameforge.heavens_cave_keyquest._420_say = "Kehre mit dem Blut von Bahar-Taraji zu Seon-Hae[ENTER]zurück. "
gameforge.heavens_cave_keyquest._430_say = "Seon-Haes Augen glitzern, als er von dir den[ENTER]Blutstropfen entgegen nimmt... "
gameforge.heavens_cave_keyquest._440_say = "Das Blut einer leibhaftigen Gِttin! Schnell, lass[ENTER]es mich zu einem Blutstein formen, damit es nicht[ENTER]vergeht. "
gameforge.heavens_cave_keyquest._450_say = "Mit einem Blutstein wird dich der Wنchter[ENTER]Koe-Pung das Portal benutzen lassen, das dich in[ENTER]die Grotte der Verbannung führt. Allerdings nur[ENTER]ein einziges Mal. Wenn du weitere Blutsteine[ENTER]brauchst, dann kehre zu mir zurück. Ich kann dir[ENTER]aber nur einmal am Tag einen solchen Blutstein[ENTER]herstellen, damit wir nicht den Zorn des Ordens[ENTER]auf uns ziehen. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae kann dir weitere Blutsteine herstellen,[ENTER]aber nur einen pro Tag. "
gameforge.heavens_cave_keyquest._470_say = "Ich werde wie bisher das Blut von Bahar-Taraji zu[ENTER]einem Blutstein formen. Mِge er dir gute Dienste[ENTER]leisten. "
gameforge.heavens_cave_keyquest._480_say_reward = "Ich werde dir nur einmal am Tag einen Bluststein[ENTER]herstellen kِnnen. Andernfalls kِnnte Koe-Pung[ENTER]misstrauisch werden. "
