gameforge.horse_guard = {}
gameforge.horse_guard._10_npcChat = "معلومات عن حصانك "
gameforge.horse_guard._20_say = "ستحتاج للبدء في مهمة الحصان إلى ميدالية الحصان.[ENTER]ستحصل عليها في برج القردة المحصن. "
gameforge.horse_guard._30_say = "هناك ثلاث أنواع من الفرسان لكل نوع حصانه:[ENTER]المبتدئ، المتقدم والمحترف. عند رغبتك في التقدم[ENTER]لصعود طبقة جديدة، بعد القيام بما يكفي من[ENTER]التداريب، فعليك اجتياز اختبار الكفاءة. "
gameforge.horse_guard._40_say = "تحتاج الأحصنة إلى أنواع مختلفة من العلف، وذلك حسب[ENTER]مدى إجهادهم من قبل الفرسان. يطعم الفارس المبتدئ[ENTER]حصانه علف التبن. ويختار الفارس المتقدم الجزر. أما[ENTER]الفارس المحترف فعليه اختيار الجنكة الصينية[ENTER]الحمراء. يمكن هنا أن يصعب إرضاء الأحصنة. "
gameforge.horse_guard._50_say = "سيتم عرض وضع حصانك بواسطة مؤشر: إذا كان لون[ENTER]المؤشر أخضر فهذا يعني أنه بصحة جيدة. وعند تلونه[ENTER]بالأصفر فهذا يعني أنه جائع. أما اللون الأحمر فإنه[ENTER]يدل على معاناة الحصان من سوء التغذية. يجب عليك[ENTER]إطعام حصانك بمجرد ظهور اللون الأصفر أو الأحمر.[ENTER]سيكون الأمر صعباً إذا مات حصانك! "
gameforge.horse_guard._60_say = "ينخفض المستوى الصحي للحصان عند ركوبه ويرتفع مستوى[ENTER]إنهاكه وتعبه. لذى فعليك من حين لآخر أن تمنحه[ENTER]قدراً من الراحة لكي لا ينهار. "
gameforge.horse_guard._70_say = "تروج إشاعات مفادها أنه من الممكن إحياء حصان ميت[ENTER]باستعمال أعشاب القردة. غير أن القردة تحرص هذه[ENTER]الأعشاب بشدة، مما يجعلها صعبة المنال. ويُحكى أن[ENTER]القردة تُصيب اللص إذا أمسكوا به بلعنة، تحوله[ENTER]ليصبح قرداً مثلها. "
gameforge.horse_guard._80_say = "تختلف قدرات الفرسان من فارس لآخر. يمكنك إذا كنت[ENTER]تملك ميدالية حصان، أن تُحسِّن مستوى دابتك. "
