gameforge.locale.bookworm.aranyeo_complete_say = "Welcher Trottel hat meinem Ehemann[ENTER]dieses merkwürdige Buch besorgt?[ENTER]Den lieben langen Tag starrt er nur noch hinein[ENTER]und lernt merkwürdige Gesنnge auswendig. Er tut[ENTER]keinen Handschlag mehr![ENTER]Ich werde ihm alle Knochen brechen,[ENTER]wenn ich ihn erwische! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "Was ist geschehen? Ist das etwa Angstschweiك auf[ENTER]deiner Stirn? "
gameforge.locale.bookworm.aranyeo_start_say = "Wo ist er nur wieder hin? Sein Verhalten macht[ENTER]mich wahnsinnig! Er verschwendet seine Tage, ohne[ENTER]auch nur einen Yang zu verdienen,[ENTER]indem er sich ausschlieكlich mit seinen Büchern[ENTER]beschنftigt. Und er schنmt sich noch nicht[ENTER]einmal, dass er den Kindern damit ein schlechtes[ENTER]Vorbild liefert. "
gameforge.locale.bookworm.aranyeo_start_say2 = "Kِnnen Bücher einen Menschen ernنhren oder[ENTER]einkleiden? Ich werde ihm alle Knochen brechen,[ENTER]wenn ich ihn erwische! "
gameforge.locale.bookworm.aranyeo_talk = "Sprechen. "
gameforge.locale.bookworm.complete_say = "Oha! Ja, ich sehe es! Ich sehe es! Ich sehe die[ENTER]neue Welt! "
