gameforge.locale.bookworm.order_find_book_text_2 = "Nimm dem Jünger Milgyos das Milgyo-Buch ab. "
gameforge.locale.bookworm.order_refuse = "Das dürfte recht schwer sein. "
gameforge.locale.bookworm.order_refuse_answer = "Warum versuchst du es nicht? Ich weiك, dass du[ENTER]dazu in der Lage bist! "
gameforge.locale.bookworm.order_say1 = "Will du etwas Bemerkenswertes hِren?[ENTER]Ich kann wirklich von mir behaupten, alle Bücher[ENTER]auf der Welt gelesen zu haben![ENTER]Momentan studiere ich eine Sammlung heiliger[ENTER]Schriften.[ENTER]Es ist das Gerücht im Umlauf, dass geheime[ENTER]Informationen und Hinweise dazu, wie[ENTER]man ein wahrer Heiliger wird, im Milgyo-Buch[ENTER]verborgen sind. "
gameforge.locale.bookworm.order_say2 = "Ich würde dieses Buch gern lesen.Was meinst du,[ENTER]kannst du es mir besorgen? Ich würde dich[ENTER]selbstverstنndlich belohnen! "
gameforge.locale.bookworm.order_too_late = "Jemand anderes hat mir das Milgyo-Buch bereits[ENTER]gebracht. Du musst es nicht mehr tun. "
gameforge.locale.bookworm.start_find_bookworm_label = "Gehe zu Soon. "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Gehe zu Soon. "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Begib dich zu Soon und frag nach dem Milgyo-Buch. "
gameforge.locale.bookworm.start_say = "Kannst du die tiefe Weisheit dieses Schriftstücks[ENTER]erkennen? Aus einzelnen Worten formt sich eine[ENTER]wunderschِne Geschichte. Man muss sich erst daran[ENTER]gewِhnen, sich von der Phantasie anderer treiben[ENTER]zu lassen. Nicht jedem gefنllt diese Vorstellung,[ENTER]aber ich genieكe es sehr. "
