gameforge.locale.forked_rule = "قواعد لخوض المعركة : [ENTER][ENTER] 1. من يمت سيطرد من الارض المقدسة فكن حريصا. [ENTER] 2. بمجرد فتح الممر ودخولة, حينها لن يتمكن احد من الدخول للارض المقدسة من خلال الحراس .[ENTER] 3. يوجد صخرة تسد الطريق. للوصول لارض المعركة لا يمكن فتحها الا بمفتاح . "
gameforge.locale.forked_rule_sungzi = "القواعد بارض المعركة : [ENTER][ENTER] 1. الامبراطورية التي لا تصل الي عدد معين من الانتصارات ضد الامبراطوريات الاخري تخسر .[ENTER] 2. After the first round, the number of monsters raises. The first Kingdom defeating those additional numbers of monsters wins.[ENTER] 3. If then the fox-o'-nine-tails gets captured, the Battle at the Crossway is over.[ENTER] 4. No Items can be captured at the Battle of the Crossway.[ENTER] 5. Whoever dies three times in the Sanctuary will return to the village. [ENTER] "
gameforge.locale.fortune_words_1_body = "هذا جيد. ماهي صيغة المثل المشهور؟ من زرع الريح[ENTER]حصد العاصفة. لديك اليوم <حظ كبير<! هذا يسعدني[ENTER]جداً. ستحقق اليوم نجاحاً كبيراً،[ENTER]وذلك ببذل جهد بسيط! "
gameforge.locale.fortune_words_1_title = "حظ كبير! "
gameforge.locale.fortune_words_2_body = "هذا جيد. ما هي صيغة المثل المشهور؟ من زرع الريح[ENTER]حصد العاصفة. لديك اليوم حظ كبير! هذا يسعدني[ENTER]جدا. ستحقق اليوم نجاحا كبيرا، وذلك ببذل جهد بسيط! "
gameforge.locale.fortune_words_2_title = "حظ كبير! "
gameforge.locale.fortune_words_3_body = "جميل، شيء جميل. لديك اليوم بعض الحظ.[ENTER]سيكون يومك أفضل من الأيام الأخرى، لكن لا تتوقع[ENTER]الحصول على هدايا عظيمة من قدرك! "
gameforge.locale.fortune_words_3_title = "بعض الحظ. "
gameforge.locale.fortune_words_4_body = "ليس بالرائع ولكنه ليس بالسيئ! يومك سيكون مليئاً[ENTER]بـ الحظ العادي. لن يفيدك هذا بشكل كبير، لكنه[ENTER]على الأقل يحميك من سوء الحظ. لا تستهن بالأيام ذات[ENTER]الحظ العادي! "
gameforge.locale.fortune_words_4_title = "حظ عادي. "
gameforge.locale.fortune_words_5_body = "لن يحالفك الحظ اليوم. حتى إذا رميت الشبكة بنفس[ENTER]الهمة والعزم كالعادة، فإنك لن تحصل اليوم إلاّ على[ENTER]القليل من السمك. لكن لا داع للقلق، فإنك لن تعاني[ENTER]سوى من بعض الجوع. إنه يوم مليء بسوء الحظ! ولكن[ENTER]أفضل شيء هو أن تكون دائماً على استعداد. بإمكاني[ENTER]أن أكتب لك تعويذة إذا أحببت، تعويذة ستمنع عنك[ENTER]السوء. ما رأيك؟ "
gameforge.locale.fortune_words_5_title = "بعض سوء الحظ. "
gameforge.locale.fortune_words_6_body = "اليوم يوم مشؤوم. يوم لا زرع فيه ولا حصاد. لديك[ENTER]اليوم سوء حظ عليك أن تنتبه جيداً لكل ما تعمله.[ENTER]بإمكاني مساعدتك بكتابة تعويذة تشتريها مني إذا[ENTER]أردت، ستمنع عنك الضرر. ما رأيك؟ هل تريد شرائها؟ "
gameforge.locale.fortune_words_6_title = "سوء حظ. "
gameforge.locale.fortune_words_7_body = "إنه أسوأ أيامك على الإطلاق. لقد غادرك ملاك الحظ[ENTER]ولن توفق في أي عمل تقوم به. إذا ما رغبت في إيقاد[ENTER]النار فإن السماء ستمطر بدون توقف، وإذا جف حلقك[ENTER]عطشاً فإن أشعة الشمس ستزداد حرا. مثلك مثل الجميع[ENTER]فإنك ستعمل بشكل شاق بدون جني ثمار أعمالك. لقد[ENTER]أصابك بالفعل بأس كبير وسوء حظ عظيم! إنك بدون[ENTER]تعويذة ستواجه صعوبات شديدة. هل تريد أن تشتري[ENTER]تعويذة؟ "
gameforge.locale.fortune_words_7_title = "سوء حظ كبير. "
