gameforge.locale.monster_chat_1091_1 = "لا تحارب الظلام . اسمح للظلام بتملك قلبك! "
gameforge.locale.monster_chat_1091_2 = "أنت لا تعلم مقدار القوة في السحر المظلم "
gameforge.locale.monster_chat_1091_3 = "لن يمكنك أن تنتقل للطابق التالي إلا إذا هزمتني وجيشي ! "
gameforge.locale.monster_chat_1091_4 = "لن يكون قتلك أمراً صعباً "
gameforge.locale.monster_chat_1091_5 = "أنا لا أتذكر أسماء من أقوم بقتلهم "
gameforge.locale.monster_chat_1091_6 = "القتل يجري في دمي! "
gameforge.locale.monster_chat_1093_1 = "لقد اقتربت نهايتك! "
gameforge.locale.monster_chat_1093_2 = "سأجعل من هذا المكان مقبرةً لك! "
gameforge.locale.monster_chat_1093_3 = "استسلم ، لامفر لك للهرب "
gameforge.locale.monster_chat_1093_4 = "هل تريد مني أن ألجأ للعنف؟ لن أتهاون معك بعد الآن "
gameforge.locale.monster_chat_1093_5 = "مرحباً بك في مخبئي اعتبر نفسك في منزلك ، فنهايتك قريبةً على كل حال. "
gameforge.locale.monster_chat_1093_6 = "هل تعتقد أنه من السهل هزيمتي!؟ "
gameforge.locale.monster_chat_11000_1 = "الشيء المميز لدى المحارب, هو كيفية خوضه للمعركة. "
gameforge.locale.monster_chat_11000_10 = "عليك التعلم إذا كنت ترغب في تحسين مهاراتك! "
gameforge.locale.monster_chat_11000_11 = "لكي تتمكن من تحسين مهاراتك كسورا! يجب أن تزيد من ذكائك! "
gameforge.locale.monster_chat_11000_12 = "إذا أردت أن تملك قوة الطبيعة وخاصة قوة البرق منها! فاطلب تدريب العلاج! "
gameforge.locale.monster_chat_11000_13 = "يختار الشامان إعادة الإحياء, الدعم والسحر "
gameforge.locale.monster_chat_11000_14 = "اصغو جميعا أنتم القلقون على مستقبلكم! "
gameforge.locale.monster_chat_11000_15 = "إذا أردت أن تصبح محاربا خبيرا , عليك أن ترفع من قوتك وحيويتك ! "
gameforge.locale.monster_chat_11000_16 = "هل تعرف مكان معبد الطائفة السرية؟ "
gameforge.locale.monster_chat_11000_17 = "لا تنسى ما تلقنته في التدريب. "
gameforge.locale.monster_chat_11000_18 = "احذر الأعداء من البلدان الآخرى لا يمكن لأحد أن يتوقع غدرهم! "
gameforge.locale.monster_chat_11000_19 = "صيد السمك؟ لا بأس به! هل تحمل معك أصلا صنارة الصيد وطعم السمك! "
gameforge.locale.monster_chat_11000_2 = "تدريب القتال عن بعد يخص فقط الننجا في المستوى 5 وما فوق! "
gameforge.locale.monster_chat_11000_20 = "استفد من خصائص الننجا! ركز على السرعة والقوة الجسدية! "
gameforge.locale.monster_chat_11000_21 = "اطمح لمستوى الخبير ! هذا هو الطريق الوحيد لتصبح بطلا حقيقيا! "
gameforge.locale.monster_chat_11000_22 = "تكمن قوة السورا في السحر , حسن من ذكائك , ولا تنسى قوتك الجسدية! "
gameforge.locale.monster_chat_11000_23 = "هل تريد أن تجدد مهاراتك؟ اذهب إلى العجوز! ولا تنسى أن تأخذ ما يكفي من اليانغ معك ! "
gameforge.locale.monster_chat_11000_24 = "كهوف العناكب عادة مجددا! إنها في صحراء يونغبي! "
gameforge.locale.monster_chat_11000_25 = "أترغب في قراءة كتاب مهارات إضافي؟ انتظر لمدة يوم آخر! "
gameforge.locale.monster_chat_11000_26 = "أيها المحاربون ذوي المستوى 1إلى ,5 أصغو جيدا! "
gameforge.locale.monster_chat_11000_27 = "بمجرد انتهائك من قراءة كتابك فإنه سيختفي! "
gameforge.locale.monster_chat_11000_28 = "أترغب في قراءة كتاب مهارات إضافي؟ انتظر لمدة يوم آخر! "
gameforge.locale.monster_chat_11000_29 = "مرحباً بكم في عالم Metin1 . "
gameforge.locale.monster_chat_11000_3 = "هل ترغب بجني الكنوز؟ إبدأ بتحطيم الماتينات وابحث عن الصناديق الغامضة التي تحوي على كنوز ثمينة. "
gameforge.locale.monster_chat_11000_30 = "غرفة البارونة وهي الغرفة السرية للعناكب توجد في كهف العناكب الطابق الثالث "
gameforge.locale.monster_chat_11000_31 = "الأحزمة الخاصة تمنحك مساحة إضافية لتخزين الجرع "
gameforge.locale.monster_chat_11000_4 = "شهادات الدواب الرهيبة يمكنك تفعيلها من صبي الإصطبل "
gameforge.locale.monster_chat_11000_5 = "لكي تتمكن من الضرب من فوق الدابة الرهيبة يجب عليك أولاً أن تصل لمستوى الحصان المدرع. "
gameforge.locale.monster_chat_11000_6 = "لكي تتمكن من استعمال مهارات الفروسية من فوق الدابة الرهيبة تحتاج أولاً أن تصل لمستوى الحصان العسكري. "
