gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "Tِte jene, die den Erreger der rنtselhaften[ENTER]Krankheit in sich tragen, und bring eine Probe[ENTER]des Erregers zu Baek-Go. Er wird eine Arznei für[ENTER]den alten Piraten herstellen. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]Jemand anderes hat mir bereits eine Probe des[ENTER]Erregers gebracht. Ich habe dem alten Piraten die[ENTER]Arznei geschickt, und es sollte ihm wieder gut[ENTER]gehen. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]Er hatte nur einmal Kontakt zu einer angesteckten[ENTER]Person, und dann begann seine Wunde zu eitern und[ENTER]juckte?! "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baekgo:[ENTER]Du meine Güte! Ich bin mir fast sicher, dass er[ENTER]an der rنtselhaften Krankheit erkrankt ist! Wenn[ENTER]er nicht behandelt wird, breitet sich die[ENTER]Krankheit im ganzen Dorf aus! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Er darf niemanden anstecken! Du musst ihn sofort[ENTER]behandeln. Dafür brauchen wir eine Probe des[ENTER]Erregers der rنtselhaften Krankheit. Diese Probe[ENTER]kannst du von Kranken erhalten, die in groكer[ENTER]Zahl auf dem Berg Sohan im Norden anzutreffen[ENTER]sind. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Du hast es geschafft! Warte einen Augenblick auf[ENTER]die Arznei! [DELAY value;1000]Ich habe das so rasch hergestellt, dass ich nicht[ENTER]weiك, ob es wirkt. Zumindest wird es ihm besser[ENTER]gehen. Bring ihm dieses Medikament so schnell wie[ENTER]mِglich. "
