gameforge.locale.old_pirate.do_you_mean_this_medicine = "Hier ist das Heilmittel! "
gameforge.locale.old_pirate.etc_shop_start_say = "Gemischtwarenhنndlerin:[ENTER]Der alte Pirat? Natürlich kenne ich ihn. Du[ENTER]sprichst von diesem ewig fluchenden Kerl, der[ENTER]sich dauernd kratzt, nicht wahr? Er kommt oft[ENTER]vorbei, um ein flüssiges Heilmittel zu kaufen. Er[ENTER]hat schon viele tausend Yang für das rote[ENTER]Heilmittel ausgegeben. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Gemischtwarenhنndlerin:[ENTER]Woher um alles in der Welt nimmt er so viel Yang,[ENTER]wenn er nicht einmal arbeitet? Ich habe ihm schon[ENTER]mehrfach gesagt, er soll sich von einem Arzt[ENTER]untersuchen lassen, aber er hِrt nicht auf mich.[ENTER]Das rote Heilmittel lindert nur die Symptome und[ENTER]heilt nicht die Krankheit. Ich fürchte, es wird[ENTER]bِse mit ihm enden. "
