gameforge.locale.old_pirate.order_refuse_answer = "Alter Pirat:[ENTER]Na, dann hab' ich dir nichts mehr zu sagen! "
gameforge.locale.old_pirate.order_say1 = "Alter Pirat:[ENTER]Verflucht! Was willst du von mir? Mist! Diese[ENTER]Ramschladenbesitzerin hat dir was erzنhlt, hm?[ENTER]Ja, was sie sagt, stimmt. Aber ich hab keine[ENTER]Zeit, zum Arzt zu gehen. Ich habe so viele[ENTER]Feinde! "
gameforge.locale.old_pirate.order_say2 = "Alter Pirat:[ENTER]Man weiك nie, ob so ein Bastard nicht plِtzlich[ENTER]vor einem steht und einfach zusticht! Aber es[ENTER]juckt so schrecklich, dass ich es wirklich nicht[ENTER]mehr aushalte! Wie sieht es aus? Kannst du für[ENTER]mich zum Arzt gehen und eine Arznei gegen den[ENTER]Juckreiz besorgen? Wenn du die Arznei besorgst,[ENTER]werde ich dich gut belohnen. "
