gameforge.locale.old_pirate.success_thanks = "Alter Pirat:[ENTER]Was? Ich hab' mich mit der rنtselhaften[ENTER]Krankheit angesteckt?! Und das ist das nِtige[ENTER]Medikament? Vielen, vielen Dank! Du hast mir[ENTER]vermutlich das Leben gerettet. Ich weiك das zu[ENTER]schنtzen. "
