gameforge.locale.questscroll5.mission_47_text = "Wir haben herausgefunden, wie die Eismonster auf[ENTER]dem Berg Sohan sich untereinander verstنndigen:[ENTER]Sie verbreiten ihre Informationen über die[ENTER]schwebenden Eissplitter, die dort überall[ENTER]anzutreffen sind.[ENTER]Um die Truppen des Eislandes zu schwنchen, müssen[ENTER]wir diese Informationsübertragung stِren. Ich[ENTER]bitte dich: Beseitige das Verzauberte Eis! "
gameforge.locale.questscroll5.mission_48_hunt = "Das Geheimnis des Dنmonenturms "
gameforge.locale.questscroll5.mission_48_mis = "Tِte 45 Gemeine Geist Kنmpfer. "
gameforge.locale.questscroll5.mission_48_text = "Einige Gerüchte besagen, dass die Gemeinen[ENTER]Speerkنmpfer im Dنmonenturm unbesiegbar seien.[ENTER]Angeblich stehen sie jedes Mal wieder auf, wenn[ENTER]man sie tِtet. Wenn das stimmt, stehen uns dunkle[ENTER]Zeiten bevor. Bitte finde mehr darüber heraus! "
gameforge.locale.questscroll5.mission_49_hunt = "Der Herr des Dنmonenturms "
gameforge.locale.questscroll5.mission_49_mis = "Tِte 60 Gemeine Geist Schamanen. "
gameforge.locale.questscroll5.mission_49_text = "Nach genauerer Untersuchung wurde festgestellt,[ENTER]dass die Geistersoldaten fortwنhrend wiederbelebt[ENTER]wurden. Wir müssen Gemeine Geist Schamanen[ENTER]vernichten, um das zu verhindern. "
gameforge.locale.questscroll5.mission_4_hunt = "Auftauchen der Grauwِlfe 1 "
gameforge.locale.questscroll5.mission_4_mis = "Erlege 35 Grauwِlfe. "
gameforge.locale.questscroll5.mission_4_text = "Hast du von den Grauwِlfen gehِrt? Sie waren[ENTER]meist alleine unterwegs, aber durch den Einfluss[ENTER]des bِsen Chi in letzter Zeit haben sie begonnen,[ENTER]in Rudeln Reisende zu jagen.[ENTER]Kِnntest du bitte diese Grauwِlfe zur Strecke[ENTER]bringen? Es soll dein Schaden nicht sein. "
gameforge.locale.questscroll5.mission_50_hunt = "Doyyumhwan erforschen "
gameforge.locale.questscroll5.mission_50_mis = "Tِte 45 Kampftigersklaven. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan ist ein Lavagebiet, das von noch[ENTER]unbekannten Monstern bevِlkert wird.[ENTER]Wir müssen diese Region erforschen. Kannst du uns[ENTER]dabei helfen? "
gameforge.locale.questscroll5.mission_51_hunt = "Flammengeist! Seine Identitنt "
gameforge.locale.questscroll5.mission_51_mis = "Tِte 45 Flammengeister. "
gameforge.locale.questscroll5.mission_51_text = "Eine Gruppe, die Kampftiger jagen sollte, wurde[ENTER]selbst von noch unbekannten Gegnern vernichtet.[ENTER]Es heiكt, dass diese Gegner wie brennende Mنdchen[ENTER]aussehen, also finde heraus, worum es sich[ENTER]handelt. "
gameforge.locale.questscroll5.mission_52_hunt = "Reduziere die Zahl der Kampftiger "
gameforge.locale.questscroll5.mission_52_mis = "Tِte 60 Kampftigersklaven und 40 Kampftiger. "
gameforge.locale.questscroll5.mission_52_text = "Jetzt, da wir die Feuergeister bekنmpfen kِnnen,[ENTER]müssen wir sie im offenen Kampf komplett[ENTER]vernichten. Diese Aufgabe wird vom Militنr[ENTER]übernommen, aber um mit voller Kampfstنrke zu den[ENTER]Feuergeistern durchdringen zu kِnnen, brauchen[ENTER]wir eine Einfallschneise.[ENTER]Bitte sorge dafür, dass uns keine Kampftiger in[ENTER]die Quere kommen. "
gameforge.locale.questscroll5.mission_53_hunt = "Erforsche die Flammen "
gameforge.locale.questscroll5.mission_53_mis = "Tِte 40 Flammen. "
gameforge.locale.questscroll5.mission_53_text = "Die Flammen sind unglaublich brutal. Sie ergِtzen[ENTER]sich am Schmerz der Menschen, deren Haut sie[ENTER]gerade verzehren. Wir haben noch keine Ahnung,[ENTER]wie wir sie ausschalten kِnnen.[ENTER]Kannst du mehr über diese Flammen herausfinden? "
gameforge.locale.questscroll5.mission_54_hunt = "Flammenkrieger "
gameforge.locale.questscroll5.mission_54_mis = "Tِte 60 Flammenkrieger. "
gameforge.locale.questscroll5.mission_54_text = "Vor kurzem wurde das Kind eines Adligen, das sich[ENTER]in das Feuerland begab, von einem Flammenkrieger[ENTER]erschlagen. Wenn du die Flammenkrieger tِtest,[ENTER]erhنltst du eine Belohnung. Warum forderst du sie[ENTER]nicht heraus? "
gameforge.locale.questscroll5.mission_55_hunt = "Untersuche die Geisterbنume "
gameforge.locale.questscroll5.mission_55_mis = "Fنlle 30 Geisterbنume. "
gameforge.locale.questscroll5.mission_55_text = "Sie stehen wie normale, etwas finster aussehende[ENTER]Bنume in der Landschaft herum – doch dann werden[ENTER]sie plِtzlich lebendig und greifen Tiere und[ENTER]Menschen an.[ENTER]Finde heraus, wie die Geisterbنume vernichtet[ENTER]werden kِnnen. "
gameforge.locale.questscroll5.mission_56_hunt = "Das Geheimnis des Geisterwaldes "
gameforge.locale.questscroll5.mission_56_mis = "Tِte 40 Geisterbaumstümpfe und 30 Dryaden. "
gameforge.locale.questscroll5.mission_56_text = "Nachforschungen haben ergeben, dass der[ENTER]Geisterwald ein Gebiet ist, das von[ENTER]Geisterbaumstumpf und Dryade dominiert wird. Wenn[ENTER]du sie vernichtest, kannst du vielleicht[ENTER]verhindern, dass sich die Geisterbنume weiter[ENTER]ausbreiten. "
gameforge.locale.questscroll5.mission_5_hunt = "Sorge um die Dِrfer "
gameforge.locale.questscroll5.mission_5_mis = "Erlege 40 Keiler. "
gameforge.locale.questscroll5.mission_5_text = "Die Sorgen der Dorfbewohner in der Nنhe der Stadt[ENTER]haben in letzter Zeit zugenommen. Keiler, die[ENTER]bisher hِchstens kleine Tiere in den Bergen[ENTER]angefallen haben, sind aggressiv geworden. Sie[ENTER]sind in die Felder eingefallen und haben die[ENTER]Bauern angegriffen. Kannst du diese Keiler[ENTER]vertreiben? "
gameforge.locale.questscroll5.mission_6_hunt = "Tiger und Bنren "
gameforge.locale.questscroll5.mission_6_mis = "Erlege 25 Tiger und 30 Bنren. "
gameforge.locale.questscroll5.mission_6_text = "Hast du das schon gehِrt? Wenn Tiger und Bنren[ENTER]100 Tage lang nur Knoblauch und Zwiebeln fressen,[ENTER]kِnnen sie sich in Groكtiger und Feuerbنren[ENTER]verwandeln. Ich glaube nicht, dass das schon[ENTER]jemals passiert ist, aber es schadet nicht,[ENTER]sicher zu gehen. Erlege ein paar Tiger und Bنren[ENTER]und schau nach, was sich in ihren Mنgen befindet. "
gameforge.locale.questscroll5.mission_7_hunt = "Metin der Gier zerstِren "
gameforge.locale.questscroll5.mission_7_mis = "Zerstِre 2 Metin der Gier. "
gameforge.locale.questscroll5.mission_7_text = "Seit kurzem regnet es Steine in der Nنhe der[ENTER]Stadt. Sie scheinen bِses Chi zu besitzen, denn[ENTER]seitdem gebنrden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte kümmere dich darum, dass diese[ENTER]Steine zerstِrt werden. Du wirst für deine Mühe[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_8_hunt = "Metin der Schlacht zerstِren "
gameforge.locale.questscroll5.mission_8_mis = "Zerstِre 2 Metin der Schlacht. "
gameforge.locale.questscroll5.mission_8_text = "Seit kurzem regnet es Steine in der Nنhe der[ENTER]Stadt. Sie scheinen bِses Chi zu besitzen, denn[ENTER]seitdem gebنrden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte kümmere dich darum, dass diese[ENTER]Steine zerstِrt werden. Du wirst für deine Mühe[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_9_hunt = "Sorge um die Dِrfer 2 "
gameforge.locale.questscroll5.mission_9_mis = "Erlege 30 Rote Keiler. "
gameforge.locale.questscroll5.mission_9_text = "Seit kurzem suchen Gruppen von Keilern mit[ENTER]jeweils einem Roten Keiler, der sie anführt, die[ENTER]Dِrfer in der Nنhe der Hauptstadt heim.[ENTER]Die Regierung hat befohlen, die Roten Keiler zu[ENTER]tِten: Jeder Krieger soll 30 von ihnen erlegen.[ENTER]Wir bitten dich um deine Mithilfe. "
gameforge.locale.questscroll_10_hunt = "Schlangenmenschensoldaten "
gameforge.locale.questscroll_10_mis = "Tِte die Soldaten, die halb Mensch, halb Schlange[ENTER]sind. "
gameforge.locale.questscroll_10_text = "Man kann sie eigentlich nicht als Menschen[ENTER]bezeichnen. Aber es ist genauso falsch zu sagen,[ENTER]dass sie keine Menschen wنren. Sie sehen aus wie[ENTER]Menschen, aber Kopf, Haut und Verhalten gleichen[ENTER]dem giftiger Schlangen. Sie durchstreifen die[ENTER]Wüste und greifen Hنndler an.[ENTER]Tِte 20 dieser Soldaten, die halb Mensch, halb[ENTER]Schlange sind. Wenn du sie vernichtest, erhنltst[ENTER]du folgende Belohnung: "
gameforge.locale.questscroll_11_hunt = "Schlangenmenschenschützen "
gameforge.locale.questscroll_11_mis = "Tِte die Schützen, die halb Mensch, halb Schlange[ENTER]sind. "
gameforge.locale.questscroll_11_text = "Sie sind so intelligent wie Menschen. Sie sind[ENTER]verschlagen und verstehen sich hervorragend auf[ENTER]den Umgang mit Waffen. Bogenschützen, die halb[ENTER]Mensch und halb Schlange sind, greifen die[ENTER]Hنndler auf Distanz an. Viele der Hنndler sind[ENTER]bereits gestorben.[ENTER]Tِte 20 der Bogenschützen, die halb Mensch und[ENTER]halb Schlange sind. Wenn du diesen Auftrag[ENTER]erfolgreich abschlieكt, erhنltst du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_12_hunt = "Wüstenbanditen "
gameforge.locale.questscroll_12_mis = "Tِte die Wüstenbanditen. "
gameforge.locale.questscroll_12_text = "In der Yongbi-Wüste leben bِse Wesen. Sie sind[ENTER]als Wüstenbanditen bekannt und ihre Untaten[ENTER]schreien zum Himmel. Sie rauben Hنndler aus und[ENTER]tِten sie zum Spaك. Sie haben auch einige Dِrfer[ENTER]in der Wüste zerstِrt.[ENTER]Erschlage 12 Wüstenbanditen, dann erhنltst du[ENTER]folgende Belohnung: "
gameforge.locale.questscroll_13_hunt = "Kampftiger "
gameforge.locale.questscroll_13_mis = "Tِte die Kampftiger. "
gameforge.locale.questscroll_13_text = "Es gibt Wesen, die Kampftiger genannt werden. Ihr[ENTER]Blut ist aus Feuer, und ihre Kِrper wurden aus[ENTER]vulkanischem Granit geformt. Sie sind[ENTER]ungewِhnlich mنchtige Monster! Diese Monster[ENTER]ernنhren sich von der Lava und dem Feuer des[ENTER]Vulkans. Manchmal steigen sie vom Vulkan herab,[ENTER]greifen Menschen an und fressen sie.[ENTER]Erschlage 20 der Kampftiger. Wenn du sie[ENTER]vernichtest, erhنltst du folgende Belohnung: "
gameforge.locale.questscroll_14_hunt = "Kriegsmannen "
gameforge.locale.questscroll_14_mis = "Tِte die Kriegsmannen. "
gameforge.locale.questscroll_14_text = "Doyyumhwan ist groك und heiك und beherbergt wilde[ENTER]Tiere. Dort treffen sich Krieger aus Chunjo,[ENTER]Jinno und Shinsoo. Furchterregende, mنchtige[ENTER]Monster warten dort auf die Krieger. Kriegsmannen[ENTER]sind die Beherrscher von Doyyumhwan.[ENTER]Willst du sie herausfordern? Wenn du 20 von ihnen[ENTER]erschlنgst, erhنltst du folgende Belohnung: "
gameforge.locale.questscroll_15_hunt = "Taehwa-Krieger "
gameforge.locale.questscroll_15_mis = "Tِte die Taehwa-Krieger. "
gameforge.locale.questscroll_15_text = "Hِrt her, alle, die Ihr Euch für starke Kنmpfer[ENTER]haltet! Dies ist das Flammenschlachtfeld der[ENTER]Trنnen, des Leids, des Kampfes und des Todes! Ich[ENTER]lebe hier mit vielen Monstern und Bِsewichten![ENTER]Wer wagt es, mich zu herauszufordern? Findet sich[ENTER]jemand, der mir mit dem Schwert in der Hand[ENTER]gegenübertritt? Wenn du auf deinen Schwertarm[ENTER]vertraust, dann komm heraus und fordere mich![ENTER]Wenn du mich und 12 meiner Kameraden bezwingst,[ENTER]erhنltst du folgende Belohnung: "
gameforge.locale.questscroll_16_hunt = "Dunkelbنren "
gameforge.locale.questscroll_16_mis = "Tِte die Dunkelbنren. "
gameforge.locale.questscroll_16_text = "Wenn du diesen Brief liest, bin ich bereits tot[ENTER]oder verschwunden. Ich lebte im Tal von[ENTER]Seungryong, wo ich Heilpflanzen sammelte. Aber[ENTER]Monster, die Dunkelbنren genannt werden, fingen[ENTER]an, allerlei Untaten zu begehen. Sie tِteten[ENTER]meine Familie. Bitte rنche mich und meine[ENTER]Familie. Wenn du 25 Dunkelbنren erschlنgst,[ENTER]erhنltst du folgende Belohnung: "
gameforge.locale.questscroll_17_hunt = "Riesendunkelbنren "
gameforge.locale.questscroll_17_mis = "Tِte die Riesendunkelbنren. "
gameforge.locale.questscroll_17_text = "Eine neue Art Monster wurde entdeckt: Es handelt[ENTER]sich um Riesendunkelbنren, grِكer und[ENTER]stنrker als Dunkelbنren und von unglaublicher[ENTER]Bِsartigkeit. Solange es diese Wesen im Tal von[ENTER]Seungryong gibt, werden die Menschen leiden.[ENTER]Tِte 20 Riesendunkelbنren. Wenn du Erfolg hast,[ENTER]erhنltst du folgende Belohnung: "
gameforge.locale.questscroll_18_hunt = "Soldaten, die an der rنtselhaften Krankheit[ENTER]leiden "
gameforge.locale.questscroll_18_mis = "Soldaten tِten, die an der rنtselhaften Krankheit[ENTER]leiden. "
gameforge.locale.questscroll_18_text = "Das Dorf wurde wohl ausgelِscht. Diejenigen, die[ENTER]an der rنtselhaften Krankheit leiden, greifen die[ENTER]Unglückseligen an, die vorbeikommen. Sie greifen[ENTER]fahrende Hنndler an und fressen Menschen. Sie[ENTER]sind extrem gefنhrlich. Erschlag 35 Soldaten, die[ENTER]an der rنtselhaften Krankheit leiden. Wenn Du[ENTER]Erfolg hast, erhنltst Du folgende Belohnung: "
gameforge.locale.questscroll_19_hunt = "Schützen, die an der rنtselhaften Krankheit[ENTER]leiden "
gameforge.locale.questscroll_19_mis = "Schützen tِten, die an der rنtselhaften Krankheit[ENTER]leiden. "
gameforge.locale.questscroll_19_text = "Die rنtselhafte Krankheit ist die Ursache der[ENTER]Schنden, die diejenigen hervorrufen, die an ihr[ENTER]leiden. Aber am gefنhrlichsten sind die[ENTER]Bogenschützen, die die Krankheit erfasste. Diese[ENTER]Schützen verschieكen Giftpfeile, die Reisende[ENTER]lنhmen, sodass sie ergriffen und verschleppt[ENTER]werden kِnnen. Tِte 25 Bogenschützen, die an der[ENTER]rنtselhaften Krankheit leiden. Wenn Du Erfolg[ENTER]hast, erhنltst Du folgende Belohnung: "
gameforge.locale.questscroll_1_hunt = "Feuerbنren "
gameforge.locale.questscroll_1_mis = "25 Feuerbنren erlegen. "
gameforge.locale.questscroll_1_text = "Feuerbنren sind oft in der Nنhe der Hauptstadt[ENTER]anzutreffen. Sie durchstreifen die Prنrie und die[ENTER]breiten Straكen der Menschen. Sie finden[ENTER]zunehmend mehr Opfer. Einige Menschen wurden[ENTER]getِtet. Jag diese Feuerbنren. Wenn Du 25[ENTER]Feuerbنren erlegst, erhنltst Du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "4 Feinde erschlagen. "
gameforge.locale.questscroll_20_text = "Ich fürchte, ich bin erledigt! Mein Blick[ENTER]verschwimmt. Wenn Du diesen Brief liest, wird[ENTER]mein Kِrper bereits verfault sein. Die Schweine[ENTER]haben mich gepackt und verschleppt. Ich bin zwar[ENTER]entkommen, aber die Wunde war so tief, dass ich[ENTER]zusammenbrach. Ich kenne Dich nicht. Aber bitte[ENTER]rنcht mich! Erschlag vier Feinde am Ort des[ENTER]Kampfes. Wenn Du Erfolg hast, erhنltst Du[ENTER]folgende Belohnung: "
gameforge.locale.questscroll_2_hunt = "Groكtiger "
gameforge.locale.questscroll_2_mis = "20 Groكtiger erlegen. "
gameforge.locale.questscroll_2_text = "Der Name der Bosheit, Groكtiger, durchdringt die[ENTER]Luft. Diese Tiger finden sich meist in der Nنhe[ENTER]der Hauptstadt. Sie greifen Menschen an und[ENTER]fressen die Leichen der Hنndler. Ihre Opfer sind[ENTER]zahllos. Jag die Groكtiger. Wenn Du 20 Groكtiger[ENTER]erlegst, erhنltst Du folgende Belohnung: "
gameforge.locale.questscroll_3_hunt = "Hundegott des Berges "
gameforge.locale.questscroll_3_mis = "Den Hundegott des Berges tِten. "
gameforge.locale.questscroll_3_text = "Der Hundegott des Berges führt ein Rudel von[ENTER]Hundemonstern in der Nنhe an. Er ist stark und[ENTER]wild. Vor kurzem ist er in der Nنhe des Dorfes[ENTER]aufgetaucht und hat begonnen, Hنndler[ENTER]anzugreifen. Viele sind diesem Monster schon zum[ENTER]Opfer gefallen. Seine Untaten kِnnen nicht lنnger[ENTER]ignoriert werden. Tِte den Hundegott des Berges.[ENTER]Wenn Du Erfolg hast, erhنltst Du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_4_hunt = "Schweinegott "
gameforge.locale.questscroll_4_mis = "Den Schweinegott tِten. "
gameforge.locale.questscroll_4_text = "In dieser Jahreszeit steht das reife Korn auf den[ENTER]Feldern. Es ist Zeit für die Ernte, Zeit für die[ENTER]Bauern, den Lohn ihrer harten Arbeit des Jahres[ENTER]einzubringen. Doch der Schweinegott und seine[ENTER]Genossen fressen das ganze Korn. Da ihre Gier das[ENTER]Leben der Bauern bedroht, müssen wir sie[ENTER]erschlagen. Tِte den Schweinegott. Er ist meisst[ENTER]in der Nنhe der Hauptstadt anzutreffen. Wenn Du[ENTER]ihn besiegst, erhنltst Du folgende Belohnung: "
gameforge.locale.questscroll_5_hunt = "Bنrengott "
gameforge.locale.questscroll_5_mis = "Den Bنrengott tِten. "
gameforge.locale.questscroll_5_text = "In seiner natürlichen Umgebung war der Bنrengott[ENTER]brav. Seit kurzem taucht er jedoch in der Nنhe[ENTER]der Hauptstadt auf und greift Menschen an. Er[ENTER]findet mehr und mehr Opfer. Wie viele schon[ENTER]gestorben sind, ist kaum noch festzustellen. Er[ENTER]muss von hier verschwinden. Tِte den Bنrengott.[ENTER]Wenn Du ihn tatsنchlich los wirst, erhنltst Du[ENTER]folgende Belohnung: "
gameforge.locale.questscroll_6_hunt = "Tigergott "
gameforge.locale.questscroll_6_mis = "Den Tigergott tِten. "
gameforge.locale.questscroll_6_text = "Ich kann es kaum glauben. Wie konnte der[ENTER]Tigergott nur so etwas Schreckliches tun? Ich bin[ENTER]nur eine einfache Frau, die jeden Tag dem[ENTER]Tigergott huldigte, der gelegentlich auf den[ENTER]Bergpfaden auftauchte. Aber eines Tages griffen[ENTER]der Tigergott und seine Anhنnger meine Familie[ENTER]an! Alle wurden getِtet, und ich verlor einen[ENTER]Arm. Bitte, rنche meine Familie. Wenn Du den[ENTER]Tigergott tِtest, erhنltst Du folgende Belohnung: "
gameforge.locale.questscroll_7_hunt = "Anführerin der weiكen Armee "
gameforge.locale.questscroll_7_mis = "Die Anführerin der weiكen Armee tِten. "
gameforge.locale.questscroll_7_text = "Die weiكe Armee ist eine Gruppe von Frauen, die[ENTER]von ihren Mنnnern und der Welt im Stich gelassen[ENTER]wurden. Sie sind zwar arm, aber wie sie die[ENTER]Dorfbewohner quنlen, ist einfach nur brutal. Eine[ENTER]der Frauen wurde gesteinigt, als sie in das Dorf[ENTER]kam. Wir dürfen nicht zulassen, dass sie ins Dorf[ENTER]kommen und die Bürger angreifen. Tِte 20 Anführer[ENTER]der weiكen Armee. Wenn Du diesen Auftrag[ENTER]erfolgreich abschlieكt, erhنltst Du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_8_hunt = "Anführer der Schwarzwindbande "
gameforge.locale.questscroll_8_mis = "Den Anführer der Schwarzwindbande tِten. "
gameforge.locale.questscroll_8_text = "Unsere Straكen sind nicht mehr sicher: Die[ENTER]Schwarzwindbande raubt seit einiger Zeit Reisende[ENTER]und Hنndler aus. Sie sind so furchterregend, dass[ENTER]sich niemand traut, zurückzuschlagen.[ENTER]Aber das kann so nicht weitergehen![ENTER]Tِte 20 Anführer der Schwarzwindbande. Wenn du[ENTER]diesen Auftrag erfolgreich abschlieكt, erhنltst[ENTER]du folgende Belohnung: "
gameforge.locale.questscroll_9_hunt = "Barbarenhنuptling "
gameforge.locale.questscroll_9_mis = "Den Barbarenhنuptling tِten. "
gameforge.locale.questscroll_9_text = "Es ist schon eine Weile her, dass die Barbaren[ENTER]die Grenzen überschritten und das Dorf angriffen.[ENTER]Die Anzahl der Leute, die sie erschlugen, ging in[ENTER]die Hunderte. Die Anzahl derer, die geschنdigt[ENTER]wurden, ist weitaus hِher. Diese bِsen Barbaren[ENTER]sind so brutal, dass sich niemand traute, Rache[ENTER]zu nehmen. Aber wir kِnnen sie nicht lنnger[ENTER]tolerieren. Erschlag 25 Barbarenhنuptlinge. Wenn[ENTER]Du diesen Auftrag erfolgreich abschlieكt,[ENTER]erhنltst Du folgende Belohnung: "
gameforge.locale.quest_temp_reward_1 = "Auftragsbelohnung "
gameforge.locale.quest_temp_reward_2 = "Wنhrend des Testzeitraums für Auftrنge gibt es[ENTER]keine Belohnungen. Spنter, nachdem eine Belohnung[ENTER]erhalten wurde, kann der aktuelle Auftrag erneut[ENTER]gespielt werden. "
