gameforge.locale.skeleton_gem.order_refuse_answer = "Fahrender Hنndler:[ENTER]Ich verstehe deine Bedenken. Die Aufgabe ist[ENTER]durchaus gefنhrlich. Aber wenn nicht bald etwas[ENTER]geschieht, ist das mein Untergang! "
gameforge.locale.skeleton_gem.order_say = "Fahrender Hنndler:[ENTER]Jetzt ist alles zu Ende. Mir bleibt nichts übrig,[ENTER]als auf den Tod zu warten. Wenn mich doch bloك[ENTER]diese Diebe nicht angegriffen hنtten! Warum[ENTER]musste das gerade mir passieren? "
