gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "Das Flugblatt enthنlt folgende Mitteilung:[ENTER]Wir rekrutieren mutige Mنnner und Frauen, die[ENTER]bereit sind, für den Frieden des Reichs und seiner[ENTER]Bürger zu kنmpfen![ENTER]Voraussetzung für den Eintritt ins Militنr:[ENTER]Mindestens Level 5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Hier werden die Ninja ausgebildet, die gut im[ENTER]Verstecken und in Angriffen aus dem Hinterhalt[ENTER]sind. Sie konzentrieren sich auf die Handhabung[ENTER]des Dolches und von Giften.[ENTER]Nur Ninja in der Ausbildung und ab Level 5 kِnnen[ENTER]beitreten. Sobald du dieses Level erreicht hast,[ENTER]erhنltst du ein Rekrutierungsschreiben.[ENTER]Wenn du bereit bist, als Ninja auf dunklen Pfaden[ENTER]zu schleichen, halte nach mir Ausschau. Dann[ENTER]unterhalten wir uns eingehender. "
gameforge.locale.skill_group.dialog_assassin_2 = "Hier werden die Ninja ausgebildet, die gut im[ENTER]Verstecken und in Angriffen aus dem Hinterhalt[ENTER]sind. Sie konzentrieren sich auf die Handhabung[ENTER]des Dolches und von Giften.[ENTER]Wenn du bereit bist, als Ninja auf dunklen Pfaden[ENTER]zu schleichen, bist du hier jederzeit willkommen. "
gameforge.locale.skill_group.dialog_assassin_3 = "Hier werden die Ninja ausgebildet, die Meister[ENTER]des Bogens sind. Es werden Fertigkeiten gelehrt,[ENTER]die einen Bogen erfordern, zum Beispiel[ENTER]Pfeilsalven gezielt auf alle Feinde in Reichweite[ENTER]zu verschieكen. Nur Ninja in der Ausbildung und[ENTER]ab Level 5 kِnnen beitreten. Sobald du dieses[ENTER]Level erreicht hast, erhنltst du ein[ENTER]Rekrutierungsschreiben. Wenn es dich[ENTER]interessiert, schau bei mir vorbei. "
gameforge.locale.skill_group.dialog_assassin_4 = "Hier werden die Ninja ausgebildet, die Meister[ENTER]des Bogens sind. Es werden Fertigkeiten gelehrt,[ENTER]die einen Bogen erfordern, zum Beispiel[ENTER]Pfeilsalven gezielt auf alle Feinde in Reichweite[ENTER]zu verschieكen. Folg mir. Ich mache dich zum[ENTER]besten Schützen des Kontinents. "
gameforge.locale.skill_group.dialog_assassin_5 = "Wنhle zwischen der Nahkampf-Lehre und der[ENTER]Fernkampf-Lehre und schon erhنltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.dialog_shaman_1 = "Dies ist der Ort, an dem sich die Schamanen[ENTER]treffen, die dem Pfad des Drachengottes folgen.[ENTER]Es werden Fertigkeiten für den Umgang mit[ENTER]Amuletten und mit der Geistesmacht gelehrt, die[ENTER]es dem Schamanen ermِglicht, Techniken des[ENTER]Feindes auf diesen zurückzuwerfen, den eigenen[ENTER]Verteidigungswert durch heiligen Schutz zu[ENTER]verstنrken und befreundete Kنmpfer zu[ENTER]unterstützen. Nur Schamanen in der Ausbildung und[ENTER]ab Level 5 kِnnen beitreten. Sobald du dieses[ENTER]Level erreicht hast, erhنltst du ein[ENTER]Rekrutierungsschreiben. Wenn du bereit bist für[ENTER]die Lehren der Drachenmacht, dann such mich auf. "
gameforge.locale.skill_group.dialog_shaman_2 = "Dies ist der Ort, an dem sich die Schamanen[ENTER]treffen, die dem Pfad des Drachengottes folgen.[ENTER]Es werden Fertigkeiten für den Umgang mit[ENTER]Amuletten und mit der Geistesmacht gelehrt, die[ENTER]es dem Schamanen ermِglicht, Techniken des[ENTER]Feindes auf diesen zurückzuwerfen, den eigenen[ENTER]Verteidigungswert durch heiligen Schutz zu[ENTER]verstنrken und befreundete Kنmpfer zu[ENTER]unterstützen. Meinst du, dass du bereit bist, die[ENTER]Lehren des Drachengottes mit mir zu verbreiten?[ENTER]Ein Glنubiger voller Demut ist allzeit[ENTER]willkommen. "
gameforge.locale.skill_group.dialog_shaman_3 = "Hier verehren die Schamanen die Macht der Natur[ENTER]und des Lichts. Es werden Fertigkeiten gelehrt,[ENTER]die im Zusammenhang mit Blitz und Wind stehen,[ENTER]aber auch solche, die die Krنfte der Heilung[ENTER]aktivieren. Schamanen, die der Lehre der Heilung[ENTER]folgen, arbeiten hنufig als Gruppe, um sich[ENTER]gegenseitig zu unterstützen.[ENTER]Nur Schamanen in der Ausbildung und ab Level 5[ENTER]kِnnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erhنltst du ein Rekrutierungsschreiben.[ENTER]Ich erwarte dich hier. "
gameforge.locale.skill_group.dialog_shaman_4 = "Hier verehren die Schamanen die Macht der Natur[ENTER]und des Lichts. Es werden Fertigkeiten gelehrt,[ENTER]die im Zusammenhang mit Blitz und Wind stehen,[ENTER]aber auch solche, die die Krنfte der Heilung[ENTER]aktivieren. Schamanen, die der Lehre der Heilung[ENTER]folgen, arbeiten hنufig als Gruppe, um sich[ENTER]gegenseitig zu unterstützen.[ENTER]Mِchtest du, zusammen mit mir, anderen helfen?[ENTER]Deine Unterstützung kنme allen Leidenden zugute.[ENTER]Bitte hilf mir dabei. "
gameforge.locale.skill_group.dialog_shaman_5 = "Wنhle zwischen der Lehre der Drachenmacht und der[ENTER]Lehre der Heilung und schon erhنltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.dialog_sura_1 = "Ich lehre diejenigen, die mit der teuflischen[ENTER]Saat gesegnet sind, wie sie deren Magie nutzen[ENTER]kِnnen. Sie lernen, Schwerter und Rüstungen mit[ENTER]Zaubern zu belegen, die Angriff und Verteidigung[ENTER]erhِhen. Auكerdem beschwِren sie Geister aus der[ENTER]Hِlle herauf und senken so die Moral des Feindes.[ENTER]Nur Sura in der Ausbildung und ab Level 5 kِnnen[ENTER]beitreten. Sobald du dieses Level erreicht hast,[ENTER]erhنltst du ein Rekrutierungsschreiben.[ENTER]Wenn du bereit bist, dein teuflisches Erbe[ENTER]anzunehmen, komm hierher. "
gameforge.locale.skill_group.dialog_sura_2 = "Ich lehre diejenigen, die mit der teuflischen[ENTER]Saat gesegnet sind, wie sie deren Magie nutzen[ENTER]kِnnen. Sie lernen, Schwerter und Rüstungen mit[ENTER]Zaubern zu belegen, die Angriff und Verteidigung[ENTER]erhِhen. Auكerdem beschwِren sie Geister aus der[ENTER]Hِlle herauf und senken so die Moral des Feindes.[ENTER]Bist du bereit, verzauberte Schwerter zu[ENTER]schwingen und finstere Flüche zu schleudern? Ich[ENTER]kann dir versichern: Die Macht, die du hier[ENTER]findest, sucht ihresgleichen. "
gameforge.locale.skill_group.dialog_sura_3 = "Wenn du dich für diesen Ort interessierst: Hier[ENTER]findest du nur jene, die sich der Dunkelheit[ENTER]verschrieben haben. Sie lehren den Umgang mit[ENTER]Geistern und Teufeln - und mit den Flammen der[ENTER]Hِlle. Nur Sura in der Ausbildung und ab Level 5[ENTER]kِnnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erhنltst du ein Rekrutierungsschreiben.[ENTER]Wenn du die Dunkelheit dein Zuhause nennst,[ENTER]findest du hier deine Brüder und Schwestern. "
gameforge.locale.skill_group.dialog_sura_4 = "Wenn du dich für diesen Ort interessierst: Hier[ENTER]findest du nur jene, die sich der Dunkelheit[ENTER]verschrieben haben. Sie lehren den Umgang mit[ENTER]Geistern und Teufeln - und mit den Flammen der[ENTER]Hِlle. Wenn du dich dafür interessierst,[ENTER]Freundschaft mit bِsen Geistern zu schlieكen, die[ENTER]dich Stück für kleines Stückchen verzehren, dann[ENTER]komm! Tritt unserem Orden bei und lass deine[ENTER]Menschlichkeit zurück... "
gameforge.locale.skill_group.dialog_sura_5 = "Wنhle zwischen der Schwarze-Magie-Lehre und der[ENTER]Magische-Waffen-Lehre und schon erhنltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.dialog_warrior_1 = "Weiكt du, wo du dich befindest? Hier werden[ENTER]Kنmpfer ausgebildet, Krieger, die Stنrksten und[ENTER]Mutigsten! Es werden Techniken für schnelle[ENTER]Schlagfolgen gelehrt und mنchtige Angriffsstile[ENTER]mit Schwert oder Speer.[ENTER]Nur Krieger in der Ausbildung und ab Level 5[ENTER]kِnnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erhنltst du ein Rekrutierungsschreiben.[ENTER]Wenn du die wahre Stنrke deines Kِrpers[ENTER]herausfinden mِchtest, komm zu mir! "
gameforge.locale.skill_group.dialog_warrior_2 = "Weiكt du, wo du dich befindest? Hier werden[ENTER]Kنmpfer ausgebildet, Krieger, die Stنrksten und[ENTER]Mutigsten! Es werden Techniken für schnelle[ENTER]Schlagfolgen gelehrt und mنchtige Angriffsstile[ENTER]mit Schwert oder Speer.[ENTER]Wie sieht es aus? Willst du trainieren? "
gameforge.locale.skill_group.dialog_warrior_3 = "Bei mir lernen angehende Krieger, ihr Chi richtig[ENTER]zu fokussieren. Das bedingt einen langsamen,[ENTER]geistig erschِpfenden Kampfstil. Dafür kِnnen die[ENTER]Angriffe mehrere Gegner gleichzeitig treffen. Und[ENTER]die undurchdringliche Verteidigung der groكen[ENTER]Mental-Krieger ist geradezu legendنr.[ENTER]Nur Krieger in der Ausbildung und ab Level 5[ENTER]kِnnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erhنltst du ein Rekrutierungsschreiben.[ENTER]Wenn du interessiert bist, schau bei mir vorbei. "
gameforge.locale.skill_group.dialog_warrior_4 = "Bei mir lernen angehende Krieger, ihr Chi richtig[ENTER]zu fokussieren. Das bedingt einen langsamen,[ENTER]geistig erschِpfenden Kampfstil. Dafür kِnnen die[ENTER]Angriffe mehrere Gegner gleichzeitig treffen. Und[ENTER]die undurchdringliche Verteidigung der groكen[ENTER]Mental-Krieger ist geradezu legendنr.[ENTER]Was meinst du? Bist du geeignet für den[ENTER]Mental-Kampf? "
