gameforge.main_quest_flame_lv100._050_say = {}
gameforge.main_quest_flame_lv100._060_say = "Wنhrend unser Alchemist nach einer Lِsung sucht,[ENTER]sollten wir nicht untنtig herumsitzen. Kehre ins[ENTER]Feuerland zurück und erledige 300 Dنmonen um die[ENTER]Festung herum. So sollten wir die Schwarze Materie[ENTER]eindنmmen kِnnen. "
