gameforge.main_quest_flame_lv100._170_say = "Der Alchemist sucht nach dir. Es scheint dringend[ENTER]zu sein! "
gameforge.main_quest_flame_lv100._180_say = "Eine Katastrophe! Ich hatte Yak-Hwan angewiesen,[ENTER]mit Bedacht zu handeln. Und was macht er? Stürzt[ENTER]uns erhobenen Schwertes ins Chaos! Die Schwarze[ENTER]Materie wنchst und verbreitet sich schneller, wenn[ENTER]der Wirt, in dem sie sich eingenistet hat, stirbt.[ENTER]Nun erfahre ich, dass bereits 300 infizierte[ENTER]Dنmonen getِtet wurden! Das ist nicht gut ... "
