gameforge.main_quest_flame_lv100._280_say = "Du hast alle Zutaten gefunden! Groكartig, dann[ENTER]werde ich mich jetzt an die Arbeit machen. Ich[ENTER]rufe dich, sobald die Nimbustinktur fertig ist. "
gameforge.main_quest_flame_lv100._290_say = "Wenn wir die Schwarze Materie nicht bald[ENTER]aufhalten, sieht es zappenduster aus. Los, bringe[ENTER]mir alle Zutaten für die Nimbustinktur. "
gameforge.main_quest_flame_lv100._300_notice = "Du hast alle nِtigen Zutaten beisammen. Kehre nun[ENTER]zum Alchemisten zurück. "
