gameforge.main_quest_flame_lv100._320_sendLetter = "Schwarze Materie aufhalten "
gameforge.main_quest_flame_lv100._330_say = "So ein ... hmpf ... Ich habe mich beim Schmied[ENTER]beschwert, weil die Fundamentsteine zu grob[ENTER]gemahlen waren. Und nun? Ist er beleidigt und[ENTER]weigert sich, die restlichen Fundamentsteine zu[ENTER]Pulver zu verarbeiten. Alter Sturkopf! Kِnntest du[ENTER]nicht mal mit ihm reden? "
