gameforge.main_quest_flame_lv101._020_say = "Yak-Hwan sucht nach dir. Gehe zu ihm und finde[ENTER]heraus, was er mِchte. "
gameforge.main_quest_flame_lv101._030_say = "Der Alchemist hat mich bereits über meinen groكen[ENTER]Fehler in Kenntnis gesetzt. Hoffentlich ist es[ENTER]noch nicht zu spنt, ihn zu korrigieren. "
gameforge.main_quest_flame_lv101._040_say = "Hier ist die Nimbustinktur des Alchemisten. Trage[ENTER]sie auf deine Waffe auf. Wenn du nun infizierte[ENTER]Dنmonen tِtest, wird die Schwarze Materie gebannt[ENTER]und kann sich nicht weiter ausbreiten. "
gameforge.main_quest_flame_lv101._050_say = "Unter diesen Voraussetzungen kannst du dich auch[ENTER]in das Innere der geheimnisvollen Festung wagen[ENTER]und die Dنmonen direkt in ihrer Heimstنtte[ENTER]bekنmpfen. Bestimmt entdeckst du darin Hinweise[ENTER]auf die Machenschaften der Diener der Dunkelheit[ENTER]und auf den Verbleib meines vermissten Spنhers. "
gameforge.main_quest_flame_lv101._060_say = {}
gameforge.main_quest_flame_lv101._070_say = "Ich mache mich sogleich auf den Weg. "
gameforge.main_quest_flame_lv101._080_say = "Danke. Ich wünsche dir das Beste. "
gameforge.main_quest_flame_lv101._090_notice = "Dringe in die Festung ein und besiege die Dنmonen.[ENTER]Halte die Augen offen nach Hinweisen und dem[ENTER]vermissten Spنher! "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "Dringe in die unbekannte Festung ein und besiege[ENTER]die Dنmonen. Halte die Augen offen nach Hinweisen[ENTER]auf die Machenschaften der Diener als auch auf den[ENTER]vermissten Spنher! "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten.[ENTER]Bilde eine Gruppe, um passieren zu dürfen.[ENTER]Du erhنltst keinen weiteren Passierschein. "
gameforge.main_quest_flame_lv101._130_say = "Warst du schon im Inneren der Festung? Es müssen[ENTER]Hinweise auf die Machenschaften der Diener der[ENTER]Dunkelheit als auch auf den Verbleib meines[ENTER]Spنhers darin zu finden sein! Reise erneut ins[ENTER]Feuerland und durchsuche die Festung. "
gameforge.main_quest_flame_lv101._140_say = "Der Spنher ist schon eine Weile tot. In seiner[ENTER]Tasche findest du einen Brief. ـberbringe ihn[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv101._150_notice = "Du hast Yak-Hwans Spنher entdeckt. "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten? "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "Deinem Gesichtsausdruck zu urteilen, keine guten[ENTER]... Das hatte ich bereits befürchtet. Einen Brief[ENTER]trug er bei sich? Zeig her. In dieser Festung muss[ENTER]noch ein Hinweis auf die Machenschaften der Diener[ENTER]der Dunkelheit zu finden sein. Kehre zurück und[ENTER]suche danach. Den Brief lesen wir spنter. "
gameforge.main_quest_flame_lv101._190_notice = "Du hast ein Nietenhalsband der Diener der[ENTER]Dunkelheit entdeckt. Zeige es Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "Interessant, das Nietenhalsband gehِrt den Dienern[ENTER]der Dunkelheit. Vielleicht enthنlt es einen[ENTER]Hinweis auf ihre Machenschaften! Aber noch keine[ENTER]Spur von meinem Spنher? Bitte suche weiter nach[ENTER]ihm. Er muss in dieser Festung sein. "
gameforge.main_quest_flame_lv101._210_notice = "Du hast sowohl ein Nietenhalsband als auch den[ENTER]Spنher entdeckt. Erstatte nun Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv101._220_say = "Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv101._230_say = "Du warst also erfolgreich! Dieses Nietenhalsband[ENTER]gehِrt den Dienern der Dunkelheit. Es enthنlt[ENTER]bestimmt einen versteckten Hinweis auf ihre[ENTER]Machenschaften. Und was hast du da in deiner[ENTER]anderen Hand? "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief ... den mir mein Spنher hinterlassen[ENTER]hat? Ich bin erschüttert. Lass uns gemeinsam seine[ENTER]letzten Worte lesen. "
gameforge.main_quest_flame_lv101._260_sayTitle = "Hastig geschriebene Worte: "
gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, ich hoffe, dieser Brief erreicht dich,[ENTER]da ich nicht lebend heimkehren werde. Ich habe im[ENTER]Feuerland eine Festung entdeckt, die auf keiner[ENTER]Karte verzeichnet ist. Ihr Herrscher ist ein[ENTER]mنchtiger Feuerland-Dنmon – eine eigenartige Aura[ENTER]umgibt ihn, so wie alle Dنmonen seines Gefolges.[ENTER]Sein Gebrüll ist ohrenbetنubend und er scheint[ENTER]etwas zu bewachen. Entsende jemanden, um diesen[ENTER]Ort zu erkunden! Denn ich habe versagt ... "
gameforge.main_quest_flame_lv101._280_say = "Irgendetwas verbirgt sich in dieser Festung und[ENTER]wir müssen herausfinden, was.[ENTER]Sieh her, auf der Innenseite des Nietenhalsbandes[ENTER]ist eine Gravur. Es muss mit dem Kult der Diener[ENTER]zusammenhنngen, dass sie immer wieder über diesen[ENTER]Gegenstand kommunizieren ... Ich werde[ENTER]Yon-I-Walker um Rat fragen. Er wird dich rufen[ENTER]lassen, sobald er dich braucht. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschlüsseln "
gameforge.main_quest_flame_lv101._300_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm. "
gameforge.main_quest_flame_lv101._310_say = "Willkommen, ich habe dich bereits erwartet. Ich[ENTER]brauche etwas Hilfe dabei, die Gravur in diesem[ENTER]Nietenhalsband zu entschlüsseln. "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Die Schriftzeichen auf der Innenseite des[ENTER]Nietenhalsbandes entstammen einer uralten Kultur,[ENTER]die vor langer Zeit existierte. Um sie lesbar zu[ENTER]machen, brauche ich das Blut des Flammenkِnigs. Es[ENTER]flieكt so heiك wie Lava durch seine Adern. Nimm[ENTER]dieses feuerfeste Gefنك, um es aufzufangen. "
gameforge.main_quest_flame_lv101._340_say = "Wird erledigt. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast, musst du so[ENTER]schnell wie mِglich zu mir zurückkehren. Denn[ENTER]selbst dieses Gefنك kann seine Hitze nur für eine[ENTER]begrenzte Zeit ohne Schaden überstehen. "
gameforge.main_quest_flame_lv101._360_notice = "Besorge das Blut des Flammenkِnigs. "
gameforge.main_quest_flame_lv101._370_say = "Ohne das Blut des Flammenkِnigs kِnnen wir die[ENTER]Gravur nicht entschlüsseln. Erledige ihn, los! "
gameforge.main_quest_flame_lv101._380_notice = "Du hast das Blut des Flammenkِnigs erhalten. Kehre[ENTER]rasch zu Yon-I-Walker zurück. "
gameforge.main_quest_flame_lv101._390_say = "Sprich mit Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Ah, sehr gut. Das Gefنك ist noch nicht unter der[ENTER]Hitze geschmolzen. Mithilfe des Blutes werde ich[ENTER]nun die Gravur wieder lesbar machen kِnnen. Das[ENTER]erfordert etwas Zeit. Kehre morgen wieder zurück. "
gameforge.main_quest_flame_lv101._410_say = "Gedulde dich noch %d Stunde(n) und %d Minute(n). "
gameforge.main_quest_flame_lv101._420_say = "Ich brauche noch etwas mehr Zeit. Komme spنter wieder! "
gameforge.main_quest_flame_lv101._430_sendLetter = "Die Gravur "
gameforge.main_quest_flame_lv101._440_say = "Du kommst zur rechten Zeit! Ich habe die Gravur[ENTER]auf dem Nietenhalsband entschlüsselt. "
gameforge.main_quest_flame_lv101._450_say = "Sie verrنt uns, dass die Diener der Dunkelheit[ENTER]einen der mنchtigesten Feuerdنmonen entsandt[ENTER]haben, um die Siegel der Tore zu schmelzen, hinter[ENTER]denen die Sechs Drachen an einem verborgenen Ort[ENTER]gefangen gehalten werden. Es wird auch ein[ENTER]spezieller Schmelzofen erwنhnt. Ich habe alles in[ENTER]diesem Schreiben an Yak-Hwan festgehalten. Bringe[ENTER]es bitte zu ihm! "
gameforge.main_quest_flame_lv101._460_say = {}
gameforge.main_quest_flame_lv101._470_notice = "ـberbringe Yak-Hwan den Brief von Yon-I-Walker. "
gameforge.main_quest_flame_lv101._480_sayTitle = "Post für Yak-Hwan "
gameforge.main_quest_flame_lv101._490_say = "ـberbringe Yak-Hwan den Brief von Yon-I-Walker. "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon-I-Walker die Gravur lesen? Oh, ein[ENTER]Brief mit allen Informationen von ihm? Sehr gut,[ENTER]zeig her! "
gameforge.main_quest_flame_lv101._510_say = "Die Siegel der Sechs Drachen ... soso ... ein[ENTER]magischer Schmelzofen ... aha ... Bei der Festung,[ENTER]die wir entdeckt haben, muss es sich um die[ENTER]sagenumwobene Rotdrachenfestung handeln! Dort soll[ENTER]einer der Drachen gefangen sein, die die Diener[ENTER]zur Gewinnung der Perlen der Nacht tِten müssen.[ENTER]Ich werde mich nun zurückziehen und mit meinen[ENTER]Strategen über unser weiteres Vorgehen beraten. "
