gameforge.main_quest_flame_lv102._030_say = "Wir haben die Rotdrachenfestung nun[ENTER]verbarrikadiert. Auf diese Weise gelangen keine[ENTER]infizierten Dنmonen mehr hinaus und wir[ENTER]verhindern, dass sich die Schwarze Materie weiter[ENTER]verbreitet. "
gameforge.main_quest_flame_lv102._040_say = "Deine Aufgabe wird es nun sein, in die Festung[ENTER]einzufallen, so viele Dنmonen wie mِglich[ENTER]unschنdlich zu machen und herauszufinden, ob darin[ENTER]tatsنchlich der legendنre Rotdrache gefangen ist. "
