gameforge.main_quest_flame_lv102._140_say = "Kehre zu Yon-I-Walker zurück. "
gameforge.main_quest_flame_lv102._150_say = "Du bist zurück – und wie ich sehe hattest du[ENTER]Erfolg! Was kannst du mir berichten? "
gameforge.main_quest_flame_lv102._160_say = {}
gameforge.main_quest_flame_lv102._170_say = "Ein mنchtiger Flammendنmon, sagst du? Das muss[ENTER]Razador, Herrscher des Feuers, sein! Du hast Glück[ENTER]– nicht viele, die ihm begegneten, konnten lebend[ENTER]davon berichten. Wenn die Diener ihn geschickt[ENTER]haben, muss sich in der Tat etwas von Bedeutung in[ENTER]der Festung befinden. Womِglich der legendنre[ENTER]Rotdrache! Ich werde mich mit meinen Beratern[ENTER]besprechen und dich dann rufen lassen. Danke vorerst! "
gameforge.main_quest_flame_lv102._180_sendLetter = "Razador "
gameforge.main_quest_flame_lv102._190_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm, um[ENTER]Genaueres zu erfahren. "
gameforge.main_quest_flame_lv102._200_say = "Du hast also eine Begegnung mit dem ungeheuren[ENTER]Razador überlebt. Ich verneige mich in Respekt. "
gameforge.main_quest_flame_lv102._210_say = {}
gameforge.main_quest_flame_lv102._220_say = "Der Herrscher des Feuers gehِrt neben dem[ENTER]Frostkِnig zu den bِsartigsten und tِdlichsten[ENTER]Unterweltgeschِpfen, die die Menschheit kennt.[ENTER]Doch alles, was wir über Razador wissen, stammt[ENTER]aus uralten Schriften und überlieferten[ENTER]Gruselgeschichten. Es ist mِglich, dass Razador[ENTER]die Quelle der Schwarzen Materie ist. "
gameforge.main_quest_flame_lv102._230_say = {}
gameforge.main_quest_flame_lv102._240_say = {}
gameforge.main_quest_flame_lv102._250_say = "Wenn dem so ist, macht ihn das zu einem[ENTER]übermنchtigen Gegner. Vernichte zunنchst die[ENTER]rangniederen Dنmonen in der Rotdrachenfestung. Die[ENTER]Schwarze Materie im Kِrper ist kugelfِrmig. Sammle[ENTER]zehn dieser Materiekugeln. Vielleicht finden wir[ENTER]so einen Weg, die Macht der Schwarzen Materie zu[ENTER]neutralisieren, bevor wir Razador entgegentregen. "
gameforge.main_quest_flame_lv102._260_say = "Ich mache mich sofort auf den Weg. "
gameforge.main_quest_flame_lv102._270_notice = "Bekنmpfe die Flammendنmonen in der Rotdrachenfestung. "
gameforge.main_quest_flame_lv102._280_sayTitle = "Materie-Kugeln "
gameforge.main_quest_flame_lv102._290_say = "Stürme die Rotdrachenfestung, bekنmpfe die[ENTER]Flammendنmonen und sammle zehn Materiekugeln. "
gameforge.main_quest_flame_lv102._300_sayReward = "Du benِtigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv102._310_say = "Das sind noch nicht genug Materiekugeln. Ich[ENTER]brauche zehn Stück für meine Forschung. Sammle[ENTER]bitte weiter. "
gameforge.main_quest_flame_lv102._320_notice = "Du hast zehn Materiekugeln gesammelt. Bringe sie[ENTER]zu Yon-I-Walker. "
gameforge.main_quest_flame_lv102._330_say = "Alleine der Anblick der Schwarzen Materie lنsst[ENTER]mich erschaudern! Also gut, an die Arbeit ... Ich[ENTER]lasse dich rufen, wenn ich erfolgreich war. "
gameforge.main_quest_flame_lv102._340_say = {}
gameforge.main_quest_flame_lv102._350_sendLetter = "Neutralisierung der Schwarzen Materie "
gameforge.main_quest_flame_lv102._360_say = "Gute Neuigkeiten! Ich habe herausgefunden, wie[ENTER]sich die Kraft der Schwarzen Materie[ENTER]neutralisieren lنsst. "
gameforge.main_quest_flame_lv102._370_say = {}
gameforge.main_quest_flame_lv102._380_say = "Alle Krنfte der Natur besitzen ein Gegengewicht –[ENTER]Licht und Schatten, Feuer und Wasser, Gut und[ENTER]Bِse. Auch die Schwarze Materie hat einen[ENTER]Gegenspieler, der die Macht hat, sie zu[ENTER]neutralisieren: Reines Lumen! "
gameforge.main_quest_flame_lv102._390_say = "Um Reines Lumen zu produzieren, muss man[ENTER]Energiesplitter in Mong-Wasser schmelzen. Kannst[ENTER]du bitte 50 Flaschen Mong-Wasser sowie 100[ENTER]Energiesplitter holen und sie zu Yu-Hwan bringen?[ENTER]Danke. "
