gameforge.main_quest_flame_lv105._120_say = "Wir kِnnen die feindliche Verteidigungslinie noch[ENTER]nicht durchbrechen. Besiege alle Flammendنmonen,[ENTER]die ich dir aufgezنhlt habe. "
