gameforge.main_quest_flame_lv105._140_say = "Kehre zu Yak-Hwan zurück. "
gameforge.main_quest_flame_lv105._150_say = "Du hast gute Arbeit geleistet. Wir sind unserem[ENTER]Ziel ein ganzes Stück nنher gekommen – der[ENTER]Rotdrache wird nicht mehr lange eine Bedrohung für[ENTER]uns sein! "
gameforge.main_quest_flame_lv105._160_sendLetter = "Gunst und Groll "
gameforge.main_quest_flame_lv105._170_say = "Dein Erzfeind, Razador, scheint es dir sehr[ENTER]übelgenommen zu haben, dass du ihn getِtet hast.[ENTER]Sein Gebrüll ist auch auكerhalb der Festung zu[ENTER]hِren und schallt weit über die Ebenen Doyyumhwans. "
gameforge.main_quest_flame_lv105._180_say = "Es wird Zeit, ihn ein weiteres Mal in die[ENTER]Schranken zu weisen. Denn er wacht mit Argusaugen[ENTER]über das Tor, hinter dem der Rotdrache gefangen[ENTER]gehalten wird. Doch nimm dich in Acht! Er wird aus[ENTER]seiner Niederlage gelernt haben und die gleichen[ENTER]Fehler nicht noch einmal begehen. "
gameforge.main_quest_flame_lv105._190_notice = "Besiege Razador, Herrscher des Feuers. "
gameforge.main_quest_flame_lv105._200_sayTitle = "Spiel mit dem Feuer "
gameforge.main_quest_flame_lv105._210_say = "Besiege Razador, Herrscher des Feuers, in der[ENTER]Rotdrachenfestung. "
gameforge.main_quest_flame_lv105._220_say = "Ist dir Razador diesmal überlegen? Das kann ich[ENTER]fast nicht glauben! Du hast es einmal geschafft –[ENTER]und wirst auch diesmal obsiegen! "
gameforge.main_quest_flame_lv105._230_notice = "Razador wurde besiegt. Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv105._240_say = "Ich wusste, du würdest es schaffen! Groكartig. Nun[ENTER]werden wir alles für die Verbannung des Rotdrachen[ENTER]vorbereiten. Ich lasse dich rufen, sobald wir[ENTER]bereit sind. "
gameforge.main_quest_flame_lv105._250_sendLetter = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._260_say = "Es ist soweit. Alles steht bereit, um den[ENTER]Rotdrachen für alle Zeit zu verbannen. "
gameforge.main_quest_flame_lv105._270_say = "Meine Mنnner haben bereits bereits zwei Bannkreise[ENTER]aufgestellt. Deine Aufgabe ist es nun, sie zu[ENTER]entzünden. Wirf den Bannbeutel auf die Kreise und[ENTER]sie werden sich entflammen. Das wird die[ENTER]Verbannung des Rotdrachen vollziehen. "
gameforge.main_quest_flame_lv105._280_notice = "Entzünde die Bannkreise und schicke den Rotdrachen[ENTER]in die Verbannung. "
gameforge.main_quest_flame_lv105._290_say = "Restliche Verbannungsanzahl "
gameforge.main_quest_flame_lv105._300_sayTitle = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._310_say = "Entzünde mithilfe der Bannbeutel die magischen[ENTER]Kreissymbole und schicke den Rotdrachen in die[ENTER]Verbannung. "
gameforge.main_quest_flame_lv105._320_say = "Grabstein des Taramor: 1 Stück "
gameforge.main_quest_flame_lv105._330_sayTitle = "Rotdrachen Flammenschauspiel "
gameforge.main_quest_flame_lv105._340_say = "War das schon alles, du Wurm?! Das hat hِchstens[ENTER]gekitzelt – verbannen wirst du mich damit nicht![ENTER]Ich werde Razador aus dem Reich der Toten[ENTER]zurückholen. Dann wird er die Versiegelung lِsen[ENTER]und mich endlich aus der Gefangenschaft befreien.[ENTER]Es gibt nichts, was ihr dagegen tun kِnnt! "
gameforge.main_quest_flame_lv105._350_notice = "Die Verbannung des Rotdrachen ist fehlgeschlagen.[ENTER]Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv105._360_say = "Die Verbannung ist fehlgeschlagen? Wie konnte das[ENTER]passieren? "
gameforge.main_quest_flame_lv105._370_say = "Ja. Eigentlich wurden die Bannkreise aktiviert und[ENTER]die Entflammung hat auch stattgefunden und die[ENTER]Verbannung hatte begonnen, aber der Rotdrache war[ENTER]so mنchtig, dass dies fehlgeschlagen ist. Er[ENTER]sagte, dass er Yamachun (6091) wiederbeleben wird[ENTER]und er die Versiegelung entfernen wird. Aber er[ENTER]hat auch groكen Schaden durch unseren[ENTER]Verbannungs-Versuch erlitten. "
gameforge.main_quest_flame_lv105._380_say = "Ach so. Gute Arbeit. Dank dir, konnten wir es so[ENTER]weit bringen. Ich habe bereits mit Yon-I-Walker[ENTER](20380) gesprochen und überlegt, was wir nun tun[ENTER]kِnnen. Meine Mنnner werden weiterhin die Lage[ENTER]beobachten und wir werden  ach anderen Methoden[ENTER]suchen, wie wir die Verbannung vollziehen kِnnen.[ENTER]Wenn wir eine perfekte Methoe gefunden haben, den[ENTER]Rotdrachen zu verbannen, werde ich nach dir rufen[ENTER]lassen. Gute Arbeit! "
gameforge.main_quest_flame_lv99 = {}
gameforge.main_quest_flame_lv99._010_sendLetter = "Lauf ins Feuer "
gameforge.main_quest_flame_lv99._020_say = "Yak-Hwan sucht nach dir. Gehe zu ihm und bringe in[ENTER]Erfahrung, was er mِchte. "
gameforge.main_quest_flame_lv99._030_say = "Willkommen zurück! Wie ich befürchtet hatte,[ENTER]sollte uns nur eine kurze Ruhepause vergِnnt sein[ENTER]– die Diener der Dunkelheit sind wieder in[ENTER]Bewegung. Das bedeutet nichts Gutes. "
gameforge.main_quest_flame_lv99._040_say = {}
gameforge.main_quest_flame_lv99._050_say = "Allerdings sind meine Informationen nur sehr vage.[ENTER]Wir wissen, dass sie sich nun im Feuerland aufhalten. "
gameforge.main_quest_flame_lv99._060_say = "Wir haben bereits einen Spنher dorthin geschickt.[ENTER]Doch vor kurzem brach der Kontakt ab und ich bin[ENTER]sehr beunruhigt. Kannst du auf deinem Weg ins[ENTER]Feuerland Ausschau nach ihm halten? "
gameforge.main_quest_flame_lv99._070_say = "Natürlich. "
gameforge.main_quest_flame_lv99._080_say = "Danke. Ich markiere dir seine letzte uns bekannte[ENTER]Position auf der Karte. Viel Erfolg! "
gameforge.main_quest_flame_lv99._090_notice = "Schaue dich an folgenden Koordinaten nach dem[ENTER]vermissten Spنher um: (%d,%d) "
gameforge.main_quest_flame_lv99._100_sayTitle = "Erkunde das Feuerland! "
gameforge.main_quest_flame_lv99._110_say = "Reise in das Feuerland und suche an dem Ort, den[ENTER]Yak-Hwan dir genannt hat, nach dem Spنher und[ENTER]weiteren Hinweisen auf die Machenschaften der Diener. "
gameforge.main_quest_flame_lv99._120_say = "An dem markierten Ort muss sich irgendetwas[ENTER]befinden. Vielleicht hast du einen Hinweis[ENTER]übersehen? Schaue dich noch einmal genauer dort um. "
gameforge.main_quest_flame_lv99._130_notice = "Dies ist der Ort, den Yak-Hwan auf der Karte[ENTER]markiert hat. Schaue dich um und kehre dann zu[ENTER]Yak-Hwan zurück. "
gameforge.main_quest_flame_lv99._140_say = "Yak-Hwan wartet auf dem Fels der Dunklen Drachen[ENTER]auf deinen Bericht. "
gameforge.main_quest_flame_lv99._150_say = "Du bist zurück! Hast du etwas herausgefunden? "
gameforge.main_quest_flame_lv99._160_say = "Vom Spنher leider keine Spur. Doch ich konnte eine[ENTER]mir bis jetzt unbekannte Festung entdecken. Eine[ENTER]seltsame Aura ging von ihr aus und schien auch die[ENTER]Umgebung zu beeinflussen. "
gameforge.main_quest_flame_lv99._170_say = "Hm, das gefنllt mir gar nicht. Ich werde[ENTER]versuchen, mehr über diese Festung in Erfahrung zu[ENTER]bringen und mich dann wieder bei dir melden. "
gameforge.main_quest_flame_lv99._180_sendLetter = "Festung erforschen "
gameforge.main_quest_flame_lv99._190_say = "Hm, wir tappen im Dunkeln. Ich habe rein gar[ENTER]nichts über diese geheimnisvolle Festung[ENTER]herausfinden kِnnen. In diesem Brief habe ich[ENTER]alles zusammengetragen, was wir bis jetzt wissen.[ENTER]Bitte überbringe ihn Yon-I-Walker. Er wird wissen,[ENTER]was zu tun ist. "
gameforge.main_quest_flame_lv99._200_say = "Gehe zu Yon-I-Walker. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich für dich tun? ... Ah, ein Brief.[ENTER]Yak-Hwan bittet also um meine Hilfe. Dann werden[ENTER]wir mal versuchen, Licht in die Dunkelheit zu bringen. "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura, die aus dem Inneren[ENTER]einer Festung strِmt? Interessant ...[ENTER]Schaue dich zunنchst einmal in der nنheren[ENTER]Umgebung dort um. Ich habe da einen Verdacht,[ENTER]worum es sich bei dieser Aura handeln kِnnte.[ENTER]Hier, nimm dieses Papier und wickel es um deine[ENTER]Waffe. Wenn sich mein Verdacht bestنtigt, sollte[ENTER]sich das Papier schwarz fنrben, sobald du damit[ENTER]Dنmonen tِtest, die unter dem Einfluss der dunklen[ENTER]Aura stehen. "
gameforge.main_quest_flame_lv99._250_notice = "Besiege Dنmonen, die um die Festung herumstreunen. "
gameforge.main_quest_flame_lv99._260_sayTitle = "Dنmonenjagd "
gameforge.main_quest_flame_lv99._270_say = "Besiege Feuerland-Dنmonen, die in der Umbebung der[ENTER]Festung herumstreunen und prüfe, ob deine Waffe[ENTER]sich verfنrbt. "
gameforge.main_quest_flame_lv99._280_say = "Hm, ich bin mir sicher, im Feuerland muss ein[ENTER]Hinweis auf diese Aura zu finden sein. Kehre noch[ENTER]einmal zurück in erschlage Dنmonen, die sich in[ENTER]unmittelbarer Nنhe dieser Festung befinden. "
gameforge.main_quest_flame_lv99._290_notice = "Das Papier hat sich schwarz verfنrbt. Kehre zu[ENTER]Yon-I-Walker zurück. "
gameforge.main_quest_flame_lv99._300_say = "Ah, so wie ich es erwartet hatte! Das ist hِchst[ENTER]bemerkenswert. Ich werde dieses Papier etwas nنher[ENTER]untersuchen. Ruhe dich solange aus. "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm, um[ENTER]Genaueres zu erfahren. "
gameforge.main_quest_flame_lv99._330_say = "Willkommen. Ich stecke noch mitten in den[ENTER]Untersuchungen des Papiers, das die Aura[ENTER]aufgefangen hat. Doch mein Verstand ist getrübt.[ENTER]Ich benِtige Sonnenkrنuter, um ihn zu erhellen.[ENTER]Kannst du mir welche besorgen? "
gameforge.main_quest_flame_lv99._340_say = "Natürlich. "
gameforge.main_quest_flame_lv99._350_say = "Die Sonnenkrنuter wachsen an heiكen, trockenen[ENTER]Orten – im Feuerland sind sie ganzjنhrig zu[ENTER]finden. Ich markiere dir meinen letzten Fundort[ENTER]auf der Karte. Obwohl ich mir gerade nicht mehr so[ENTER]sicher bin, ob das tatsنchlich auch dort war ... "
gameforge.main_quest_flame_lv99._360_say = "Ich mache mich sofort auf den Weg. "
gameforge.main_quest_flame_lv99._370_notice = "Gehe zum markiert Ort und suche dort nach[ENTER]Sonnenkrنutern. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkrنuter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Gehe zu dem Ort, den Yon-I-Walker auf der Karte[ENTER]markiert hat, und suche dort nach Sonnenkrنutern. "
gameforge.main_quest_flame_lv99._400_say = "Du kommst mit leeren Hنnden? Das ist nicht gut.[ENTER]Ich fühle, wie mein Verstand immer mehr durch die[ENTER]Aura getrübt wird. Bitte hole mir diese Sonnenkrنuter. "
gameforge.main_quest_flame_lv99._410_notice = "Du hast die Sonnenkrنuter gefunden. Bringe sie zu[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._420_say = "Ah, du hast die Sonnenkrنuter gefunden![ENTER]Ausgezeichnet. Nun kann ich meine Untersuchungen[ENTER]fortsetzen. Yak-Hwan wird dich dann davon[ENTER]unterrichten. "
gameforge.main_quest_flame_lv99._430_say = "Das Abenteuer geht weiter, sobald du Level 100[ENTER]erreicht hast. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "أهلاً بك في Metin1 "
gameforge.main_quest_lv1._20_say = "أوشكت مغامرات Metin1 الشيّقة أن تبدأ. عليك أولاً[ENTER]أن تبحث عن حارس المدينة. سيزودك ببعض المعلومات[ENTER]الأساسية وسيكلفك بمهمات مختلفة. إذا أردت أن[ENTER]تصطاد، فستجد حيوانات مفترسة خارج حدود القرية.[ENTER]ستظهر على الخريطة الصغيرة على شكل نقاط حمراء.[ENTER]عليك أن تبدأ بالكلاب البرية أولاً لأنهم من أسهل[ENTER]الخصوم. أتمنى لك التوفيق والنجاح! "
gameforge.main_quest_lv1._30_targetVid = "رسالة من حارس المدينة "
gameforge.main_quest_lv1._40_sayTitle = "رسالة من حارس المدينة "
gameforge.main_quest_lv1._50_sayReward = "Sprich mit dem Stadtwنchter, indem du ihn[ENTER]anklickst. Er ist der NPC, auf den der groكe rote[ENTER]Pfeil zeigt. Wenn du ihn nicht siehst, bist du[ENTER]vermutlich zu weit entfernt. Folge den blinkenden[ENTER]Kreisen auf der Karte, bis du zum Stadtwنchter[ENTER]gelangst. "
gameforge.main_quest_lv1._60_sayTitle = "حارس المدينة: "
gameforge.main_quest_lv1._70_say = "يبدو أنك جديد في هذه المنطقة! لم يصنعوا منك جندي[ENTER]بعد؟ هل إنخرطت في تدريب ما؟ أنظر إلى نفسك! هل[ENTER]استخدمت في حياتك سلاح قط؟اسمع إذً! عليك أن تكون[ENTER]يقظاً إن أردت أن تنجو في الحرب. سأساعدك حتى تبلغ[ENTER]المستوى 10. لا تظن أن الأمر سيكون سهلاً! هيا[ENTER]تحرك! "
gameforge.main_quest_lv1._80_say = "اذهب الآن وتعلم للأساليب الأساسية في القتال[ENTER]والصيد! عليك بالعودة إلى القرية بمجرد بلوغك إلى[ENTER]مستوى أعلى، لكي تتحدث إلي من جديد. مالذي[ENTER]تنتظره؟ هيا، انطلق! "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "Du erhنltst 5.000 Erfahrungspunkte.[ENTER]Du erhنltst 2.000 Yang. "
gameforge.main_quest_lv10._10_sendLetter = "Gehe zum Hauptmann "
gameforge.main_quest_lv10._110_sayTitle = "Ausbildung beim Hauptmann "
gameforge.main_quest_lv10._120_sayReward = "Der erste Auftrag des Hauptmanns führt dich ins[ENTER]Nachbardorf. Du sollst dort den Musiker Yu-Hwan[ENTER]aufsuchen und nach den geheimen Dokumenten für[ENTER]den Hauptmann fragen. "
gameforge.main_quest_lv10._130_sayTitle = "Musiker Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "Das Leben ist ein Traum, so wie jedwede Existenz[ENTER]in den Weiten der Zeit. Woher kommen wir und[ENTER]wohin gehen wir? Die Welt ist voller Zwiespalt[ENTER]und Streit. Der Same der Ehrlichkeit fنllt nie[ENTER]auf fruchtbaren Boden...[ENTER]Bist du hier, um meinem Gesang zu lauschen? "
gameforge.main_quest_lv10._150_say = "Ah, der Hauptmann schickt dich! Dann musst du ein[ENTER]vertrauenswürdiger Mensch sein.[ENTER]Psst, sprich leise... Niemand im Dorf darf von[ENTER]meiner Identitنt erfahren. Hier, nimm dies an[ENTER]dich. Das Dokument enthنlt wichtige[ENTER]Informationen, die ich sammeln konnte. Bringe sie[ENTER]zum Hauptmann. "
gameforge.main_quest_lv10._160_sayTitle = "Musiker Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Geh und beeil dich! Es ist nicht gut, wenn du zu[ENTER]lange zِgerst. Denn denk immer daran: Das Leben[ENTER]ist kurz und daher kostbar. Genieكe es,[ENTER]solange du kannst. "
gameforge.main_quest_lv10._180_targetVid = "Zurück zum Hauptmann "
gameforge.main_quest_lv10._190_sayReward = "Der Musiker Yu-Hwan, der heimlich als Spion[ENTER]arbeitet, hat dir wichtige Dokumente überreicht.[ENTER]Bringe sie dem Hauptmann im ersten Dorf. "
gameforge.main_quest_lv10._200_say = "Das ist das Dokument, das der Musiker dir[ENTER]überreicht hat? Keine schlechte Arbeit für[ENTER]einen neuen Abenteurer![ENTER]Ich setze groكe Hoffnungen in dich. Nimm dies[ENTER]als Anerkennung für deine Zuverlنssigkeit. Und[ENTER]setze dich weiter so engagiert für das Land ein. "
gameforge.main_quest_lv10._20_sayReward = "Du hast genügend Erfahrung gesammelt, um deinem[ENTER]Reich als vollwertiger Kنmpfer zu dienen. Von nun[ENTER]an wird der Hauptmann dein Auftraggeber sein. Du[ENTER]findest ihn im ersten Dorf. Zِgere nicht zu lange[ENTER]damit, ihn aufzusuchen. "
gameforge.main_quest_lv10._30_sayTitle = "Hauptmann: "
gameforge.main_quest_lv10._40_say = "Du kommst mir bekannt vor... Ja, ich erinnere[ENTER]mich. Du bist der neue Abenteurer, von dem man[ENTER]mir erzنhlt hat.[ENTER]Ich weiك nicht, wie gut du bislang ausgebildet[ENTER]wurdest, aber hier warten einige Aufgaben auf[ENTER]dich, die womِglich eine Herausforderung[ENTER]darstellen kِnnten. "
gameforge.main_quest_lv10._50_say = "Es werden einige Herausforderungen auf dich[ENTER]zukommen, also sei bereit.[ENTER]Kennst du die Geschichte der drei Reiche vom[ENTER]Kontinent des Strahlenden Himmels? Du kennst sie[ENTER]nicht? Was bringen die Ausbilder den jungen[ENTER]Leuten heutzutage nur bei? Sollte ich dich[ENTER]wirklich so Grundlegendes lehren müssen? "
gameforge.main_quest_lv10._60_say = "Also gut. Dies ist wichtig, denn es ist die[ENTER]Geschichte des Kontinents. Ich werde es für dich[ENTER]zusammenfassen.[ENTER]Einst gab es ein vereintes Reich.[ENTER]Dann kamen die Metinsteine und führten Krieg und[ENTER]Zwietracht mit sich. Das Land wurde geteilt:[ENTER]Shinsoo ist das Reich des Handels,[ENTER]Chunjo das Reich der Religion,[ENTER]und Jinno das Reich des Militنrs. "
gameforge.main_quest_lv10._70_say = "Jedes Reich versucht, sich von den Unruhen[ENTER]zu erholen, die nach Einschlag der Metinsteine[ENTER]über die Lنndereien hereinbrachen. Viele[ENTER]wünschen sich die Vereinigung des Kontinents.[ENTER]Das ist etwas, für das auch du einstehen[ENTER]solltest! Vergiss das niemals. "
gameforge.main_quest_lv10._80_say = "Ich werde dir nun deinen ersten Auftrag erteilen.[ENTER]Entspanne dich, es ist eine leicht zu[ENTER]bewنltigende Aufgabe.[ENTER]Im Nachbardorf lebt ein Musiker namens Yu-Hwan.[ENTER]Die Leute sind der ـberzeugung, er habe den[ENTER]Armeedienst quittiert, um Musiker zu werden. Aber[ENTER]in Wahrheit arbeitet er als geheimer Spنher, um[ENTER]wichtige Dokumente zu beschaffen. Es gibt eines,[ENTER]das ich von ihm benِtige. Bringe es mir – und[ENTER]vergiss nicht, dass dies ein geheimer Auftrag[ENTER]ist. "
gameforge.main_quest_lv10._90_say = "Drücke die M-Taste, um herauszufinden, wie du in[ENTER]das nنchste Dorf auf der Karte gelangst. Benutze[ENTER]das Teleportationsportal, das den entsprechenden[ENTER]Dorfnamen trنgt.[ENTER]Beeile dich! Yu-Hwan ist ein hochgewachsener Kerl[ENTER]- aber du wirst ihn an seinem Musikinstrument[ENTER]erkennen. "
