gameforge.main_quest_lv12._160_sayReward = "Du hast die geforderte Zahl an Alpha-Grauwِlfen[ENTER]getِtet. Kehre zum Hauptmann zurück und berichte[ENTER]von deinem Erfolg. "
gameforge.main_quest_lv12._170_say = "Du hast die Alpha-Grauwِlfe erledigt? Gute[ENTER]Arbeit. Dank dir ist es jetzt einfacher, die[ENTER]Sicherheit im Dorf zu gewنhrleisten. Das ist[ENTER]einmal eine gute Nachricht in Kriegszeiten wie[ENTER]diesen. "
gameforge.main_quest_lv12._180_sayReward = "Du erhنltst 10.000 Erfahrungspunkte und 3.500[ENTER]Yang. "
gameforge.main_quest_lv12._20_say = "Mehrere Alpha-Grauwِlfe haben auكerhalb des[ENTER]Dorfes groكes Unheil angerichtet. Sie waren[ENTER]schon immer wild, aber nun gebنrden sie sich[ENTER]unberechenbar! Sie greifen das Dorf und die Leute[ENTER]auf der Straكe an. Um dieser Situation Herr zu[ENTER]werden, müssen wir einige Alpha-Grauwِlfe[ENTER]tِten. Kannst du helfen? Erledige 10[ENTER]Alpha-Grauwِlfe für uns. "
gameforge.main_quest_lv12._30_sayReward = "Als Belohnung warten 10.000 Erfahrungspunkte und[ENTER]3.500 Yang auf dich. "
