gameforge.main_quest_lv30._110_say = "Uriel hatte Recht: Auf dem Steindenkmal befand[ENTER]sich tatsنchlich eine Inschrift. Du konntest sie[ENTER]zwar nicht lesen, aber immerhin eine Abschrift[ENTER]anfertigen. Bringe deine Notizen zu Uriel. "
gameforge.main_quest_lv30._120_say = "Hast du das Hasun Steindenkmal gefunden? Oh, du[ENTER]hast sogar eine Abschrift dabei. Sehr gut! Das[ENTER]ist eine Entdeckung von wahrhaft historischen[ENTER]Ausmaكen! Zeig her.[ENTER]Hmm... Es scheint sich tatsنchlich um[ENTER]Informationen über die Metinsteine zu handeln.[ENTER]Allerdings kann ich nicht alles entziffern. Diese[ENTER]Schrift ist sehr altertümlich, einige der[ENTER]Buchstaben wirken fast antik. Was machen wir nur? "
gameforge.main_quest_lv30._130_say = "Ah, ich habe eine Idee! Kennst du das Tal von[ENTER]Seungryong? Dort steht eine rنtselhafte Anlage[ENTER]aus der Antike. Wenn du dort alte Inschriften[ENTER]findest, kِnnte ich vielleicht Rückschlüsse auf[ENTER]die fehlenden Buchstaben ziehen. Geh ins Tal von[ENTER]Seungryong und suche das Seul Rong Steindenkmal! "
gameforge.main_quest_lv30._140_targetVid = "Steindenkmal im Tal von Seungryong "
gameforge.main_quest_lv30._150_say = "Der Gelehrte Uriel benِtigt weitere alte Texte,[ENTER]um Rückschlüsse auf einige ihm unbekannte[ENTER]Buchstaben ziehen zu kِnnen.[ENTER]Geh ins Tal von Seungryong und suche dort nach[ENTER]Inschriften auf dem Seul Rong Steindenkmal. "
gameforge.main_quest_lv30._160_say = "Du hast weitere Inschriften gefunden? Oh! Dank[ENTER]dir werde ich bald in der Lage sein, das[ENTER]Geheimnis der Metinsteine zu lüften. Meine[ENTER]Forschung kommt vielleicht schneller voran als[ENTER]ich dachte. Danke, ich danke dir! Wenn ich wieder[ENTER]einmal deine Hilfe brauche, lasse ich es dich[ENTER]wissen. Und hier, nimm bitte diese Belohnung für[ENTER]deine Mühen an! "
gameforge.main_quest_lv30._20_sendLetter = "Das Geheimnis der Metinsteine "
gameforge.main_quest_lv30._30_say = "Uriel hat endlich neue Informationen über das[ENTER]Geheimnis der Metinsteine.[ENTER]Geh und suche Uriel, den Gelehrten. "
gameforge.main_quest_lv30._40_sayTitle = "أوريل : "
gameforge.main_quest_lv30._50_say = "Du wurdest schon einmal vom Hauptmann zu mir[ENTER]geschickt. Du scheinst sehr fنhig zu sein.[ENTER]Ich muss dich um einen Gefallen bitten.[ENTER]Du weiكt Bescheid über die Metinsteine, oder? Die[ENTER]Metinsteine kommen vom Himmel. Sie besitzen bِse[ENTER]Krنfte und verbreiten Seuchen und die Tiere[ENTER]werden wild. Wir wissen nicht, wie sie in unsere[ENTER]Welt gelangt sind oder woraus sie bestehen. Das[ENTER]erschwert meine Untersuchung.[ENTER]Kürzlich habe ich aber einen Schlüssel zu den[ENTER]Geheimnissen der Metinsteine gefunden. "
gameforge.main_quest_lv30._60_say = "Es gibt eine Tafel, ein Denkmal eines antiken[ENTER]Kِnigreichs in einer Hِhle im leichten[ENTER]Affendungeon. Ich glaube, dass es bei den[ENTER]Schriften auf dieser Tafel um die Geheimnisse der[ENTER]Metinsteine geht.[ENTER]Wenn du mir diese Informationen bringen[ENTER]kِnntest, wنre ich vielleicht in der Lage, die[ENTER]Geheimnisse der Metinsteine zu lüften.[ENTER]Bitte bringe mir die Informationen vom[ENTER]Hasun-Steindenkmal im leichten Affendungeon! "
gameforge.main_quest_lv30._70_sayReward = "Du erhنltst 420.000 Erfahrungspunkte.[ENTER]Du erhنltst 20.000 Yang. "
gameforge.main_quest_lv30._80_targetVid = "Steindenkmal im leichten Affendungeon "
gameforge.main_quest_lv30._90_say = "Der Gelehrte Uriel glaubt eine Spur gefunden zu[ENTER]haben, die ihm die Entrنtselung der Metinsteine[ENTER]ermِglichen kِnnte.[ENTER]Geh zum leichten Affendungeon und suche dort nach[ENTER]dem Hasun Steindenkmal. "
gameforge.main_quest_lv32 = {}
gameforge.main_quest_lv32._100_sayReward = "Tipp: Wenn man mit dem Pferd reitet,[ENTER]kann man es schneller und bequemer schaffen. "
gameforge.main_quest_lv32._10_sendLetter = "Das geheime Buch "
gameforge.main_quest_lv32._110_npcChat = "Die Seiten des geheimen Buches "
gameforge.main_quest_lv32._120_sayTitle = "Fahrender Hنndler: "
gameforge.main_quest_lv32._130_say = "Jetzt, wo die ganze Welt in Unruhe geraten ist,[ENTER]ist der Handel auch schwierig geworden. Was[ENTER]mِchtest du kaufen?[ENTER]Ach, du wurdest vom Gelehrten Uriel geschickt? Er[ENTER]ist ein Stammkunde, er sucht immer alte Bücher[ENTER]aus verschiedenen Gebieten. Für mich ist das[ENTER]eher lنstig. Ha, ha, ha.[ENTER]Du mِchtest etwas über die alten Bücher[ENTER]wissen? Hm, die alten Bücher... "
gameforge.main_quest_lv32._140_say = "Ich habe da etwas gehِrt, aber das kann ich nicht[ENTER]umsonst weitererzنhlen. Eine Hand wنscht die[ENTER]andere, nicht wahr?[ENTER]Was zur Zeit gut lنuft, ist der Handel mit[ENTER]Waffen. Aber allein kann ich unmِglich die[ENTER]geforderten Mengen besorgen. Ich werde mit[ENTER]Anfragen geradezu überhنuft! Du stehst doch hier[ENTER]sowieso nur nutzlos in der Gegend herum. Warum[ENTER]tust du zur Abwechslung nicht mal was Sinnvolles[ENTER]und besorgst mir 20 Silberschwerter+0?[ENTER]Sobald du mir diese gebracht hast, gebe ich dir[ENTER]die Information, die die brauchst. "
gameforge.main_quest_lv32._150_targetVid = "Suche den Fahrenden Hنndler "
gameforge.main_quest_lv32._160_sayTitle = "Du hast 20 Silberschwerter+0 "
gameforge.main_quest_lv32._170_say = "Der Fahrende Hنndler hat von den alten Seiten[ENTER]gehِrt. Bringe ihm die 20 Silberschwerter+0, dann[ENTER]verrنt er dir, was er weiك. "
gameforge.main_quest_lv32._180_sayTitle = "Besorge 20 Silberschwerter+0 "
gameforge.main_quest_lv32._190_say = "Der Fahrende Hنndler hat von den alten Seiten[ENTER]gehِrt, wollte sein Wissen aber nicht umsonst[ENTER]preisgeben. Besorge 20 Silberschwerter+0 und[ENTER]bringe sie dem Fahrenden Hنndler als[ENTER]Gegenleistung für die Information. "
gameforge.main_quest_lv32._200_npcChat = "Ich habe die Schwerter besorgt. "
gameforge.main_quest_lv32._20_targetVid = "Suche nach dem Gelehrten Uriel "
gameforge.main_quest_lv32._210_say = "Gut. Du bist begabter als ich dachte. Dank deiner[ENTER]Hilfe wird mein Geschنft bald besser laufen.[ENTER]Was deine Buchseite betrifft... Vor ein paar[ENTER]Tagen kam ich an einem Pavillon vorbei, neben dem[ENTER]ein Denkmal stand. Ich machte dort Rast und[ENTER]bemerkte dabei ein zerfetztes Stück Papier am Fuك[ENTER]des Denkmals. "
gameforge.main_quest_lv32._220_say = "Ich habe mir in dem Moment nichts weiter dabei[ENTER]gedacht. Aber jetzt glaube ich, dass das eine der[ENTER]alten Seiten gewesen sein kِnnte, die du suchst.[ENTER]Der Name des Denkmals? Hmm... War es das Weol[ENTER]Denkmal? Ja, so heiكt es. Das Weol Denkmal in der[ENTER]Nنhe des Nachbardorfes. Dort solltest du suchen! "
gameforge.main_quest_lv32._230_sayTitle = "Fahrender Hنndler: "
gameforge.main_quest_lv32._240_say = "Bring mir 20 Silberschwerter+0. Dann erst gebe[ENTER]ich dir die Information über die alten Seiten. "
gameforge.main_quest_lv32._250_sendLetter = "Suche nach der ersten Seite "
gameforge.main_quest_lv32._260_targetVid = "Ein Denkmal neben dem Pavillon "
gameforge.main_quest_lv32._270_say = "Der Fahrende Hنndler hat am Fuك des Weol Denkmals[ENTER]eine alte Buchseite gesehen, als er im Pavillon[ENTER]neben dem Denkmal Rast machte.[ENTER]Geh zum Weol Denkmal in der Nنhe des ersten[ENTER]Dorfes und sieh nach, ob es sich wirklich um die[ENTER]gesuchte Seite handelt. "
gameforge.main_quest_lv32._280_npcChat = "Das Weol Denkmal "
gameforge.main_quest_lv32._290_say = "Das ist das Denkmal. Oh, da ist sie! Ich habe die[ENTER]Seite! "
gameforge.main_quest_lv32._300_sendLetter = "Die erste Seite "
gameforge.main_quest_lv32._30_say = "Der Gelehrte Uriel schickt nach dir. Er braucht[ENTER]Hilfe bei seinen Forschungen über ein altes[ENTER]geheimes Buch. Geh zu Uriel und sieh nach, was du[ENTER]für ihn tun kannst. "
gameforge.main_quest_lv32._310_targetVid = "Suche den Gelehrten Uriel "
gameforge.main_quest_lv32._320_sayTitle = "Die erste Seite gefunden "
gameforge.main_quest_lv32._330_say = "Du bist den Hinweisen des Fahrenden Hنndlers[ENTER]gefolgt und hast die erste der fehlenden Seiten[ENTER]gefunden. Bringe sie dem Gelehrten Uriel. "
gameforge.main_quest_lv32._340_say = "Hast du die alte Seite gefunden?[ENTER]Oh, du hast sie, sehr gut! Mal sehen, was da[ENTER]geschrieben steht. Hm...[ENTER]Das sieht aus wie ein Tagebuch. Hِr zu! "
gameforge.main_quest_lv32._350_sayTitle = "Erste Buchseite: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop vom Taejo Reich erweitert sein[ENTER]Territorium durch Eroberungszüge. Er will mit[ENTER]seiner Streitmacht alle Lنnder erobern. Wir[ENTER]müssen ihn aufhalten, bevor er unser Land[ENTER]einnimmt. Unglücklicherweise gibt es nicht viele[ENTER]Mِglichkeiten, denn sein Heer ist zu groك und zu[ENTER]stark.[ENTER]Daher haben wir uns zu einer Verzweiflungstat[ENTER]entschlossen: Wir müssen die verbotene Schwarze[ENTER]Hexerei anwenden. "
gameforge.main_quest_lv32._370_sayTitle = "Fortsetzung der ersten Buchseite: "
gameforge.main_quest_lv32._380_sayReward = "Das ist die einzige Mِglichkeit, zu überleben.[ENTER]Wir kِnnen nicht wissen, ob wir erfolgreich sein[ENTER]werden, aber versuchen müssen wir es. Noch bevor[ENTER]sie uns angreifen, müssen wir Informationen über[ENTER]die Schwarze Hexerei bekommen.[ENTER]Wenn die alten Geschichten stimmen, kann man[ENTER]solche Informationen im Drachental finden. "
gameforge.main_quest_lv32._390_say = "Aus dem Inhalt ersehe ich, dass in dem Land, aus[ENTER]dem dieses Buch stammt, ein alter Glaube[ENTER]geherrscht hat.[ENTER]Bevor Lee Seop vom Taejo Reich alle Lنnder unter[ENTER]sich vereinigte, hatte jedes Land seine ganz[ENTER]speziellen Eigenheiten. Soweit ich weiك, hatte[ENTER]zum Beispiel jedes Land einen eigenen Glauben.[ENTER]Der Schreiber dieses Buches scheint sehr gebildet[ENTER]gewesen zu sein. Wahrscheinlich gehِrte er einer[ENTER]der Gilden an oder war sogar ihr Oberhaupt. Die[ENTER]Gildenmitglieder waren damals die oberste Schicht[ENTER]der Gesellschaft. "
gameforge.main_quest_lv32._400_say = "Hier ist von alten Geschichten über das[ENTER]Drachental die Rede. Ich kenne auch einige alte[ENTER]Mنrchen darüber. Vielleicht sind dort auch heute[ENTER]noch Informationen zu finden oder sogar weitere[ENTER]Seiten des Buches. Leider habe ich nie[ENTER]nachgeforscht, wo dieses Tal sich befindet.[ENTER]Geh zum Jنger Yang-Shin im Nachbardorf, er kennt[ENTER]sich gut aus in der Umgebung. Vielleicht weiك er,[ENTER]wo das Drachental ist und ob es dort etwas zu[ENTER]entdecken gibt. "
gameforge.main_quest_lv32._40_say = "Sei gegrüكt! Was du mir das letzte Mal gebracht[ENTER]hast, war wirklich sehr hilfreich. Mit deiner[ENTER]Hilfe bin ich mit meinen Forschungen gut voran[ENTER]gekommen. Nun habe ich aber ein Problem.[ENTER]Bei der Untersuchung einiger Informationen über[ENTER]die Meteoriten habe ich ein altes Buch gefunden.[ENTER]Soweit ich das überblicken kann, werden darin[ENTER]interessante Vermutungen über die Ursachen der[ENTER]Verنnderungen beschrieben, die unser Land[ENTER]heimsuchen. Es ist also von hِchster Wichtigkeit. "
gameforge.main_quest_lv32._410_say = "Ist das aufregend! Oh, bevor ich es vergesse:[ENTER]Hier hast du deine Belohnung für die erste Seite! "
gameforge.main_quest_lv32._420_sayReward = "Du erhنltst 1.000.000 Erfahrungspunkte. "
