gameforge.main_quest_lv32._470_sayTitle = "Frage Yang-Shin nach dem Drachental "
gameforge.main_quest_lv32._480_say = "Auf der ersten Seite des geheimen Buches ist von[ENTER]einem Drachental die Rede. Uriel kennt[ENTER]Geschichten darüber, weiك aber nicht, wo es[ENTER]liegt. Geh ins Nachbardorf und frage den Jنger[ENTER]Yang-Shin, ob er Nنheres weiك. "
gameforge.main_quest_lv32._490_sayReward = "Tipp: Der Jنger befindet sich im Nachbardorf. "
gameforge.main_quest_lv32._500_npcChat = "Informationen über das Drachental "
gameforge.main_quest_lv32._50_say = "Das Problem: Das Buch ist sehr mitgenommen und[ENTER]ziemlich zerrissen. Wahrscheinlich war es lange[ENTER]Zeit von Hand zu Hand unterwegs und ist daher so[ENTER]stark beschنdigt.[ENTER]Es fehlen insgesamt 13 Seiten aus diesem Buch.[ENTER]Kannst du sie mir besorgen? Wahrscheinlich stehen[ENTER]in den Seiten wichtige Informationen, mit denen[ENTER]man den Krieg beenden kann. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Du mِchtest wissen, wo das Drachental ist? Das[ENTER]ist eine sehr alte Bezeichnung für das Tal von[ENTER]Seungryong. Heute gibt es dort keine Drachen[ENTER]mehr, dafür jede Menge Orks und sogar eine[ENTER]geheime Sekte. Warum mِchtest du an so einen[ENTER]gefنhrlichen Ort? Selbst ich, ein geschickter[ENTER]Jنger, gehe nicht gerne dorthin. Es wنre besser,[ENTER]du hنltst dich fern davon. "
gameforge.main_quest_lv32._530_say = "Wie? Du suchst nach alten Buchseiten? Hm![ENTER]Früher habe ich von den anderen Jنgern gehِrt,[ENTER]dass die Zauberer der Orks etwas Papier haben.[ENTER]Aber ob das wahr ist? Wenn du so neugierig bist,[ENTER]such selber danach. Ich habe bereits erwنhnt,[ENTER]dass es dort sehr gefنhrlich ist. Pass gut auf[ENTER]dich auf! "
gameforge.main_quest_lv32._540_sendLetter = "Suche nach der zweiten Seite "
gameforge.main_quest_lv32._550_say = "Nach dem, was der Jنger erzنhlt hat, müssen die[ENTER]Stolzen Ork-Zauberer, die sich im Tal von[ENTER]Seungryong befinden, im Besitz der zweiten alten[ENTER]Seite sein.[ENTER]Tِte die Stolzen Ork-Zauberer und hole dir die[ENTER]zweite Seite. Bringe diese anschlieكend dem[ENTER]Gelehrten Uriel. "
gameforge.main_quest_lv32._560_sendLetter = "Die zweite Seite "
gameforge.main_quest_lv32._570_sayTitle = "Die zweite Seite gefunden "
gameforge.main_quest_lv32._580_say = "Die Jagd auf die Stolzen Ork-Zauberer war[ENTER]erfolgreich: Du hast die zweite Seite des[ENTER]geheimen Buches gefunden.[ENTER]Bringe sie dem Gelehrten Uriel. "
gameforge.main_quest_lv32._590_say = "Ist das die zweite Seite? Lass mich sehen.[ENTER]Hmm, ist gar nicht so leicht, sie zu entziffern.[ENTER]Hier steht geschrieben: "
gameforge.main_quest_lv32._600_sayTitle = "Zweite Buchseite: "
gameforge.main_quest_lv32._60_say = "Sobald du die alten Seiten findest, bring sie zu[ENTER]mir. Dann werde ich versuchen, sie zu entziffern.[ENTER]Hmm...Wo kِnnte man zuerst suchen?[ENTER]Vor einiger Zeit habe ich von einem Fahrenden[ENTER]Hنndler im Nachbardorf gehِrt, dass er eine[ENTER]alte Buchseite gefunden hat. Geh zu ihm und[ENTER]schau, ob du etwas in Erfahrung bringen kannst. "
gameforge.main_quest_lv32._610_sayReward = "Die Anhنnger der dunklen Magie sind gefunden. Sie[ENTER]hatten sich im Drachental versteckt. Sie kennen[ENTER]sich in der Schwarzen Hexerei gut aus, die aus[ENTER]früheren Zeiten überliefert worden ist.[ENTER]Es brauchte einige ـberredungskunst, Drohungen[ENTER]und Schmeicheleien, bis sie uns weiterhalfen.[ENTER]Das Ergebnis: Man braucht einen speziellen Ort,[ENTER]um die Schwarze Hexerei anzuwenden. Einen Ort[ENTER]voller bِser Energie.[ENTER]Die Zeit drنngt. Ich muss so schnell wie mِglich[ENTER]den angemessen Ort finden. "
gameforge.main_quest_lv32._620_say = "Hm, für die Schwarze Hexerei braucht man also[ENTER]einen Ort, der voll von bِser Energie ist. Wo[ENTER]jede Anstrengung, jeder Zauber umgewandelt wird[ENTER]in bِse Energie. Hmm... Wo kِnnte das passieren?[ENTER]Hm... Hm... Bestimmt ist es der Hwang-Tempel![ENTER]Der Volksmund nennt ihn nicht ohne Grund Dunkler[ENTER]Tempel. Das ist ein Ort, an den niemand, der[ENTER]guten Herzens ist, gerne geht. Selbst Tiere[ENTER]meiden ihn. Und eine geheime Sekte treibt dort[ENTER]ihr Unwesen. "
gameforge.main_quest_lv32._630_say = "Es gibt bestimmt einen Zusammenhang zwischen der[ENTER]Schwarzen Hexerei und dieser geheimen Sekte. Im[ENTER]Hwang-Tempel ist der Schlüssel zu diesem Rنtsel[ENTER]zu finden.[ENTER]Finde heraus, was es mit dem Hwang-Tempel auf[ENTER]sich hat und sieh nach, ob du dort weitere[ENTER]Buchseiten findest![ENTER]Und hier ist natürlich auch deine Belohnung für[ENTER]die zweite Seite. "
gameforge.main_quest_lv32._640_sayReward = "Du erhنltst 1.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv32._650_sayReward = "Du erhنltst 50.000 Yang. "
gameforge.main_quest_lv32._660_sayReward = "Du erhنltst 10 Weiكe Flaggen. "
