gameforge.main_quest_lv40._260_npcChat = "Die vierte alte Seite "
gameforge.main_quest_lv40._270_say = "Oh! Du hast die vierte alte Seite gefunden.[ENTER]Hoffentlich kommen wir weiter mit der[ENTER]Information, die uns das Buch gibt. "
gameforge.main_quest_lv40._280_sayTitle = "Vierte Seite: "
gameforge.main_quest_lv40._290_sayReward = "Ich bin nun in der tiefen Hِhle, wo die Affen[ENTER]wohnen. Alle meine Begleiter zittern vor Angst,[ENTER]aber auch hier reicht die angesammelte bِse[ENTER]Energie nicht aus.[ENTER]Die Zeit vergeht viel zu schnell und Lee Seops[ENTER]Armee kommt immer nنher. Ob wir es noch[ENTER]rechtzeitig schaffen? "
gameforge.main_quest_lv40._300_sayTitle = "Fortsetzung der vierten Buchseite: "
gameforge.main_quest_lv40._30_sayTitle = "Die dritte Seite gefunden "
gameforge.main_quest_lv40._310_sayReward = "Ich muss so schnell wie mِglich den nنchsten Ort[ENTER]finden, der uns weiterhelfen kِnnte. Noch ist[ENTER]nichts verloren.[ENTER]Ich werde es in den Spinnenhِhlen versuchen. Mِge[ENTER]sich diesmal unser Wunsch erfüllen... "
gameforge.main_quest_lv40._320_say = "Hm. Der Affendungeon ist also nicht der Ort, den[ENTER]wir suchen. Dann auf ein Neues! Nach dem, was[ENTER]hier geschrieben steht, müssen wir zu den[ENTER]Spinnenhِhlen gehen.[ENTER]Aber zunنchst ist eine dringlichere Angelegenheit[ENTER]zu regeln: Der Hauptmann ist in groكer Sorge,[ENTER]weil sich zur Zeit viele Fremde in der Nنhe des[ENTER]Dorfes herumtreiben und seltsame Fragen stellen.[ENTER]Du solltest zu ihm gehen und nachsehen, was da[ENTER]los ist. "
gameforge.main_quest_lv40._330_say = "Ich habe ein unangenehmes Gefühl bei dieser[ENTER]Sache. Mal sehen, was der Hauptmann sagt.[ENTER]Oh, fast hنtte ich es vergessen: Hier ist deine[ENTER]Belohnung für die vierte Seite. "
