gameforge.main_quest_lv40._370_targetVid = "Suche den Hauptmann auf "
gameforge.main_quest_lv40._380_sayTitle = "Frage den Hauptmann nach den Fremden "
gameforge.main_quest_lv40._390_say = "Man sagt, dass zur Zeit viele Fremde im Dorf[ENTER]auftauchen. Sie stellen verdنchtig viele Fragen[ENTER]über die Denkmنler. Der Hauptmann will etwas[ENTER]dagegen unternehmen. Geh zu ihm, um mehr zu[ENTER]erfahren. "
gameforge.main_quest_lv40._400_npcChat = "Die Fremden im Dorf "
gameforge.main_quest_lv40._40_say = "Uriels Vermutungen über die Stolzen dunklen[ENTER]Fanatiker waren korrekt. Du hast die dritte[ENTER]Tagebuchseite bei ihnen gefunden. Bringe die[ENTER]Seite dem Gelehrten Uriel. "
gameforge.main_quest_lv40._410_say = "Zur Zeit kommen vermehrt Fremde in unser Dorf.[ENTER]Sie fragen die Bewohner über die Denkmنler und[ENTER]alten Bücher aus. Es gibt einige Leute, die[ENTER]etwas darüber wissen, aber den Fremden nichts[ENTER]verraten wollen. Ich fürchte, das bringt uns[ENTER]alle in Gefahr. Wer weiك, von wem diese Fremden[ENTER]geschickt wurden und wie weit sie gehen würden,[ENTER]um Informationen zu erhalten. Immerhin befinden[ENTER]wir uns im Krieg... "
gameforge.main_quest_lv40._420_say = "Wenn ich richtig informiert bin, steht Nakajima[ENTER]aus dem Nachbardorf irgendwie damit in[ENTER]Zusammenhang. Versuch bitte von ihm[ENTER]herauszufinden, was die Fremden hier wollen. "
gameforge.main_quest_lv40._430_sendLetter = "Geh zu Nakajima "
gameforge.main_quest_lv40._440_say = "Der Hauptmann meint, es gنbe eine Verbindung[ENTER]zwischen Nakajima und den Fremden, die überall[ENTER]im Dorf nach den Denkmنlern fragen.[ENTER]Geh zu Nakajima und finde heraus, was er weiك.[ENTER]Du findest ihn auكerhalb des zweiten Dorfes. "
gameforge.main_quest_lv40._450_npcChat = "Was weiكt du über die Fremden im Dorf? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Wie bitte? Was soll die Frage? Was für[ENTER]verdنchtige Fremde? Tut mir leid. Ich kann dir[ENTER]nicht helfen. Ich habe nicht die geringste[ENTER]Ahnung, wovon du überhaupt redest. Nein, nein.[ENTER]Es ist schwer genug, in diesen Zeiten Arbeit zu[ENTER]finden. Wovon soll ich mich denn ernنhren, hن? "
gameforge.main_quest_lv40._480_say = "Na gut, ich geb's ja zu. Aber ich habe nur[ENTER]zugesagt, weil sie mir eine Menge Yang[ENTER]versprochen haben.[ENTER]Was die Fremden hier wollen, das weiك ich nicht.[ENTER]Aber sie haben mir einen Auftrag gegeben: Ich[ENTER]soll die Brutalen Hauptmنnner tِten. "
gameforge.main_quest_lv40._490_say = "Von den Brutalen Hauptmنnnern kِnntest du sicher[ENTER]mehr erfahren. Die Fremden waren ganz heiك[ENTER]darauf, dass ich sie tِte.[ENTER]Oh, ich habe eine Idee: Am besten gehst du und[ENTER]tِtest sie für mich, ja? Bitte? "
gameforge.main_quest_lv40._500_sendLetter = "Tِte die Brutalen Hauptmنnner "
gameforge.main_quest_lv40._50_say = "Oh, du hast den nنchsten Hinweis gefunden?![ENTER]Das ist die dritte Seite.[ENTER]Lass sehen, was dort geschrieben steht. "
gameforge.main_quest_lv40._510_say = "Nakajima hat mir verraten, dass die Fremden die[ENTER]Brutalen Hauptmنnner tِten wollen. Da die[ENTER]Fremden nach den Tagebuchseiten gefragt haben,[ENTER]ist zu vermuten, dass die Brutalen Hauptmنnner[ENTER]eine dieser Seiten bei sich tragen.[ENTER]Um mehr herauszufinden, muss ich Brutale[ENTER]Hauptmنnner tِten. Sie sind auكerhalb des zweiten[ENTER]Dorfes zu finden. "
gameforge.main_quest_lv40._520_sendLetter = "Die fünfte Seite gefunden "
gameforge.main_quest_lv40._530_say = "Ich konnte den Fremden zuvorkommen und habe den[ENTER]Brutalen Hauptmنnnern die fünfte Tagebuchseite[ENTER]abgenommen. Bestimmt verschwinden die Fremden[ENTER]jetzt, denn es gibt hier nichts mehr zu finden.[ENTER]Die Seite bringe ich am Besten zum Gelehrten[ENTER]Uriel, damit er sie entziffern kann. "
gameforge.main_quest_lv40._540_sayTitle = "Die fünfte Seite "
gameforge.main_quest_lv40._550_sayReward = "Tipp: Du kannst die fünfte Seite des geheimen[ENTER]Buches erst zu Uriel bringen, wenn du Level 47[ENTER]erreicht hast. Bewahre die Seite bis dahin gut[ENTER]auf! "
gameforge.main_quest_lv40._60_sayTitle = "Dritte Buchseite: "
gameforge.main_quest_lv40._70_sayReward = "Wir haben einen Ort gefunden, an dem die Energie[ENTER]des Bِsen regiert. Aber das reicht nicht aus. Der[ENTER]Ort ist bِse, aber er ist ungeeignet zum[ENTER]Praktizieren von Hexerei. Das ist ein herber[ENTER]Rückschlag.[ENTER]Aber unsere Spنher sprechen von einem versteckten[ENTER]Ort in der Wüste, der vielversprechend sein soll.[ENTER]Voller Hoffnung begeben wir uns nun dorthin. "
gameforge.main_quest_lv40._80_say = "Im Drachental konnten sie ihr Ziel also nicht[ENTER]erreichen. Hm...[ENTER]Und jetzt die Wüste Yongbi? Dort trifft man sehr[ENTER]selten Menschen und das Gebiet ist weitgehend[ENTER]unerforscht. Das ist sehr kompliziert. Wo genau[ENTER]mag dieser Ort sein, von dem hier die Rede ist?[ENTER]Ich vermute, dass der Affendungeon Jungsun Dong[ENTER]gemeint ist. Das ist eine tiefe Hِhle, die gut[ENTER]geeignet ist, um bِse Energien zu sammeln. "
gameforge.main_quest_lv40._90_say = "Geh bitte zum Jungsun Dong und suche dort nach[ENTER]weiteren Steindenkmنlern. Mit ein bisschen Glück[ENTER]sind bei den Denkmنlern auch weitere Buchseiten[ENTER]zu finden. Oh, und natürlich sollten wir deine[ENTER]Belohnung für die dritte Seite nicht vergessen. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "Die Seite im Spinnendungeon "
gameforge.main_quest_lv47._10_sayTitle = "Die Seite der Brutalen Hauptmنnner "
gameforge.main_quest_lv47._110_say = "Uriel meint, dass im Spinnendungeon weitere[ENTER]Informationen über die Schwarze Hexerei zu[ENTER]finden sein kِnnten. Vielleicht gibt es dort[ENTER]auch so ein Denkmal wie im Affendungeon.[ENTER]Zum Spinnendungeon kommt man über die[ENTER]Yongbi-Wüste. "
gameforge.main_quest_lv47._120_npcChat = "Das Mok Denkmal "
gameforge.main_quest_lv47._130_say = "Tatsنchlich! Hier ist ein Denkmal und auch eine[ENTER]Tagebuchseite. Nun schnell zurück zu Uriel. "
gameforge.main_quest_lv47._140_sayTitle = "Die sechste Seite gefunden "
gameforge.main_quest_lv47._150_say = "Du hast im Spinnendungeon ein weiteres altes[ENTER]Denkmal gefunden und auch die dort versteckte[ENTER]sechste Tagebuchseite. Bringe sie zu Uriel dem[ENTER]Gelehrten. "
gameforge.main_quest_lv47._160_npcChat = "Die sechste Seite "
gameforge.main_quest_lv47._170_say = "Wie war der Spinnendungeon? Hast du die sechste[ENTER]Seite gefunden? Das ist ja fantastisch![ENTER]Ich habe mir schon Sorgen gemacht, dass du zu[ENTER]spنt kommen kِnntest. Man hِrt immer wieder[ENTER]von anderen Leuten, die ebenfalls nach den[ENTER]Geheimnissen der Schwarzen Hexerei suchen. Es[ENTER]scheinen sehr wichtige Informationen zu sein.[ENTER]Schauen wir mal, was uns diese Seite bringt. "
gameforge.main_quest_lv47._180_say = "Oje, diese Seite ist sehr schlecht zu lesen.[ENTER]Dafür werde ich wohl lنnger brauchen. Aber es[ENTER]sieht wichtig aus. Dieses Zeichen hier bedeutet[ENTER]\"Schwarze Hexerei\", wir sind also auf der[ENTER]richtigen Spur.[ENTER]Ich mِchte zu gerne wissen, warum die Schwarze[ENTER]Hexerei verboten ist. Das hat sicher einen guten[ENTER]Grund... "
gameforge.main_quest_lv47._190_say = "Wنhrend ich diese Seite übersetze, kannst du[ENTER]zum Musiker Yu-Hwan gehen. Ich habe gehِrt, er[ENTER]hنtte interessante Informationen für unsere[ENTER]Suche. Wenn du wiederkommst, kann ich dir sagen,[ENTER]was hier auf der Seite steht. Deine Belohnung[ENTER]sollst du aber natürlich jetzt schon bekommen. "
gameforge.main_quest_lv47._200_sayReward = "Du erhنltst 3.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv47._20_say = "Mit Level 40 hast du den Brutalen Hauptmنnnern[ENTER]die fünfte Seite des geheimen Tagebuchs[ENTER]abgenommen. Du solltest diese nun zu Uriel[ENTER]bringen. "
gameforge.main_quest_lv47._210_sayReward = "Du erhنltst 75.000 Yang. "
gameforge.main_quest_lv47._220_sayReward = "Du erhنltst einen Segen des Drachen. "
gameforge.main_quest_lv47._230_sendLetter = "Geh zu Yu-Hwan "
gameforge.main_quest_lv47._240_targetVid = "Suche den Musiker Yu-Hwan "
gameforge.main_quest_lv47._250_sayTitle = "Die geheimen Krنfte "
gameforge.main_quest_lv47._260_say = "Der Musiker Yu-Hwan hat vielleicht Informationen[ENTER]über die alten Tagebuchseiten. Suche ihn auf und[ENTER]frage ihn danach. "
gameforge.main_quest_lv47._270_npcChat = "Gibt es Neuigkeiten? "
gameforge.main_quest_lv47._280_say = "Genieكe das Leben, denn es ist vergنnglich![ENTER]Trallalaaa...[ENTER]Ah, du bist es wieder. Du kommst sicher vom[ENTER]Gelehrten Uriel. Er hat mich vor ein paar Tagen[ENTER]gefragt, ob ich mich etwas umhِren kann. Ich[ENTER]habe herausgefunden, dass in allen Reichen Leute[ENTER]unterwegs sind, die wichtige Dokumente suchen.[ENTER]Leider konnte mir niemand sagen, worum es da[ENTER]genau geht. "
gameforge.main_quest_lv47._290_say = "Wenn man bedenkt, dass wir uns im Krieg befinden,[ENTER]kann einem schon seltsam zumute werden bei all[ENTER]diesen herumschleichenden Gestalten. Dich[ENTER]natürlich ausgenommen![ENTER]Auكerdem habe ich gehِrt, dass die Wüstenbanditen[ENTER]ein paar Sachan erbeuten konnten, die für uns von[ENTER]grِكter Wichtigkeit sein kِnnten. Vielleicht[ENTER]solltest du mal schauen, ob etwas aus ihnen[ENTER]herausprügeln kannst. "
gameforge.main_quest_lv47._300_say = "Die Wüstenbanditen sind nicht ganz ungefنhrlich,[ENTER]also sei auf der Hut. Aber ich denke, es wird[ENTER]sich lohnen. Ich werde dir ein Lied widmen und es[ENTER]dem Wind anvertrauen, damit er es dir in die[ENTER]Wüste hinterhertrنgt. Viel Erfolg! "
gameforge.main_quest_lv47._30_npcChat = "Die fünfte Seite "
gameforge.main_quest_lv47._310_sendLetter = "Die Wüstenbanditen "
gameforge.main_quest_lv47._320_sayTitle = "Die Suche nach den geheimen Informationen "
gameforge.main_quest_lv47._330_say = "Uriel braucht jegliche Informationen zur[ENTER]Schwarzen Hexerei. Der Musiker Yu-Hwan sagte,[ENTER]dass die Wüstenbanditen etwas gestohlen hنtten,[ENTER]das uns weiterhelfen kِnnte. Ich sollte mich auf[ENTER]den Weg machen und ein paar Wüstenbanditen[ENTER]tِten. "
gameforge.main_quest_lv47._340_sendLetter = "Die siebte Seite gefunden "
gameforge.main_quest_lv47._350_targetVid = "Die Suche nach dem Musiker Yu-Hwan "
gameforge.main_quest_lv47._360_say = "Nach den Informationen, die dir der Musiker[ENTER]Yu-Hwan gegeben hatte, konntest du die siebte[ENTER]Seite des geheimen Buchs bei den Wüstenbanditen[ENTER]finden.[ENTER]Geh zu Yu-Hwan und teile ihm mit, dass seine[ENTER]Information richtig war. "
gameforge.main_quest_lv47._370_say = "Deine Augen sind so schِn wie ein Bergsee,[ENTER]lalalala... He, da bist du ja wieder. Hast du bei[ENTER]den Wüstenbanditen Erfolg gehabt?[ENTER]Wie, das ist alles? Ein altes Stück Papier? Damit[ENTER]kann ich nichts anfangen. Aber wenn es euch[ENTER]glücklich macht...[ENTER]Du solltest es zu Uriel bringen. Und richte meine[ENTER]Grüكe aus! "
gameforge.main_quest_lv47._380_sendLetter = "Geh zu Uriel "
gameforge.main_quest_lv47._390_targetVid = "Geh zu Uriel "
gameforge.main_quest_lv47._400_sayTitle = "Die siebte Seite "
gameforge.main_quest_lv47._40_say = "Du hast die fünfte Seite? Unglaublich. Was für[ENTER]ein Glück, dass diese Seiten überhaupt noch[ENTER]existieren, nach all den Jahren. Du bist sehr[ENTER]tüchtig. Jetzt lass uns nachsehen, was darin[ENTER]geschrieben steht. "
gameforge.main_quest_lv47._410_say = "Du hast die siebte Seite des alten Tagebuchs[ENTER]gefunden. Bringe sie zu Uriel. "
gameforge.main_quest_lv47._420_say = "Hallo, schِn dich wiederzusehen! Ich habe eine[ENTER]gute Nachricht: Die Entzifferung der sechsten[ENTER]Seite ist bereits fertig. Nicht schlecht, was?[ENTER]Ich muss zugeben, ich bin ein wenig stolz auf[ENTER]mich. Mir ist nنmlich aufgefallen, dass die[ENTER]Schriftzeichen... Wie bitte? Du hast schon wieder[ENTER]eine gefunden? Meine Güte! Das ging wirklich[ENTER]schnell. Zeig her. Oho, woher hast du die denn[ENTER]bekommen? Wenn mich nicht alles tنuscht, sind[ENTER]das Schriftzeichen, die nur von der kaiserlichen[ENTER]Familie benutzt wurden. "
gameforge.main_quest_lv47._430_say = "Da diese Schriftzeichen nur von sehr wenigen[ENTER]Menschen und auch nur selten benutzt wurden, wird[ENTER]es sehr schwierig werden, sie zu übersetzen. Aber[ENTER]der Mensch braucht Herausforderungen, haha! Ich[ENTER]freue mich darauf.[ENTER]Die Wüstenbanditen haben diese Seite von den[ENTER]geheimnisvollen Fremden gestohlen? Hmm... Heiكt[ENTER]das, dass die Fremden diese Schriftzeichen[ENTER]kennen? Es wird immer verworrener. Wir müssen[ENTER]aufpassen, dass wir nichts übersehen. "
gameforge.main_quest_lv47._440_say = "Ach ja, übersehen: Bevor ich mich der nنchsten[ENTER]Seite zuwende, sollte ich dir wohl erstmal[ENTER]mitteilen, was auf der sechsten Seite stand.[ENTER]Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "Sechste Buchseite: "
gameforge.main_quest_lv47._460_sayReward = "Uns lنuft die Zeit davon. Nun haben wir die[ENTER]Schwarze Hexerei sogar im Spinnendungeon[ENTER]anzuwenden versucht, ohne Ergebnis. Was fehlt uns[ENTER]zum Erfolg? Einige unserer Mystiker vermuten,[ENTER]dass die Schwarze Hexerei nach hِheren Opfern[ENTER]verlangt. Wenn dem so ist, muss sie wahrhaft[ENTER]mنchtig sein. "
gameforge.main_quest_lv47._470_sayReward = "In den Mنrchen und Legenden braucht diese Art von[ENTER]Magie immer Menschenopfer. Aber wenn ich ihre[ENTER]Liebsten auf einem Altar tِte, wird mein Ansehen[ENTER]bei den Menschen rasch schwinden. Wir brauchen[ENTER]geeigneten Ersatz. Versuchen wir es mit den[ENTER]Schlangenschwertkنmpfern aus der Wüste. "
gameforge.main_quest_lv47._480_say = "Soso. Da sie keine Menschen als Opfer benutzen[ENTER]konnten, haben sie sich entschieden,[ENTER]Schlangenkنmpfer zu nehmen. Ich kann nicht[ENTER]behaupten, dass mir diese neue Entwicklung[ENTER]gefنllt. Das wird bِse enden...[ENTER]Dennoch müssen wir ihrer Spur folgen. Du solltest[ENTER]dich in die Wüste begeben und dort einige[ENTER]Schlangen-Schwertkنmpfer und[ENTER]Schlangen-Bogenschützen tِten. Wer weiك, was wir[ENTER]dort noch so finden. A propos finden: In dieser[ENTER]Bِrse findest du deine Belohnung! "
gameforge.main_quest_lv47._490_sendLetter = "Tِte die Schlangenkنmpfer "
gameforge.main_quest_lv47._500_sayTitle = "Die achte Seite "
gameforge.main_quest_lv47._50_sayTitle = "Fünfte Buchseite: "
gameforge.main_quest_lv47._510_say = "Das Tagebuch beschreibt den Versuch,[ENTER]Schlangenschwertkنmpfer und[ENTER]Schlangenbogenschützen für das Gelingen der[ENTER]Schwarzen Hexerei zu opfern. Geh in die Wüste[ENTER]Yongbi und tِte Schlangenkنmpfer. Halte dabei[ENTER]nach weiteren Informationen Ausschau. "
gameforge.main_quest_lv47._520_sendLetter = "Die achte Seite gefunden "
gameforge.main_quest_lv47._530_targetVid = "Geh zum Gelehrten Uriel "
gameforge.main_quest_lv47._540_say = "Du hat die achte Seite des geheimen Tagebuchs bei[ENTER]den Schlangenkنmpfern in der Wüste gefunden.[ENTER]Bringe sie zum Gelehrten Uriel. "
gameforge.main_quest_lv47._550_say = "Du hast die achte Seite. Sehr gut. Sie ist sehr[ENTER]kurz. Ich denke, ich kann sie direkt vorlesen.[ENTER]Einen Moment bitte... Ah, ja. "
gameforge.main_quest_lv47._560_sayTitle = "Achte Buchseite: "
gameforge.main_quest_lv47._570_sayReward = "Die nِtigen Opfer sind gefunden. Wir haben[ENTER]Glück. Ob das ein Zeichen ist? Als Nنchstes[ENTER]brauchen wir ein zeremonielles Glِckchen. Wenn[ENTER]ich mich richtig erinnere, habe ich so etwas bei[ENTER]den Spinnen gesehen. Wir machen uns auf dem Weg. "
gameforge.main_quest_lv47._580_say = "Schon wieder der Spinnendungeon, seltsam. Du[ENTER]musst unbedingt dort hin und nach diesem[ENTER]Glِckchen suchen. Aber es wird eine anstrengende[ENTER]Reise, also ruh dich erst einmal aus und komm[ENTER]spنter wieder. Ich werde noch etwas nachdenken[ENTER]und weitere Fragmente übersetzen. Wenn du[ENTER]wiederkommst, gebe ich dir einen neuen Auftrag.[ENTER]Und keine Sorge. Deine Belohnung für die achte[ENTER]Seite bekommst du natürlich jetzt schon. "
gameforge.main_quest_lv47._590_sayReward = "Du erhنltst 3.000.000 Erfahrungspunkte.[ENTER]Du erhنltst 70.000 Yang.[ENTER]Du erhنltst 20 Tapferkeitsumhنnge.[ENTER]Tipp:[ENTER]Für die nنchste Aufgabe musst du mindestens[ENTER]Level 50 erreicht haben. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop ist mit seiner Reiterei im Reich Taejo[ENTER]angekommen und scheint vorerst dort verweilen zu[ENTER]wollen. Unterdessen regnen Meteoriten auf das[ENTER]Land nieder. Sie bringen Chaos, Zerstِrung und[ENTER]Zwietracht. Das groكe Reich hat sich in drei[ENTER]kleinere Reiche aufgespalten. Sie bekنmpfen sich[ENTER]untereinander, statt gemeinsam gegen das ـbel[ENTER]vorzugehen. Der Drachengott spricht nicht mehr zu[ENTER]uns. Seine Unterstützung scheint mal dem einen,[ENTER]mal dem anderen Reich zu gelten. So kنmpfen alle[ENTER]um seine Gunst und wنhrenddessen breitet sich das[ENTER]Unheil weiter aus... "
gameforge.main_quest_lv47._70_sayTitle = " أوريل : "
gameforge.main_quest_lv47._80_say = "Ein Augenzeugenbericht aus den Anfangstagen[ENTER]unseres Zeitalters. Absolut unbezahlbar! Ach ja,[ENTER]bezahlen. Hier hast du deine Belohnung für diese[ENTER]hervorragende Arbeit. Und noch etwas: Jemand[ENTER]anderes stellt offensichtlich die gleichen[ENTER]Untersuchungen an, wie wir. Wir haben also keine[ENTER]Zeit zu verlieren. Am Ende dieser Seite hier[ENTER]steht, dass Lee Seop als Nنchstes im[ENTER]Spinnendungeon nach bِser Energie gesucht hat.[ENTER]Wenn du dort etwas findest, komm sofort zu mir![ENTER]Ich brenne vor Ungeduld! "
gameforge.main_quest_lv47._90_sendLetter = "Die sechste Seite "
gameforge.main_quest_lv50 = {}
