gameforge.main_quest_lv50._160_sayTitle = "Suche die alte Box mit Papieren "
gameforge.main_quest_lv50._170_say = "Auf dem Berg Sohan sind die feindlichen Heere[ENTER]schlieكlich aufeinandergetroffen. Suche dort nach[ENTER]weiteren Tagebuchseiten oder anderen[ENTER]schriftlichen Hinweisen auf den Verlauf der[ENTER]Schlacht. "
gameforge.main_quest_lv50._180_npcChat = "Eine alte Truhe mit Schriftstücken! "
gameforge.main_quest_lv50._190_say = "Das sind militنrische Plنne und Aufzeichnungen.[ENTER]Und hier ist auch eine weitere Tagebuchseite![ENTER]Ich sollte sie zu Uriel bringen. "
gameforge.main_quest_lv50._200_sendLetter = "Die zehnte Seite "
gameforge.main_quest_lv50._20_say = "Die bisherigen Untersuchungen deuten auf Spuren[ENTER]im Spinnendungeon hin. Geh und tِte Stolze[ENTER]Soldat-Giftspinnen im Kuahlo Dong. Wenn du eine[ENTER]weitere Seite des alten Buches findest, bringe[ENTER]sie zum Gelehrten Uriel. "
gameforge.main_quest_lv50._210_sayTitle = "Die zehnte Seite gefunden "
gameforge.main_quest_lv50._220_say = "Du hast die zehnte Seite des geheimen Tagebuchs[ENTER]im Eisland gefunden. Sie war in einer alten Box[ENTER]mit Papieren. Bringe sie zu Uriel. "
gameforge.main_quest_lv50._230_say = "Ah, du hast die zehnte Tagebuchseite gefunden![ENTER]Wir kommen dem Ende der Geschichte immer nنher.[ENTER]Nur gut, dass damals alles aufgeschrieben wurde,[ENTER]sonst wنre dieses Wissen jetzt verloren. Schauen[ENTER]wir mal, was uns diese Seite sagt. "
gameforge.main_quest_lv50._235_sayTitle = "Zehnte Buchseite: "
gameforge.main_quest_lv50._240_sayReward = "Es ist uns gelungen, den ersten Angriff[ENTER]abzuwehren. Aber der nنchste wird bald folgen.[ENTER]Das Terrain behindert Lee Seops schwere[ENTER]Eisensoldaten und verschafft uns Vorteile, aber[ENTER]es sind einfach zu viele. Wir kِnnen nicht[ENTER]gewinnen. Uns bleibt nur noch eine letzte Chance,[ENTER]unsere Forschungen über die Schwarze Hexerei zu[ENTER]vollenden. Im Schutze der Nacht werden wir die[ENTER]feindlichen Linien durchbrechen und zu den[ENTER]Spinnenhِhlen zurückkehren. Ich bete. Nicht für[ENTER]den Sieg, aber für ein kleines bisschen[ENTER]Hoffnung... "
gameforge.main_quest_lv50._250_say = "Ooohh. Ich glaube, wir sind kurz vor dem Ziel![ENTER]Bald werden wir herausfinden, was es mit der[ENTER]Schwarzen Hexerei auf sich hat. Ich kann es kaum[ENTER]erwarten! Du musst einmal mehr zum Spinnendungeon[ENTER]zurückgehen. Dort ist hoffentlich die elfte[ENTER]Seite des Buches zu finden. "
gameforge.main_quest_lv50._260_say = "Und hier ist - einmal mehr - deine wohlverdiente[ENTER]Belohnung! "
gameforge.main_quest_lv50._270_sayReward = "Du erhنltst 5.500.000 Erfahrungspunkte. "
gameforge.main_quest_lv50._280_sayReward = "Du erhنltst 137.500 Yang. "
gameforge.main_quest_lv50._290_sayReward = "Du erhنltst einen Handschuh weiser Kaiser. "
gameforge.main_quest_lv50._300_sayTitle = "Tِte Klauengiftspinnen "
gameforge.main_quest_lv50._30_sendLetter = "Die neunte Seite "
gameforge.main_quest_lv50._310_say = "Die Forschungen zur Schwarzen Hexerei wurden in[ENTER]den Spinnenhِhlen fortgesetzt. Gehe dorthin und[ENTER]tِte Klauengiftspinnen, um die benِtigten[ENTER]Informationen zu bekommen. "
