gameforge.main_quest_lv50._335_sayTitle = "Die elfte Seite gefunden "
gameforge.main_quest_lv50._340_say = "Im Spinnendungeon hast du die elfte Seite des[ENTER]geheimen Tagebuchs gefunden. Bringe sie zu Uriel. "
gameforge.main_quest_lv50._350_say = "Hast du etwas Neues herausgefunden?[ENTER]Oho, die elfte Seite! Lass sehen...[ENTER]Ah ja, das sieht recht einfach aus. Inzwischen[ENTER]bin ich richtig gut darin, diese Schriftzeichen[ENTER]zu lesen. Pass auf! "
gameforge.main_quest_lv50._355_sayTitle = "Elfte Buchseite: "
gameforge.main_quest_lv50._360_sayReward = "Es ist misslungen.[ENTER]Trotz aller Vorbereitung mussten wir schlieكlich[ENTER]schnell handeln. Zu schnell. Nun sind viele von[ENTER]uns verwundet, andere sind verrückt geworden. Die[ENTER]Schwarze Hexerei ist wahrlich bِse.[ENTER]Lee Seops Reiterei ist uns dicht auf den Fersen,[ENTER]aber das ist jetzt egal. Wir haben nicht mehr[ENTER]genug Leute, um ihm etwas entgegenzusetzen.[ENTER]Sterben werden wir sowieso. "
gameforge.main_quest_lv50._365_sayTitle = "Fortsetzung der elften Buchseite: "
gameforge.main_quest_lv50._370_sayReward = "Ein letzter Gedanke hنlt den Rest der Truppe[ENTER]zusammen und verleiht uns Kraft: Die Informanten[ENTER]im Drachental haben gelogen. Sie haben uns[ENTER]absichtlich nicht vor den schrecklichen[ENTER]Nebenwirkungen der Schwarzen Hexerei gewarnt.[ENTER]Dafür werden sie bezahlen. Es wird unsere letzte[ENTER]Tat auf dieser Erde sein. "
gameforge.main_quest_lv50._380_say = "Tja, letztendlich ist es wohl anders ausgegangen,[ENTER]als sie gehofft hatten. Eine traurige Geschichte.[ENTER]Man kann keinem Menschen trauen, der sich mit der[ENTER]Schwarzen Hexerei beschنftigt. Das hنtten sie[ENTER]bedenken sollen. Es ist schon seltsam genug, dass[ENTER]der Schreiber dieser Zeilen überhaupt[ENTER]Informationen über diese verbotenen[ENTER]Machenschaften erhalten konnte. Wer weiك, welches[ENTER]Ziel seine Informanten verfolgten.[ENTER]Wir aber sollten diesen Weg zuende gehen, auch[ENTER]wenn es gefنhrlich ist. Wir wissen schon so viel,[ENTER]es wنre schade, jetzt[ENTER]aufzugeben. "
gameforge.main_quest_lv50._390_say = "Im Tal von Seungryong warst du ja bereits. Ich[ENTER]denke nicht, dass wir dort noch etwas finden.[ENTER]Hmm, wo kِnnten wir noch suchen...[ENTER]Ich weiك! Die Denkmنler haben eine groكe Rolle[ENTER]bei unserer Suche gespielt. Und es gibt[ENTER]Denkmنler, die wir noch nicht untersucht haben.[ENTER]Nنmlich die in den anderen Reichen! Es ist sehr[ENTER]gefنhrlich dort. Man wird dich oft angreifen.[ENTER]Also bereite dich gut vor und komm zu mir, wenn[ENTER]du bereit bist. "
gameforge.main_quest_lv50._400_say = "Aber zunنchst bekommst du natürlich noch deine[ENTER]Belohnung für die elfte Seite. "
gameforge.main_quest_lv50._40_targetVid = "Geh zum Gelehrten Uriel "
gameforge.main_quest_lv50._410_sayReward = "Du erhنltst 6.000.000 Erfahrungspunkte.[ENTER]Du erhنltst 150.000 Yang.[ENTER]Du erhنltst eine Medaille des Drachen.[ENTER]Tipp:[ENTER]Für die nنchste Aufgabe musst du mindestens[ENTER]Level 55 erreicht haben. "
gameforge.main_quest_lv50._50_sayTitle = "Die neunte Seite gefunden "
gameforge.main_quest_lv50._60_say = "Du hast die neunte Seite im Spinnendungeon[ENTER]gefunden. Bringe sie zum Gelehrten Uriel. "
gameforge.main_quest_lv50._70_say = "Du hast eine weitere Spur der Schwarzen Hexerei[ENTER]gefunden? Tatsنchlich, die neunte Seite! Ich bin[ENTER]gespannt, ob der Zauber funktioniert hat. Lass[ENTER]uns schnell nachsehen. Hmm, hier steht... "
gameforge.main_quest_lv50._75_sayTitle = "Neunte Buchseite: "
gameforge.main_quest_lv50._80_sayReward = "Lee Seops Angriff hat begonnen. Ich bin sehr[ENTER]nervِs, denn wir wissen immer noch nicht genau,[ENTER]wie wir die Schwarze Hexerei benutzen kِnnen. Wir[ENTER]sind hier an vorderster Front, um unser Reich zu[ENTER]verteidigen. Doch unsere Mittel reichen nicht[ENTER]aus. Die feindliche Armee ist viel zu stark und[ENTER]wenn nicht bald etwas geschieht, werden wir die[ENTER]Schlacht verlieren. Wir müssen uns an einen Ort[ENTER]zurückziehen, an dem sie ihre Pferde nicht[ENTER]richtig einsetzen kِnnen: Die Eiswüste. Mit etwas[ENTER]Glück bleibt dann genug Zeit, um weiter zu[ENTER]forschen. Oh, Gott hilf uns... "
gameforge.main_quest_lv50._90_say = "Hmm... Der Angriff begann, noch bevor sie die[ENTER]Schwarze Hexerei ausreichend erforschen konnten.[ENTER]Sie mussten sich in der \"Eiswüste\" verschanzen.[ENTER]Damit kann nur der Berg Sohan gemeint sein, den[ENTER]man heute auch Eisland nennt. Wir sollten dort[ENTER]nach weiteren Spuren suchen. Geh zum Berg Sohan[ENTER]und sieh nach, was du herausfinden kannst. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Du hast die zwِlfte Seite im Gebiet Joan[ENTER]gefunden. Bringe sie zu Uriel im Gebiet Yongan. "
gameforge.main_quest_lv55._10_sendLetter = "Die Suche nach den Denkmنlern "
gameforge.main_quest_lv55._110_say = "Du hast die zwِlfte Seite im Gebiet Yongan[ENTER]gefunden. Bringe sie zu Uriel im Gebiet Pyungmoo. "
gameforge.main_quest_lv55._120_say = "Ich freue mich, dich gesund und munter[ENTER]wiederzusehen. Es tut mir leid, dich so viel[ENTER]umherschicken zu müssen, aber der Erfolg gibt uns[ENTER]recht, findest du nicht auch?[ENTER]Schauen wir mal, was dort steht. Ich hoffe, die[ENTER]Mühe hat sich gelohnt. "
gameforge.main_quest_lv55._130_sayTitle = "Zwِlfte Buchseite: "
gameforge.main_quest_lv55._140_sayReward = "Wir haben die Informanten gefunden und sie haben[ENTER]für unsere Irreführung mit ihrem Leben bezahlt.[ENTER]Doch viel wichtiger ist, dass wir ihnen noch eine[ENTER]letzte Information entreiكen konnten: Nicht die[ENTER]Spinnenhِhlen brauchen wir, sondern den Dunklen[ENTER]Tempel. An diesem Ort haben seit Anbeginn der[ENTER]Zeit die Anhنnger des Alten Glaubens ihre dunklen[ENTER]Rituale vollführt. "
gameforge.main_quest_lv55._145_sayTitle = "Fortsetzung der zwِlften Buchseite: "
gameforge.main_quest_lv55._150_sayReward = "Damit bietet sich uns nun eine weitere Chance,[ENTER]Lee Seop aufzuhalten.[ENTER]Wir müssen zum Dunklen Tempel reisen, um doch[ENTER]noch die Schwarze Hexerei ausführen zu kِnnen.[ENTER]Es sind nur noch wenige von uns übrig und die[ENTER]Strapazen der letzten Monate wiegen schwer. Doch[ENTER]selbst eine müde Handvoll Mنnner kann das[ENTER]Schicksal der Welt نndern, wenn sie solch[ENTER]mنchtige Informationen besitzt.[ENTER]Wir haben unser Ziel vor Augen. Es geht los. "
gameforge.main_quest_lv55._160_say = "Dann haben sie den richtigen Ort also doch noch[ENTER]gefunden. Und ich hatte von Anfang an recht! Es[ENTER]ist tatsنchlich der Hwang-Tempel. Du erinnerst[ENTER]dich sicher an diesen dunklen Ort, der vor bِser[ENTER]Energie schon fast brummt. Seit jeher finden dort[ENTER]Rituale und Zeremonien statt, von denen brave[ENTER]Bürger lieber nichts wissen sollten. "
gameforge.main_quest_lv55._170_say = "Heute bewohnen nur noch Monster den Tempel,[ENTER]Menschen gibt es dort schon lange nicht mehr.[ENTER]Zwar ist es sehr gefنhrlich, aber ich bin sicher,[ENTER]dass du es schaffen kannst. Geh ins Tal von[ENTER]Seungryong und suche im Hwang-Tempel nach der[ENTER]letzten Seite. Die Geschichte, die dieses[ENTER]Tagebuch erzنhlt, hat sich dort vollendet. Ich[ENTER]muss wissen, wie sie ausgeht. Alles Gute![ENTER]Ach, warte kurz, hier ist noch deine Belohnung[ENTER]für die zwِlfte Seite. "
gameforge.main_quest_lv55._180_sayReward = "Du erhنltst 6.500.000 Erfahrungspunkte. "
gameforge.main_quest_lv55._190_sayReward = "Du erhنltst 162.500 Yang. "
gameforge.main_quest_lv55._200_sendLetter = "Die letzte Seite "
gameforge.main_quest_lv55._20_say = "Da ihr bereits mehrere Tagebuchseiten in der[ENTER]Nنhe von Denkmنlern gefunden habt, geht Uriel[ENTER]davon aus, dass sich weitere Informationen über[ENTER]die geheime Schwarze Hexerei in der Nنhe von[ENTER]noch nicht untersuchten Denkmنlern finden[ENTER]lassen. Begib dich in das Reich Chunjo und[ENTER]untersuche dort das Denkmal im Gebiet Joan. "
gameforge.main_quest_lv55._210_sayTitle = "Tِte Buhmنnner im Tempel "
gameforge.main_quest_lv55._220_say = "Du hast bisher zwِlf der dreizehn verloren[ENTER]gegangenen Tagebuchseiten gefunden. Nun stehst du[ENTER]vor dem letzten Schritt.[ENTER]Uriel sagt, im Hwang-Tempel sei die Schwarze[ENTER]Hexerei letztendlich ausgeführt worden. Deshalb[ENTER]solltest du dich dorthin auf den Weg machen und[ENTER]nach Informationen suchen. Beginne deine Suche[ENTER]mit dem Tِten von Buhmنnnern im Tempel. "
gameforge.main_quest_lv55._230_say = "Ich muss tiefer in den Tempel! "
gameforge.main_quest_lv55._240_sendLetter = "Der Dunkle Tempel "
gameforge.main_quest_lv55._250_sayTitle = "Die bِse Energie des Tempels "
gameforge.main_quest_lv55._260_sayReward = "Nachdem du dich eine Weile im Tempel aufgehalten[ENTER]hast, entwickelst du ein Gespür für die[ENTER]Eigenheiten dieses finsteren Ortes:[ENTER]Trنge Schatten flackern in jedem Winkel.[ENTER]Bِse Energie sickert wie ضl aus allen Fugen und[ENTER]Ritzen.[ENTER]Es ist offensichtlich, dass der Tempel selbst die[ENTER]Ursache dafür ist.[ENTER]Hier hat alles begonnen... "
gameforge.main_quest_lv55._270_say = "Dir wird klar, dass die Boshaftigkeit, die hier[ENTER]überall in der Luft liegt, stنrker wird, je[ENTER]weiter du in das Innere des Tempels vordringst.[ENTER]Du solltest versuchen, die Mitte des Tempels zu[ENTER]finden. Dort muss die Dunkelheit ihren Ursprung[ENTER]haben. "
gameforge.main_quest_lv55._280_npcChat = "Das Gum-Denkmal "
gameforge.main_quest_lv55._290_say = "Im Herzen des Tempels steht unscheinbar das Gum[ENTER]Denkmal. Du nنherst dich vorsichtig und findest[ENTER]tatsنchlich die letzte Tagebuchseite. "
gameforge.main_quest_lv55._300_say = "Du hast die letzte Seite des geheimen Tagebuchs[ENTER]im Dunklen Tempel gefunden. Geh zu Uriel und[ENTER]berichte ihm von deinem Fund. "
gameforge.main_quest_lv55._30_say = "Da ihr bereits mehrere Tagebuchseiten in der[ENTER]Nنhe von Denkmنlern gefunden habt, geht Uriel[ENTER]davon aus, dass sich weitere Informationen über[ENTER]die geheime Schwarze Hexerei in der Nنhe von[ENTER]noch nicht untersuchten Denkmنlern finden[ENTER]lassen. Begib dich in das Reich Jinno und[ENTER]untersuche dort das Denkmal im Gebiet Pyungmoo. "
gameforge.main_quest_lv55._310_say = "Da ist sie endlich, die dreizehnte, die letzte[ENTER]Seite! Ich kann dir gar nicht sagen, wie dankbar[ENTER]ich bin, dass du das für mich getan hast.[ENTER]Sieh nur, wie meine Hنnde zittern. Ich wage[ENTER]kaum, die Seite zu lesen, so aufgeregt bin ich.[ENTER]Puh...[ENTER]Na gut, dann wollen wir mal sehen, wie die[ENTER]Geschichte ausging. "
gameforge.main_quest_lv55._320_sayTitle = "Dreizehnte Buchseite: "
gameforge.main_quest_lv55._330_sayReward = "Wir sind endlich angekommen.[ENTER]Nach all den Strapazen folgt nun die groكe[ENTER]Aufgabe: Wir müssen die Zeremonie abhalten und[ENTER]den alten Zauber der Schwarzen Hexerei[ENTER]aktivieren. Ich hoffe nur, wir sind stark genug.[ENTER]Viele von uns schwanken bereits im Stehen, weil[ENTER]sie so erschِpft sind von der langen Reise und[ENTER]der stetigen Flucht vor Lee Seops Kriegern.[ENTER]Dennoch müssen wir es versuchen, oder unser Reich[ENTER]wird untergehen. "
gameforge.main_quest_lv55._335_sayTitle = "Fortsetzung der dreizehnten Buchseite: "
gameforge.main_quest_lv55._340_sayReward = "Sieben Leute sind wir. Wir haben unsere besten[ENTER]Kleider angelegt, auch wenn selbst diese[ENTER]inzwischen wie Lumpen aussehen.[ENTER]Wir werden uns im Kreis aufstellen und uns an den[ENTER]Hنnden fassen, so dass die Kraftlinien[ENTER]geschlossen sind. Dann werden wir den steten[ENTER]Singsang der magischen Worte beginnen und hoffen,[ENTER]dass die Schwarze Hexerei keine weiteren Opfer[ENTER]von uns verlangt.[ENTER]… "
gameforge.main_quest_lv55._350_sayReward = "... Es ist vorbei ...[ENTER]Der Anfang war vielversprechend. Der Raum füllte[ENTER]sich mit Energie und Gesang, aber plِtzlich[ENTER]überkam mich ein seltsames Gefühl. Meine sechs[ENTER]Mitstreiter gingen in die Knie. Der Tempel begann[ENTER]zu beben. Dann gab es einen Lichblitz und wir[ENTER]wurden rückwنrts geschleudert. Die Kraftlinien[ENTER]brachen...[ENTER]Nun ist es still. Meine Kameraden liegen tot am[ENTER]Boden. Der Zauber ist misslungen.[ENTER]Wir haben versagt. "
gameforge.main_quest_lv55._360_say = "Was? Das ist alles?!?[ENTER]Da soll mich doch der Schlag treffen! Die ganze[ENTER]Mühe umsonst? Wir sind gereist, haben gekنmpft,[ENTER]haben stundenlang übersetzt und nachgedacht. Für[ENTER]nichts! Wir sind genauso schlau wie vorher.[ENTER]Na jedenfalls scheint es besser zu sein, wenn wir[ENTER]die Finger von der Schwarzen Hexerei lassen. Habe[ENTER]ich ja von Anfang an vermutet. Aber wissen ist[ENTER]besser als glauben, nicht wahr? "
gameforge.main_quest_lv55._370_say = "Wir machen jetzt erstmal Pause. Ich habe schon[ENTER]Kopfschmerzen und du bist sicher auch recht[ENTER]mitgenommen. Ich muss mir das alles noch einmal[ENTER]durch den Kopf gehen lassen. Wenn ich damit[ENTER]fertig bin, reden wir weiter.[ENTER]Trotz allem hast du mir einen unglaublich[ENTER]wertvollen Dienst erwiesen. Das soll nicht ohne[ENTER]Belohnung bleiben! "
gameforge.main_quest_lv55._380_sayReward = "Du erhنltst 7.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv55._390_sayReward = "Du erhنltst 175.000 Yang. "
gameforge.main_quest_lv55._400_sayReward = "Du erhنltst ein Buch des Anführers. "
