gameforge.main_quest_lv6._10_targetVid = "إذهب إلى حارس المدينة "
gameforge.main_quest_lv6._110_say = "Wer bist du und was willst du hier?[ENTER]Ich bin sehr beschنftigt, also stِre mich nicht.[ENTER]Oh, der Stadtwنchter schickt dich? Ich dachte[ENTER]schon, es würde nie jemand kommen. Es ist keine[ENTER]schwierige Aufgabe und sie wird nicht lange[ENTER]dauern. Genau das Richtige für einen jungen[ENTER]Abenteurer wie dich. "
gameforge.main_quest_lv6._120_say = "Heute sollte ich eine Lieferung des[ENTER]Lagerverwalters erhalten - ich benِtige dringend[ENTER]eine Schweinenase. Bisher warte ich jedoch[ENTER]vergeblich. Kannst du mir helfen und die[ENTER]Schweinenase beschaffen? Es ist wirklich wichtig. "
