gameforge.main_quest_lv6._150_sayReward = "Der Schmied wartet auf eine dringende Lieferung[ENTER]vom Lagerverwalter. Geh zum Lagerverwalter und[ENTER]frage ihn nach der Schweinenase für den Schmied. "
gameforge.main_quest_lv6._160_sayTitle = "أمين المستودع: "
gameforge.main_quest_lv6._170_say = "Willkommen. Ich bin der Lagerverwalter dieses[ENTER]Dorfes. Du kannst meine Dienste in Anspruch[ENTER]nehmen, wenn du nicht dein gesamtes Hab und Gut[ENTER]mit dir herumtragen mِchtest. In meinem[ENTER]Lagerhaus kannst du einen Teil davon aufbewahren. "
gameforge.main_quest_lv6._180_say = "Mِchtest du etwas aufbew... Ah, der Schmied[ENTER]schickt dich wegen der Schweinenase! "
gameforge.main_quest_lv6._190_say = "Ich fürchte, ich werde alt und vergesslich.[ENTER]Früher ist mir so etwas nicht passiert. Hier hast[ENTER]du die Schweinenase. Bringe sie bitte gleich dem[ENTER]Schmied. Wir sehen uns spنter. "
gameforge.main_quest_lv6._200_sendLetter = "Zurück zum Schmied "
gameforge.main_quest_lv6._20_sayReward = "حارس المدينة لديه مهمة جديدة لك[ENTER]اذهب إليه واعرف ماذا يريد. "
gameforge.main_quest_lv6._210_sayReward = "Der Lagerverwalter hatte die Lieferung vِllig[ENTER]vergessen. Nun hat er die Schweinenase dir[ENTER]überreicht. Bringe sie schnell zum Schmied, damit[ENTER]er nicht noch lنnger warten muss. "
gameforge.main_quest_lv6._220_say = "Du bist schneller wieder zurück als ich dachte![ENTER]Diese Schnelligkeit solltest du beibehalten, kann[ENTER]dir in Zukunft sehr nützlich sein. Und jetzt hِr[ENTER]gut zu, ich habe eine wichtige Information für[ENTER]dich. "
gameforge.main_quest_lv6._230_say = "Bist du mit der Veredelung vertraut?[ENTER]Natürlich nicht, du bist ein noch junger[ENTER]Abenteurer! Es geht um Folgendes:[ENTER]Wenn du mir ein Stück deiner Ausrüstung[ENTER]überlنsst, kann ich es für nur wenige Yang so[ENTER]bearbeiten, dass seine Eigenschaften verbessert[ENTER]werden. "
gameforge.main_quest_lv6._240_say = "Die Kunst der Veredelung kann auf[ENTER]unterschiedliche Weisen erfolgen - je hِher das[ENTER]angestrebte Ziel, desto schwieriger die[ENTER]Durchführung. Eine Verbesserung +3 oder darunter[ENTER]benِtigt lediglich einige Yang, für alles[ENTER]Weitere ist ein zusنtzlicher Gegenstand[ENTER]notwendig. So wie die Schweinenase, die du mir[ENTER]gebracht hast. Allerdings kann es stets[ENTER]vorkommen, dass der Gegenstand, den man zu[ENTER]veredeln wünscht, zerstِrt wird - selbst wenn[ENTER]man in diesen Dingen geübt ist, so wie ich.[ENTER]Komm vorbei, wenn es deine Zeit erlaubt. Ich kann[ENTER]dir wunderbare Waffen schmieden! "
