gameforge.main_quest_lv60._210_sayReward = "حصلت على %s. "
gameforge.main_quest_lv60._220_sendLetter = "القوم الظلامي II "
gameforge.main_quest_lv60._230_say = "Laut Uriel gehِrte der Geisterwald früher zum[ENTER]Reich der Dunklen Nation. Vielleicht lassen sich[ENTER]dort weitere Hinweise entdecken.[ENTER]Dieser Wald steckt voller Gefahren. Die[ENTER]Metinsteine machen alle Kreaturen rasend.[ENTER]Finde den Bِsen Baum, um weitere Anhaltspunkte zu[ENTER]erhalten. Sprich Uriel darauf an. "
gameforge.main_quest_lv60._240_say = "Um die Dunkle Nation ranken sich unzنhlige[ENTER]Geheimnisse. Dank dir konnten wir einige lüften,[ENTER]aber uns fehlen noch immer notwendige[ENTER]Informationen. Bitte begib dich auf die Suche[ENTER]nach einem alten Dokument. Es soll sich im[ENTER]Geisterwald nahe des Bergs Sohan befinden. "
gameforge.main_quest_lv60._250_counter = "Verbleibende Seiten: "
gameforge.main_quest_lv60._260_say = "Um die Dunkle Nation ranken sich unzنhlige[ENTER]Geheimnisse. Dank dir konnten wir einige lüften,[ENTER]aber uns fehlen noch immer notwendige[ENTER]Informationen. Bitte begib dich auf die Suche[ENTER]nach einem alten Dokument. Es soll sich im[ENTER]Geisterwald nahe des Bergs Sohan befinden. "
gameforge.main_quest_lv60._270_sayReward = "Du hast den Bِsen Baum besiegt und das Dokument[ENTER]an dich genommen. Es ist in einer[ENTER]fremden Sprache verfasst. Lass es von Uriel[ENTER]übersetzen. "
gameforge.main_quest_lv60._280_say = "Endlich! Du hast das alte Dokument gefunden. Es[ENTER]wird hoffentlich Licht ins Dunkel bringen! "
gameforge.main_quest_lv60._290_say = "Aber was ...?! Da steht ja kaum etwas drin! Das[ENTER]Dokument besteht eigentlich aus zehn Seiten.[ENTER]Bitte geh zurück in den Geisterwald und finde[ENTER]die übrigen neun Seiten. "
gameforge.main_quest_lv60._300_say = "Du musst noch %d Seiten finden. "
gameforge.main_quest_lv60._30_say = "Wie geht es dir? Erinnerst du dich noch an das[ENTER]Tagebuch und die Geschichte, die mit der[ENTER]dreizehnten und letzten Seite abrupt endete? "
gameforge.main_quest_lv60._310_say = "So, nun wollen wir doch mal sehen ...[ENTER]Anscheinend belegte die Dunkle Nation die[ENTER]Hohepriesterin des Drachenkults mit[ENTER]einem Fluch und missbrauchte die heiligen Krنfte[ENTER]der sieben Frauen, um die uralte Kunst der[ENTER]Schwarzen Hexerei auszuüben. "
gameforge.main_quest_lv60._320_say = "Um Sung Mahi zu beschwِren, muss die Schwarze[ENTER]Hexerei zur selben Zeit an sieben verschiedenen[ENTER]Orten durchgeführt werden.[ENTER]Doch Lee Seop und seine Armee haben das Ritual[ENTER]rechtzeitig gestِrt und den unheilvollen Plan der[ENTER]Dunklen Nation vereitelt. "
gameforge.main_quest_lv60._330_say = "Diese Nation war in der Tat furchteinflِكend. Sie[ENTER]war imstande, durch schwarze Magie das[ENTER]menschliche Bewusstsein zu kontrollieren! "
gameforge.main_quest_lv60._340_sendLetter = "Der Hinweis "
gameforge.main_quest_lv60._350_say = "Uriel hat in den alten Schriften Hinweise über[ENTER]das Gum-Denkmal entdeckt. Geh zu ihm, um mehr zu[ENTER]erfahren. "
gameforge.main_quest_lv60._360_say = "Fassen wir mal zusammen, was wir bis jetzt[ENTER]herausgefunden haben:[ENTER]Einst existierte ein Volk, das sich die Dunkle[ENTER]Nation nannte und dem Dنmonengott Sung Mahi[ENTER]diente. Um ihn zu beschwِren, verführte es die[ENTER]sieben Drachenpriesterinnen und missbrauchte die[ENTER]heiligen Krنfte von ihnen für die verbotene[ENTER]Kunst der Schwarzen Hexerei. Diese musste[ENTER]unbedingt an sieben Orten gleichzeitig ausgeführt[ENTER]werden. "
gameforge.main_quest_lv60._370_say = "Die Drachenpriesterinnen haben die Schwarze[ENTER]Hexerei aber nur in einem Turm ausgeführt[ENTER]und nicht an sieben verschiedenen Orten ...[ENTER]Deswegen ist die Beschwِrung Sung Mahis[ENTER]fehlgeschlagen! "
gameforge.main_quest_lv60._380_say = "Die Dunkle Nation muss den sieben[ENTER]Drachenpriesterinnen die falschen Informationen[ENTER]gegeben haben. "
gameforge.main_quest_lv60._390_say = "Vielleicht wussten sie es auch nicht besser ...[ENTER]Es mag ein Zufall sein, aber die alten Schriften[ENTER]erwنhnen diesen Turm im Zusammenhang mit dem[ENTER]Gum-Denkmal. Es scheint sich hierbei um den[ENTER]Dنmonenturm am Hwang-Tempel zu handeln. "
gameforge.main_quest_lv60._400_say = "Wir haben endlich die entscheidende Spur der[ENTER]sieben Drachenpriesterinnen gefunden![ENTER]Ruhe dich kurz aus und lass uns dann darüber[ENTER]sprechen, was wir als Nنchstes unternehmen[ENTER]werden. Denn ich fürchte, dir steht eine Reise[ENTER]zum Dنmonenturm bevor ... "
gameforge.main_quest_lv60._40_say = "Ja, natürlich. Sieben Personen sind vor Lee Seop[ENTER]und seiner Kavallerie in den Hwang-Tempel[ENTER]geflohen und haben dort in letzter Verzweiflung[ENTER]die verbotene Schwarze Hexerei vollzogen ... Am[ENTER]Ende hat das nur eine von ihnen überlebt. "
gameforge.main_quest_lv60._410_sayReward = "Der nنchste Teil dieses Abenteuers erwartet dich,[ENTER]sobald du Level 66 erreicht hast. "
gameforge.main_quest_lv60._50_say = "Richtig. Ich habe weitere Nachforschungen[ENTER]betrieben und herausgefunden, dass diese sieben[ENTER]Personen Mitglieder des heiligen Kults der[ENTER]Drachenpriesterinnen waren. In alten Schriften[ENTER]werden sie in den Zusammenhang mit einem[ENTER]theokratischen Volk, genannt die Dunkle Nation,[ENTER]gebracht.[ENTER]Ob die sieben Drachenpriesterinnen wohl dieser[ENTER]mysteriِsen Nation angehِrten? Hier, lies dir[ENTER]diese Schriftrolle gut durch und sprich mich[ENTER]anschlieكend noch einmal an. "
gameforge.main_quest_lv60._60_sendLetter = "Dunkle Nation I "
gameforge.main_quest_lv60._70_say = "Laut Uriels Nachforschungen stammen die sieben[ENTER]Drachenpriesterinnen aus der Dunklen Nation.[ENTER]Untersuche den alten Grabstein auf dem Berg[ENTER]Sohan. Dort soll sich auch die Hauptstadt der[ENTER]Dunklen Nation befunden haben. Sprich vorher noch[ENTER]einmal mit Uriel. "
gameforge.main_quest_lv60._80_say = "Ihre unglaublich hochentwickelte Hexenkunst und[ENTER]die Tatsache, dass sie laut Tagebuch von Lee[ENTER]Seop vernichtet wurden, deuten darauf hin, dass[ENTER]die sieben Drachenpriesterinnen tatsنchlich der[ENTER]Dunklen Nation angehِrten. "
gameforge.main_quest_lv60._90_say = "In den alten Schriften gibt es eine Karte. Bei[ENTER]genauerer Betrachtung stellt man fest, dass die[ENTER]Hauptstadt der Dunklen Nation sich tatsنchlich[ENTER]auf dem Berg Sohan befunden haben muss. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Unfassbar! Verstehst du, was das bedeutet? Im[ENTER]Dنmonenturm gab es ursprünglich gar keine Dنmonen[ENTER]und Geister. Es ist das Vermنchtnis der[ENTER]Drachenpriesterin. Mit einem verzweifelten[ENTER]letzten Versuch, die Kavallerie Lee Seops[ENTER]zu vernichten, ِffnete sie den Dنmonen durch[ENTER]dieses verfluchte dunkle Ritual das Tor zu[ENTER]unserer Welt. Am Ende bezahlte sie dafür mit[ENTER]ihrem Leben. "
gameforge.main_quest_lv66._10_sendLetter = "Das Tagebuch "
gameforge.main_quest_lv66._110_say = "Auf diesem Weg ist also der Sensenmann und sein[ENTER]dنmonisches Gefolge in unsere Welt gekommen.[ENTER]Dennoch scheiterte die groكe Mission der Dunklen[ENTER]Nation und der Drachenpriesterinnen: Die[ENTER]Beschwِrung Sung Mahis schlug fehl, Lee Seop[ENTER]hingegen gewann an Macht und schuf letztendlich[ENTER]ein vereintes Weltreich.[ENTER]Dank deiner Hilfe konnte ich endlich das grِكte[ENTER]Mysterium meines Lebens lِsen! "
gameforge.main_quest_lv66._120_say = "Als Belohnung mِchte ich dir eine[ENTER]Segensschriftrolle geben. Bitte nimm mein[ENTER]Geschenk an, ich bestehe darauf! "
gameforge.main_quest_lv66._130_sendLetter = "Du hast Post. "
gameforge.main_quest_lv66._140_say = "Der Wنchter des Dorfplatzes hat einen Brief für[ENTER]dich. Lies ihn und finde heraus, wer der[ENTER]geheimnisvolle Absender ist. "
gameforge.main_quest_lv66._150_say = "Du hast dich in letzter Zeit ziemlich rar[ENTER]gemacht, was? Ich soll dir diesen Brief hier[ENTER]geben - keine Ahnung, von wem der ist, er hat[ENTER]sich mir nicht vorgestellt. "
gameforge.main_quest_lv66._160_say = "Das Papier, auf dem der Brief verfasst wurde,[ENTER]scheint sehr alt zu sein. In hastigen Worten[ENTER]steht darauf geschrieben:[ENTER]Habe wichtige Informationen zu den sieben[ENTER]Drachenpriesterinnen und Sung Mahi. Warte auf der[ENTER]Rückseite des Dنmonenturms im Hwang-Tempel auf[ENTER]dich. Du findest mich im Schatten des Baumes.[ENTER]Beeil dich, die Zeit drنngt! "
gameforge.main_quest_lv66._170_sendLetter = "Anonymer Brief "
gameforge.main_quest_lv66._180 = "Gehe zum Hwang-Tempel und triff dort auf der[ENTER]Rückseite des Dنmonenturms den geheimnisvollen[ENTER]Briefschreiber. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Ich heiكe dich willkommen! Wenn ich mich zuerst[ENTER]einmal vorstellen darf: Mein Name ist Lee Chung.[ENTER]Es ist sehr mutig von dir, den Anweisungen eines[ENTER]Unbekannten zu folgen. Ich habe mich nicht in dir[ENTER]getنuscht - und du wirst es auch nicht bereuen.[ENTER]Hِr, was ich zu sagen habe! "
gameforge.main_quest_lv66._20_say = "Uriel hat Neuigkeiten über die letzte ـberlebende[ENTER]der Drachenpriesterinnen. Ihr Tagebuch muss sich[ENTER]im Dنmonenturm befinden. Geh zu Uriel, um mehr[ENTER]darüber zu erfahren. "
gameforge.main_quest_lv66._210_sendLetter = "Neues ـbel "
gameforge.main_quest_lv66._220_say = "Hِre dir an, was Lee Chung zu berichten hat. "
gameforge.main_quest_lv66._230_say = "Es gibt einen Grund, warum du zum Hwang-Tempel[ENTER]kommen solltest: In letzter Zeit ereignen sich[ENTER]hier seltsame Dinge. Und vor Kurzem haben wir auf[ENTER]der Rückseite des Dنmonenturms den Zugang zu[ENTER]einer riesigen Hِhle entdeckt! "
gameforge.main_quest_lv66._240_say = "Eine riesige Hِhle? Und was befindet sich darin? "
gameforge.main_quest_lv66._250_say = "In dieser Hِhle erwartet uns ein weiteres,[ENTER]unvorstellbares ـbel: Unsere Spنher haben von[ENTER]einem grauenhaften Wesen berichtet, das selbst[ENTER]Dنmonen in den Schatten stellt.[ENTER]Seine erschreckende Erscheinung und die[ENTER]unstillbare Gier nach Leben lassen uns vermuten,[ENTER]dass es sich hierbei um den legendنren Agwi[ENTER]handelt - einer der zehn groكen Teufel der[ENTER]Dنmonenwelt.[ENTER]Wenn wir Recht behalten, droht der Menschheit[ENTER]groكe Gefahr. "
gameforge.main_quest_lv66._260_say = "Furchteinflِكender als Dنmonen ... Dieses Wesen[ENTER]muss wahrhaft mنchtig und bِsartig sein. "
gameforge.main_quest_lv66._270_say = "So ist es. Meine Mنnner und ich haben mehrfach[ENTER]versucht, die Devil's Catacomb zu stürmen. Doch[ENTER]wir haben jedes Mal versagt und groكe Verluste[ENTER]davon getragen.[ENTER]In dieser Angelegenheit benِtigen wir die[ENTER]Unterstützung eines herausragenden Kنmpfers -[ENTER]deswegen haben wir dich hierher gerufen. Wirst du[ENTER]uns helfen? "
gameforge.main_quest_lv66._280_say = "Ja, ich werde dir helfen. "
gameforge.main_quest_lv66._290_say = "Oh, das gibt uns neue Hoffnung![ENTER]Nun, da ich weiك, dass du auf unserer Seite[ENTER]stehst, werde ich dir die ganze Wahrheit[ENTER]verraten: Ich, Lee Chung, bin Kommandant der[ENTER]Schattenkrieger. Wir sind eine geheime[ENTER]Elite-Einheit der Armee Lee Seops. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, schِn, dich gesund und wohlbehalten[ENTER]wiederzusehen. Bist du bereit für ein neues[ENTER]Abenteuer? Uns fehlen noch immer wichtige[ENTER]Informationen zur Dunklen Nation[ENTER]und den sieben Drachenpriesterinnen. Die letzte[ENTER]Drachenpriesterin muss ihr Tagebuch im[ENTER]Dنmonenturm verborgen haben, bevor sie die[ENTER]Schwarze Hexerei ausführte. Ziehe los und bringe[ENTER]mir das Tagebuch. Der Dنmonenkِnig kِnnte es in[ENTER]seinen Fنngen haben. "
gameforge.main_quest_lv66._310_say = "Die Schattenkrieger verfolgen seit je her im[ENTER]Geheimen das Ziel, die Wiederauferstehung Sung[ENTER]Mahis zu verhindern. Das ist unsere Mission.[ENTER]Lass uns nun gemeinsam versuchen, den Agwi wieder[ENTER]zurück in seine Hِlle zu befِrdern, und[ENTER]herausfinden, wie er in unsere Welt gelangen[ENTER]konnte! "
gameforge.main_quest_lv66._320_sendLetter = "Keine Zeit "
gameforge.main_quest_lv66._330_say = "Lee Chung, der Kommandant der Schattenkrieger,[ENTER]sucht nach dir. Es ist sehr dringend! "
gameforge.main_quest_lv66._340_say = "Ich habe eine dringende Bitte. Siehst du dort[ENTER]drüben den verletzten Soldaten?[ENTER]Das ist einer meiner Spنher, der in meinem[ENTER]Auftrag die Devil's Catacomb erkundet hat. Dabei[ENTER]wurde er vom Agwi angegriffen und vergiftet.[ENTER]Das Gift breitet sich bereits in seinem Kِrper[ENTER]aus und ihm bleibt nicht mehr viel Zeit. "
gameforge.main_quest_lv66._350_say = "Er braucht ein Gegengift - und zwar so schnell[ENTER]wie mِglich![ENTER]Kِnntest du es holen? Du findest es im Roten[ENTER]Wald bei den Roten Dryaden.[ENTER]Er ist einer meiner wichtigsten Kنmpfer - rette[ENTER]sein Leben und ich werde dir %s geben. "
gameforge.main_quest_lv66._360_say = "Ich werde das Gegengift holen! "
gameforge.main_quest_lv66._370_say = "Ich danke dir! Noch ist er am Leben, aber er wird[ENTER]von Minute zu Minute schwنcher. Wir haben[ENTER]keine Zeit zu verlieren! "
gameforge.main_quest_lv66._380_notice = "Dir bleiben noch %d Minuten. "
gameforge.main_quest_lv66._390_sendLetter = "Das Gegengift "
gameforge.main_quest_lv66._400_say = "Von Lee Chung weiكt du, dass du das Gegengift[ENTER]im Roten Wald findest. Fange dafür %d Rote[ENTER]Dryaden.[ENTER]Im Roten Wald drohen noch grِكere Gefahren[ENTER]als im Geisterwald, also sieh dich vor. "
gameforge.main_quest_lv66._40_say = "Du hast den Dنmonenkِnig besiegt und das Tagebuch[ENTER]der Drachenpriesterin erhalten. Bringe es zum[ENTER]Gelehrten Uriel. Er wird es durchsehen. "
gameforge.main_quest_lv66._410_say = "Die Zeit ist abgelaufen. Der Soldat liegt im[ENTER]Sterben, also bringe ihm schnellstmِglich das[ENTER]Gegengift. "
gameforge.main_quest_lv66._420_say = "Dir bleiben noch %d Minuten. "
gameforge.main_quest_lv66._430_say = "Du hast endlich das Gegengift gefunden! Bringe[ENTER]es schnell zu Lee Chung. "
gameforge.main_quest_lv66._440_say = "Hierher, schnell! Ich glaube, du bist gerade noch[ENTER]rechtzeitig gekommen. Mir fنllt ein Stein vom[ENTER]Herzen. Meine Mنnner und ich sind dir unendlich[ENTER]dankbar. "
gameforge.main_quest_lv66._450_say = "Dank deiner Hilfe hat mein Soldat überlebt. Hier[ENTER]ist deine Belohnung für seine Rettung. "
gameforge.main_quest_lv66._460_say = "Du hast sehr lange gebraucht. Er klammert sich[ENTER]nur noch mit letzter Kraft an sein Leben.[ENTER]Zum Glück bist du gerade noch rechtzeitig[ENTER]gekommen. "
gameforge.main_quest_lv66._470_say = "Er scheint durchzukommen. Doch es war sehr[ENTER]knapp und er wنre fast gestorben, weil du so[ENTER]lange gebraucht hast, um das Gegengift zu[ENTER]finden.[ENTER]Es tut mir leid, aber das hier ist alles, was ich[ENTER]dir als Belohnung geben kann. "
gameforge.main_quest_lv66._480_sendLetter = "Der Bericht "
gameforge.main_quest_lv66._490_say = "Der Spنher ist wieder bei Bewusstsein.[ENTER]Hِr dir an, was er in der Devil's Catacomb[ENTER]beobachtet hat. "
gameforge.main_quest_lv66._500_say = "Danke, dass du mich gerettet hast. Ich habe[ENTER]Unglaubliches in der Devil's Catacomb[ENTER]beobachten kِnnen. Aber dann wurde ich[ENTER]entdeckt und ... "
gameforge.main_quest_lv66._50_say = "Du hast es gefunden! Das Tagebuch der letzten[ENTER]Drachenpriesterin. Meine Hنnde sind ganz zittrig[ENTER]vor Aufregung.[ENTER]Ich werde etwas Zeit benِtigen, um ihre[ENTER]Aufzeichnungen durchzusehen. Ruhe dich inzwischen[ENTER]aus. Ich werde dich zu mir rufen, wenn ich dir[ENTER]mehr sagen kann. "
gameforge.main_quest_lv66._510_say = "Was hast du gesehen? "
gameforge.main_quest_lv66._520_say = "Da waren Leute in schwarzen Umhنngen mit[ENTER]Kapuzen, tief ins Gesicht gezogen.[ENTER]Ihren Gesprنchsfetzen konnte ich entnehmen, dass[ENTER]es sich bei dieser Gruppe um die Diener der[ENTER]Dunkelheit handelt. Doch das ist noch nicht[ENTER]alles:[ENTER]Ein grنsslicher Geist, der einer Frauengestalt[ENTER]glich, schwebte über ihren Kِpfen. Die Diener[ENTER]der Dunkelheit nannten sie Banshee. "
gameforge.main_quest_lv66._530_say = "Das klingt nicht gut. Was haben die Diener der[ENTER]Dunkelheit und diese Banshee vor? "
gameforge.main_quest_lv66._540_say = "Die Banshee beschwor durch einen schwarzen[ENTER]Zauber die Agwi, teuflische Wesen,[ENTER]die direkt aus dem Hِllenschlund kommen. Den[ENTER]Kِnig der Agwi rief sie Azrael. "
gameforge.main_quest_lv66._550_say = "Ich eilte sofort los, um Lee Chung davon zu[ENTER]berichten. Doch ich stolperte und wurde entdeckt.[ENTER]Ah, da fنllt mir ein, dass Kommandant Lee[ENTER]Chung dir noch etwas Wichtiges mitteilen[ENTER]mِchte. Gehe am besten gleich zu ihm. "
gameforge.main_quest_lv66._560_sendLetter = "Dunkle Bedrohung "
gameforge.main_quest_lv66._570_say = "Geh zu Lee Chung. Sprich mit ihm über die neue[ENTER]Bedrohung, die in der Devil's Catacomb lauert. "
gameforge.main_quest_lv66._580_say = "Was mein Spنher berichtet hat, ist[ENTER]erschreckend. Die Diener der[ENTER]Dunkelheit, eine Art Sekte, sind verantwortlich[ENTER]für das Erscheinen der Agwi. Und sie haben den[ENTER]Geist der letzten Drachenpriesterin erweckt.[ENTER]Als Banshee, eine Manifestation des Bِsen,[ENTER]kehrte sie in diese Welt zurück und mithilfe[ENTER]ihrer magischen Krنfte soll nun der Dنmonengott[ENTER]Sung Mahi beschworen werden. "
gameforge.main_quest_lv66._590_say = "Was? Diese Banshee ist der Geist der letzten[ENTER]Drachenpriesterin? "
gameforge.main_quest_lv66._600_say = "Zweifellos. Selbst unter ihren Schwestern des[ENTER]Drachenkults besaك sie als Einzige die Macht, die[ENTER]heiligen vier Wنchter des Himmels anzurufen und[ENTER]die Schwarze Hexerei durchzuführen.[ENTER]Nun wissen wir, wer hinter der neuen Bedrohung[ENTER]steckt: Die Diener der Dunkelheit und die Banshee[ENTER]planen, das grauenvolle Werk der Dunklen Nation[ENTER]zu vollenden und Sung Mahi zu erwecken! "
gameforge.main_quest_lv66._60_sendLetter = "Des Rنtsels Lِsung "
gameforge.main_quest_lv66._610_say = "Wir haben dir viel zu verdanken: Du hast einen[ENTER]meiner besten Mنnner vor dem sicheren Tod bewahrt[ENTER]und nur so konnten wir alles über das plِtzliche[ENTER]Erscheinen der Agwi und die neue Bedrohung in der[ENTER]Devil's Catacomb erfahren.[ENTER]Nun ruhe dich erst einmal aus - und dann denken[ENTER]wir über eine geeignete Taktik nach. "
gameforge.main_quest_lv66._620_say = "Das Abenteuer geht weiter, sobald du Level 72[ENTER]erreicht hast. "
gameforge.main_quest_lv66._70_say = "Uriel sucht nach dir. Er hat das Tagebuch nun[ENTER]gelesen. "
gameforge.main_quest_lv66._80_say = "Ah, sehr schِn! Da bist du ja.[ENTER]Die Aufzeichnungen der letzten Drachenpriesterin[ENTER]sind in der Tat erstaunlich. Hِr gut zu: "
gameforge.main_quest_lv66._90_say = "Mein Schicksal ist besiegelt! Ich habe mich im[ENTER]obersten Stock dieses Turms verbarrikadiert und[ENTER]die Mنnner Lee Seops stehen kurz davor, die Tür[ENTER]zu meinem letzten Gefنngnis zu durchbrechen. Es[ENTER]gibt keinen Ausweg... Ich habe verloren.[ENTER]Nein, so darf es nicht enden! Es kann nicht alles[ENTER]vergebens gewesen sein. Ich muss die Schwarze[ENTER]Hexerei, diese uralte Kraft des Bِsen, alleine[ENTER]beschwِren und die dunklen Mنchte[ENTER]herbeirufen.[ENTER]Das wird meinen sicheren Tod bedeuten. Doch meine[ENTER]Feinde werde ich mit mir ins Verderben reiكen -[ENTER]und wenn es das Letzte ist, was ich tue! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Du hast sie noch nicht abgeliefert? Die Angelrute[ENTER]ist für den Fischer unten am Fluss. Beeile dich,[ENTER]er benِtigt sie dringend! "
gameforge.main_quest_lv7._10_targetVid = "Ein weiterer Gefallen "
gameforge.main_quest_lv7._110_npcChat = "Der Schmied sendet diese neue Angelrute! "
gameforge.main_quest_lv7._120_say = "Ich danke dir. Nun kann ich endlich meine zwar[ENTER]treue, aber schon recht abgenutzte alte Angel[ENTER]ausmustern.[ENTER]Mit dem Angeln verdiene ich nicht nur meinen[ENTER]Lebensunterhalt, sondern es ist für mich auch[ENTER]eine der grِكten Freuden des Tages![ENTER]Bist du mit der Angelkunst vertraut? "
gameforge.main_quest_lv7._130_say = "Nimm zuerst die Angel in die Hand, dann verwende[ENTER]einen Kِder, indem du ihn anklickst. Wirf die[ENTER]Angel dadurch aus, dass du die Fertigkeit Fischen[ENTER]benutzt. Wenn du denkst, dass ein Fisch[ENTER]angebissen haben kِnnte, nutze die Fertigkeit[ENTER]erneut. Falls du dich geirrt hast, versuche es[ENTER]einfach noch einmal. Diese Gewنsser sind aufgrund[ENTER]ihrer Artenvielfalt sehr gut zu befischen. Zudem[ENTER]ist Fisch nicht nur nahrhaft und gesund, sondern[ENTER]kann auch wertvolle Schنtze mit sich bringen.[ENTER]Versuch es ruhig einmal. "
gameforge.main_quest_lv7._140_say = "Ach ja, hier ist der Beleg für den Erhalt der[ENTER]Angel. Bitte überreiche sie dem Schmied, wenn du[ENTER]in die Stadt zurückkehrst. "
gameforge.main_quest_lv7._150_sayItem = "Lieferschein für die Angelrute "
gameforge.main_quest_lv7._160_sayReward = "Du hast dem Fischer die Angelrute überbracht.[ENTER]Kehre nun mit dem Beleg zum Schmied zurück[ENTER]und nimm deine Belohnung entgegen. "
gameforge.main_quest_lv7._170_say = "Hast du den Fischer gefunden?[ENTER]Wunderbar. Du hast mir mit diesem Botengang viel[ENTER]Zeit gespart. Als Dank gebe ich dir einige Yang[ENTER]als Belohnung. "
gameforge.main_quest_lv7._180_sendLetter = "Wertschein "
gameforge.main_quest_lv7._190_sayReward = "Mit diesem Schreiben bekommst du vom Schmied[ENTER]ein Stück deiner Ausrüstung kostenlos veredelt.[ENTER]Ziehe dazu einfach das entsprechende Stück auf[ENTER]den Schmied, um das Veredelungsfenster zu[ENTER]ِffnen. "
gameforge.main_quest_lv7._200_sayItem = "Wertschein für das kostenlose Veredeln eines[ENTER]Gegenstands "
gameforge.main_quest_lv7._20_sayReward = "Begib dich bitte zum Schmied. Er sucht jemanden,[ENTER]der einen Botengang für ihn erledigen kann. "
