gameforge.main_quest_lv7._30_say = "Sei gegrüكt, Abenteurer! Kِnntest du mir noch[ENTER]einmal einen Gefallen erweisen? Normalerweise[ENTER]bitte ich andere Leute nicht oft um solche, aber[ENTER]du scheinst mir vertrauenswürdig zu sein.[ENTER]Betrachte es als Ehre! "
gameforge.main_quest_lv7._40_say = "Ich habe eine Angelrute für den Fischer[ENTER]gefertigt. Leider habe ich am heutigen Tag zu[ENTER]viele Anfragen zu bearbeiten und kann sie ihm[ENTER]daher nicht persِnlich bringen. Kannst du das für[ENTER]mich erledigen? "
