gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "Durch die magische Verbindung von Geweihtem[ENTER]Baumharz, Blauer Kristallessenz und Rotem[ENTER]Hِllenquarz erhنlt die Trنne des Himmels ihre[ENTER]vollkommene Brillanz.[ENTER]Die Blaue Kristallessenz muss vom Herrscher des[ENTER]Eislandes besorgt werden. "
gameforge.main_quest_lv72._10_sendLetter = "Verwitterte Steintafel "
gameforge.main_quest_lv72._110_say = "Du hast dir eine Notiz von dieser bemerkenswerten[ENTER]Inschrift gemacht.[ENTER]Erstatte Lee Chung sofort Bericht über[ENTER]das, was du soeben gelesen hast. "
gameforge.main_quest_lv72._120_say = "Du bist wohlbehalten zurückgekehrt! Wenn ich[ENTER]deinen Gesichtsausdruck richtig deute, hattest du[ENTER]Erfolg. "
gameforge.main_quest_lv72._130_say = "Ja, allerdings! Durch die Inschrift auf der[ENTER]verwitterten Steintafel habe ich herausgefunden,[ENTER]dass man die Heiligen Mنchte durch einen[ENTER]magischen Edelstein, genannt die Trنne des[ENTER]Himmels, beschwِren kann. "
gameforge.main_quest_lv72._140_say = "Die Trنne des Himmels ... Es gibt sie also[ENTER]wirklich. Hast du Hinweise finden kِnnen, wie man[ENTER]sie erhalten kann? "
gameforge.main_quest_lv72._150_say = "Um die Trنne des Himmels herzustellen, benِtigt[ENTER]man Geweihtes Baumharz, Blaue Kristallessenz und[ENTER]Roten Hِllenquarz. Blaue Kristallessenz, so stand[ENTER]es geschrieben, erhنlt man vom Herrscher des[ENTER]Eislandes. "
gameforge.main_quest_lv72._160_say = "Der Herrscher des Eislandes? Hmm ... Damit wird[ENTER]Berg Sohan gemeint sein.[ENTER]Ich werde deine Notizen sofort den Magiern[ENTER]der Schattenkrieger zeigen und diese mit ihnen[ENTER]gemeinsam auswerten.[ENTER]Ich gebe dir Bescheid, sobald ich mehr weiك! "
gameforge.main_quest_lv72._170_say = "Nimm dies als Belohnung für deine Taten. Ich[ENTER]zنhle auch weiterhin auf deine Hilfe! "
gameforge.main_quest_lv72._180_sendLetter = "Eisiger Schatz "
gameforge.main_quest_lv72._190_say = "Kommandant Lee Chung hat dir mitgeteilt,[ENTER]dass es sich beim ersten Element für die[ENTER]Trنne des Himmels, der Blauen Kristallessenz,[ENTER]um den legendنren Schatz des Neunschwanzes[ENTER]auf dem Berg Sohan handelt.[ENTER]Er wird mit Argusaugen von Eisgolems, Yetis und[ENTER]Frostigen Eismنnnern bewacht. Jage diese Monster,[ENTER]um in den Besitz der Blauen Kristallessenz zu[ENTER]gelangen.[ENTER]Sprich noch einmal mit Lee Chung, bevor du[ENTER]dich in den Kampf stürzt. "
gameforge.main_quest_lv72._200_say = "Die Magier der Schattenkrieger haben[ENTER]herausgefunden, dass der gefürchtete Neunschwanz[ENTER]vom Berg Sohan die Blaue Essenz hütet wie seinen[ENTER]Augapfel. "
gameforge.main_quest_lv72._20_say = "Lee Chung, der Kommandant der Schattenkrieger,[ENTER]mِchte mit dir sprechen. Er hat herausgefunden,[ENTER]wie man die Agwi in der Devil's Catacomb[ENTER]besiegen kann. "
gameforge.main_quest_lv72._210_say = "Der Schatz des Neunschwanzes wird von Eisgolems,[ENTER]Yetis und Frostigen Eismنnnern bewacht.[ENTER]50 Blaue Kristallessenzen werden zur Herstellung[ENTER]der Trنne des Himmels benِtigt. "
gameforge.main_quest_lv72._220_say = "Roter Hِllenquarz wird entweder im[ENTER]Hwang-Tempel oder im Feuerland vermutet.[ENTER]Ich habe einen Spنher ausgesandt, um[ENTER]Genaueres herauszufinden. "
gameforge.main_quest_lv72._230 = "Kommandant Lee Chung hat dir mitgeteilt,[ENTER]dass es sich beim ersten Element für die[ENTER]Trنne des Himmels, der Blauen Kristallessenz,[ENTER]um den legendنren Schatz des Neunschwanzes[ENTER]auf dem Berg Sohan handelt.[ENTER]Er wird mit Argusaugen von Eisgolems, Yetis und[ENTER]Frostigen Eismنnnern bewacht. Jage diese Monster,[ENTER]um in den Besitz der Blauen Kristallessenz zu[ENTER]gelangen. "
gameforge.main_quest_lv72._240_notice = "Du durchsuchst den Kadaver des besiegten Monsters[ENTER]und findest einen blau schimmernden Edelstein.[ENTER]Das muss die Blaue Kristallessenz sein. "
gameforge.main_quest_lv72._250_notice = "Du musst noch %d Blaue Kristallessenz(en) suchen. "
gameforge.main_quest_lv72._260_say = "Für heute hast du genügend Ratschlنge erhalten.[ENTER]Komm morgen wieder. "
gameforge.main_quest_lv72._270_say = "Diese Kristalle sind nutzlos. Hier, sieh selbst:[ENTER]Sie haben Risse. Um sie verwenden zu kِnnen,[ENTER]müssen sie makellos sein. Suche weiter! "
gameforge.main_quest_lv72._280_say = "Diese sind von hervorragender Qualitنt.[ENTER]Weiter so! Bringe mir noch %d Stück. "
gameforge.main_quest_lv72._290_say = "Du hast alle Blauen Kristallessenzen gesammelt.[ENTER]Ich kann die Macht des Neunschwanzes, die darin[ENTER]steckt, spüren. Unglaublich ... Sie vibrieren[ENTER]fِrmlich vor Energie. Gut gemacht! "
gameforge.main_quest_lv72._300_say = "Das Abenteuer geht weiter, sobald du Level 78[ENTER]erreicht hast. "
gameforge.main_quest_lv72._30_say = "Anders als gewِhnliche Dنmonen kann man die Agwi[ENTER]nicht so einfach tِten. Wir Schattenkrieger haben[ENTER]bereits alles Erdenkliche versucht - doch stets[ENTER]ohne Erfolg. "
gameforge.main_quest_lv72._40_say = "Doch nun habe ich herausgefunden, dass die[ENTER]Drachenpriesterinnen die Fنhigkeit besaكen,[ENTER]die Heiligen Mنchte zu beschwِren, um bِse[ENTER]Geister zu vertreiben. "
gameforge.main_quest_lv72._50_say = "Im Roten Wald befand sich einst der geweihte[ENTER]Tempel der Drachenpriesterinnen. Suche dort nach[ENTER]Ruinen und alten Zeugnissen ihres Kults. Spنher[ENTER]haben von einer verwitterten Steintafel[ENTER]berichtet, die vom Unterholz überwuchert wurde[ENTER]... Vielleicht finden wir darauf weitere[ENTER]Hinweise. "
gameforge.main_quest_lv72._60_sendLetter = "Die Entdeckung "
gameforge.main_quest_lv72._70_say = "Von Lee Chung weiكt du, dass die[ENTER]Drachenpriesterinnen die Heiligen Mنchte, einen[ENTER]uralten weiكen Zauber, beschwِren konnten,[ENTER]um bِse Geister zu vertreiben.[ENTER]Suche im Roten Wald nach der verwitterten[ENTER]Steintafel, von der Lee Chung sprach, und[ENTER]erhalte weitere Hinweise. "
gameforge.main_quest_lv72._80_say = "Nach langer Suche stِكt du im Unterholz auf eine[ENTER]Steintafel, die schon seit Jahrhunderten hier zu[ENTER]liegen scheint. Das muss die alte Tafel sein, von[ENTER]der Lee Chung gesprochen hat![ENTER]Mühsam entzifferst du die verwitterte Inschrift. "
gameforge.main_quest_lv72._90_say = "Die Trنne des Himmels ist das wertvollste[ENTER]Geheimnis der Drachenpriesterinnen. Die Kunst[ENTER]ihrer Herstellung wird seit Generationen[ENTER]streng gehütet und notfalls mit Blut verteidigt.[ENTER]Dem Trنger dieses magischen Edelsteines kِnnen[ENTER]sich Agwi und Dنmonen nicht ohne Weiteres[ENTER]nنhern. Ist die Trنne des Himmels erst einmal[ENTER]erfüllt von der Kraft der Heiligen Mنchte, ist[ENTER]ihre Wirkung einfach überwنltigend. Sieben[ENTER]Sonnenscheiben lang strahlt sie hell wie der[ENTER]Polarstern am Firmament. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Ah, phantastisch! Es hat geklappt. Hier hast du[ENTER]den Roten Hِllenquarz. "
gameforge.main_quest_lv78._10_sendLetter = "Roter Hِllenquarz "
gameforge.main_quest_lv78._110_sendLetter = "Letztes Element "
gameforge.main_quest_lv78._120_say = "Lee Chung und der Rat der Magier haben[ENTER]entdeckt, dass man das letzte Element, das[ENTER]Geweihte Baumharz, aus Roten Bِsen Bنumen[ENTER]gewinnt. Gehe auf die Jagd nach Roten Bِsen[ENTER]Bنumen im Roten Wald und sammle 100 Portionen des[ENTER]Geweihten Baumharzes.[ENTER]Sprich vorher unbedingt noch einmal mit Lee[ENTER]Chung. "
gameforge.main_quest_lv78._130_say = "Lee Chung und der Rat der Magier haben[ENTER]entdeckt, dass man das letzte Element, das[ENTER]Geweihte Baumharz, aus Roten Bِsen Bنumen[ENTER]gewinnt. Gehe auf die Jagd nach Roten Bِsen[ENTER]Bنumen im Roten Wald und sammle 100 Portionen[ENTER]des Geweihten Baumharzes. "
gameforge.main_quest_lv78._140_say = "Das ist der letzte Schritt für die Herstellung[ENTER]der Trنne des Himmels. Pass gut auf dich auf, im[ENTER]Roten Wald wimmelt es vor todbringenden[ENTER]Kreaturen! "
gameforge.main_quest_lv78._150_say = "Du musst noch %d Portion(en) des Geweihten[ENTER]Baumharzes sammeln. "
gameforge.main_quest_lv78._160_notice = "Du hast genug Geweihtes Baumharz gefunden! Bring[ENTER]es zu Kommandant Lee Chung. "
gameforge.main_quest_lv78._170_say = "Ist dies das Geweihte Baumharz? Ich kann seine[ENTER]enorme Kraft spüren. Sagenhaft![ENTER]Leider musste ich sنmtliche Magier auf eine[ENTER]Mission schicken. Sie werden eine Weile weg sein.[ENTER]Gibt es in deinem Heimatdorf nicht einen[ENTER]Apotheker namens Baek-Go? "
gameforge.main_quest_lv78._180_say = "Ja, den gibt es tatsنchlich. "
gameforge.main_quest_lv78._190_say = "Ah, das trifft sich gut! Nimm die drei Elemente[ENTER]und bringe sie zu Baek-Go. Er wird die Trنne des[ENTER]Himmels daraus fertigen kِnnen. "
gameforge.main_quest_lv78._200_say = "Du hast eine anstrengende Reise hinter dir. Bitte[ENTER]nimm diese Belohnung für all deine Mühen[ENTER]entgegen. "
gameforge.main_quest_lv78._20_say = "Lee Chung, Kommandant der Schattenkrieger, hat[ENTER]mehr über den Roten Hِllenquarz herausgefunden.[ENTER]Um es herzustellen, benِtigt man drei[ENTER]verschiedene Substanzen: Vulkanerde des[ENTER]Doyyumhwan, eine Flammenmنhne und einen[ENTER]Fundamentstein. Jage Flammen, Flammenkrieger und[ENTER]Kampftiger im Feuerland, um an diese Substanzen[ENTER]zu kommen und lasse sie anschlieكend zu 20 Stück[ENTER]des Roten Hِllenquarzes formen.[ENTER]Bevor du in den Kampf ziehst, suche Lee Chung[ENTER]auf. "
gameforge.main_quest_lv78._210_sendLetter = "Trنne des Himmels "
gameforge.main_quest_lv78._220_say = "Kehre zurück in dein Heimatdorf, suche dort[ENTER]Baek-Go auf und bitte ihn im Namen Lee Chungs,[ENTER]die Trنne des Himmels aus den drei Elementen zu[ENTER]fertigen. "
gameforge.main_quest_lv78._230_say = "Du warst lange fort. Ich habe mich schon gefragt,[ENTER]ob dir etwas passiert ist. Was führt dich zu[ENTER]mir? "
gameforge.main_quest_lv78._240_say = "Lee Chung hat mich beauftragt, dich um einen[ENTER]Gefallen zu bitten. "
gameforge.main_quest_lv78._250_say = "Lee Chung?! Der Kommandant der Schattenkrie...[ENTER]oh, shhhh! Leise! Vor dir steht ein Magier der[ENTER]Schattenkrieger. Doch das ist streng geheim und[ENTER]keiner im Dorf darf davon erfahren.[ENTER]Um welchen Gefallen mِchte Lee Chung mich bitten? "
gameforge.main_quest_lv78._260_say = "Er mِchte, dass du aus diesen drei Elementen die[ENTER]Trنne des Himmels fertigst. "
gameforge.main_quest_lv78._270_say = "Die Trنne des Himmels, soso ... Er hat so viele[ENTER]Magier unter sich. Warum überlنsst er aber immer[ENTER]mir die schwierigen Aufgaben?[ENTER]...[ENTER]Na, also. Da hنtten wir sie - die Trنne des[ENTER]Himmels. Wunderschِn! Ich werde sie mit einem[ENTER]Boten direkt zu Lee Chung schicken und er wird[ENTER]nach dir rufen, wenn alles bereit ist.[ENTER]Verrنtst du mir, wozu sie dient? "
gameforge.main_quest_lv78._280_say = "Ich kann dir leider nichts Genaueres erzنhlen.[ENTER]Nur so viel: Dieser Stein ruft die Heiligen[ENTER]Mنchte herbei, um Dنmonen und andere bِse[ENTER]Wesen zu vertreiben. "
gameforge.main_quest_lv78._290_say = "Sehr interessant. Ich wünsche dir viel Erfolg bei[ENTER]deiner Aufgabe. Als Belohnung für deine Taten[ENTER]bekommst du zwei Schrumpfkِpfe.[ENTER]Nun, da ich weiك, wie es geht, stehe ich dir[ENTER]gerne zu Diensten, sobald du eine weitere Trنne[ENTER]des Himmels brauchst.[ENTER]Ach, und würdest du Lee Chung bitte meine besten[ENTER]Grüكe ausrichten? "
gameforge.main_quest_lv78._300_say = "Das Abenteuer geht weiter, sobald du Level 84[ENTER]erreicht hast. "
gameforge.main_quest_lv78._30_say = "Unsere Magier haben herausgefunden, dass[ENTER]Roter Hِllenquarz, welcher der Herstellung der[ENTER]Trنne des Himmels dient, die Mنchte des Feuers[ENTER]in sich trنgt. Dieser Quarz muss auch die[ENTER]Ursache für die unglaublichen Krنfte der[ENTER]Feuerland-Kreaturen sein. "
gameforge.main_quest_lv78._40_say = "Roter Hِllenquarz wird aus drei Substanzen[ENTER]hergestellt: Vulkanerde, Flammenmنhne und[ENTER]Fundamentstein. Du findest alles im Feuerland. "
gameforge.main_quest_lv78._50_say = "Du hast es geschafft! Endlich haben wir die[ENTER]erforderlichen %d Stücke des Roten Hِllenquarzes.[ENTER]Deine Tapferkeit und Kampfstنrke beeindrucken[ENTER]mich stets aufs Neue! "
gameforge.main_quest_lv78._60_say = "Eine Substanz fehlt. Wir benِtigen Vulkanerde,[ENTER]Flammenmنhne sowie Fundamentstein. "
gameforge.main_quest_lv78._70_say = "Es tut mir leid, aber ich kann an einem Tag nur[ENTER]sieben Stück des Roten Hِllenquarzes herstellen.[ENTER]Diese Prozedur ist eine Herausforderung für meine[ENTER]Zauberfنhigkeiten. Schlieكlich bin ich kein[ENTER]Magier! "
gameforge.main_quest_lv78._80_say = "Also dann! Ich werde nun die drei Substanzen[ENTER]miteinander vermischen und versuchen, einen Roten[ENTER]Hِllenquarz herzustellen. "
gameforge.main_quest_lv78._90_say = "Argh! Der Zauber ist fehlgeschlagen. Anscheinend[ENTER]habe ich meine magischen Fنhigkeiten überschنtzt.[ENTER]Das nنchste Mal klappt es bestimmt. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Nachdem du General Tartaros besiegt hast,[ENTER]ِffnet sich ein Zugang zu einer bisher[ENTER]verborgenen Ebene der Devil's Catacomb.[ENTER]Dort muss sich Fürst Charon befinden![ENTER]Teleportiere dich in die sechste Ebene und[ENTER]stelle dich dem Fürsten der Agwi. Doch Vorsicht![ENTER]Er ist نuكerst stark und gerissen wie ein Teufel. "
gameforge.main_quest_lv84._10_sendLetter = "Der Kampf beginnt "
gameforge.main_quest_lv84._110_say = "So wie du dich in der Devil's Catacomb bewegst -[ENTER]frei und ohne Angst -, kannst du unmِglich ein[ENTER]Normalsterblicher sein![ENTER]Der Basalt-Obelisk auf der fünften Ebene dient[ENTER]dir als Portal zur verborgenen sechsten Ebene. "
gameforge.main_quest_lv84._120_say = "Von dort erteilt Fürst Charon all seine Befehle[ENTER]an Agwi-General Tartaros.[ENTER]Worauf wartest du noch? Vernichte Charon und[ENTER]vereitle die düsteren Plنne der Diener der[ENTER]Dunkelheit und der Banshee! "
gameforge.main_quest_lv84._130_sayReward = "Du hast es geschafft! Charon, Fürst der Agwi,[ENTER]wurde vernichtend geschlagen. "
gameforge.main_quest_lv84._140_say = "Erschِpft und erleichtert wischst du dir den[ENTER]Schweiك von der Stirn.[ENTER]Plِtzlich erschüttert ein schrilles[ENTER]Gelنchter die Devil's Catacomb, so[ENTER]durchdringend, dass es dir bis ins Mark fنhrt:[ENTER]Ahahahah! Zu spنt, ihr erbنrmlichen Menschen![ENTER]Unser Meister, Sung Mahi, ist bereits auferstanden[ENTER]und ihr kِnnt nichts tun, um das jetzt noch zu[ENTER]verhindern.[ENTER]Der Tag ist nah, an dem Sung Mahi auf der Insel, wo[ENTER]die bِsen Drachen schlafen, zu seiner vollkommenen[ENTER]Macht gelangen wird. Eure Welt ist dem Untergang[ENTER]geweiht! "
gameforge.main_quest_lv84._150_sendLetter = "Unvollendete Geschichte "
gameforge.main_quest_lv84._160_say = "Gehe zu Lee Chung und berichte ihm über[ENTER]die bedrohliche Botschaft der Banshee. "
gameforge.main_quest_lv84._170_say = "Nachdem du dem Kommandanten von deinem Sieg über[ENTER]Tartaros und Charon berichtet hast, wiederholst[ENTER]du die bedrückende Botschaft der Banshee.[ENTER]Mit ernster Miene beginnt er zu sprechen: "
gameforge.main_quest_lv84._180_say = "Ich hatte angenommen, dass wir auch die[ENTER]finsteren Plنne der Diener der Dunkelheit und[ENTER]der Banshee vereiteln, wenn wir den[ENTER]Fürsten der Agwi stürzen. Weit gefehlt ... "
gameforge.main_quest_lv84._190_say = "Die Banshee muss zusammen mit Azrael, dem dunklen[ENTER]Kِnig der Agwi, bereits die Auferstehung[ENTER]des Dنmonengottes Sung Mahi vollzogen haben. Ich[ENTER]erschaudere bei der Vorstellung ... "
gameforge.main_quest_lv84._200_say = "Die Insel, auf der die bِsen Drachen schlafen ...[ENTER]Hm, damit muss der Fels der Dunklen Drachen[ENTER]gemeint sein, eine unerforschte Insel, weit[ENTER]entfernt von hier.[ENTER]Auch wenn wir nicht erreicht haben, was wir[ENTER]wollten, sind wir dir dennoch zu groكem Dank[ENTER]verpflichtet. Ohne dich hنtten wir die Ursache[ENTER]für das Unheil, das in den Untiefen der Devil's[ENTER]Catacomb lauerte, nie aufdecken kِnnen. "
gameforge.main_quest_lv84._20_say = "Lee Chung hat die Trنne des Himmels erhalten und[ENTER]alles für deinen Einsatz in der Devil's Catacomb[ENTER]vorbereitet. Gehe zu ihm, um mehr zu erfahren. "
gameforge.main_quest_lv84._210_say = "Du hast wahrhaft groكe Taten vollbracht,[ENTER]niemand auكer dir wنre dazu in der Lage[ENTER]gewesen. Ich werde dir für alle Zeit zur Seite[ENTER]stehen, wenn du mich brauchst. Leb wohl! "
gameforge.main_quest_lv84._30_say = "Jetzt, da wir die Trنne des Himmels in unseren[ENTER]Hنnden halten, ist es nur noch eine Frage der[ENTER]Zeit, bis wir die Diener der Dunkelheit besiegt[ENTER]und die Agwi aus unserer Welt vertrieben haben![ENTER]Doch ihre gesamte Macht entfaltet sich nur, wenn[ENTER]sie an einem bestimmten Ort in der Devil's[ENTER]Catacomb eingesetzt wird. "
gameforge.main_quest_lv84._40_say = "Wir wissen von fünf Ebenen in der Devil's[ENTER]Catacomb. Auf dieser fünften und letzten uns[ENTER]bekannten Ebene wirst du auf Tartaros treffen,[ENTER]grausamer Agwi-General und Dritter in der[ENTER]Rangfolge hinter Kِnig Azrael und Fürst Charon.[ENTER]Vernichte ihn mithilfe der Trنne des Himmels! "
gameforge.main_quest_lv84._50_say = "Aber wo versteckt sich nur Fürst Charon? "
gameforge.main_quest_lv84._60_sendLetter = "General Tartaros "
gameforge.main_quest_lv84._70_say = "Verwende die Trنne des Himmels erst, wenn du[ENTER]die fünfte Ebene der Devil's Catacomb erreicht[ENTER]hast. Den Eingang zur Devil's Catacomb befindet[ENTER]sich auf der Rückseite des Dنmonenturms. "
gameforge.main_quest_lv84._80_say = "Die Heiligen Mنchte beginnen, in der Trنne des[ENTER]Himmels zu wirken. Du spürst eine ungeheure[ENTER]Energie durch deinen Kِrper flieكen. Die Kraft[ENTER]dieses Steines ist überwنltigend![ENTER]Vernichte General Tartaros. "
gameforge.main_quest_lv84._90_sendLetter = "Fürst Charon "
