gameforge.main_quest_lv9._10_targetVid = "Finde den Stadtwنchter "
gameforge.main_quest_lv9._20_sendLetter = "Sprich mit dem Stadtwنchter "
gameforge.main_quest_lv9._30_sayReward = "Die ersten Schritte auf dem Weg zu wahrem[ENTER]Heldentum liegen hinter dir. Nun ist es Zeit für[ENTER]grِكere Taten. Geh zum Stadtwنchter und hole dir[ENTER]deinen letzten Anfنnger-Auftrag ab. "
gameforge.main_quest_lv9._40_say = "Bist du bereit, schwierigere Aufgaben zu[ENTER]bewنltigen? Bedenke, dass die Zeit der leichten[ENTER]Erledigungen vorbei ist, wenn du für die Zukunft[ENTER]deines Reiches einstehen willst. Du wirst viele[ENTER]Schlachten und Nِte durchleben. Sei also immer[ENTER]auf der Hut. Hier, diese Belohnung gebührt dir[ENTER]als Anerkennung deines bisherigen Einsatzes. Mِge[ENTER]es dir von Nutzen sein. "
gameforge.main_quest_lv9._50_say = "Von jetzt an wird der Hauptmann dir zur Seite[ENTER]stehen. Er wird dich und deine Fortschritte[ENTER]beaufsichtigen und dir Aufgaben stellen, um dich[ENTER]zu trainieren. ـbe dich noch ein wenig im Kampf[ENTER]und begib dich anschlieكend zu ihm. Alles Gute! "
