gameforge.main_quest_lv97._020_say = "Das Versteck der Banshee wurde entdeckt! Gehe zu[ENTER]Admiral Angmur, um mehr zu erfahren. "
gameforge.main_quest_lv97._030_say = "Meine Mنnner haben endlich die Basis der Banshee[ENTER]am Gautamakliff gefunden. Sie hat sich tief in die[ENTER]Dunkelheit der Wنlder dieser Gegend verkrochen und[ENTER]wirkt von dort aus ihre schwarze Magie. Auكerdem[ENTER]hat sie eine ihrer früheren Tempeldienerinnen des[ENTER]Drachenkultes wiedererweckt. Mit ihr zusammen wird[ENTER]sie den Fluch des Lebens beschwِren. "
gameforge.main_quest_lv97._040_say = "Ohne ihre Hilfe wird die Banshee den Fluch nicht[ENTER]aufrechterhalten kِnnen. Besiege die[ENTER]Tempeldienerin Mu-Shu und besنnftige die Seelen[ENTER]unserer Kameraden, ehe ihre Kِrper sich gegen uns[ENTER]erheben. "
gameforge.main_quest_lv97._050_say = "Es ist fast unmِglich, sich der Tempeldienerin[ENTER]unbemerkt zu nنhern, um sie anzugreifen. Nutze den[ENTER]Moment, wenn sie so in ihren dunklen Zauber[ENTER]vertieft ist, dass sie in eine Trance verfنllt! "
gameforge.main_quest_lv97._060_say = "In Ordnung. "
gameforge.main_quest_lv97._070_say = "Sieh dich vor! Zu Lebzeiten war sie die erste[ENTER]Leibwنchterin der Hohepriesterin und nicht nur in[ENTER]der Magie, sondern auch im Schwertkampf bestens[ENTER]ausgebildet. "
