gameforge.main_quest_lv97._140_say = "Du bist zurück! Ist die Tempeldienerin besiegt? "
gameforge.main_quest_lv97._150_say = "Nein, wir sind von einer Doppelgنngerin getنuscht[ENTER]worden. Die echte Tempeldienerin konnte[ENTER]in Ruhe die Totenbeschwِrung vorbereiten. Hier,[ENTER]dieses Dokument habe ich gefunden. "
gameforge.main_quest_lv97._160_say = "Verflucht! Wie konnten wir nur auf ihre Spielchen[ENTER]reinfallen?! Bitte zeige mir das Dokument. "
