gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hm, verschlüsselt. Aber vielleicht verrنt uns[ENTER]diese Nachricht, wo sich ihre Basis tatsنchlich[ENTER]befindet. Schriftzeichen wie diese habe ich doch[ENTER]schon einmal gesehen ... Ich glaube, Yak-Hwan, der[ENTER]Palastwنchter, hat mir erst kürzlich etwas[ENTER]ؤhnliches gezeigt. Gehe zu ihm. Er soll einen[ENTER]Blick darauf werfen. "
gameforge.main_quest_lv97._200_sendLetter = "Dokument entschlüsseln "
gameforge.main_quest_lv97._210_say = "Gehe zu Yak-Hwan und zeige ihm das verschlüsselte[ENTER]Dokument. "
gameforge.main_quest_lv97._220_say = "Sei gegrüكt! Mein Name ist Yak-Hwan. Es ist mir[ENTER]eine Ehre, dich kennenzulernen. Deine Taten sind[ENTER]bereits legendنr! Was kann ich für dich tun? Ah,[ENTER]eine verschlüsselte Nachricht. Lass mich mal sehen. "
gameforge.main_quest_lv97._230_say = "Ja, diese Schriftzeichen sollte ich problemlos[ENTER]entschlüsseln kِnnen. Doch dafür benِtige ich[ENTER]Fossilerde. Der Alchemist müsste noch einen[ENTER]Klumpen davon haben. Bitte frage ihn danach. "
