gameforge.main_quest_lv97._400_say = "Beseitige die Brigade des Schwarzen Todes,[ENTER]bestehend aus Moghu, Carnifex, General Albus und[ENTER]Skeletos. "
gameforge.main_quest_lv97._410_say = "Erledige die Mitglieder der Brigade des Schwarzen[ENTER]Todes, bevor sie den Spنhtrupp entdecken. "
gameforge.main_quest_lv97._420_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv97._430_say = "Unser Plan ist aufgegangen! Wنhrend du die Brigade[ENTER]des Schwarzen Todes abgelenkt hast, haben meine[ENTER]Mنnner eine geeignete Stelle für einen Hinterhalt[ENTER]ausgemacht. Sobald unsere Angriffsstrategie steht,[ENTER]lasse ich dich rufen. "
gameforge.main_quest_lv97._440_sendLetter = "Die Tempeldienerin "
gameforge.main_quest_lv97._450_say = "Admiral Angmur benِtigt deine Hilfe! "
gameforge.main_quest_lv97._460_say = "Gut, du bist hier. Skeletos, Anführer der Brigade[ENTER]des Schwarzen Todes, hat überlebt und meine[ENTER]Mنnner angegriffen, als sie gerade die Basis[ENTER]stürmen wollten. Niemand kommt an ihm vorbei. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Du hast ihn schon einmal besiegt, also bitte hilf[ENTER]meinen Leuten am Gautamakliff! Tritt gegen[ENTER]Skeletos an. Stürme anschlieكend die Basis[ENTER]und tِte die Tempeldienerin Yah-Ki. "
gameforge.main_quest_lv97._490_say = "Verstanden! "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Yah-Ki vernichten "
gameforge.main_quest_lv97._520_say = "Besiege die Tempeldienerin Yah-Ki und halte sie[ENTER]davon ab, die Armee der Toten zu beschwِren. "
gameforge.main_quest_lv97._530_say = "Der Tag der Entscheidung ist gekommen. Wenn wir[ENTER]fallen, fنllt die ganze Welt. Doch wenn wir[ENTER]siegreich sind, werden unsere Taten noch[ENTER]Jahrhunderte spنter in Liedern besungen werden.[ENTER]Halte die Diener der Dunkelheit auf. Vernichte die[ENTER]Tempeldienerin Yah-Ki! "
gameforge.main_quest_lv97._540_say = "Warum bist du hier? Der Kampf ist noch nicht[ENTER]gewonnen! Besiege die Tempeldienerin Yah-Ki. All[ENTER]unsere Hoffnungen liegen auf dir. "
gameforge.main_quest_lv97._550_1_notice = "Du hast deinen Gegner in die Knie gezwungen und der Sieg ist dein! "
gameforge.main_quest_lv97._550_2_notice = "Dir bleibt keine Zeit zum Ausruhen – die[ENTER]Tempeldienerin Yah-Ki erwartet dich schon. "
gameforge.main_quest_lv97._560_notice = "Du hast gesiegt! Mit einem markerschütternden Schrei sinkt Yah-Ki zu Boden. "
gameforge.main_quest_lv97._570_say = "Ahhhhh! Das kann nicht sein! Geschlagen von einem[ENTER]Sterblichen ... Oh, Banshee, verzeih! Ich habe[ENTER]versagt. Meine Aufgabe konnte ich nicht erf... "
gameforge.main_quest_lv97._580_say = "Du durchsuchst ihren leblosen Kِrper und findest[ENTER]einen versiegelten Brief. Kehre damit zu Admiral[ENTER]Angmur zurück. "
gameforge.main_quest_lv97._590_say = "Aye, dem Drachengott sei Dank! Du bist unversehrt[ENTER]zurück. Hast du die Tempeldienerin besiegt? "
gameforge.main_quest_lv97._600_say = "Ja, ich habe sie wieder in die Hِlle[ENTER]zurückbefِrdert, aus der sie gekrochen kam. Im[ENTER]Sterben hat sie die Banshee um Vergebung für ihr[ENTER]Versagen angefleht. Das trug sie bei sich. "
gameforge.main_quest_lv97._610_say = "Einen versiegelten Brief. Zeig her! "
gameforge.main_quest_lv97._620_sayReward = "Meine Herrin,[ENTER]sie haben unseren Kِder geschluckt und Euer Plan[ENTER]ist aufgegangen. Die Beschwِrung Eurer untoten[ENTER]Armee schreitet voran und niemand wird uns jetzt[ENTER]noch aufhalten kِnnen. Wenn die seelenlosen Kِrper[ENTER]erst marschieren, ziehen wir gegen das Kap des[ENTER]Drachenfeuers und werden seine Bewohner unter uns[ENTER]begraben. Anschlieكend werden wir zum Festland[ENTER]hinübersetzen und Euch im Feuerland treffen. Die[ENTER]Welt wird unter unseren Schritten brennen![ENTER]Ich verneige mich tief[ENTER]Eure ewige Dienerin "
gameforge.main_quest_lv97._630_say = "Eine Botschaft an die Banshee! Aye, die[ENTER]schنndliche Hexe wartet im Feuerland nun vergebens[ENTER]auf ihre Armee der Finsternis.[ENTER]Ich danke dir. Ohne deine Hilfe wنre das Kap und[ENTER]seine Bewohner von dem Heer der Untoten dem[ENTER]Erdboden gleichgemacht worden. Du hast nicht nur[ENTER]uns gerettet, sondern auch den Seelenfrieden[ENTER]unserer Ahnen wiederhergestellt. Diese Belohnung[ENTER]überreiche ich dir stellvertretend für das ganze[ENTER]Fort. "
gameforge.main_quest_lv97._640_sayTitle = "Das Abenteuer geht weiter, sobald du Level 98[ENTER]erreicht hast. "
gameforge.main_quest_lv97._650_say = "Wir haben lange gebraucht, um die Basis ausfindig[ENTER]zu machen. Bitte, wir dürfen nicht noch mehr Zeit[ENTER]verlieren! "
gameforge.main_quest_lv97._660_say = "Braucht Yak-Hwan Fossilerde? Was für ein Glück,[ENTER]dass ich sie noch nicht verbraucht habe. Hier,[ENTER]bitte sehr. Nun bringe sie ihm und richte einen[ENTER]schِnen Gruك von mir aus. "
gameforge.main_quest_lv97._670_counterName = "Verbleibend "
gameforge.main_quest_lv97._680_sayReward = {}
gameforge.main_quest_lv97._690_1_notice = "Du hast die Brigade des Schwarzen Todes vernichtet. "
gameforge.main_quest_lv97._690_2_notice = "Erstatte nun Admiral Angmur Bericht. "
gameforge.main_quest_lv97._700_sayTitle = "Besiege Skeletos, Anführer der Brigade[ENTER]des Schwarzen Todes! "
gameforge.main_quest_lv97._710_say = "Die Tempeldienerin kann erst endgültig vernichtet[ENTER]werden, wenn du Skeletos besiegt hast. "
