gameforge.main_quest_lv98._010_sendLetter = "Wiederaufbau des Forts "
gameforge.main_quest_lv98._020_say = "Admiral Angmur bittet um deine Hilfe. Gehe zu ihm. "
gameforge.main_quest_lv98._030_say = "Danke, dass du gekommen bist. Der Kampf ist nicht[ENTER]spurlos an uns vorbeigezogen. Auch das Fort wurde[ENTER]angegriffen und der Schutzwall an vielen Stellen[ENTER]niedergerissen. Dieser Frieden wird nicht lange[ENTER]wنhren. Wir sollten die Ruhe für den Wiederaufbau[ENTER]nutzen. "
gameforge.main_quest_lv98._040_say = "Um den Schutzwall zu befestigen, benِtigen wir die[ENTER]Panzer des Krustenstammes. "
gameforge.main_quest_lv98._050_say = "Verstanden. Wie viele dieser Panzer braucht ihr? "
gameforge.main_quest_lv98._060_say = "100 Stück sollten ausreichen. Der Krustenstamm[ENTER]haust noch immer in der Nephritbucht. "
gameforge.main_quest_lv98._070_say = "Aye, das sind noch nicht genug Krustenpanzer.[ENTER]Bitte sammle noch mehr. "
gameforge.main_quest_lv98._080_1_notice = "Du hast nun alle Krustenpanzer gesammelt. "
gameforge.main_quest_lv98._080_2_notice = "Bringe sie zu Admiral Angmur. "
gameforge.main_quest_lv98._090_say = "Aye, sehr gut. Mit den Krustenpanzern kِnnen wir[ENTER]den Schutzwall wieder befestigen. Bitte nimm dies[ENTER]als Belohnung. Ich werde meine Ingenieure fragen,[ENTER]ob sie noch weitere Materialien benِtigen, und dir[ENTER]dann Bescheid geben. "
gameforge.main_quest_lv98._130_sendLetter = "Wiederaufbau des Forts "
gameforge.main_quest_lv98._140_say = "Admiral Angmur braucht noch einmal deine Hilfe.[ENTER]Gehe zu ihm. "
gameforge.main_quest_lv98._150_say = "Zur weiteren Befestigung benِtigen wir[ENTER]Tritonspeere. Wie der Name schon sagt, findest du[ENTER]sie bei den Tritonen. Bitte bringe mir 100 Stück. "
gameforge.main_quest_lv98._160_say = "Verstanden. "
gameforge.main_quest_lv98._170_say = "Da bist du ja! Aye, aber das sind noch nicht genug[ENTER]Tritonspeere. Bitte sammle weiter. "
gameforge.main_quest_lv98._180_1_notice = "Du hast alle Tritonspeere gesammelt. "
gameforge.main_quest_lv98._180_2_notice = "Bringe sie Admiral Angmur. "
gameforge.main_quest_lv98._190_say = "Perfekt! Nun kِnnen wir eine sichere[ENTER]Verteidigungsanlage bauen. Ich danke dir für deine[ENTER]Hilfe. ـbrigens sucht Yak-Hwan nach dir. Finde[ENTER]heraus, was er mِchte. "
gameforge.main_quest_lv98._200_sendLetter = "Notstand "
gameforge.main_quest_lv98._210_say = "Gehe zu Yak-Hwan. Er hat eine wichtige Aufgabe für[ENTER]dich. "
gameforge.main_quest_lv98._220_say = "Ah, sehr gut, du bist hier! Wir sind ein weiteres[ENTER]Mal auf deine Hilfe angewiesen. "
gameforge.main_quest_lv98._230_say = {}
gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "Die harte Zeit des Krieges ist nicht spurlos an[ENTER]den Bewohnern des Forts vorbeigezogen. Sie leiden[ENTER]Hunger und mit jedem Tag wird ihr Elend grِكer.[ENTER]Wenn wir nicht bald etwas unternehmen, sieht es[ENTER]nicht gut für sie aus. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Ogerbanden lauern unseren Versorgungstransporten[ENTER]auf und greifen sie an. Wir müssen diesen[ENTER]Plünderern Einhalt gebieten. Kapitنn Shrack und[ENTER]seine Generنle stecken dahinter. Tِte den Kapitنn[ENTER]der Oger und 50 Generنle Ogg! "
