gameforge.main_quest_lv98._310_2_notice = "Kehre nun zu Yak-Hwan zurück. "
gameforge.main_quest_lv98._320_say = "Endlich erreichen die Lebensmitteltransporte das[ENTER]Fort und unsere Bürger kِnnen mit Nahrung und[ENTER]Medikamenten versorgt werden! Die Not hat ein[ENTER]Ende. Du bist wahrlich ein Held. "
gameforge.main_quest_lv98._330_sendLetter = "Danksagung "
gameforge.main_quest_lv98._340_say = "Yak-Hwan mِchte mit dir sprechen. "
gameforge.main_quest_lv98._350_say = "Dank deiner Hilfe ist die Gefahr auf dem Fels der[ENTER]Dunklen Drachen einstweilen gebannt. Hierfür[ENTER]mِchten dir seine Bewohner gerne persِnlich ihren[ENTER]Dank aussprechen. "
