gameforge.main_quest_lv98._390_say = "Nicht alle Bürger hatten die Chance, dir zu[ENTER]danken. Sie werden sehr enttنuscht sein. Bitte[ENTER]stelle sicher, dass du keinen vergisst. "
gameforge.main_quest_lv98._400_say = "Mut und Weisheit teilen sich dein Herz[ENTER]gleichermaكen. Deine Taten werden noch[ENTER]Generationen spنter besungen werden. Ich verneige[ENTER]mich vor dir. "
gameforge.main_quest_lv98._410_say = "Mِgest du stets gegen alle Gefahren gut gewappnet[ENTER]sein! "
gameforge.main_quest_lv98._420_say = "Du wirst für alle Zeit einen Ehrenplatz in unseren[ENTER]Herzen haben. "
gameforge.main_quest_lv98._430_say = "Das waren turbulente Zeiten, nicht wahr? Ich bin[ENTER]mir sicher, der Drachengott persِnlich hat deine[ENTER]Wege auf unsere Insel geleitet. "
