gameforge.manwoo._20_sayTitle = "Fischer: "
gameforge.manwoo._30_say = "Ich will meine Fischzucht erweitern. Deshalb[ENTER]brauche ich lebende Karpfen. Diese Fische eignen[ENTER]sich gut für die Zucht und sind bei Anglern sehr[ENTER]beliebt. Aber sie sind nicht leicht zu fangen. "
gameforge.manwoo._40_say = "Wenn du mir ein Karpfen bringst, werde ich dich[ENTER]belohnen. Ich habe eine Truhe, die steht schon[ENTER]seit Ewigkeiten auf meinem Speicher. Ich weiك[ENTER]nicht mehr, was sie enthنlt. Vielleicht etwas[ENTER]Nutzloses, vielleicht etwas Wertvolles. Es[ENTER]kِnnen sich aber auch Monster in ihr versteckt[ENTER]haben.[ENTER]Wenn du sie haben mِchtest, dann bringe[ENTER]mir einen lebenden Karpfen. "
