gameforge.map_warp._260_npcChat = "صخرة التنين الظلامي "
gameforge.map_warp._270_say = "لقد تم مؤخرًا اكتشاف جزيرة غريبة ومليئة بالأسرار.[ENTER]يُطلق عليها اسم صخرة التنين الظلامي. لا يكون[ENTER]البقاء فيها سوى لمن يملك خبرة عالية. لن أنقل[ENTER]إليها من لم يصل مستواه المستوى 90 بعد. هل أنت[ENTER]مستعد لدخول الرحلة وخوض المغامرة؟ "
gameforge.map_warp._280_say = "لا يمكن الوصول إلى الجزيرة إلاّ على ظهر سفينة،[ENTER]بعد رحلة طويلة وشاقة. كلما ارتفع مستواك، كلما[ENTER]ازدادت مشقة وصعوبة الرحلة. هذا باختصار هو سبب[ENTER]طلبي منك دفع سعر مُرتفع. "
gameforge.map_warp._280_sayReward = "ستكلفك هذه الرحلة %d يانغ. "
gameforge.map_warp._30_say = "إنه فعلاً موقع رائع، ولكن هل تحصل هنا أي إثارة؟[ENTER]بالتأكيد لا. إن الوضع في أماكن أخرى مختلف جداً![ENTER]هناك أماكن عدة أكثر إثارة وحركة يمكنني نقلك[ENTER]إليها.[ENTER]لقد ازدادت قوى الشر قوة من جديد، وانزلق كل من[ENTER]المكان والزمان في فوضى عارمة. لذلك فإنه من الممكن[ENTER]أن لا ينجح إرجاعك على الفور. هل تريد رغم هذا أن[ENTER]يتم نقلك؟ "
gameforge.map_warp._40_say = "همم...لا يمكنك تحمل عبئ السفر وسط الزمن والمكان[ENTER]بمستواك الحالي. لن تستطيع تحمل ذلك إلاّ ابتداءً[ENTER]من المستوى 10. "
gameforge.map_warp._50_say = "إلى أين تريد الانتقال؟ "
