gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ah, du bist es![ENTER]Wir haben uns ja schon lange nicht mehr gesehen.[ENTER]Es ist nun schon ein Jahr her, ho ho![ENTER]Vielleicht fragst du dich, warum ich wieder im[ENTER]Dorf bin.[ENTER]Ich will es dir erklنren … "
gameforge.new_christmas._030_say = "Die Zeiten sind hart. Niemand mِchte in diesen[ENTER]Tagen Bücher oder andere Sachen kaufen.[ENTER]Und in meinem fortgeschrittenen Alter ist es viel[ENTER]zu mühselig, stنndig im Rentierschlitten durch[ENTER]die Lüfte zu fliegen. Deswegen habe ich[ENTER]beschlossen, Weihnachten dieses Jahr hier im Dorf[ENTER]zu feiern. "
gameforge.new_christmas._040_say = "Wenn du noch Fragen hast, kannst du jederzeit[ENTER]zu mir kommen. Frِhliche Weihnachten! "
gameforge.new_christmas._050_npcChat = "Mِchtest du einen Glühwein? "
gameforge.new_christmas._060_say = "Ho ho ho! Du weiكt doch bestimmt, was das ist,[ENTER]oder? Es gibt kein besseres Getrنnk für die[ENTER]Winterzeit! Man nehme einen guten Wein, eine[ENTER]Prise Zimt, ein paar Nelken … mmmmmh! "
gameforge.new_christmas._070_say = "Bei dieser Kنlte wird dir ein Schluck Glühwein[ENTER]guttun! Er verleiht dir Kraft und du kannst dich[ENTER]schneller bewegen. Mِchtest du probieren? Sehr[ENTER]schِn, er kommt sofort! "
gameforge.new_christmas._080_say = "Der Glühwein scheint dir gut zu schmecken, ho ho![ENTER]Spürst du, wie er dich von innen wنrmt? Und[ENTER]dieser Geschmack, so süك und fruchtig. Frِhliche[ENTER]Weihnachten! "
gameforge.new_christmas._090_npcChat = "Mehr Glühwein, bitte! "
gameforge.new_christmas._100_say = "Ah, Moment![ENTER]Eine Kleinigkeit habe ich vergessen![ENTER]Glühwein kann ich dir nur einmal am Tag[ENTER]zubereiten, für mehr reichen meine Zutaten nicht[ENTER]aus. Und er ist nur 20 Stunden haltbar. In einer[ENTER]Flasche sind jeweils 6 Portionen, die Wirkung[ENTER]eines Schlucks hنlt 30 Minuten an. Teile ihn dir[ENTER]also gut ein! "
gameforge.new_christmas._110_say = "Bitte sehr! Du hast lange genug darauf warten[ENTER]müssen. Dieses wunderbare Getrنnk wird dir Flügel[ENTER]verleihen, ho ho ho! So, lass es dir[ENTER]schmecken. Frِhliche Weihnachten! "
gameforge.new_christmas._120_say = "Was, du mِchtest noch mehr?[ENTER]Tut mir leid, aber du hast genug getrunken. Seit[ENTER]deiner letzten Portion Glühwein sind noch keine[ENTER]24 Stunden vergangen. Zu viel davon ist nicht gut[ENTER]für dich! Komm spنter wieder.[ENTER]Dennoch ein frohes Fest! "
