gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "Was ist mit den Socken? "
gameforge.new_christmas_sock._020_say = "Die Socken! Beinahe hنtte ich sie vergessen! Ich[ENTER]wollte meine Geschenke in den Socken, die über[ENTER]die Kamine gehنngt wurden, verstecken. Aber[ENTER]unweihnachtliche Kreaturen haben alle gestohlen![ENTER]Hilf mir dabei, sie zurückzuholen. "
gameforge.new_christmas_sock._030_say = "Socken sind gar nicht so leicht zu finden. Du[ENTER]wirst das Rentierjunge brauchen, um welche[ENTER]aufzuspüren. "
gameforge.new_christmas_sock._040_say = "Ist es nicht niedlich?[ENTER]Und es hat einen ausgezeichneten Geruchssinn. Ein[ENTER]Spezialist im Sockenfinden![ENTER]Es bleibt 2 Stunden lang bei dir und hilft dir[ENTER]bei der Suche. Danach ist es müde und kann[ENTER]erst nach 24 Stunden weitermachen.[ENTER]Wenn du nicht so lange warten mِchtest, dann[ENTER]schau mal unten links hinter der drehenden Münze[ENTER]- ich habe gehِrt, da wartet ein weiteres[ENTER]Rentierjunges. Ich freue mich aber auch, wenn du[ENTER]mich morgen wieder besuchen kommst! "
gameforge.new_christmas_sock._050_npcChat = "Ich bringe dir Socken! "
gameforge.new_christmas_sock._060_say = "Bring mir mindestens 5 Socken, dann[ENTER]erhنltst du eine Belohnung.[ENTER]Urrgh, der Geruch von getragenen Socken ist[ENTER]unertrنglich! Komm wieder, wenn du genügend[ENTER]gesammelt hast. Frِhliche Weihnachten! "
gameforge.new_christmas_sock._070_say = "Ho ho ho, du hast genügend Socken gesammelt.[ENTER]Dann lass mich mal sehen.[ENTER]Urrgh, dieser Geruch … Das sind auf jeden Fall[ENTER]die richtigen Socken![ENTER]Frِhliche Weihnachten! "
gameforge.new_christmas_sock._080_npcChat = "Rentierjunges "
gameforge.new_christmas_sock._090_say = "Heute hast du bereits ein Rentierjunges-Siegel[ENTER]von mir erhalten. Ich fürchte, das kleine Rentier[ENTER]braucht jetzt eine Pause. Es kann erst[ENTER]morgen weitersuchen. Wenn du nicht so lange[ENTER]warten mِchtest, dann[ENTER]schau mal unten links hinter der drehenden Münze[ENTER]- ich habe gehِrt, da wartet ein weiteres[ENTER]Rentierjunges. Ich freue mich aber auch, wenn du[ENTER]mich morgen wieder besuchen kommst! "
gameforge.new_christmas_sock._100_say = "Du hast mir heute schon deine Socken gebracht.[ENTER]Denke daran, dass du nur alle 24 Stunden welche[ENTER]abgeben kannst. "
