gameforge.new_quest_lv17._021_say = "Mein Onkel Chaegirab hat sein Leben der[ENTER]Wissenschaft verschrieben und steckt all sein[ENTER]Yang in die Forschung. Er war stets gut zu mir,[ENTER]daher mِchte ich ihn mit einem Geschenk[ENTER]überraschen. Würdest du zu Uriel gehen und ihn[ENTER]fragen, ob er eine Idee hat? Er ist der alte[ENTER]Lehrer meines Onkels und kennt ihn sehr gut. "
gameforge.new_quest_lv17._030_say = "Aber verrate meinem Onkel nichts! "
gameforge.new_quest_lv17._031_say = "Wirst du mir helfen? "
gameforge.new_quest_lv17._039_say_title = " أوريل : "
gameforge.new_quest_lv17._040_say_title = "Sprich mit Uriel "
gameforge.new_quest_lv17._040_target = "Uriel "
gameforge.new_quest_lv17._041_say = "Sprich mit Uriel über seinen ehemaligen Schüler[ENTER]Chaegirab. "
gameforge.new_quest_lv17._042_say = "Uriel befindet sich in %s. "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim mِchte Chaegirab beschenken... "
gameforge.new_quest_lv17._051_say = "Des Forschers Freude ist schlicht und einfach die[ENTER]Forschung. Du wirst Chaegirab die grِsste Freude[ENTER]machen, wenn du seine Arbeit unterstützt. Der[ENTER]Mu-Rang-Wolf ist ein seltener Gast in unseren[ENTER]Landen, sein Fell die Freude eines jeden[ENTER]Biologen. Fünf Felle sollten genügen. Sag das[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._052_say = "Ein solches Fell würde den Biologen sicher[ENTER]beeindrucken. "
gameforge.new_quest_lv17._060_select = "Ja, ich werde es ihm sagen. "
gameforge.new_quest_lv17._065_say_title = "Zurück zu Wonda-Rim "
gameforge.new_quest_lv17._066_say = "Uriel hatte eine gute Idee, was man Chaegirab[ENTER]schenken kِnnte. Geh zurück zu Wonda-Rim und[ENTER]berichte ihm davon. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim befindet sich in %s. "
gameforge.new_quest_lv17._070_say = "Der Rat Uriels klingt gut. Da ich meinen Onkel[ENTER]Chaegirab wirklich überraschen mِchte, muss ich[ENTER]an diese Felle gelangen. Kannst du losziehen und[ENTER]5 Mu-Rangs für mich tِten? "
gameforge.new_quest_lv17._071_say = "Ich soll Mu-Rang-Wِlfe tِten, um an ihre Felle zu[ENTER]gelangen. "
gameforge.new_quest_lv17._072_say = "5 Stück reichen für ein gutes Geschenk. "
gameforge.new_quest_lv17._073_say = "Los geht's! "
gameforge.new_quest_lv17._074_notice = "Du hast ein gut erhaltenes Fell erbeutet. "
gameforge.new_quest_lv17._075_say = "Jage Mu-Rang-Wِlfe und erbeute ihre Felle. "
gameforge.new_quest_lv17._076_say_reward = "Bis jetzt hast du %s von 5 Fellen gesammelt. "
gameforge.new_quest_lv17._081_say_title = "Felle für Wonda Rim "
gameforge.new_quest_lv17._082_say = "Du hast genügend Felle erbeutet, bringe sie zu[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._092_say_reward = "Du hast bereits %s Wolfsfelle gesammelt. "
gameforge.new_quest_lv17._110_say = "Das sind wirklich schِne Felle, ich danke dir.[ENTER]Kannst du sie meinem Onkel Chaegirab bringen? "
gameforge.new_quest_lv17._120_target = "Onkel Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim hat dich gebeten, die Wolfsfelle weiter[ENTER]zu Chaegirab zu bringen. "
gameforge.new_quest_lv17._122_say = "Chaegirab befindet sich in %s. "
gameforge.new_quest_lv17._130_say = "Aha. So versucht er es nun. "
gameforge.new_quest_lv17._131_say = "Von wem sind diese Felle? Von Wonda-Rim, aber du[ENTER]hast die Wِlfe für ihn erlegt?[ENTER]Es beschنmt mich, einen Neffen zu haben, der[ENTER]andere für sich arbeiten lنsst. Daher werde ich[ENTER]die Felle nicht annehmen, auch wenn es mir um[ENTER]deine Zeit und Mühe Leid tut. "
gameforge.new_quest_lv17._132_say_reward = "Sag Wonda-Rim, dass ich ihn durchschaut habe![ENTER]Wenn er mir eine wirkliche Freude machen will,[ENTER]soll er selbst auf die Jagd gehen. "
gameforge.new_quest_lv17._140_say = "Chaegirab hat die Felle nicht angenommen und ist[ENTER]über Wonda-Rims Tun verنrgert. Er hat dich zu[ENTER]Wonda-Rim zurückgeschickt. "
gameforge.new_quest_lv17._141_say = "Was hat mein Onkel gesagt? Ich hoffe, ihm hat das[ENTER]Geschenk gefallen? "
gameforge.new_quest_lv17._142_1_select = "Ja, er war begeistert. "
gameforge.new_quest_lv17._142_2_select = "Nein, gar nicht. "
gameforge.new_quest_lv17._143_say = "Sehr schِn! Es ist ein gutes Gefühl, anderen[ENTER]Menschen Freude zu bereiten. Und du sollst[ENTER]natürlich belohnt werden. Hier, nimm! "
gameforge.new_quest_lv17._144_say_reward_a = "Du erhنltst 20.000 Erfahrungspunkte.[ENTER]Du erhنltst 20.000 Yang.[ENTER]Du erhنltst einen Goldklumpen. "
gameforge.new_quest_lv17._144_say_reward_b = "Du hast Wonda-Rim belogen und deshalb[ENTER]Rangpunkte verloren! "
gameforge.new_quest_lv17._145_say = "Er hat die Felle nicht angenommen?[ENTER]Hmm, es war wirklich keine gute Idee, dich an[ENTER]meiner Stelle auf die Jagd zu schicken. Nنchstes[ENTER]Mal werde ich es anders machen. "
gameforge.new_quest_lv17._146_say_reward = "Aber du sollst dir die ganze Arbeit nicht umsonst[ENTER]gemacht haben: Geh zu Yang-Shin. Er wird dir die[ENTER]Felle zu einem guten Preis abkaufen. "
gameforge.new_quest_lv17._147_say = "Was für ein ernüchternder Ausgang der Ereignisse.[ENTER]Wenigstens hast du noch die Felle. Geh zum Jنger[ENTER]Yang-Shin in Yayang und verkaufe sie ihm. "
gameforge.new_quest_lv17._148_say = "Was für ein ernüchternder Ausgang der Ereignisse.[ENTER]Wenigstens hast du noch die Felle. Geh zum Jنger[ENTER]Yang-Shin in Bokjung und verkaufe sie ihm. "
gameforge.new_quest_lv17._149_say = "Was für ein ernüchternder Ausgang der Ereignisse.[ENTER]Wenigstens hast du noch die Felle. Geh zum Jنger[ENTER]Yang-Shin in Bakra und verkaufe sie ihm. "
gameforge.new_quest_lv17._151_say = "Mu-Rang-Felle? Die kann ich gut gebrauchen.[ENTER]Ich mache mir daraus eine neue Wنschegarnitur.[ENTER]Hier, nimm einen Beutel Yang dafür. Und dieses[ENTER]Buch habe ich gestern gefunden, vielleicht kannst[ENTER]du etwas damit anfangen. "
gameforge.new_quest_lv17._152_say_reward = "Du erhنltst 40.000 Erfahrungspunkte.[ENTER]Du erhنltst 10.000 Yang.[ENTER]Du erhنltst ein Fertigkeitsbuch. "
