gameforge.new_quest_lv22._010_target = "حارس ساحة القرية "
gameforge.new_quest_lv22._011_say = "Der Wنchter des Dorfplatzes hat eine Aufgabe für[ENTER]dich. Gehe zu ihm und erkundige dich, worum es[ENTER]geht. "
gameforge.new_quest_lv22._015_npcChat = "أخي المريض "
gameforge.new_quest_lv22._016_send_letter = "Der kranke Wنchter "
gameforge.new_quest_lv22._017_say_title = "حارس ساحة القرية: "
gameforge.new_quest_lv22._018_say_title = "بايك-غو: "
gameforge.new_quest_lv22._019_say_title = "Wنchter des Dنmonenturms: "
gameforge.new_quest_lv22._021_say = "Ich sorge mich um meinen Bruder, den Wنchter des[ENTER]Dنmonenturms. Er fühlt sich seit einiger Zeit[ENTER]unwohl und nun hat die Krankheit vollends[ENTER]zugeschlagen: Ihn plagen Kopfschmerzen und[ENTER]Hautrِtungen, aber er kann seinen Posten nicht[ENTER]verlassen. Kِnntest du ihm Medizin von Baek-Go[ENTER]besorgen? "
gameforge.new_quest_lv22._022_say = "Ich würde ja selbst gehen, aber der Dنmonenturm[ENTER]befindet sich innerhalb des Hwang-Tempels, mitten[ENTER]im Tal von Seungryong. Dort wimmelt es nur so von[ENTER]gefنhrlichen Kreaturen... "
gameforge.new_quest_lv22._023_say = "Da bist du ja schon wieder. Du hast die Symptome[ENTER]vergessen? Du solltest besser zuhِren, wenn dir[ENTER]jemand etwas sagt.[ENTER]Meinen Bruder plagen Kopfschmerzen und[ENTER]Hautrِtungen. Sag das Baek-Go! "
gameforge.new_quest_lv22._024_select = "Dem Bruder helfen "
gameforge.new_quest_lv22._025_say_title = "Medizin von Baek-Go "
gameforge.new_quest_lv22._026_say = "Sprich mit Baek-Go über die Medizin für den[ENTER]Wنchter des Dنmonenturms. "
gameforge.new_quest_lv22._027_say = "Baek-Go befindet sich in %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go "
gameforge.new_quest_lv22._031_say = "Du benِtigst also Medizin? Es kann gefنhrlich[ENTER]sein, auf gut Glück etwas zu verabreichen! Du[ENTER]musst mir schon die Symptome der Krankheit[ENTER]nennen, die bekنmpft werden soll. "
gameforge.new_quest_lv22._032_1_select = "Kopfschmerzen und Hautrِtungen "
gameforge.new_quest_lv22._032_2_select = "Halsschmerzen und Krنmpfe "
gameforge.new_quest_lv22._032_3_select = "Das weiك ich nicht. "
gameforge.new_quest_lv22._035_say = "Das klingt für mich ganz nach Dنmonenkrنtze - das[ENTER]bleibt nicht aus, wenn zu viele dieser[ENTER]milbenverseuchten Biester in der Nنhe sind.[ENTER]Ich kann dir ein Mittel herstellen, das ihm[ENTER]helfen wird. Du musst mir dafür allerdings einige[ENTER]Zutaten besorgen. "
gameforge.new_quest_lv22._040_say = "Ich brauche: "
gameforge.new_quest_lv22._041_say_reward = "للحصول عليه اصطد: "
gameforge.new_quest_lv22._042_say = "Ich brauche auكerdem: "
gameforge.new_quest_lv22._043_say = "Von solch einer Krankheit habe ich noch niemals[ENTER]gehِrt. Bist du sicher, dass der Wنchter des[ENTER]Dorfplatzes dir die richtigen Symptome genannt[ENTER]hat? Frage besser noch einmal nach. "
gameforge.new_quest_lv22._044_say = "Ohne Symptome kann ich keine Diagnose stellen.[ENTER]Geh und frage noch einmal nach. "
gameforge.new_quest_lv22._050_set_title = "Medizin "
gameforge.new_quest_lv22._056_notice = "Gut, jetzt fehlen nur noch %s Bündel Krنuter. "
gameforge.new_quest_lv22._057_notice = "Das müssten alle Krنuter sein, die ich brauche.[ENTER]Nun schnell zurück zu Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Gut, jetzt fehlen nur noch %s Lebern. "
gameforge.new_quest_lv22._060_notice = "Ah, eine Leber. Nun fehlen mir noch %s. "
gameforge.new_quest_lv22._061_notice = "Das müssten alle Lebern sein, die ich brauche.[ENTER]Nun schnell zurück zu Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Leider ist diese Leber nicht zu gebrauchen. "
gameforge.new_quest_lv22._063_say = "Du brauchst noch %s x Medizinische Krنuter+. "
gameforge.new_quest_lv22._064_say = "Du brauchst noch %s x Tigerleber+. "
gameforge.new_quest_lv22._065_say = "Du hast nun alle Zutaten, die für die Medizin[ENTER]benِtigt werden. Geh und bringe sie zu Baek-Go. "
gameforge.new_quest_lv22._066_say = "Sammle die Zutaten für Baek-Gos Medizin: "
gameforge.new_quest_lv22._070_say = "Danke, damit kann ich die Medizin gegen die[ENTER]Dنmonenkrنtze herstellen. "
gameforge.new_quest_lv22._071_say = "Fertig! Hier hast du das gewünschte Mittel. Durch[ENTER]die frischen Zutaten verdirbt die Medizin jedoch[ENTER]schnell - du solltest sie daher innerhalb von %s[ENTER]Minuten abliefern! "
gameforge.new_quest_lv22._072_say = "Du findest den Bruder des Wنchters in der Mitte[ENTER]des Hwang-Tempels. Sei jedoch vorsichtig auf dem[ENTER]Weg dorthin - das Tal von Seungryong wird von[ENTER]vielen gefنhrlichen Kreaturen bevِlkert! "
gameforge.new_quest_lv22._073_say = "Das reicht nicht aus. Hast du auf dem Weg hierher[ENTER]Zutaten verloren? Ohne die restlichen[ENTER]Bestandteile kann ich nichts für dich tun. "
gameforge.new_quest_lv22._080_target = "Wنchter des Dنmonenturms "
gameforge.new_quest_lv22._082_set_clock = "Verbleibende Zeit "
gameforge.new_quest_lv22._083_say = "Noch hast du genug Zeit, aber du musst dich[ENTER]beeilen. Also auf nach Seungryong zum Wنchter[ENTER]des Dنmonenturms, bevor die Medizin verdirbt! "
gameforge.new_quest_lv22._084_say = "Du warst zu langsam, die Zeit ist abgelaufen.[ENTER]Aber du solltest die Medizin dennoch zum Wنchter[ENTER]des Dنmonenturms bringen. Vielleicht ist sie noch[ENTER]wirksam. "
gameforge.new_quest_lv22._085_say = "Danke, dass du mir diese Medizin bringst. Der[ENTER]Juckreiz bringt mich beinahe um. "
gameforge.new_quest_lv22._086_say = "Oh, das schmeckt sogar ziemlich gut. Ich spüre[ENTER]bereits, wie der Juckreiz nachlنsst. "
gameforge.new_quest_lv22._087_say = "Dafür hast du dir eine besondere Belohnung[ENTER]verdient! "
gameforge.new_quest_lv22._088_say_reward = "Du erhنltst 50.000 Erfahrungspunkte.[ENTER]Du erhنltst 12.000 Yang.[ENTER]Du erhنltst Goldverzierte Schuhe+4.[ENTER]Du erhنltst 5 Violette Trنnke. "
gameforge.new_quest_lv22._089_say = "ؤh, das schmeckt ja furchtbar. Die Medizin ist[ENTER]verdorben - wie lange hast du für den Weg[ENTER]gebraucht? Meine Zunge fühlt sich an wie[ENTER]gepِkelter Affendung. "
gameforge.new_quest_lv22._090_say = "Hmm, moment... es scheint besser zu werden. Ja,[ENTER]es wirkt! Dann will ich mal nicht so sein. Du[ENTER]erhنltst trotzdem eine Belohnung. "
gameforge.new_quest_lv22._091_say = "Du scheinst die Medizin verloren zu haben. Bitte[ENTER]gehe noch einmal auf die Jagd und bringe Baek-Go[ENTER]die Zutaten für eine neue Medizin. Ich werde[ENTER]sonst selbst zum Dنmon, wenn das mit dem Juckreiz[ENTER]so weiter geht. "
gameforge.new_quest_lv22._095_say_reward = "Du erhنltst 50.000 Erfahrungspunkte.[ENTER]Du erhنltst 8.000 Yang. "
gameforge.new_quest_lv22._098_say = "Du hast schon wieder die Medizin verloren? Ein so[ENTER]schusseliger Mensch ist mir noch nie begegnet![ENTER]Aber gut, da kann man wohl nichts machen. "
gameforge.new_quest_lv22._100_say_reward = "Du erhنltst 25.000 Erfahrungspunkte. "
