gameforge.new_quest_lv26._020_say_title = "يانغ-شين: "
gameforge.new_quest_lv26._020_set_title = "الزوج الهارب "
gameforge.new_quest_lv26._021_say = "Der Jنger Yang-Shin hat Probleme, gute Jagdgründe[ENTER]zu finden. Geh zu ihm und sieh nach, ob du ihm[ENTER]helfen kannst. "
gameforge.new_quest_lv26._025_say = "Seit dem Auftauchen der Metinsteine ist nichts[ENTER]mehr, wie es einmal war. Auch die Jagd ist in[ENTER]vielen Gegenden unmِglich geworden, da die[ENTER]Wildtiere sich beinahe tollwütig gebنrden.[ENTER]Irgendwo dort drauكen in der Wildnis soll jedoch[ENTER]der Wanderer Nakajima leben - ich bin sicher,[ENTER]dass er weiك, wo sich gute Jagdgründe befinden.[ENTER]Kannst du ihn suchen und danach fragen? "
gameforge.new_quest_lv26._030_target = "ناكاجيما "
gameforge.new_quest_lv26._031_say = "So so, du willst also wissen, wo man hier am[ENTER]besten jagt? Nicht so hastig. Wenn ich etwas für[ENTER]dich tun soll, musst du auch mir einen Gefallen[ENTER]erweisen. "
gameforge.new_quest_lv26._032_say = "Du sollst wissen... ich lebe nicht freiwillig[ENTER]hier drauكen. Ich muss mich verstecken, da ich[ENTER]vor den Grنueltaten des Militنrs geflüchtet bin.[ENTER]Ich wünschte nur, meine geliebte Frau Ah-Yu würde[ENTER]wissen, dass ich noch lebe. Kannst du ihr diese[ENTER]Nachricht überbringen?[ENTER]Aber denk daran, sie ist nur für Ah-Yus Ohren[ENTER]bestimmt! Dafür soll sie dir verraten, wo ich sie[ENTER]zum ersten Mal geküsst habe - dort will ich sie[ENTER]treffen, und dort findest du deinen Jagdgrund. "
gameforge.new_quest_lv26._034_say_title = "ناكاجيما: "
gameforge.new_quest_lv26._035_say_title = "أه-يو: "
gameforge.new_quest_lv26._036_say_title = "Suche nach Nakajima "
gameforge.new_quest_lv26._037_say = "Nakajima soll Kenntnis von guten Jagdgründen[ENTER]haben. Suche nach ihm. "
gameforge.new_quest_lv26._038_say = "Nakajima befindet sich in %s. "
gameforge.new_quest_lv26._040_say = "Bist du Nakajima? Yang-Shin schickt mich! Er ist[ENTER]auf der Suche nach guten Jagdgründen - vielleicht[ENTER]hast du einen Rat, wo es nicht ganz so gefنhrlich[ENTER]ist? "
gameforge.new_quest_lv26._050_target = "أه-يو "
gameforge.new_quest_lv26._051_say = "Nakajima ist ein Deserteur und muss sich nun vor[ENTER]der Armee verstecken. Seine Frau Ah-Yu denkt, er[ENTER]sei im Krieg gefallen. Bring ihr die Kunde, dass[ENTER]Nakajima noch lebt. "
gameforge.new_quest_lv26._052_say = "Ah-Yu befindet sich in %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... er lebt? Mein geliebter Mann lebt? Oh[ENTER]ich danke dir für diese Information![ENTER]Es ist das Tal von Yonjang, von dem er gesprochen[ENTER]hat. Ich werde mich sofort auf den Weg machen und[ENTER]mich dort mit ihm treffen. "
gameforge.new_quest_lv26._058_say = "Danke, dass du uns dieses Wiedersehen ermِglicht[ENTER]hast. Nimm diese Rose, vielleicht kannst du sie[ENTER]einem geliebten Menschen schenken? Und nun...[ENTER]entschuldige mich, aber ich muss mich beeilen! "
gameforge.new_quest_lv26._061_say = "Das Tal von Yonjang - wo Nakajima und Ah-Yu sich[ENTER]zum ersten Mal geküsst haben - ist also auch[ENTER]heute noch gutes Jagdgebiet. "
gameforge.new_quest_lv26._062_say = "Yang-Shin wird zufrieden sein, wenn er das hِrt.[ENTER]Geh nach %s und überbringe ihm die gute[ENTER]Nachricht. "
gameforge.new_quest_lv26._063_say = "Das Tal von Yonjang? Das klingt einleuchtend,[ENTER]denn ich habe noch nie von einem Metinstein[ENTER]gehِrt, der dort die Gegend verseuchen soll. Ich[ENTER]werde in den nنchsten Tagen sicher gute Beute[ENTER]machen! Hier, die Belohnung hast du dir verdient. "
gameforge.new_quest_lv26._064_sayReward = "Du erhنltst 35.000 Erfahrungspunkte. "
gameforge.new_quest_lv26._065_sayReward = "Du erhنltst 17.500 Yang. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan "
gameforge.new_quest_lv28._011_say = "Der Musiker Yu-Hwan braucht deine Hilfe.[ENTER]Geh schnell und sieh nach, was los ist! "
gameforge.new_quest_lv28._015_npcChat = "Ah-Yus Sorgen "
gameforge.new_quest_lv28._016_say = "Ah-Yu scheint Sorgen zu haben, die sie Yu-Hwan[ENTER]nicht anvertrauen mِchte. Geh zu ihr und sieh[ENTER]nach, ob sie dir gegenüber offener ist. "
gameforge.new_quest_lv28._017_say = "Ah-Yu befindet sich in %s. "
gameforge.new_quest_lv28._018_select = "Ich spreche gleich mit Ah-Yu! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Kennst du Ah-Yu? Sie sammelt Krنuter für meine[ENTER]Trنnke. Bisher war sie stets gut gelaunt, doch[ENTER]gestern schien sie mir vollkommen aufgelِst zu[ENTER]sein. ـber ihre Sorgen reden wollte sie[ENTER]allerdings nicht - womِglich weil sie für mich[ENTER]arbeitet? Bitte gehe zu ihr und stelle fest, wie[ENTER]es ihr geht. Vielleicht vertraut sie dir mehr an! "
gameforge.new_quest_lv28._022_say = "Es ist sehr freundlich von Yu-Hwan, sich um mich[ENTER]zu sorgen. Ja, es gibt da etwas... ich wollte[ENTER]nicht darüber reden, aber der Kummer frisst mich[ENTER]innerlich auf! Es geht um Yang-Shin, den Jنger.[ENTER]Er erpresst mich, seitdem er herausgefunden hat,[ENTER]dass mein Mann Nakajima ein Deserteur ist.[ENTER]Yang-Shin droht, ihn zu verraten! Sie werden ihn[ENTER]tِten... "
gameforge.new_quest_lv28._023_say = "Dieses Mal fordert er von mir eine Bنrentatze,[ENTER]um sein Schweigen zu wahren. Ich kann aber nicht[ENTER]hier weg und auf die Jagd gehen. Wirst du mir[ENTER]helfen und Yang-Shin bringen, was er verlangt? "
gameforge.new_quest_lv28._024_set_title = "Bنrenjagd "
gameforge.new_quest_lv28._025_notice = "Auf zur Jagd! Bera zu tِten ist die beste[ENTER]Mِglichkeit, um an Bنrentatzen zu gelangen. "
gameforge.new_quest_lv28._026_notice = "Ich habe eine Bنrentatze erbeutet! "
gameforge.new_quest_lv28._027_notice = "Das dürfte alles sein. Auf zu Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "Die Tatze dieses Bنren war unbrauchbar. "
gameforge.new_quest_lv28._029_say = "Du benِtigst noch %s x Bنrentatze. "
gameforge.new_quest_lv28._031_say_reward = "للحصول عليه اصطد: "
gameforge.new_quest_lv28._032_say = "Ah-Yu hat dich gebeten, die Forderung von[ENTER]Yang-Shin zu erfüllen. "
gameforge.new_quest_lv28._032_say_reward = "Du benِtigst noch %s x Bنrentatze.[ENTER]Jage Bera, um sie zu erbeuten. "
gameforge.new_quest_lv28._035_target = "Yang-Shin "
gameforge.new_quest_lv28._036_say = "Du hast die geforderte Bنrentatze erbeutet.[ENTER]Bringe sie zu Yang-Shin und lِse Ah-Yus Schuld[ENTER]ein. "
gameforge.new_quest_lv28._037_say = "Yang-Shin befindet sich in %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "Die Erpressung "
gameforge.new_quest_lv28._041_say_title = "Bنrentatzen "
gameforge.new_quest_lv28._042_say = "Du bringst mir Bنrentatzen? Du darfst nicht[ENTER]schlecht von mir denken! Wir leben in schweren[ENTER]Zeiten und ich muss sehen, wie ich über die[ENTER]Runden komme - jetzt, wo das Jagdwild rar[ENTER]geworden ist oder sich durch die Metinsteine in[ENTER]mِrderische Bestien verwandelt hat. Das Leben als[ENTER]Jنger ist sehr gefنhrlich geworden. "
gameforge.new_quest_lv28._043_say = "Bitte richte Ah-Yu aus, dass sie nichts mehr zu[ENTER]befürchten hat. Sie kann sich darauf verlassen.[ENTER]Zumindest bis ich wieder etwas brauche... hehehe! "
gameforge.new_quest_lv28._044_say = "Du willst mich ohne Beute abspeisen? Ich habe[ENTER]frische Bنrentatzen verlangt! "
gameforge.new_quest_lv28._045_say_reward = "Es ist nett von dir, Ah-Yu zu helfen. Es bedeutet[ENTER]aber auch, dass du tun musst, was ich verlange.[ENTER]Gehe also wieder auf die Jagd, bis du mir zwei[ENTER]Bنrentatzen bringen kannst! "
gameforge.new_quest_lv28._046_say = "Bringe Ah-Yu die Kunde, dass Yang-Shin aufgrund[ENTER]deiner Hilfe aufhِren wird, sie zu erpressen. "
gameforge.new_quest_lv28._051_say = "Du bist unser Retter! Ich bin dir so unendlich[ENTER]dankbar. Hier, nimm all mein Yang. Es ist nicht[ENTER]viel, aber du hast es dir redlich verdient. "
gameforge.new_quest_lv28._055_1_select = "Vielen Dank, ich kann es gut gebrauchen! "
gameforge.new_quest_lv28._055_2_select = "Nein, das kann ich nicht annehmen. "
gameforge.new_quest_lv28._056_say = "Hier ist alles was ich habe. Solange ich diesen[ENTER]unmenschlichen Halsabschneider damit loswerde,[ENTER]ist es das wert. "
gameforge.new_quest_lv28._057_say = "Oh, hab Dank! Dafür ist dir ein Platz an der[ENTER]Seite des Drachengottes sicher! "
gameforge.new_quest_lv28._058_say_reward = "Du erhنltst %s Yang. "
gameforge.new_quest_lv28._059_say_reward = "Du erhنltst %s Erfahrungspunkte. "
gameforge.new_quest_lv28._070_say = "Ich brauche: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah "
gameforge.new_quest_lv29._015_npcChat = "Das zerbrochene Porzellan "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "Mein geliebtes Seladon-Porzellan! Seit drei[ENTER]Generationen befindet es sich in meiner Familie,[ENTER]und nun sind drei der kostbaren Vasen zerbrochen.[ENTER]Vor kurzem habe ich Taurean beobachtet, den[ENTER]kleinen Taugenichts, wie er um das Lagerhaus[ENTER]schlich. Ich bin sicher, er ist für das Unglück[ENTER]verantwortlich! "
gameforge.new_quest_lv29._022_say = "Es wنre nicht die erste Dummheit, die er[ENTER]anstellt, aber dieses Mal ist er eindeutig zu[ENTER]weit gegangen. Jemand sollte ihm eine gehِrige[ENTER]Tracht Prügel verpassen! Vielleicht hast du dafür[ENTER]Zeit? "
gameforge.new_quest_lv29._023_1_select = "Aber mit Vergnügen! "
gameforge.new_quest_lv29._023_2_select = "Das geht mich nichts an. "
gameforge.new_quest_lv29._024_say = "Ich habe keine Zeit, um bِse Kinder zu erziehen.[ENTER]Du wirst ihn schon selbst einfangen müssen. Ich[ENTER]bezweifle allerdings, dass du das schaffst... "
gameforge.new_quest_lv29._030_target = "Taurean "
gameforge.new_quest_lv29._031_say = "Yonahs wertvolle Familienerbstücke, drei Vasen[ENTER]aus Seladon-Porzellan, sind zerbrochen. Er[ENTER]glaubt, dass Taurean daran schuld sei.[ENTER]Geh zu Taurean und stelle ihn zur Rede. "
gameforge.new_quest_lv29._032_say = "Taurean befindet sich in %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Warum guckst du mich so finster an? Ich habe[ENTER]nichts Bِses getan... "
gameforge.new_quest_lv29._035_say_reward = "Was hast du mit Yonahs Vasen gemacht? "
gameforge.new_quest_lv29._036_say_reward = "Vasen? Yonah? Ich weiك wirklich nicht, wovon du[ENTER]redest! "
gameforge.new_quest_lv29._037_say_reward = "Dann erklنr mir doch einmal, warum drei von ihnen[ENTER]zu Bruch gegangen sind. "
gameforge.new_quest_lv29._038_say_reward = "Ich schwِre dir, ich bin heute weder in die Nنhe[ENTER]einer Vase gekommen, noch habe ich Yonah gesehen.[ENTER]Im Gegenteil, den gesamten Tag über habe ich mit[ENTER]Harang gekنmpft. Sie hat mich sogar für ein paar[ENTER]Stunden im Heuschober eingesperrt! Geh doch und[ENTER]frag sie! Ich sage die Wahrheit! "
gameforge.new_quest_lv29._040_target = "Harang "
gameforge.new_quest_lv29._041_say = "Taurean behauptet, unschuldig zu sein: Er habe[ENTER]den ganzen Tag mit Harang gespielt und kِnne die[ENTER]Vasen daher nicht zerbrochen haben.[ENTER]Geh zu Harang und frage sie, ob das stimmt. "
gameforge.new_quest_lv29._042_say_reward = "Harang, hast du Taurean heute gesehen? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean? Ja, wir haben den ganzen Tag gespielt.[ENTER]Stimmt was nicht? "
gameforge.new_quest_lv29._045_say_reward = "Yonah sagt, dass Taurean heute drei seiner Vasen[ENTER]zerbrochen habe. "
gameforge.new_quest_lv29._046_say_reward = "Yonah ist gemein. Er verjagt Taurean und mich[ENTER]schon, wenn wir nur in seine Nنhe kommen.[ENTER]Stنndig hat er Angst um sein Porzellan.[ENTER]Seine kostbaren Vasen darf nur sein Freund, der[ENTER]Stallbursche, berühren. Vielleicht hat der sie ja[ENTER]kaputt gemacht?! "
gameforge.new_quest_lv29._047_say = "Harang befindet sich in %s. "
gameforge.new_quest_lv29._050_target = "Stallbursche "
gameforge.new_quest_lv29._051_say = "Harang hat Taureans Aussage, er sei unschuldig,[ENTER]bestنtigt. Mag sein, dass die beiden unter einer[ENTER]Decke stecken. Doch bevor du ein Urteil fنllst,[ENTER]solltest du noch Yonahs Freund, den[ENTER]Stallburschen, befragen. "
gameforge.new_quest_lv29._052_say = "Ach, der gute Yonah. Er sorgt sich um sein[ENTER]Porzellan und verdنchtigt die Dorfkinder. Dabei[ENTER]sind die Metinsteine Schuld - seitdem sie das[ENTER]Land vergiften, sind unsere Bodenschنtze nicht[ENTER]mehr das, was sie mal waren. Auch das Porzellan[ENTER]ist brüchig geworden. Doch Yonah will das nicht[ENTER]wahrhaben... "
gameforge.new_quest_lv29._053_say = "Wenn du etwas Heu für ihn sammelst, kِnnte er das[ENTER]Porzellan in seinen Truhen besser polstern.[ENTER]Auf diese Weise kannst du ihn sicher wieder milde[ENTER]stimmen. "
gameforge.new_quest_lv29._054_say = "Der Stallbursche befindet sich in[ENTER]%s oder %s. "
gameforge.new_quest_lv29._061_say = "Taurean trنgt offensichtlich keine Schuld an[ENTER]Yonahs zerbrochenen Vasen. Es liegt an der bِsen[ENTER]Strahlung der Metinsteine, die das Material[ENTER]sprِde macht.[ENTER]Sammle Heu für Yonah, damit er sein Porzellan[ENTER]besser lagern kann! Einige der Dorfbewohner[ENTER]kِnnen dir sicher welches geben. "
gameforge.new_quest_lv29._062_say = "Vor den Toren des Dorfes sind %s und %s zu[ENTER]finden. Sie tragen Strohhüte, die bestimmt eine[ENTER]akzeptable Menge Heu ergeben. "
gameforge.new_quest_lv29._063_notice = "Daraus bekomme ich ein schِnes Bündel Stroh.[ENTER]Jetzt fehlen mir nur noch %s weitere. "
gameforge.new_quest_lv29._064_notice = "Dieser Hut ist nicht aus Stroh gefertigt, sondern[ENTER]aus Kokosfasern. Das kann ich nicht gebrauchen. "
gameforge.new_quest_lv29._065_1_say = "Wie ich sehe, hast du einen Menge Heu bei dir.[ENTER]Wenn du Yonah etwas davon gibst, beruhigt er sich[ENTER]bestimmt. "
gameforge.new_quest_lv29._065_notice = "Der Hut ist nicht aus Stroh gefertigt, sondern[ENTER]aus Kokosfasern. Dazu ist er stark beschنdigt... "
gameforge.new_quest_lv29._066_say = "Du kannst auch Wilde Infanteristen oder Starke[ENTER]wilde Infanteristen tِten. Aus ihren Strohhüten[ENTER]kann man ebenfalls Heu gewinnen. "
gameforge.new_quest_lv29._067_say_reward = "Bis jetzt hast du %s von %s Bündeln Heu[ENTER]gesammelt. "
gameforge.new_quest_lv29._068_notice = "Du hast ein Bündel Heu erbeutet. "
gameforge.new_quest_lv29._070_npcChat = "Der Heuschober "
gameforge.new_quest_lv29._071_say_reward = "Taurean, du hast doch vorhin erwنhnt, dass du im[ENTER]Heuschober gewesen bist. Hast du zufنllig etwas[ENTER]Heu mitgenommen? "
gameforge.new_quest_lv29._072_say_reward = "Hihi, mal sehen... es steckte überall in meinen[ENTER]Haaren und meinen Schuhen. Siehst du? Da sind[ENTER]noch ein paar Halme. Hier nimm! "
gameforge.new_quest_lv29._073_notice = "Viel Heu ist das nicht, aber für ein kleines[ENTER]Bündel sollte es reichen. Jetzt fehlen nur noch[ENTER]%s weitere. "
gameforge.new_quest_lv29._074_say_reward = "Ich war es wirklich nicht! Hat dir Harang nicht[ENTER]gesagt, dass wir uns im Heuschober geprügelt[ENTER]haben? "
gameforge.new_quest_lv29._075_say_reward = "Du warst doch vorhin im Heuschober, oder? Hast du[ENTER]zufنllig etwas Heu von dort mitgenommen? "
gameforge.new_quest_lv29._076_say_reward = "Woher weiكt du das mit dem Heuschober?[ENTER]Habe ich etwa noch Heu in meinen Kleidern?[ENTER]Tatsنchlich, hier sind noch einige Halme! "
gameforge.new_quest_lv29._077_say_reward = "Kann ich das haben? "
gameforge.new_quest_lv29._078_say_reward = "Von mir aus... "
gameforge.new_quest_lv29._079_say_reward = "Ich habe jetzt keine Zeit. Ich muss zu Taurean[ENTER]und ihn wegen der Geschichte mit den Vasen[ENTER]beruhigen! "
gameforge.new_quest_lv29._080_npcChat = "Heu für Yonah "
gameforge.new_quest_lv29._081_say_reward = "Liegt im Stall vielleicht noch Heu, das ich Yonah[ENTER]mitbringen kِnnte? "
gameforge.new_quest_lv29._082_say_title = "صبي الإسطبل: "
gameforge.new_quest_lv29._083_say_reward = "Wir haben nicht mehr viel Heu. Die wilden Tiere[ENTER]und die Banditen ausserhalb des Dorfes[ENTER]verhindern, dass wir neues schneiden kِnnen. "
gameforge.new_quest_lv29._084_say_reward = "Aber ein klein wenig kann ich dir schon geben! "
gameforge.new_quest_lv29._085_notice = "Es ist wirklich nicht viel, aber für ein Bündel[ENTER]reicht es. Jetzt fehlen nur noch %s weitere. "
gameforge.new_quest_lv29._086_say_reward = "Ich kann leider nichts für dich tun. "
gameforge.new_quest_lv29._090_send_letter = "Heu statt Haue "
gameforge.new_quest_lv29._091_say = "Du hast genügend Heu für Yonah gesammelt.[ENTER]Geh nach %s und bringe es ihm. "
gameforge.new_quest_lv29._101_say_reward = "Taurean ist nicht der Schuldige. Die Strahlung[ENTER]der Metinsteine hat das Porzellan brüchig werden[ENTER]lassen. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Was sagst du da? Das ist kompletter Unsinn, der[ENTER]kleine Nichtsnutz hat dich angelogen. "
gameforge.new_quest_lv29._104_say_reward = "Taurean hat heute den ganzen Tag mit Harang im[ENTER]Heuschober gespielt. "
gameforge.new_quest_lv29._105_say_reward = "Ich soll dich auch von deinem Freund, dem[ENTER]Stallburschen, schِn grüssen - und ich habe dir[ENTER]etwas Heu mitgebracht, damit du deine Vasen[ENTER]besser schützen kannst. "
gameforge.new_quest_lv29._106_say_reward = "Ich gebe zu, ich schنme mich wegen meiner[ENTER]Reaktion. Aber du musst wissen, dass ich sehr an[ENTER]meinem Porzellan hنnge, da es mich an meine[ENTER]Familie erinnert. Wenn eine Vase zu Bruch geht,[ENTER]ist das für mich mehr als nur ein verlorener[ENTER]Gegenstand... "
gameforge.new_quest_lv29._107_say_reward = "Ich muss mich bei dir und Taurean entschuldigen.[ENTER]Hier hast du eine kleine Belohnung für deine[ENTER]Mühen! "
gameforge.new_quest_lv29._108_notice = "Du erhنltst einen Bonus von %s Erfahrungspunkten! "
gameforge.new_quest_lv29._109_say_reward = "Ich soll dich auch von deinem Freund, dem[ENTER]Stallburschen, schِn grüssen - und ich habe dir[ENTER]etwas Heu mitgebracht, damit du deine Vasen[ENTER]besser schützen kannst. "
gameforge.new_quest_lv29._110_say_reward = "Das ist sehr freundlich von dir, aber kannst du[ENTER]mir noch %s weitere Bündel Heu besorgen, damit[ENTER]meine Vasen wirklich sicher sind? "
gameforge.new_quest_lv29._111_say_reward = "Ich schنtze, dass es schwer werden wird, noch[ENTER]mehr Heu zu finden. Aber meine Vasen sind mir[ENTER]heilig. Ich wنre dir wirklich dankbar und würde[ENTER]dir dafür auch etwas Yang geben. "
gameforge.new_quest_lv29._112_say_reward = "Dann steckt wohl die vorlaute Gِre Harang mit[ENTER]Taurean unter einer Decke. "
gameforge.new_quest_lv29._113_say_reward = "Anscheinend glaubt mir hier niemand, wenn ich[ENTER]sage, dass ich den Jungen vorhin in der Nنhe des[ENTER]Lagerhauses gesehen habe. "
gameforge.new_quest_lv29._114_say_reward = "Lass gut sein. Hier hast du eine Entschنdigung[ENTER]für deine Mühen. "
gameforge.new_quest_lv29._115_say_reward = "Hier, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "وحوش البحر الغريبة "
gameforge.new_quest_lv42._020_target = "اكتافيو "
gameforge.new_quest_lv42._021_say = "Mein Magen knurrt wie ein Roter Keiler.[ENTER]Vielleicht sollte ich mal wieder bei Octavio[ENTER]vorbeischauen. Er macht den besten Fischeintopf[ENTER]weit und breit. "
gameforge.new_quest_lv42._022_say_title = "اكتافيو: "
gameforge.new_quest_lv42._023_say = "Du mِchtest Fischeintopf? Den mit den ganzen[ENTER]Kِpfen? Oh das tut mir leid, meine Küche hat seit[ENTER]Tagen keinen Fisch mehr gesehen. Normalerweise[ENTER]liefert der Fischer mir den guten Hochseefisch,[ENTER]den ich für meinen Eintopf verwende. "
gameforge.new_quest_lv42._024_say = "Nun hat er sich aber seit Tagen nicht blicken[ENTER]lassen. Kannst du vielleicht gehen und ihn[ENTER]fragen, was los ist? "
gameforge.new_quest_lv42._025_say = "Octavio befindet sich in %s. "
gameforge.new_quest_lv42._026_select = "Ich gehe den Fischer suchen! "
gameforge.new_quest_lv42._030_target = "الصياد "
gameforge.new_quest_lv42._031_say = "Die friedlichen Tage auf dem Meer sind vorbei![ENTER]Tنglich verschwinden Fischer, es ist schrecklich![ENTER]Seit die Metinsteine ins Meer gestürzt sind,[ENTER]haben sich friedliche Wale in grausame[ENTER]Seeungeheuer verwandelt. Das Fischen ist einfach[ENTER]zu gefنhrlich geworden. "
gameforge.new_quest_lv42._032_say = "Unsere Lanzen kِnnen die Wale nicht mehr[ENTER]verletzen. Ihre Haut ist zنher geworden als die[ENTER]eines Ogers! "
gameforge.new_quest_lv42._033_say = "Vielleicht weiك Yonah, was zu tun ist. Er ist[ENTER]früher selbst zur See gefahren und hat viele[ENTER]Jahre lang Wale gejagt. "
gameforge.new_quest_lv42._034_say_title = "الصياد: "
gameforge.new_quest_lv42._035_say = "Octavio wartet auf seinen Hochseefisch. Frage den[ENTER]Fischer, warum sich die Lieferung verzِgert. "
gameforge.new_quest_lv42._036_say = "Der Fischer befindet sich in %s. "
gameforge.new_quest_lv42._037_send_letter = "Grimmige Seeungeheuer "
gameforge.new_quest_lv42._038_say = "Der Fischer hat dich gebeten, Yonah um Rat zu[ENTER]fragen, wie die bِsartigen Wale gejagt werden[ENTER]kِnnen. "
gameforge.new_quest_lv42._039_say = "Yonah befindet sich in %s. "
gameforge.new_quest_lv42._040_target = "يوناه "
gameforge.new_quest_lv42._041_say = "Ich habe bereits gehِrt, was mit den Walen[ENTER]geschehen ist. Für die Fischer ist es eine[ENTER]schlimme Sache. Selbst wenn sie sich auf das Meer[ENTER]wagen, sind ihre Lanzen zu schwach, um die[ENTER]Walhaut zu durchdringen. Damals, als ich auf[ENTER]einem Walfنnger gearbeitet habe, nutzten wir[ENTER]spezielle Waffen - für die Wale, deren Haut[ENTER]bereits alt und narbig war. Die konnten alles[ENTER]durchdringen... "
gameforge.new_quest_lv42._042_say = "Es handelt sich um mit einer besonderen Technik[ENTER]gehنrtete Walfanglanzen. Nur der Schmied kann[ENTER]solche Lanzen herstellen. "
gameforge.new_quest_lv42._043_say_reward = "Gehe zum Schmied. "
gameforge.new_quest_lv42._044_say_title = "يوناه: "
gameforge.new_quest_lv42._045_say = "Yonah empfiehlt besonders harte und scharfe[ENTER]Lanzen für die Waljagd. Begib dich zum Schmied[ENTER]und frage ihn, ob er solche Lanzen herstellen[ENTER]kann. "
gameforge.new_quest_lv42._050_target = "الحداد "
gameforge.new_quest_lv42._051_say = "Ja, von derartigen Lanzen habe ich gehِrt und ich[ENTER]kann sie auch herstellen. Um die nِtige Hنrte zu[ENTER]erreichen, benِtige ich allerdings Diamantstein. "
gameforge.new_quest_lv42._052_say = "Ich brauche: "
gameforge.new_quest_lv42._053_say_reward = "Bearbeite dafür: "
gameforge.new_quest_lv42._054_say_title = "الحداد: "
gameforge.new_quest_lv42._060_set_title = "Diamantstein "
gameforge.new_quest_lv42._061_notice = "Mal sehen. Ich brauche eine Spitzhacke, um den[ENTER]Stein abzubauen. Habe ich meine noch irgendwo,[ENTER]oder muss ich mir bei Deokbae eine neue besorgen? "
gameforge.new_quest_lv42._062_say = "Du brauchst noch %s x Diamantstein. "
gameforge.new_quest_lv42._063_say = "Du hast alles, was du brauchst.[ENTER]Nun schnell zurück zum Schmied. "
gameforge.new_quest_lv42._064_say = "Wunderbar, das ist alles, was ich brauche. Komm[ENTER]morgen um die gleiche Zeit wieder, um die Lanze[ENTER]abzuholen. Solch ein Eisen muss wohl geschmiedet[ENTER]werden! "
gameforge.new_quest_lv42._065_say = "Du findest Diamantstein, wenn du Diamantadern mit[ENTER]der Spitzhacke bearbeitest. "
gameforge.new_quest_lv42._066_say = "Der Schmied benِtigt Diamantstein, um die[ENTER]besonderen Walfanglanzen herstellen zu kِnnen.[ENTER]Suche Diamantadern, um Diamantstein abzubauen.[ENTER]Wenn du noch keine Spitzhacke für den Bergbau[ENTER]besitzt, kannst du bei Deokbae eine erwerben. "
gameforge.new_quest_lv42._067_say = "Der Schmied befindet sich in %s. "
gameforge.new_quest_lv42._068_say = "Wir brauchen noch %s x Diamantstein, bevor wir[ENTER]mit der Arbeit an den Lanzen beginnen kِnnen. "
gameforge.new_quest_lv42._070_set_title = "Die Lanzen "
gameforge.new_quest_lv42._071_set_clock = "Wartezeit "
gameforge.new_quest_lv42._072_say = "Der Schmied sollte jetzt fertig sein mit deinem[ENTER]Auftrag. Geh zu ihm und hole die speziellen[ENTER]Walfanglanzen ab. "
gameforge.new_quest_lv42._073_say = "Die Lanzen sind leider noch nicht fertig.[ENTER]Du musst noch ein wenig Geduld aufbringen. "
gameforge.new_quest_lv42._074_say = "Hier hast du die Lanzen. Bring sie dem Fischer. "
gameforge.new_quest_lv42._075_say = "Ich habe dich doch gebeten zu warten, bis die[ENTER]Lanzen fertig sind. Komm spنter wieder. "
gameforge.new_quest_lv42._079_say = "Du hast vom Schmied die Waljagdlanzen bekommen.[ENTER]Bringe sie zum Fischer. "
gameforge.new_quest_lv42._080_say = "Wunderbar! Diese Lanzen sind wahrlich[ENTER]eindrucksvoll! Nun kِnnen wir uns endlich vor den[ENTER]Angriffen der Wale schützen und uns verteidigen.[ENTER]Richte doch bitte Octavio aus, dass er bald[ENTER]wieder mit frischem Fisch rechnen kann! "
gameforge.new_quest_lv42._081_say_reward = "Du erhنltst 500.000 Yang. "
gameforge.new_quest_lv42._082_say_reward = "Als besondere Anerkennung erhنltst du 3x: "
gameforge.new_quest_lv42._083_say = "Das sind zu wenig Lanzen, um einen Wal zu[ENTER]vertreiben. Damit kِnnen wir ihn gerade mal am[ENTER]Speck kitzeln! "
gameforge.new_quest_lv42._084_say_reward = "Bitte geh noch einmal zum Schmied und lass dir[ENTER]weitere Lanzen anfertigen. "
gameforge.new_quest_lv42._090_say = "Die Fischer sind nun gut gerüstet und kِnnen[ENTER]wieder auf dem offenen Meer jagen. Geh zu Octavio[ENTER]und beruhige ihn, dass er in Kürze neue[ENTER]Lieferungen erhalten wird. "
gameforge.new_quest_lv42._095_say = "Was sagst du da? Friedliche Wale sind zu[ENTER]aggressiven Seeungeheuern geworden? Das ist ja[ENTER]schrecklich...[ENTER]Danke, dass du den Fischern geholfen hast. Ein[ENTER]groكer Teil meiner Speisekarte ist von ihren[ENTER]Lieferungen abhنngig. "
gameforge.new_quest_lv42._096_say = "Und was deinen Hunger betrifft: Fischeintopf kann[ENTER]ich dir natürlich noch keinen bieten, aber wie[ENTER]wنre es mit etwas Sushi? "
gameforge.new_quest_lv42._098_say_reward = "Du erhنltst 750.000 Erfahrungspunkte.[ENTER]Du erhنltst 2 Stück Sushi. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "زيارة وندا-ريم "
gameforge.new_quest_lv43._006_send_letter = "اليتيم "
gameforge.new_quest_lv43._010_target = "وندا-ريم "
gameforge.new_quest_lv43._011_say = "Du hast lange nichts von Wonda-Rim gehِrt.[ENTER]Vielleicht hat sich das Verhنltnis zu seinem[ENTER]Onkel mittlerweile gebessert und die Episode mit[ENTER]den Mu-Rang-Fellen ist vergessen.[ENTER]Besuche ihn doch einmal. "
gameforge.new_quest_lv43._012_say = "Wonda-Rim befindet sich in %s. "
gameforge.new_quest_lv43._020_say = "Schِn, dass du wieder vorbeischaust. "
gameforge.new_quest_lv43._021_say_title = "وندا-ريم: "
gameforge.new_quest_lv43._022_say = "Ich bin bei meinem Onkel Chaegirab aufgewachsen.[ENTER]Im Grunde hatten wir stets ein gutes Verhنltnis[ENTER]zueinander... aber wenn ich nach meinen Eltern[ENTER]frage, weicht er mir aus. Sie sind tot - das ist[ENTER]auch schon alles, was er mir verrنt. "
gameforge.new_quest_lv43._023_say_reward = "Irgendwann will ich aber auch heiraten und eine[ENTER]Familie gründen. Ich sollte daher wissen, wer ich[ENTER]bin, woher ich stamme. Kannst du mit meinem Onkel[ENTER]reden und ihn nach meinen Eltern fragen? Aber[ENTER]verrate bitte nicht, dass ich dich schicke. "
gameforge.new_quest_lv43._024_select = "Ich werde mit ihm sprechen! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim ist nicht der leibliche Neffe[ENTER]Chaegirabs, er ist nur bei ihm aufgewachsen.[ENTER]Es ist nun an der Zeit für ihn, zu erfahren, wer[ENTER]seine wahren Eltern sind. Befrage Chaegirab zu[ENTER]Wonda-Rims Herkunft. "
gameforge.new_quest_lv43._026_say = "Chaegirab befindet sich in %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... ja, ich bin nicht sein richtiger[ENTER]Onkel. Wer seine Eltern sind, weiك ich nicht.[ENTER]Bisher habe ich ihn mit der Wahrheit geschont, da[ENTER]er noch nicht bereit war, sie zu erfahren. Aber[ENTER]vielleicht ist es nun an der Zeit. "
gameforge.new_quest_lv43._033_say = "Ich hab ihn im Tal von Seungryong gefunden, bei[ENTER]einer Horde von Ork-Kنmpfern. Wenn sich noch[ENTER]Hinweise auf Wonda-Rims Herkunft finden lassen,[ENTER]dann dort bei den Orks. "
gameforge.new_quest_lv43._034_say = "Auch wenn ich streng zu ihm bin, werde ich ihm[ENTER]doch immer ein Onkel sein. Sogar, wenn er[ENTER]weiterhin so ein Taugenichts bleibt. "
gameforge.new_quest_lv43._035_say_reward = "Begib dich ins Tal von Seungryong und jage dort[ENTER]Ork-Kنmpfer, bis du einen Hinweis auf Wonda-Rims[ENTER]Abstammung findest. "
gameforge.new_quest_lv43._036_say = "In der verschmutzten Tasche eines erschlagenen[ENTER]Ork-Kنmpfers hast du einen alten Brief entdeckt.[ENTER]Er ist kaum noch zu entziffern, aber du kannst[ENTER]den Namen Wonda-Rim darauf erkennen. Das ist der[ENTER]benِtigte Hinweis, bringe ihn zu Wonda-Rim. "
gameforge.new_quest_lv43._041_say = "Dann los! Die beste Mِglichkeit, etwas über[ENTER]Wonda-Rims Herkunft zu erfahren, besteht wohl[ENTER]darin, Ork-Kنmpfer zu tِten. Vielleicht tragen[ENTER]sie einen entsprechenden Hinweis bei sich! "
gameforge.new_quest_lv43._043_notice = "Hinweise auf Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "Ich hab dir alles gesagt, was ich weiك. Der[ENTER]einzige Anhaltspunkt, den wir haben, sind die[ENTER]Ork-Kنmpfer. Nur kann man leider nicht vernünftig[ENTER]mit denen reden... "
gameforge.new_quest_lv43._049_say = "Ein Brief? Mal sehen... Die Schriftzeichen sind[ENTER]undeutlich... Es geht um einen ـberfall, Orks[ENTER]haben die Farm niedergebrannt, nun rennen sie um[ENTER]ihr Leben. Sie mussten ihr Kind zurücklassen...[ENTER]Und hier steht mein Name. "
gameforge.new_quest_lv43._050_say = "Danke, dass du mir das gebracht hast. Nun weiك[ENTER]ich endlich, was passiert ist. "
gameforge.new_quest_lv43._051_say = "Ich sollte mit Chaegirab sprechen. Er hat[ENTER]offensichtlich einige Gefahren auf sich genommen,[ENTER]um mich zu retten. Ich werde versuchen, ihm ein[ENTER]besserer Neffe zu sein. Bis bald, Freund! "
gameforge.new_quest_lv43._052_say_title = "معلومات: "
gameforge.new_quest_lv43._053_say_reward = "Du erhنltst 32.000 Yang. "
gameforge.new_quest_lv43._054_say_reward = "Du erhنltst 1.250.000 Erfahrungspunkte. "
gameforge.new_quest_lv43._060_say = "Hast du mit meinen Onkel Chaegirab[ENTER]gesprochen? Ein Hinweis? Wovon[ENTER]redest du? Wenn du nichts[ENTER]vorzuweisen hast, solltest du dich[ENTER]mit Vermutungen zurückhalten![ENTER]Bitte frage nochmal meinen Onkel.[ENTER]Schlieكlich bezahle ich dich dafür. "
