gameforge.new_quest_lv52._020_say_title = "Treuer Landsmann "
gameforge.new_quest_lv52._021_say_reward = "Ich mِchte dich bitten, mir einen Gefallen zu[ENTER]erweisen. Ich kann nachts nicht mehr schlafen,[ENTER]trotz der Medizin von Baek-Go wنlze ich mich nur[ENTER]herum. Kannst du ihn aufsuchen und nach einem[ENTER]stنrkeren Schlafmittel für mich fragen? "
