gameforge.new_quest_lv52._030_set_title = "Nachtruhe "
gameforge.new_quest_lv52._035_target = "بايك-غو "
gameforge.new_quest_lv52._040_say = "Der Hauptmann hat Probleme, nachts[ENTER]durchzuschlafen. Geh zu Baek-Go und frage ihn[ENTER]nach einem stنrkeren Schlafmittel für den[ENTER]Hauptmann. "
gameforge.new_quest_lv52._041_say = "Ein Schlafmittel für den Hauptmann? Ich habe[ENTER]leider nichts Stنrkeres, das ich dir überlassen[ENTER]kِnnte. Nur Yu-Hwan kِnnte auf Krنuterbasis etwas[ENTER]herstellen, das die gewünschte Wirkung zeigt. "
gameforge.new_quest_lv52._042_say = "Ah, du hast meinen Brief erhalten. Ich weiك[ENTER]wirklich nicht mehr weiter. Ich finde des Nachts[ENTER]einfach keine Ruhe mehr. Bitte hilf mir und frage[ENTER]Baek-Go um Rat. "
gameforge.new_quest_lv52._042_select = "Dann gehe ich besser zu Yu-Hwan! "
gameforge.new_quest_lv52._043_say = "Baek-Go befindet sich in %s. "
gameforge.new_quest_lv52._044_say_title = "بايك-غو: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan befindet sich in %s. "
gameforge.new_quest_lv52._046_say = "Dann geh zum Hauptmann und sag ihm, dass du[ENTER]ihm nicht helfen kannst. "
gameforge.new_quest_lv52._049_say_title = "يو-هوان: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan "
gameforge.new_quest_lv52._051_say = "Baek-Go hat keine stنrkere Medizin mehr im[ENTER]Sortiment. Aber womِglich kann Yu-Hwan helfen,[ENTER]wenn er ein Kraut kennt, das die gewünschte[ENTER]Wirkung besitzt. "
gameforge.new_quest_lv52._052_say = "Ich kenne den Hauptmann gut. Wie du sicher weiكt,[ENTER]erledige ich bereits seit langer Zeit geheime[ENTER]Auftrنge für ihn. Daher kann ich dir sagen, dass[ENTER]Krنuter ihm bei seinem Problem nicht helfen[ENTER]werden. "
gameforge.new_quest_lv52._053_say = "Es gibt einen anderen Grund, warum der Hauptmann[ENTER]nicht mehr schlafen kann. Und glaub mir, er kennt[ENTER]ihn selbst sehr gut. Aber das ist eine Sache, die[ENTER]er klنren muss - ich kann es nicht für ihn tun.[ENTER]Geh zu ihm und sprich ihn darauf an. "
gameforge.new_quest_lv52._054_say_title = "Hauptmann: "
gameforge.new_quest_lv52._055_say_reward = "Ah, du hast meinen Brief erhalten. Ich weiك[ENTER]wirklich nicht mehr weiter. Bitte geh und frage[ENTER]Baek-Go um Rat, damit ich nachts wieder Schlaf[ENTER]finde. "
gameforge.new_quest_lv52._055_select = "Ja, Sir! "
gameforge.new_quest_lv52._056_say = "Ich danke dir! "
gameforge.new_quest_lv52._056_say_reward = "Das habe ich bereits getan, aber er hat keine[ENTER]stنrkere Medizin in seinem Sortiment. Aber ich[ENTER]werde Yu-Hwan aufsuchen und fragen, ob er helfen[ENTER]kann. "
gameforge.new_quest_lv52._060_target = "Hauptmann "
gameforge.new_quest_lv52._061_say = "Yu-Hwan will keine Geheimnisse ausplaudern,[ENTER]wahrscheinlich geht es um etwas Unangenehmes.[ENTER]Aber es hilft nichts: Du musst mit dem Hauptmann[ENTER]darüber sprechen. Ohne Kenntnis der Ursache kann[ENTER]es keine Lِsung des Schlafproblems geben.[ENTER]Also auf nach %s. "
gameforge.new_quest_lv52._062_say_reward = "Es gibt kein stنrkeres Schlafmittel mehr. Aber[ENTER]vielleicht kann ich euch helfen, Hauptmann, wenn[ENTER]ich den Grund für eure Schlaflosigkeit erfahre. "
gameforge.new_quest_lv52._063_say_reward = "Das ist nichts, was ich einem jungen Mann wie dir[ENTER]gerne erzنhlen würde. "
gameforge.new_quest_lv52._064_say_reward = "Das ist nichts, was ich einer jungen Frau wie dir[ENTER]gerne erzنhlen würde. "
gameforge.new_quest_lv52._065_say_reward = "Aber wenn ich nicht bald durchschlafe, werde ich[ENTER]früher oder spنter den Verstand verlieren. Es[ENTER]muss wohl sein...[ENTER]Aber denk daran, dies ist nur für deine Ohren[ENTER]bestimmt: Jede Nacht werde ich von vier Geistern[ENTER]heimgesucht. Das ist aber noch nicht das[ENTER]Schlimmste... Ich bin für ihren Tod[ENTER]verantwortlich. "
gameforge.new_quest_lv52._066_say_reward = "Es sind vier Soldaten. Sie sagen, dass sie im Tal[ENTER]von Seungryong von Beschwِrern und Peinigern[ENTER]gefoltert und getِtet wurden. Ich war derjenige,[ENTER]der sie dorthin beordert hat - in ihren Tod! "
gameforge.new_quest_lv52._067_say_reward = "Was tun gegen solche Geister? "
gameforge.new_quest_lv52._068_say_reward = "Sie wollen Rache! Aber was kann ich tun? Wenn ich[ENTER]nun losziehe, um Vergeltung zu üben, ist das Dorf[ENTER]ohne Führung und wird überrannt. Gehe ich nicht,[ENTER]werde ich noch verrückt. "
gameforge.new_quest_lv52._069_say_reward = "Wenn ich nicht für den Schutz des Dorfes mit all[ENTER]seinen Bewohnern verantwortlich wنre, würde ich[ENTER]sofort gehen. So sehe ich nur einen Ausweg: "
gameforge.new_quest_lv52._070_say_reward = "Jemand anderes muss an meiner Stelle Rache üben![ENTER]Aber wie kann ich weitere Mنnner in dieses Tal[ENTER]und somit in ihr Verderben schicken!? Wie kann[ENTER]ich das verlangen, nur damit ich ruhig schlafen[ENTER]kann? "
gameforge.new_quest_lv52._071_say_reward = "So eine Entscheidung ist nicht leicht. "
gameforge.new_quest_lv52._080_1_select = "Das Wohl des Dorfes... "
gameforge.new_quest_lv52._080_2_select = "Es wird ein Leichtes sein... "
gameforge.new_quest_lv52._080_3_select = "Das kann man nicht verlangen! "
gameforge.new_quest_lv52._081_say_reward = "...wiegt mehr als eure Skrupel. Ich werde eure[ENTER]Mنnner rنchen. Und wenn ich nicht wiederkomme,[ENTER]sehen wir uns heute Nacht! "
gameforge.new_quest_lv52._082_say_reward = "...mit diesen Beschwِrern und Peinigern fertig zu[ENTER]werden. Heute Nacht werdet ihr gut schlafen, das[ENTER]verspreche ich euch! "
gameforge.new_quest_lv52._083_say_reward = "Es grenzt an Selbstmord, sich mit Beschwِrern und[ENTER]Peinigern anzulegen. Versucht den Geistern zu[ENTER]verdeutlichen, wie sehr ihr hier gebraucht[ENTER]werdet! "
gameforge.new_quest_lv52._084_say_reward = "Ihr habt recht. Dennoch hatte ich gehofft, ihr[ENTER]würdet euch freiwillig melden und dem Dorf und[ENTER]mir somit einen groكen Dienst erweisen. "
gameforge.new_quest_lv52._090_1_select = "Nun gut... "
gameforge.new_quest_lv52._090_2_select = "Nein, das schaffe ich nicht! "
gameforge.new_quest_lv52._091_say_reward = "...wenn ich eure letzte Hoffnung bin, dann werde[ENTER]ich diese Beschwِrer und Peiniger für euch[ENTER]erledigen! "
gameforge.new_quest_lv52._092_say_reward = "Wenn ich das versuche, würde euch noch ein[ENTER]weiterer Geist heimsuchen. "
gameforge.new_quest_lv52._093_say_reward = "Nun gut. Lass mich dich dennoch für deine Mühe[ENTER]mit etwas Yang belohnen. "
gameforge.new_quest_lv52._093_say_reward_exp = "Du erhنltst 20.000 Erfahrungspunkte. "
gameforge.new_quest_lv52._093_say_reward_gold = "Du erhنltst 25.000 Yang. "
gameforge.new_quest_lv52._100_notice = "Das Gesprنch wurde beendet. "
gameforge.new_quest_lv52._110_say_reward = "Ich hatte gehofft, dass du so etwas sagst. Leider[ENTER]weiك ich nicht, welcher Beschwِrer oder Peiniger[ENTER]sie getِtet hat. Ich hoffe, dass ich es spüren[ENTER]werde, wenn einer der Geister erlِst wird. "
gameforge.new_quest_lv52._111_say_reward = "Ich werde dir einen Brief zukommen lassen.[ENTER]Die Geister teilten mir mit, dass die Rache im[ENTER]Dreieck des Drachgottes erfolgen muss. Dort[ENTER]befinden sich drei Sنulen, die anscheinend die[ENTER]Eckpunkte des Dreiecks bilden. "
gameforge.new_quest_lv52._120_set_title = "Rنche 4 Gefallene "
gameforge.new_quest_lv52._125_say_title = "Brief vom Hauptmann "
gameforge.new_quest_lv52._130_say_reward = "Noch 3 Soldaten zu rنchen! "
gameforge.new_quest_lv52._131_say = "Du scheinst Erfolg gehabt zu haben. Soeben habe[ENTER]ich die Stimme eines meiner gefallenen Soldaten[ENTER]vernommen. Er sagte, dass er mir verzeiht, da[ENTER]sein Tod nun gerنcht wurde. Dies ist einzig dein[ENTER]Verdienst! "
gameforge.new_quest_lv52._132_say = "Bitte rنche auch die anderen gefallenen Soldaten[ENTER]und tِte Dunkle Peiniger, Dunkle Beschwِrer, Hohe[ENTER]Peiniger und Hohe Beschwِrer. Denke dabei stets[ENTER]daran, dass du sie nur im Dreieck der drei groكen[ENTER]Sنulen des Drachengottes erlِsen kannst. "
gameforge.new_quest_lv52._140_say_reward = "Noch 2 Soldaten zu rنchen! "
gameforge.new_quest_lv52._141_say = "Wieder hast du einen der Mِrder meiner Soldaten[ENTER]erwischt! Mir war, als hنtte ich im Dنmmerlicht[ENTER]einen der Gefallenen gesehen, der die Hand zum[ENTER]Abschied erhoben hatte. "
gameforge.new_quest_lv52._150_say_reward = "Noch 1 Soldat zu rنchen! "
gameforge.new_quest_lv52._151_say = "Du bist unglaublich! Gerade eben noch stand der[ENTER]Geist eines gefallenen Soldaten neben mir und hat[ENTER]sich von mir verabschiedet. Vermutlich wird es[ENTER]nun sehr schwer sein, auch den letzten der Mِrder[ENTER]zu finden. "
gameforge.new_quest_lv52._160_say = "Die Geister, die den Hauptmann plagen, sind[ENTER]diejenigen junger Soldaten, die in seinem Auftrag[ENTER]fielen. Sie wurden von Dunklen Peinigern, Dunklen[ENTER]Beschwِrern, Hohen Peinigern und Hohen[ENTER]Beschwِrern getِtet. "
gameforge.new_quest_lv52._161_say = "Du musst es schaffen, die verantwortlichen[ENTER]Peiniger und Beschwِrer im Dreieck der drei[ENTER]Sنulen des Drachengottes zu erledigen, um die[ENTER]Soldaten zu rنchen. "
gameforge.new_quest_lv52._162_say = "Das Dreieck des Drachengottes befindet sich in[ENTER]der Mitte des Tals von Seungryong. "
gameforge.new_quest_lv52._170_send_letter = "Erster Soldat gerنcht "
gameforge.new_quest_lv52._171_send_letter = "Zweiter Soldat gerنcht "
gameforge.new_quest_lv52._172_send_letter = "Dritter Soldat gerنcht "
gameforge.new_quest_lv52._173_send_letter = "Alle Soldaten gerنcht "
gameforge.new_quest_lv52._180_say_reward = "Du hast alle 4 Soldaten gerنcht! "
gameforge.new_quest_lv52._181_say = "Du hast auch den letzten der Mِrder gefunden![ENTER]Der letzte der vier gefallenen Soldaten ist mir[ENTER]soeben erschienen und bat mich, dir für deinen[ENTER]Mut zu danken. Er hat auch etwas für dich[ENTER]hinterlassen: %s "
gameforge.new_quest_lv52._182_say = "Komm zu mir, um deine Belohnung in Empfang zu[ENTER]nehmen. Ich warte auf dich in %s. "
gameforge.new_quest_lv52._183_say_reward = "Du hast mir und dem Dorf einen groكen Dienst[ENTER]erwiesen. Hier ist die Belohnung, die mir der[ENTER]Geist für dich überreicht hat: %s "
gameforge.new_quest_lv52._184_say_reward = "Und hier ist noch etwas Yang von mir. Ich werde[ENTER]mich nun zurückziehen und endlich in Ruhe[ENTER]schlafen. "
gameforge.new_quest_lv52._185_say_reward = "Ich stehe tief in deiner Schuld, mein Sohn. "
