gameforge.new_quest_lv54._040_set_title = "Nachschub "
gameforge.new_quest_lv54._050_target = "تاجرة البضائع المختلفة "
gameforge.new_quest_lv54._051_say = "Ja, in der letzten Zeit bereiten mir die[ENTER]Nachschublieferungen groكe Schwierigkeiten. Die[ENTER]Handelswege sind unsicher geworden, immer[ENTER]hنufiger tauchen Wegelagerer und wilde Bestien[ENTER]auf. Vor allem gegen die Tiger haben die[ENTER]fahrenden Hنndler, von denen ich meine Waren[ENTER]beziehe, keine Chance. "
gameforge.new_quest_lv54._052_say = "Vielleicht kann der Hauptmann mit seinen Soldaten[ENTER]helfen. Geh bitte zu ihm und frage ihn, ob er[ENTER]Soldaten abstellen kann, um die Hنndler zu[ENTER]schützen. "
gameforge.new_quest_lv54._054_say = "Geh zur Gemischtwarenhنndlerin und bringe in[ENTER]Erfahrung, warum der Nachschub an Trنnken ins[ENTER]Stocken geraten ist. "
gameforge.new_quest_lv54._055_say = "Die Gemischtwarenhنndlerin befindet sich in[ENTER]%s. "
gameforge.new_quest_lv54._056_say_title = "Hauptmann: "
gameforge.new_quest_lv54._060_say = "Die Handelswege sichern? Ja... im Grunde würde[ENTER]ich das gerne tun. Nur verfüge ich nicht über[ENTER]genügend Soldaten, um auch noch die fahrenden[ENTER]Hنndler aus anderen Reichen zu schützen. "
gameforge.new_quest_lv54._061_say = "Darüber hinaus dürfen wir Soldaten keine Tiger[ENTER]jagen. Dies ist alleine den Jنgern der Jنgergilde[ENTER]gestattet. Es wنre nicht fِrderlich für den[ENTER]Frieden im Dorf, gegen diese Bestimmungen zu[ENTER]verstoكen. "
gameforge.new_quest_lv54._062_say_reward = "Du müsstest dich daher an Yang-Shin wenden.[ENTER]Er ist Mitglied der Jنgergilde. Vielleicht kann[ENTER]er dir helfen, die Probleme mit den Tigern in den[ENTER]Griff zu bekommen. "
gameforge.new_quest_lv54._064_say = "Geh zum Hauptmann und versuche ihn zu überreden,[ENTER]die Handelswege gegen Tiger zu sichern. "
gameforge.new_quest_lv54._065_say = "Der Hauptmann befindet sich in %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin "
gameforge.new_quest_lv54._071_say = "Viele meiner Jنger sind als Krieger einberufen[ENTER]worden und im Kampf gefallen. Nun ist es beinahe[ENTER]unmِglich geworden, die Population der Wildtiere[ENTER]im Gleichgewicht zu halten. Besonders die[ENTER]Raubkatzen breiten ihre Reviere aus und gefنhrden[ENTER]Reisende. "
gameforge.new_quest_lv54._072_say = "Wenn du uns in dieser Sache hilfst, kann ich dir[ENTER]als Belohnung diesen wertvollen Tigerschild+3[ENTER]meines gefallenen Kameraden Mi-Song anbieten.[ENTER]Dafür müsstest du die Tigerpopulation spürbar[ENTER]dezimieren. "
gameforge.new_quest_lv54._073_say = "Besonders Verfluchte weiكe Tiger haben sich[ENTER]unkontrolliert vermehrt. "
gameforge.new_quest_lv54._074_say = "Ich brauche als Beweis: "
gameforge.new_quest_lv54._075_say = "للحصول عليه اصطد: "
gameforge.new_quest_lv54._076_say = "Suche Yang-Shin und versuche ihn zu überreden,[ENTER]die Handelswege gegen Tiger zu sichern. "
