gameforge.new_quest_lv7._020_say_title = "Die Hochzeit der Tochter "
gameforge.new_quest_lv7._021_say = "Habt ihr Kinder? Dann würdet ihr meine Sorge[ENTER]sicher verstehen... es geht um meine Tochter![ENTER]Sie hat diesen Mann kennengelernt, der ihr vِllig[ENTER]den Kopf verdreht hat. Und nun ist sie mit ihrem[ENTER]Geliebten durchgebrannt. "
gameforge.new_quest_lv7._022_say = "Er stammt aus Chunjo. Natürlich war ich dagegen![ENTER]Eine Dame aus Shinsoo kann doch keinen[ENTER]vergeistigten Trنumer aus Chunjo heiraten, dachte[ENTER]ich. Wir trennten uns im Streit, sie ist mit ihm[ENTER]geflohen. "
gameforge.new_quest_lv7._023_say = "Er stammt aus Jinno. Natürlich war ich dagegen![ENTER]Eine Dame aus Chunjo kann doch keinen tumben[ENTER]Rohling aus Jinno heiraten, dachte ich. Wir[ENTER]trennten uns im Streit, sie ist mit ihm geflohen. "
gameforge.new_quest_lv7._024_say = "Er stammt aus Shinsoo. Natürlich war ich dagegen![ENTER]Eine Dame aus Jinno kann doch keinen[ENTER]geldscheffelnden Weichling aus Shinsoo heiraten,[ENTER]dachte ich. Wir trennten uns im Streit, sie ist[ENTER]mit ihm geflohen. "
gameforge.new_quest_lv7._030_say = "Ich habe gehِrt, dass sie ihn heiraten will. "
gameforge.new_quest_lv7._031_say = "Nun wartet meine Tochter auf ein Zeichen von mir.[ENTER]Was soll ich tun? Sie ist mein einziges Kind![ENTER]Natürlich werde ich ihr meinen Segen geben.[ENTER]Bitte gehe für mich zur Alten Frau und bitte sie,[ENTER]bei den Hochzeitsvorbereitungen zu helfen. "
gameforge.new_quest_lv7._040_target = "Alte Frau "
gameforge.new_quest_lv7._041_say = "Suche die alte Frau auf und bitte sie, die[ENTER]Hochzeitsvorbereitungen zu treffen. "
gameforge.new_quest_lv7._042_say = "Die alte Frau befindet sich in %s. "
gameforge.new_quest_lv7._051_say = "Eine Hochzeit, sagst du? Nun, das ist ein[ENTER]wichtiger Moment im Leben einer Frau. Alles muss[ENTER]stimmen, angefangen vom Brautkleid und dem[ENTER]Smoking des Brنutigams bis zu den[ENTER]Verlobungsringen, die durch die Zeremonie zu[ENTER]Eheringen werden. Wenn der Brautvater sein[ENTER]Einverstنndnis erklنrt hat und die nِtigen Yang[ENTER]für die Zeremonie zur Verfügung stellt, so kann[ENTER]das Fest ausgerichtet werden. "
gameforge.new_quest_lv7._052_say = "Besonders wichtig sind Blumen - ohne einen[ENTER]Brautstrauك, vom Brنutigam an seine Liebste[ENTER]überreicht, kann keine Hochzeit stattfinden.[ENTER]Der Strauك sollte folgende Blumen enthalten: "
