gameforge.new_quest_lv7._055_say = "للحصول عليه اصطد: "
gameforge.new_quest_lv7._056_say = "Ich brauche auch noch: "
gameforge.new_quest_lv7._060_say = "Komm wieder zu mir, wenn du alle drei Blumen[ENTER]besorgt hast. Ich sehe nach, ob die Blüten frisch[ENTER]genug sind und binde dann ein hübsches Bouquet[ENTER]daraus. Das kannst du anschlieكend zu meiner[ENTER]Schwester bringen. Sie wird die Zeremonie[ENTER]durchführen. "
gameforge.new_quest_lv7._081_say = "Sammle jeweils eine Blume von jeder Sorte. Du[ENTER]erhنltst sie, indem du Hungrige Alpha-Wِlfe,[ENTER]Hungrige Blauwِlfe und Hungrige Alpha-Blauwِlfe[ENTER]tِtest. "
