gameforge.new_quest_lv7._160_say = "Du musst mich mit einem entfernten Verwandten[ENTER]verwechseln. Ich habe keine Tochter und besitze[ENTER]auch nicht genügend Yang, um eine Hochzeit[ENTER]ausrichten zu kِnnen. "
gameforge.new_quest_lv7._165_say = "Aber mِchtest du nicht mein Gast sein und einen[ENTER]Lِffel Ochsenfroschsuppe probieren? Ich habe sie[ENTER]nach einem alten Rezept meiner Tante zubereitet. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young "
gameforge.new_quest_lv75._020_set_title = "Tagebuch einer Legende "
gameforge.new_quest_lv75._021_say = "Ich habe die ـberreste eines Kriegers gefunden.[ENTER]Ich weiك nicht, ob es sich um diesen Sura[ENTER]handelt, den Heuk-Young sucht, aber interessieren[ENTER]wird es sie bestimmt. "
gameforge.new_quest_lv75._022_say = "Hier sind mehr als nur ein Sura gestorben. Ihre[ENTER]ـberreste habe ich ja gesehen. Ob dieser[ENTER]legendنre Krieger wohl auch unter ihnen ist?[ENTER]Ich sollte Heuk-Young davon berichten gehen. "
gameforge.new_quest_lv75._023_say = "Ich habe ein altes Stück Papier gefunden,[ENTER]eingefroren in einem Unterwelt-Eisgolem.[ENTER]Ich kann es kaum lesen, aber es kِnnte sich dabei[ENTER]um einen Hinweis handeln, der Heuk-Young[ENTER]interessiert. "
gameforge.new_quest_lv75._024_say = "Inzwischen habe ich einiges gefunden, was[ENTER]Heuk-Young interessieren kِnnte. Ich sollte zu[ENTER]ihr gehen und ihr das Stück Papier geben. Dabei[ENTER]kann ich ihr auch gleich von der Leiche erzنhlen. "
gameforge.new_quest_lv75._025_say = "Heuk-Young hat mich gebeten, die Augen nach[ENTER]Hinweisen auf diesen legendنren Sura offen zu[ENTER]halten. Leider habe ich keine Ahnung, wonach ich[ENTER]überhaupt suche... "
gameforge.new_quest_lv75._030_say = "Suche nach dem legendنren Kنmpfer Akuma. Er war[ENTER]womِglich der berühmteste Sura, der je gelebt hat[ENTER]- ein nahezu unbesiegbarer Krieger. Man sagt,[ENTER]dass er sogar den Kaiser herausgefordert hat. Ich[ENTER]denke, dass dieser Ort hier jener ist, an dem[ENTER]Akuma vor mehreren hundert Jahren verschwunden[ENTER]ist. Halte bitte Ausschau nach Spuren, die[ENTER]vielleicht nach all diesen Jahren noch auf seinen[ENTER]Aufenthalt hinweisen kِnnen. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Gefallenen Krieger betrachten "
gameforge.new_quest_lv75._060_say = "Es handelt sich um die ـberreste eines Kriegers.[ENTER]Der linke Arm sieht jedoch nicht menschlich[ENTER]aus... es muss ein Sura gewesen sein. Davon muss[ENTER]ich Heuk-Young erzنhlen. "
gameforge.new_quest_lv75._070_notice = "Eine Buchseite... eingefroren in den ـberresten[ENTER]des Unterwelt-Eisgolems... "
gameforge.new_quest_lv75._090_say = "Ich kann auch nicht sagen, wonach wir genau[ENTER]suchen. Sieh dich einfach um und komm wieder zu[ENTER]mir, wenn du etwas gefunden hast. "
gameforge.new_quest_lv75._100_say = "Was hast du da? Lass mich sehen! "
gameforge.new_quest_lv75._105_say = "Eine Notiz… was ist das für eine Schrift? Sie[ENTER]muss ziemlich alt sein. Es kِnnte sein, dass du[ENTER]wirklich etwas Wichtiges gefunden hast. Das, was[ENTER]hier geschrieben steht, kommt mir bekannt vor. Es[ENTER]sieht so aus, als wنre diese Seite früher einmal[ENTER]Teil eines Buches gewesen. "
gameforge.new_quest_lv75._109_say = "Wenn wir mehr Seiten finden würden, kِnnte das[ENTER]alles einen Sinn ergeben. Halte Ausschau, auch[ENTER]nach weiteren Hinweisen! "
gameforge.new_quest_lv75._110_say = "Da bist du ja wieder. Du hast etwas gefunden?[ENTER]Erzنhl! "
gameforge.new_quest_lv75._115_say = "Ein toter Sura… es kِnnte sein, dass er es ist,[ENTER]oder einer aus seinem Gefolge. Aber wir brauchen[ENTER]mehr Beweise, um sicher zu sein. Suche nach[ENTER]weiteren Hinweisen, von denen man auf seine[ENTER]Identitنt schlieكen kann. Waffen, Schmuck...[ENTER]vielleicht Notizen oder ؤhnliches. "
gameforge.new_quest_lv75._120_say = "Die Leiche eines Sura und eine Buchseite? Lass[ENTER]mich einen Blick auf das Pergament werfen...[ENTER]Hmm, es kِnnte tatsنchlich sein, dass du Akumas[ENTER]ـberreste gefunden hast. Allerdings brauchen wir[ENTER]noch mehr Beweise. Schau bitte nach, ob du[ENTER]weitere Buchseiten finden kannst. "
gameforge.new_quest_lv75._130_say = "Ich habe bereits einen Anhaltspunkt gefunden, bin[ENTER]mir aber nicht sicher, ob dieser legendنre Sura[ENTER]wirklich hier gewesen ist. Ich brauche mehr[ENTER]Informationen. "
gameforge.new_quest_lv75._140_1_select = "Gut. "
gameforge.new_quest_lv75._140_2_select = "Wesen aus Eis "
gameforge.new_quest_lv75._140_3_select = "Am Rande der Verzweiflung "
gameforge.new_quest_lv75._140_4_select = "Dunkle Schrecken "
gameforge.new_quest_lv75._140_5_select = "Das Angesicht des Todes "
gameforge.new_quest_lv75._140_6_select = "Das Schicksal des Kriegers "
gameforge.new_quest_lv75._140_7_select = "Nein, ich habe kein Interesse daran. "
gameforge.new_quest_lv75._150_say = "Ich kann hier nur Satzfetzen entziffern. Etwas[ENTER]von hِfischem Leben und übertriebener[ENTER]Abenteuerlust... "
gameforge.new_quest_lv75._160_1_say = "Die Schrift auf dem vergilbten Pergament ist[ENTER]verblasst und zittrig, so als stamme sie von[ENTER]einem sehr alten oder sehr schwachen Menschen:[ENTER]\"...Wesen aus Eis. Selbst meine Fنhigkeiten als[ENTER]Sura haben mir nicht geholfen, sie alle zu[ENTER]besiegen. Einige von ihnen streifen noch durch[ENTER]diese Hِhlen und wehe, sollten sie mich finden.[ENTER]Bisher bietet mir mein Versteck Schutz, doch[ENTER]bald...\" An dieser Stelle verblasst die Schrift. "
gameforge.new_quest_lv75._160_2_say = "Auch diese Seite ist durch ihr Alter stark in[ENTER]Mitleidenschaft gezogen. An dem Datum in der[ENTER]oberen Ecke erkennst du, dass es sich um eine Art[ENTER]Tagebuch handelt: \"Nicht zum ersten Mal wünsche[ENTER]ich mir, damals anders gehandelt zu haben, als[ENTER]ich die Grotte suchte. Wie stolz war ich, wie[ENTER]prahlerisch und selbstverliebt! All jene[ENTER]Eigenschaft haben mich hierher geführt, in meinen[ENTER]sicheren Tod...\" Das letzte Wort ist mehrmals[ENTER]dick unterstrichen. "
gameforge.new_quest_lv75._160_3_say = "Die Pergamentseite weist starke Beschنdigungen[ENTER]auf, teilweise sind Stücke herausgerissen worden.[ENTER]Du kannst nur Teile der Botschaft entziffern:[ENTER]\"...Hof des Kaisers... als die Gelehrten mir[ENTER]beibrachten, was ich so innig zu wissen[ENTER]begehrte... leicht, die Portale zu ِffnen,[ENTER]doch... Tod und Schrecken in der Dunkelh...\" Ein[ENTER]dicker, gezackter Riss verbirgt den Rest der[ENTER]Worte vor dir. "
gameforge.new_quest_lv75._160_4_say = "Auf dieser Pergamentseite findest du eine[ENTER]Zeichnung: Das lنchelnde Gesicht einer Frau.[ENTER]Darunter stehen Worte in der Schrift geschrieben,[ENTER]die dir bereits bekannt ist. Nur scheint sie[ENTER]dieses Mal noch zittriger und unsicherer zu sein:[ENTER]\"Der Tod hat Klauen – ich weiك es seit gestern.[ENTER]Nur einen Blick habe ich auf die Kreatur[ENTER]geworfen, ehe die Angst mich hierher zurück[ENTER]trieb. Oh meine geliebte Sunmi, wenn ich gewusst[ENTER]hنtte! Wenn ich dieses unsنgliche Grauen zuvor[ENTER]gekannt hنtte, niemals wنre ich hier herab[ENTER]gestiegen!\" "
gameforge.new_quest_lv75._160_5_say = "Wنhrend der Hee-Se Dynastie lebte ein legendنrer[ENTER]Sura namens Akuma. Er war so talentiert im Kampf,[ENTER]dass sich mit der Zeit nur noch wenige Gegner[ENTER]fanden, an denen er sich messen konnte. So suchte[ENTER]er nach neuen Herausforderungen. Als ihm die[ENTER]Aufzeichnungen über einen lang versiegelten Ort[ENTER]in die Hنnde fielen, setzte er alles daran, um[ENTER]diesen zu finden. Es gelang ihm, zu erlernen, wie[ENTER]er ein Portal zu jenem Platz finden und ِffnen[ENTER]konnte. Er versprach, mit der Kunde seiner neuen[ENTER]Taten zu seiner Liebsten, Sunmi,[ENTER]zurückzukehren... doch er wurde nie wieder[ENTER]gesehen. "
gameforge.new_quest_lv75._170_say = "Die Schrift wirkt altertümlich... zudem zittrig[ENTER]und ungleichmنكig, so als habe der Schreiber[ENTER]nicht genügend Kraft besessen... "
gameforge.new_quest_lv75._171_say = "Das ergibt keinen Sinn. Wir benِtigen mehr[ENTER]Aufzeichnungen. "
gameforge.new_quest_lv75._172_say = "So langsam glaube ich zu verstehen, was hier[ENTER]mِglicherweise geschehen ist. Aber vieles ist[ENTER]noch unklar. "
gameforge.new_quest_lv75._173_say = "Mِchtest du die Einzelheiten wissen? "
gameforge.new_quest_lv75._174_say = "Noch eine Seite! Wer auch immer die Zeilen[ENTER]verfasst hat, er muss voller Verzweiflung gewesen[ENTER]sein. Soll ich für dich zusammenfassen, was dort[ENTER]geschrieben steht? "
gameforge.new_quest_lv75._175_say = "Manche Seiten sind in einem solch schlechten[ENTER]Zustand, dass ich nur raten kann. Dennoch fügt[ENTER]sich so langsam die Geschichte zusammen, die sich[ENTER]vor langer Zeit in dieser Hِhle abgespielt hat. "
gameforge.new_quest_lv75._176_say = "Viel fehlt nicht mehr. Mِchtest du hِren, was ich[ENTER]bisher herausgefunden habe? "
gameforge.new_quest_lv75._177_say = "Es scheinen nicht mehr viele Seiten zu fehlen. "
gameforge.new_quest_lv75._178_say = "Willst du hِren, was ich bisher herausgefunden[ENTER]habe? "
gameforge.new_quest_lv75._180_notice = "Ich habe die letzte Buchseite bei den[ENTER]Unterwelt-Eisgolems gefunden. "
gameforge.new_quest_lv75._185_send_letter = "Das müssten nun alle Seiten sein! "
