gameforge.new_quest_lv75._195_send_letter = "Eine Seite gefunden! "
gameforge.new_quest_lv75._200_npcChat = "Gefallenen Krieger durchsuchen "
gameforge.new_quest_lv75._210_say = "Bei den menschlichen ـberresten liegen 3 Seiten[ENTER]brüchigen Pergaments. Gezackte Kanten lassen[ENTER]darauf schlieكen, dass sie aus einem Buch[ENTER]gerissen wurden. Die Schrift darauf ist verblasst[ENTER]und schwer zu lesen. "
gameforge.new_quest_lv75._220_say = "Ich denke, das sollte reichen. Ich bringe meinen[ENTER]Fund zu Heuk-Young. "
gameforge.new_quest_lv75._230_say = "Wer hier wohl sein Leben gelassen hat? Auf jeden[ENTER]Fall hatte er nichts bei sich, was sich heute[ENTER]noch verwenden lنsst. "
gameforge.new_quest_lv75._240_send_letter = "Ich habe die Seiten! "
gameforge.new_quest_lv75._250_say = "Ich sollte zu Heuk-Young zurückkehren. Vielleicht[ENTER]kann sie das Puzzle zusammensetzen. "
gameforge.new_quest_lv75._270_say = "Ich bin erstaunt, dass du in diesen Hِhlen so[ENTER]viel gefunden hast. Diese Seiten scheinen[ENTER]ursprünglich Teil eines Buches gewesen zu sein.[ENTER]Was hier steht, ist sehr interessant. Mit den[ENTER]Geschichten, die ich gehِrt habe, ergibt es einen[ENTER]Sinn... Wenn du mir die Seiten überlنsst, binde[ENTER]ich dir daraus ein Buch. Vielleicht kannst du es[ENTER]nutzen, wenn du dich erneut in die Grotte der[ENTER]Verbannung begeben willst. Solltest du keine[ENTER]Verwendung mehr dafür haben, wird sich bestimmt[ENTER]jemand finden, der es dir für eine ordentliche[ENTER]Summe abkauft. "
gameforge.new_quest_lv75._280_say = "Ich habe dir die Seiten zu einem Buch gebunden[ENTER]und noch einige meiner Aufzeichnungen[ENTER]hinzugefügt. Vielleicht nutzen sie dir. Wenn du[ENTER]mِchtest, erzنhle ich dir noch den Rest der[ENTER]Geschichte. "
gameforge.new_quest_lv75._290_1_select = "Ja, erzنhl mir mehr! "
gameforge.new_quest_lv75._290_2_select = "Nein, das interessiert mich nicht! "
gameforge.new_quest_lv75._310_say = "Was willst du von mir? Kannst du nicht sehen,[ENTER]dass ich gerade über ein Buch sinniere? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "Das ist ein sehr interessantes Buch, das du da in[ENTER]deinen Hنnden hنltst. Woher stammt es? Kann ich[ENTER]es mir mal ansehen? "
gameforge.new_quest_lv75._340_say = "Das sind Aufzeichnungen aus der Grotte der[ENTER]Verbannung, nicht wahr? Sie sehen sehr alt aus.[ENTER]Die Schrift ist ungewِhnlich, die Schreibweise[ENTER]sehr alt... Es muss ein groكer Aufwand gewesen[ENTER]sein, an ein solches Buch zu gelangen. Du kannst[ENTER]dir sicherlich denken, dass ich solche Bücher[ENTER]liebe. Hنttest du Interesse daran, es zu[ENTER]verkaufen? "
gameforge.new_quest_lv75._350_1_select = "Ja. "
gameforge.new_quest_lv75._350_2_select = "Nein. "
gameforge.new_quest_lv75._360_say = "Wieviel Yang mِchtest du für das Buch haben? "
gameforge.new_quest_lv75._370_say = "Haha... du scheinst Scherze zu mِgen. Mit dir[ENTER]kann man anscheinend keine Geschنfte machen. Ich[ENTER]mache dir einen Vorschlag: 500.000 Yang für[ENTER]dieses legendنre Tagebuch. Nimm es oder lass es[ENTER]bleiben! "
gameforge.new_quest_lv75._380_1_select = "Ich nehme die 500.000 Yang. "
