gameforge.npc_talk._100_say = "إن أخي يتجول في الآونة الأخيرة بكثرة. لم أعد[ENTER]أقابله وإنني جد قلق عليه. "
gameforge.npc_talk._10_say = "Stillgestanden und Haltung bewahren![ENTER]Benimm dich und fange keinen Streit an. Du[ENTER]solltest Respekt gegenüber deinen Mitmenschen[ENTER]haben. Verstanden? "
gameforge.npc_talk._110_npcChat = "همم... يالها من رائحة طيبة... "
gameforge.npc_talk._120_say = "Seit vielen Jahren wird in unserer Familie das[ENTER]Geheimnis der Stنrke weitergeben. Wenn man die[ENTER]Glockenblume auf richtige Art und Weise zu einem[ENTER]Trank verarbeitet, erzنhlte mein Vater, kann[ENTER]dieser Trank dir für kurze Zeit Stنrke verleihen.[ENTER]Soweit ich weiك, kann Baek-Go diesen Trank[ENTER]herstellen. Du musst ihm nur eine Glockenblume[ENTER]bringen. "
gameforge.npc_talk._130_npcChat = "Im Frühtau zu Berge wir ziehn, fallera... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan, der Musiker: "
gameforge.npc_talk._150_say = "...es grünen alle Wنlder, alle Hِhn, fallera...[ENTER]Bist du auch ein Musikfreund? Ich singe in[ENTER]aller Abgeschiedenheit, um nicht in den Krieg[ENTER]verwickelt zu werden. Aber ohne ein Land, das[ENTER]mich beschützt, kann ich dieser Muكe nicht[ENTER]frِnen. "
gameforge.npc_talk._160_npcChat = "Warum liest du so viel? "
gameforge.npc_talk._170_sayTitle = "Soon, der Bücherwurm: "
gameforge.npc_talk._180_say = "Oh, Abenteurer! Die Welt ist voller Probleme. Nur[ENTER]mit dem nِtigen Wissen kann man überleben.[ENTER]Darum halte deine Bücher immer in Ehren. In[ENTER]schlechten Zeiten – und die Zeiten sind[ENTER]heutzutage immer schlecht – werden sie dir[ENTER]weiterhelfen. Das kannst du mir ruhig glauben! "
gameforge.npc_talk._190_npcChat = "Hast du eigentlich Kinder? "
gameforge.npc_talk._200_say = "Eigentlich wollte ich keine Kinder, aber...[ENTER]Ich sammle immer mal wieder Kakiblüten, weil man[ENTER]mit ihnen – bei richtiger Zubereitung – die[ENTER]magische Energie stنrken kann. Baek-Go hat das[ENTER]herausgefunden. Er braucht nur eine einzige[ENTER]Blüte, um daraus 100 Trنnke herzustellen.[ENTER]Leider hat die Kakiblüte auch eine Nebenwirkung.[ENTER]Wenn eine Frau eine Kette aus diesen Blüte um[ENTER]den Hals trنgt, dann bekommt sie einen Sohn. Im[ENTER]Vertrauen: Meine Frau hat das schamlos[ENTER]ausgenutzt. "
gameforge.npc_talk._20_npcChat = "Hier riecht es aber gut... "
gameforge.npc_talk._210_npcChat = "Was ist mit deinem Fuك? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Es geht schon wieder. Beim Spazierengehen[ENTER]stolperte ich über eine Gango-Wurzel und[ENTER]verstauchte mir den Fuك. Zum Glück kenne ich den[ENTER]Heilkundigen Baek-Go. Er hat mich behandelt und[ENTER]mir einen Tipp gegeben: Zum Heilen kleinerer[ENTER]Wunden kann man aus eben dieser Gango-Wurzel[ENTER]einen Trank brauen. Also habe ich den kleinen[ENTER]ـbeltنter in Tee verwandelt und er hat den[ENTER]Schaden, den er angerichtet hatte, auch wieder[ENTER]beseitigt... "
gameforge.npc_talk._240_npcChat = "Wer bist du? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Ich bin Wonda-Rim, der Neffe von Chaegirab. Mein[ENTER]Onkel ist eine Berühmtheit! Kennst du ihn? Er[ENTER]experimentiert viel mit Trنnken und Krنutern.[ENTER]Dabei hat er herausgefunden, dass man einen sehr[ENTER]mنchtigen Schutz gegen magische Energie erhنlt,[ENTER]wenn man 100 Bo-Wasser mit einer Maulbeere[ENTER]mischt. Soweit ich weiك, kann Huahn-So solche[ENTER]Trنnke herstellen, wenn du ihm die Zutaten[ENTER]bringst. "
gameforge.npc_talk._270_npcChat = "Warum hast du so viele Narben? "
gameforge.npc_talk._280_sayTitle = "Verrنter Balso: "
gameforge.npc_talk._290_say = "Ich bin kein guter Kنmpfer und wurde im Krieg[ENTER]stنndig verletzt. Irgendwann fragte ich Yu-Hwan,[ENTER]ob er nicht einen Trank für mich herstellen kann,[ENTER]der meinen Kِrper vor Verletzungen schützt. Er[ENTER]braute mir etwas aus Glockenblumensaft und[ENTER]Flieder, doch leider war der Schutz nicht[ENTER]ausreichend. Vielleicht lag es auch an meiner[ENTER]Unfنhigkeit. Dir wird der Trank in deinen Kنmpfen[ENTER]sicher helfen. "
gameforge.npc_talk._300_npcChat = "Warum nennt man dich Verrنter? "
gameforge.npc_talk._30_sayTitle = "Octavio, der Restaurantbesitzer: "
gameforge.npc_talk._310_say = "مرحباً بك! أنا المسؤول هنا عن تحسين البنود. إذا[ENTER]كان لديك بند أو سلاح ما تريد تحسينه، فعليك إحضاره[ENTER]لي. "
gameforge.npc_talk._320_say = "Du hast unschuldige Menschen auf dem Gewissen?[ENTER]Dann führst du deinen Titel zurecht. Du hast sie[ENTER]darum gebracht, ein gutes Leben zu führen. "
gameforge.npc_talk._330_say = "Es ist eine gesetzlose Welt. Aber ich habe[ENTER]beschlossen, nichts Schlechtes mehr zu tun,[ENTER]niemals. Die Leute sollten mich nicht als[ENTER]Verrنter bezeichnen.[ENTER]Hast du etwas Yang für mich? "
gameforge.npc_talk._340_npcChat = "إذهب وقل ذلك للجبال ...(غناء) "
gameforge.npc_talk._350_sayTitle = "الموسيقي يو هوان: "
gameforge.npc_talk._360_say = "فلتخضر الغابات، والسهول... للا لا لا... هل تحب[ENTER]الموسيقى؟ إني أغني في عزلة هنا، لكي لا أورط في[ENTER]الحرب. ولكني لا يمكنني الاستمرار بدون بلد يحميني. "
gameforge.npc_talk._370_npcChat = "ما أخبار الصيد؟ "
gameforge.npc_talk._380_say = "Ich tue, was ich kann. Aber in dieser[ENTER]gefنhrlichen Welt gibt es jeden Tag mehr[ENTER]Verletzte. Wir haben viel zu wenig Arzneien und[ENTER]an Helfern mangelt es auch. Die Zeiten sind hart![ENTER]Vielleicht kannst du mir spنter ein wenig zur[ENTER]Hand gehen? "
gameforge.npc_talk._390_npcChat = "Wie lنuft das Jagdgeschنft? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin, der Jنger: "
gameforge.npc_talk._40_say = "Willkommen! Unser traditioneller Familienbetrieb[ENTER]ist so erfolgreich, dass wir weltweit Restaurants[ENTER]erِffnen konnten. Wenn dir der Sinn nach etwas[ENTER]Leckerem steht, dann komm vorbei und iss bei[ENTER]uns. "
gameforge.npc_talk._410_say = "لا أحد يعلى علي في القتال بالقوس، السر يكمن في[ENTER]وصفة خاصة أملكها، ها ها ها! إذا قمت بخلط عصير[ENTER]أزهار الخوخ بأزهار الليلك، فإنك ستحصل على جرعة[ENTER]سترفع من دقة تصويبك. خذ المكونات إلى يو-هوان،[ENTER]فإنه سيقوم بخلطها لك. "
gameforge.npc_talk._420_npcChat = "ضحية عصابة الريح الأسود "
gameforge.npc_talk._430_say = "Mit dem Bogen bin ich unschlagbar, denn ich habe[ENTER]ein spezielles Rezept, hehe! Wenn du[ENTER]Pfirsichblütensaft mit Flieder mischst, bekommst[ENTER]du einen Trank, der deine Treffsicherheit erhِht.[ENTER]Bringe Yu-Hwan die Zutaten, dann braut er dir[ENTER]bestimmt diesen Trank. "
gameforge.npc_talk._440_npcChat = "So ein schِner Blumenkranz... "
gameforge.npc_talk._450_say = "Früher habe ich immer mit meinem Bruder[ENTER]Pfirsichblüten gesammelt. Heute muss ich das[ENTER]alleine machen. Die Blüten sehen aber nicht nur[ENTER]hübsch aus, sie haben auch eine besondere[ENTER]Wirkung: Wenn man eine Pfirsichblüte zu Baek-Go[ENTER]bringt, braut er daraus einen Trank, der einen[ENTER]sehr leichtfüكig macht! "
gameforge.npc_talk._460_npcChat = "ما الذي تسبب لك في كل هذه الندوب؟ "
gameforge.npc_talk._470_say = "إني لست بالمحارب البارع وتعرضت في الحرب بشكل[ENTER]مُستمر للعديد من الإصابات. سألني يو-هوان في يوم[ENTER]من الأيام إذا كنت أوده أن يخلط لي إحدى الجرع،[ENTER]التي بإمكانها أن تحمي جسدي من الجراح. فقام بخلط[ENTER]جرعة من زهرة الجرس وزهرة الليلك، لكن الحماية مع[ENTER]الأسف لم تكن كافية. ربما كان السبب في ذلك عدم[ENTER]قدرتي. لكن الجرعة ستكون بالأكيد جد مساعدة في[ENTER]قتالك. "
gameforge.npc_talk._480_npcChat = "ما السبب في مناداتك بالخائن؟ "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, die Reiskuchenverkنuferin: "
gameforge.npc_talk._500_say = "In Kriegszeiten ist es schwierig, Reiskuchen[ENTER]herzustellen. Auكerdem habe ich wegen der[ENTER]Banditen viele Kunden verloren. Ich weiك nicht[ENTER]mehr, wovon ich leben soll. "
gameforge.npc_talk._50_say = "أنا رجل عجوز جداً، ولكني نشيط دائماً وأتمتع بصحة[ENTER]جيدة، لأني أملك سر خفيّاً. لقد اكتشفت أن جرعة من[ENTER]خليط من جذور الغانغو وفطر التو تطيل الحياة. إذا[ENTER]أردت أن تجرب هذه الجرعة، عليك الذهاب بهذه[ENTER]المكونات إلى يو هوان، فإنه سيخلط لك الجرعة. "
gameforge.npc_talk._510_npcChat = "Wer kauft bei dir? "
gameforge.npc_talk._520_say = "لم أكن أتوقع أن تتحطم أحلامنا بلا رحمة بهذا[ENTER]الشكل... لقد وقع زوجي العزيز ضحية في الحرب! أرجوك[ENTER]اثأر لموته. "
gameforge.npc_talk._530_npcChat = "تُكلف الحرب أرواحا عديدة.. "
gameforge.npc_talk._540_say = "لأننا نفقد المزيد والمزيد من الرجال خلال الحرب،[ENTER]لقد طلبنا نحن، نساء القرية، من هوان-سو أن يخلط[ENTER]لنا جرعة تزيد من قوة الدفاع، بشكل لا نحتاج فيه[ENTER]إلى الكثير من الجرعات. اذهب إليه، يمكنه أن يصنع[ENTER]لك هذه الجرعة، إنه يطلق عليها اسم ماء سام "
gameforge.npc_talk._550_npcChat = "لم تهوى القراءة بهذا الشغف؟ "
gameforge.npc_talk._560_say = "Da wir immer mehr Mنnner im Krieg verlieren,[ENTER]haben wir Frauen aus dem Dorf uns zusammen getan[ENTER]und Huahn-So gebeten, einen besseren Heiltrank[ENTER]herzustellen.[ENTER]Nach langer Forschung hat er einen Trank[ENTER]entwickelt, der statt dessen die Verteidigung[ENTER]erhِht, so dass weniger Heiltrنnke benِtigt[ENTER]werden. Geh zu ihm. Er kann dir diesen Trank, den[ENTER]er SamBo-Wasser nennt, bestimmt herstellen. Er[ENTER]benِtigt dafür ein Dok-Wasser und eine Alpenrose. "
gameforge.npc_talk._570_npcChat = "Das ist aber ein süكer Fratz... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "لم أكن أصلاً أود الحصول على أطفال، لكن... إنني[ENTER]أجمع من حين لآخر أزهار الخرمة، لأنه باستعمالها[ENTER]-بجرعات دقيقة- يمكن للإنسان أن يرفع من مستوى قوته[ENTER]السحرية. لقد إكتشف بايك-غو هذه الطريقة. إنه يحتاج[ENTER]عادة لزهرة خرمة واحدة فقط لكي ينتج منها 100 جرعة.[ENTER]لكن لزهرة الخرمة آثار جانبية جد سلبية. إذا قامت[ENTER]امرأة بارتداء قلادة من الأزهار فإنها تنجب ذكر.[ENTER]بيني وبينك: لقد استغلت زوجتي هذا من دون حياء. "
gameforge.npc_talk._600_npcChat = "ما الذي تفعله الآن؟ "
gameforge.npc_talk._60_npcChat = " يا لها من باقة أزهار جميلة... "
gameforge.npc_talk._610_say = "Da mein Mann im Krieg gefallen ist, muss ich[ENTER]sehen, wo ich bleibe. Ich versuche, mich und das[ENTER]Kind zu ernنhren. Mit dem Bo-Wasser habe ich eine[ENTER]Mِglichkeit gefunden, meinen Lebensunterhalt[ENTER]etwas aufzubessern. Ich muss Yu-Hwan 100[ENTER]Kakiblütensنfte und einen Tue-Pilz bringen.[ENTER]Daraus braut er Bo-Wasser, das ich gut verkaufen[ENTER]kann. Irgendwie muss ich ja über die Runden[ENTER]kommen. "
gameforge.npc_talk._620_npcChat = "Wie geht es deinem Ehemann? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "إن طاوران عادة أقوى منِّي بكثير. لذى فكرت بحل[ENTER]يمكنني من الفوز عليه أثناء قتالنا. فقد علمت من[ENTER]محارب نينجا حكيم أنه من الممكن مزج عصير اليونغ[ENTER]ببعض التوت للحصول على جرعة تمكن الشخص من توجيه[ENTER]ضربات سريعة. طريقة ستمكنني من الفوز على طاوران![ENTER]إذا كنت تود أن تصبح مهاجماً سريعاً فخذ المكونات[ENTER]إلى هوان-سو، إن بإمكانه بالتأكيد أن يخلط لك تلك[ENTER]الجرعة. "
gameforge.npc_talk._650_npcChat = "Wie lنuft das Geschنft? "
gameforge.npc_talk._660_say = "Seit der Krieg ausgebrochen ist, laufen die[ENTER]Geschنfte schlecht. Die Gewerkschaft der[ENTER]Hنndler war einmal eine reiche und mنchtige[ENTER]Vereinigung, aber diese Zeiten sind vorbei. Wir[ENTER]kِnnen es uns nicht mehr leisten, die Wilden,[ENTER]die Weiكer-Eid Kriegerinnen und die[ENTER]Schwarzwindbande zu ignorieren, wie wir es[ENTER]früher taten. "
gameforge.npc_talk._670_npcChat = "Warum so schlecht gelaunt? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang ist ein bِses Mنdchen![ENTER]Ich hasse sie! Ich bin schwach, und sie macht mir[ENTER]zu oft das Leben schwer! "
gameforge.npc_talk._700_say = "Du bist ein Mann und hast Muskeln.[ENTER]Trainiere sie ein bisschen! "
gameforge.npc_talk._70_sayTitle = "ميريني: "
gameforge.npc_talk._710_npcChat = "Was machst du gerade? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Ich warte auf Taurean. Wir spielen oft[ENTER]miteinander und hنufig kنmpfen wir auch. Dieser[ENTER]Feigling! Wenn er heute nicht freiwillig kommt,[ENTER]werde ich ihn fertig machen! "
gameforge.npc_talk._740_npcChat = "Taurean hat Angst vor dir. "
gameforge.npc_talk._750_say = "Taurean ist eigentlich stنrker als ich. Deshalb[ENTER]habe ich mir etwas einfallen lassen, wie ich[ENTER]unsere Kنmpfe trotzdem gewinnen kann. Von einem[ENTER]weisen Ninja erfuhr ich, dass man Young-Wasser[ENTER]mit einer Maulbeere mischen kann. Daraus entsteht[ENTER]ein Trank, der einen schneller zuschlagen lنsst.[ENTER]Damit kann ich Taurean besiegen! Wenn du auch ein[ENTER]schneller Angreifer werden willst, dann geh mit[ENTER]den Zutaten zu Huahn-So. Er wird dir den Trank[ENTER]sicher herstellen. "
gameforge.npc_talk._760_npcChat = "Die neuen Erkenntnisse... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Mein Freund, die Welt ist voller ungelِster[ENTER]Fragen. Und ich, ich bin ein Sucher der[ENTER]Antworten, ein Sucher des Wissen.[ENTER]Hast du schon einmal von epischen Waffen und[ENTER]Geiststeinen gehِrt? "
gameforge.npc_talk._790_npcChat = "Was tust du gerade? "
gameforge.npc_talk._800_say = "Du weiكt ja bereits, dass ich nach noch[ENTER]unbekanntem Wissen forsche. Im Moment untersuche[ENTER]ich eine Methode, Waffen über das Normalmِgliche[ENTER]hinaus zu verstنrken und auch die Macht der[ENTER]Geiststeine zu vervollkommnen. "
gameforge.npc_talk._80_say = "لقد تعودت في الماضي أن أرافق أخي لجمع أزهار شجر[ENTER]الخوخ. لكني الآن مضطرة إلى القيام بهذا لوحدي.[ENTER]إنها أزهار جدُّ جميلة ولها أيضاً تأثير خاص: إذا[ENTER]أحضرت زهرة الليلك لبايك-غو فإنه سيخلط لك منها[ENTER]جرعة ترفع من سرعة تنقلك! "
gameforge.npc_talk._810_npcChat = "Die Waffenforschung... "
gameforge.npc_talk._820_say = "Interessant, nicht wahr? Willst du mehr darüber[ENTER]wissen? Dann bring mir eine der folgenden[ENTER]+9-Waffen: Schlachtschwert+9,[ENTER]Groكgelbdrachenbogen+9, Erlِsungsfنcher+9,[ENTER]Drachenmesser+9, Exorzismusschwert+9,[ENTER]Himmel-&-Erde-Glocke+9 oder Geisterzahnklinge+9.[ENTER]Auكerdem brauche ich noch ein Traktat zur[ENTER]Fechtkunst und zwei Segensschriftrollen. Ich[ENTER]werde versuchen, dir daraus eine epische Waffe[ENTER]herzustellen. "
gameforge.npc_talk._830_say = "Allerdings kann ich dir nicht versprechen, dass[ENTER]es funktioniert. "
gameforge.npc_talk._840_npcChat = "Die Geiststeine... "
gameforge.npc_talk._850_say = "Geiststeine sind weit verbreitet. Viele nutzen[ENTER]sie, aber bisher hat noch niemand ihre wahre[ENTER]Macht erkannt. Doch ich habe wنhrend meiner[ENTER]Nachforschungen neue Erkenntnisse gewonnen.[ENTER]Wenn du mir einen Geiststein bringst, kann ich[ENTER]ihn für dich verbessern. "
gameforge.npc_talk._90_npcChat = "أين هو أخوك؟ "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Heldenmedaille "
gameforge.olympic_badge._020_say = "Zu Hilfe! "
gameforge.olympic_badge._030_say = "Elendes Diebesgesindel ...[ENTER]Gestern Nacht wurde bei mir eingebrochen![ENTER]Sie haben die Heldenmedaille gestohlen. Mein[ENTER]Vorfahre bekam sie einst verliehen, nachdem er[ENTER]42,195 Kilometer vom Schlachtfeld zu seinem[ENTER]Kaiser gerannt war, um ihm die Kunde des Sieges[ENTER]zu übermitteln.[ENTER]Nun ist sie weg! "
gameforge.olympic_badge._040_say = "Oh weh ... für meine Familie ist sie von[ENTER]unschنtzbarem Wert. Was soll ich bloك tun? "
gameforge.olympic_badge._050_say = "Wirst du mir helfen? "
gameforge.olympic_badge._060_npcChat = "Heldenmedaille "
gameforge.olympic_badge._070_say = "Endlich! Du bist du zurück![ENTER]Hast du die Heldenmedaille gefunden? "
gameforge.olympic_badge._080_say = "Warum nur? Was wollen diese Verbrecher mit meiner[ENTER]Medaille? Für Fremde ist sie doch wertlos![ENTER]Kannst du mir helfen, sie wiederzufinden? "
gameforge.olympic_badge._090_npcChat = "Finde die Heldenmedaille! "
gameforge.olympic_badge._100_say = "Du kommst mit leeren Hنnden? Oh nein, ich bin[ENTER]verzweifelt. Wenn du mir nicht helfen kannst, wer[ENTER]dann? Suche weiter. Bitte! "
gameforge.olympic_badge._110_say = "Du hast meine Medaille gefunden![ENTER]Aber warte ... das ist ja bloك ein Stück. Welch[ENTER]Schande, sie haben sie in fünf Teile zerbrochen![ENTER]Bitte bringe mir alle Bruchstücke! Dann kann ich[ENTER]die Medaille vielleicht wieder zusammensetzen. "
gameforge.olympic_badge._120_say = "Diese elenden Verbrecher haben mein kostbares[ENTER]Familienerbstück zerbrochen![ENTER]Ich danke dir, dass du alle Bruchstücke gefunden[ENTER]hast. Nun kann ich die einzelnen Teile[ENTER]zusammenfügen. "
gameforge.olympic_badge._130_say = "Tausend Dank! Du hast die Ehre meiner Familie[ENTER]wiederhergestellt.[ENTER]All die Mühe sollst du dir natürlich nicht[ENTER]umsonst gemacht haben. Hier ist dein gerechter[ENTER]Lohn! "
gameforge.olympic_badge._140_say = "Mِchtest du diesen Auftrag wirklich ablehnen?[ENTER]Wenn du jetzt 'Ja' wنhlst, kannst du ihn nicht[ENTER]mehr wiederaufnehmen. "
gameforge.olympic_badge._150_say = "Ich verstehe, wenn du jetzt keine Zeit dafür[ENTER]hast. Komm wieder, wenn es dir besser passt.[ENTER]Aber lass mich nicht zu lange warten! "
gameforge.olympic_badge._160_say = "Leider bist du zu spنt gekommen und kannst mir[ENTER]nun nicht mehr helfen. Ich wünsche dir[ENTER]alles Gute auf deinem weiteren Weg! "
gameforge.olympic_badge._170_say = "Jage die Monster, die mich bestohlen haben! Doch[ENTER]Vorsicht, sie waren sehr stark - mindestens Level[ENTER]30. Wenn du mir die Heldenmedaille wiederbringst,[ENTER]werde ich dich reichlich entlohnen! "
gameforge.olympic_badge._180_say = "Finde die Heldenmedaille und bringe sie zu[ENTER]Yu-Hwan. "
gameforge.olympic_badge._190_say = "Yu-Hwan bittet um deine Hilfe. Geh zu ihm! Du[ENTER]findest ihn im zweiten Dorf. "
