gameforge.oxevent._300_npcChat = "مسابقة OX: إلغاء "
gameforge.oxevent._30_say = "سأسمح لك بالمشاركة، عند بدأ المسابقة.[ENTER]لم يتم بعد تحديد موعد الانطلاق.[ENTER]سأبلغك بذلك، فكن مستعداً! "
gameforge.oxevent._310_say = "مسابقة OX: إلغاء[ENTER]يمكن أن تحصل مشاكل غي متوقعة![ENTER]أتريد المواصلة بالفعل؟ "
