gameforge.skill_reset2._20_say = "إنك لم تبدأ في أي تدريب بعد! طالما أنك لا تصرف[ENTER]نقاط المهارة، فإنك لن تستطيع إرجاعها إلى الوضعية[ENTER]الأولى. عُد من جديد عندما ترتكب خطأ ما في دورتك[ENTER]التدريبية، سأساعدك حينها. "
gameforge.skill_reset2._30_say = "لا يمكنني مساعدتك يا عزيزي. لقد وصلت بالفعل إلى[ENTER]المستوى %s، لكن إجراء تغيير في التدريب ممكن حتى[ENTER]المستوى 30 فقط. "
