gameforge.spider_dungeon_3floor_boss._180_say = "ذلك الرجل المسن العنيد ... هل كلمة شكر صغيرة[ENTER]بالشيء الكثير؟ لكن حسناً. لقد قال بأن المعلومات[ENTER]في غاية الأهمية، لذلك فأنا سأرع بإبلاغها للزعيم. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "رسالة أوريل "
gameforge.spider_dungeon_3floor_boss._200_say = "أوه كلاّ! إن شيطان عناكب هائل قد بنى عشّه في[ENTER]الطابق الثالث من برج العناكب المحصن ـ إنها بارونة[ENTER]العناكب. بحسب النص المنقوش فالدخول إلى تلك[ENTER]المغارة الخفية يحتاج إلى مفتاح خاص. اذهب أولاً[ENTER]إلى أوريل واسأله عن ذلك المفتاح. ثم انضم بعد ذلك[ENTER]إلى فريق من المقاتلين المحنّكين واقتحموا سوياً[ENTER]مخبأ بارونة العناكب! خذ، لدي بطاقة مرور أخرى لك. "
gameforge.spider_dungeon_3floor_boss._20_say = "لا يمكن فتح هذه البوابة إلا بواسطة مفتاح العناكب. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "مفتاح العناكب "
gameforge.spider_dungeon_3floor_boss._220_say = "عليّ أن أزور أوريل بأسرع ما يمكن. "
gameforge.spider_dungeon_3floor_boss._230_say = "آه، ها قد عدتَ. فقد أمرك الزعيم إذن بالقضاء على[ENTER]بارونة العناكب؟ لكن المدخل إلى مغارة التفريخ[ENTER]الخاصة بالبارونة مغلق ولا يمكن فتحه إلا بمفتاح[ENTER]العناكب. وصنع ذلك المفتاح شاق للغاية. لكني سأصنعه[ENTER]لك إذا أحضرت لي كيس العنكبوت السام وكيس بيض[ENTER]العنكبوت وشبكة العنكبوت وعيون العنكبوت وأرجل[ENTER]العنكبوت وسم الملكة العنكبوت. "
gameforge.spider_dungeon_3floor_boss._240_say = "هل تريد أن أصنع لك مفتاح العناكب؟ أحتاج لذلك إلى[ENTER]كيس العنكبوت السام وكيس بيض العنكبوت وشبكة[ENTER]العنكبوت وعيون العنكبوت وأرجل العنكبوت وكذا سم[ENTER]الملكة العنكبوت. هل تمكنتَ من الحصول على كل[ENTER]المكونات؟ "
gameforge.spider_dungeon_3floor_boss._250_say = "ممتاز! لقد وجدتَ كل العناصر الضرورية لصنع مفتاح[ENTER]العناكب. انتظر لحظة. لن يستغرق صنعه مدة طويلة ... "
gameforge.spider_dungeon_3floor_boss._260_say = "ها، لقد نجح الأمر! خذ، ها هو ذا مفتاح العناكب.[ENTER]سيفتح لك المدخل إلى مخبأ بارونة العناكب. أتمنى لك[ENTER]ولرفاقك الكثير من النجاح في قتال تلك الحشرة طويلة[ENTER]الأرجل! لكن عليكم أن تسرعوا - فالمفتاح غير مستقر[ENTER]وستتفكك أجزاؤه خلال 24 ساعة. "
gameforge.spider_dungeon_3floor_boss._270_say = "أوه أوه! أخشى بأن الأمر يحتاج للكثير من التجربة[ENTER]والصبر. عليك أن تعلم بأن طريقة صنع هذا المفتاح[ENTER]معقدة للغاية. إن مجرد خطأ صغير يمكن أن يقود[ENTER]للفشل. لقد أضعتُ للأسف كل المكونات التي تعبتَ في[ENTER]جمعها. ستنجح المحاولة القادمة بالتأكيد! "
gameforge.spider_dungeon_3floor_boss._280_say = "ما زال ينقص شيء آخر، لا يمكنني هكذا صنع مفتاح[ENTER]العناكب. للتذكير مرة أخرى، هذا كل ما سنحتاج إليه[ENTER]للقيام بذلك: كيس العنكبوت السام وكيس بيض العنكبوت[ENTER]وشبكة العنكبوت وعيون العنكبوت وأرجل العنكبوت وكذا[ENTER]سم الملكة العنكبوت. "
