gameforge.spider_dungeon_3floor_boss._320_say = "هناك فريق بالفعل في مغارة التفريخ يقوم بمهاجمة[ENTER]بارونة العناكب. "
gameforge.spider_dungeon_3floor_boss._330_say = "لا يمكنك الدخول إلا بعد أن ينتهي الفريق السابق من[ENTER]إنجاز مهمته. عُد ثانية خلال %s دقيقة. "
