gameforge.subquest_03._30_say = "Kannst du mir die Zutat für die Arznei bringen?[ENTER]Ich frage dich, weil du ein Soldat bist.[ENTER]Ich brauche für die Arznei die Leber[ENTER]eines Blauwolfs. "
gameforge.subquest_03._40_say = "Bringe mir die Leber eines Blauwolfs. Sage mir[ENTER]Bescheid, wenn du sie hast. "
gameforge.subquest_03._50_sayReward = "Seit die Metinsteine fallen, ist eine unbekannte[ENTER]Krankheit ausgebrochen. Um die Arznei für die[ENTER]Krankheit herstellen zu kِnnen, braucht Baek-Go[ENTER]eine Blauwolfsleber. Bringe sie ihm. "
gameforge.subquest_03._60_npcChat = "Woher soll ich eine Wolfsleber nehmen? "
gameforge.subquest_03._70_say = "Es gibt nur einen Weg, eine Wolfsleber zu[ENTER]bekommen: Du musst Blauwِlfe jagen. "
gameforge.subquest_03._80_say = "Die Wِlfe tun mir leid. Aber wir brauchen die[ENTER]Leber, um die Arznei herzustellen. Vielen Dank[ENTER]im Voraus. "
gameforge.subquest_03._90_sendLetter = "Rückkehr zu Baek-Go "
