gameforge.subquest_04._110_sayReward = "Geh und bring den Brief des Schmieds zu Deokbae,[ENTER]dem Holzfنller. Du findest ihn im zweiten Dorf,[ENTER]zu dem du nur mit Hilfe des Portals gelangst. "
gameforge.subquest_04._120_sendLetter = "Ein Brief vom Schmied "
gameforge.subquest_04._130_targetVid = "Finde Deokbae, den Holzfنller. "
gameforge.subquest_04._140_npcChat = "Ein Brief vom Schmied "
gameforge.subquest_04._150_sayTitle = "Holzfنller Deokbae: "
gameforge.subquest_04._160_say = "Willkommen! Ich habe gute ؤxte, willst du eine[ENTER]kaufen? Du brauchst keine Axt? Warum bist du dann[ENTER]hier? Ah, ein Brief vom Schmied. Hab vielen Dank.[ENTER]Ich bin Holzfنller, verkaufe aber auch[ENTER]Spitzhacken und andere Werkzeuge. Manchmal[ENTER]bestelle ich verschiedene Werkzeuge bei ihm. So[ENTER]sind wir gute Freunde geworden. "
gameforge.subquest_04._170_say = "Ich sollte wirklich mal wieder mit ihm in der[ENTER]Seo-Pyung-Bar einen trinken gehen.[ENTER]Vielen Dank, dass du mir den Brief gebracht hast.[ENTER]Und viele Grüكe an den Schmied! "
gameforge.subquest_04._180_say = "Ein Brief vom Schmied?[ENTER]Mann, das ist lange her. Wo ist der Brief?[ENTER]Du hast ihn doch nicht unterwegs verloren, oder? "
gameforge.subquest_04._190_select = "Hier ist er. "
gameforge.subquest_04._200_select = "Ach, doch nicht. "
gameforge.subquest_04._20_say = "Hey, du, Abenteurer! Ich mِchte dich um[ENTER]einen Gefallen bitten.[ENTER]Kennst du einen Burschen namens Deokbae?[ENTER]Er ist Holzfنller und ein guter Freund von mir.[ENTER]Vielleicht ein bisschen langweilig, aber er[ENTER]ist einer der letzten hart arbeitenden[ENTER]Holzfنller. "
gameforge.subquest_04._210_say = "Quest beenden? "
gameforge.subquest_04._220_say = "Das freut mich sehr.[ENTER]Komm schnell wieder. "
gameforge.subquest_04._230_say = "Du hast ihn also verloren?[ENTER]Verschwinde! "
gameforge.subquest_04._240_say = "Geh zum Schmied und hol ihn.[ENTER]Verlier aber den Brief diesmal nicht.[ENTER]Mach es gut. "
gameforge.subquest_04._250_sayReward = "Geh zum Schmied zurück und hole dir deine[ENTER]Belohnung ab. "
gameforge.subquest_04._260_targetVid = "Zurück zum Schmied "
gameforge.subquest_04._270_npcChat = "Ich habe den Brief übergeben. "
gameforge.subquest_04._280_say = "Und, wie geht es Deokbae? Ha, ha! Er hat sich[ENTER]kein bisschen verنndert. Danke. Nimm dies als[ENTER]Belohnung. Es ist nicht viel, aber du wirst es[ENTER]eines Tages gebrauchen kِnnen.[ENTER]Danke. "
gameforge.subquest_04._290_sayReward = "Du erhنltst 4.000 Erfahrungspunkte.[ENTER]Du erhنltst 3.000 Yang. "
gameforge.subquest_04._30_say = "Ich habe ihn schon lange nicht mehr gesehen und[ENTER]ihm einen Brief geschrieben, um zu fragen,[ENTER]wie es ihm geht.[ENTER]Ich mِchte, dass du ihm den Brief bringst.[ENTER]Im Dorf gibt es heutzutage viele Probleme.[ENTER]Also sei vorsichtig.[ENTER]Und knick den Brief nicht! "
gameforge.subquest_04._40_say = "Oh, du weiكt nicht, wie man zum nنchsten[ENTER]Dorf gelangt?[ENTER]Drücke M, um die Minikarte anzuzeigen. Darauf ist[ENTER]ein blauer Punkt verzeichnet. Dieser Punkt[ENTER]bezeichnet ein Portal, das dich in das[ENTER]angrenzende Gebiet bringt. In diesem Gebiet[ENTER]befindet sich auch das zweite Dorf. "
