gameforge.subquest_06._270_say = "Vielen Dank, dass du mir mein Buch zurückbringst![ENTER]Nun kann ich meine Forschungen fortführen.[ENTER]Hier, nimm etwas Eisenerz. Nutze es gut. "
gameforge.subquest_06._280_say = "Du willst Eisenerz? Ich kann dir etwas geben.[ENTER]Allerdings hنtte ich vorher noch eine Bitte:[ENTER]Kürzlich habe ich ein Buch verloren, als ich von[ENTER]einem Rudel Wildhunde gejagt wurde. Ich glaube,[ENTER]dass die Wildhunde mein Buch noch haben. Bring es[ENTER]mir zurück, dann werde ich dir etwas Eisenerz[ENTER]geben. "
gameforge.subquest_06._285_say = "Uriel wird dir Eisenerz geben, wenn du ihm sein[ENTER]Buch von den Wildhunden zurückbringst. "
