gameforge.subquest_06._330_say = "Danke für die Galle! Nun kann ich wieder meine[ENTER]besonders leckeren Gerichte zubereiten! Mhm...[ENTER]Hier, nimm das Leder als Belohnung. "
gameforge.subquest_06._340_say = "Ich kann dir Leder geben.[ENTER]Aber in dieser Welt gibt es nichts umsonst.[ENTER]Was hنltst du von einem Tausch? Ich werde dir[ENTER]Leder geben, wenn du mir eine Bنrengalle bringst.[ENTER]Ich brauche oft Bنrengalle für meine Gerichte.[ENTER]Wenn du nicht interessiert bist, dann soll es mir[ENTER]auch recht sein. "
gameforge.subquest_06._345_say = "Octavio wird dir Leder geben, wenn du ihm eine[ENTER]Bنrengalle bringst. "
gameforge.subquest_06._350_npcChat = "Ich benِtige Leder. "
gameforge.subquest_06._360_say = "Ich hab dir schon Leder gegeben.[ENTER]Hast du es verloren?[ENTER]Ich habe keines mehr. "
gameforge.subquest_06._370_npcChat = "Ich brauche Kohle. "
gameforge.subquest_06._380_say = "Danke für den Lehm.[ENTER]Eine Hand wنscht die andere: Hier hast du deine[ENTER]Kohle. Bis bald! "
gameforge.subquest_06._390_say = "Was gibt es?[ENTER]Du bist hier, um Kohle zu holen? Ich habe eine[ENTER]Menge Kohle. Aber die gibt es nicht umsonst.[ENTER]Erst musst du etwas für mich tun. "
