gameforge.subquest_08._200_say = "Du wirst sehen, es lohnt sich.[ENTER]Gute Reise! "
gameforge.subquest_08._20_say = "Entschuldige, kannst du mir bitte helfen?[ENTER]Mein Baby weint pausenlos und ich weiك nicht mehr[ENTER]weiter. Das Einzige, das vielleicht helfen[ENTER]kِnnte, wنre ein Reiskuchen; das Kindchen liebt[ENTER]diese Speise. Gehst du bitte für mich zum[ENTER]Waffenhنndler? Ich glaube er weiك, wo man[ENTER]Reiskuchen bekommen kann. "
gameforge.subquest_08._210_makequestbutton = "Yu-Rang suchen "
gameforge.subquest_08._220_targetVid = "Reiskuchen "
gameforge.subquest_08._230_sayReward = "Geh zur Reiskuchenverkنuferin Yu-Rang.[ENTER]Du findest sie im nنchsten Dorf. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Kann ich dir helfen?[ENTER]Oh, Reiskuchen! Klar kann ich dir Reiskuchen[ENTER]geben! Aber... kِnntest du vorher etwas für[ENTER]mich tun? Ein Junge namens Taurean kommt oft[ENTER]hierher und نrgert mich, obwohl ich ihm nie[ENTER]etwas getan habe. Wenn du ihn dafür bestrafst,[ENTER]werde ich dir Reiskuchen geben.[ENTER]Einverstanden? "
gameforge.subquest_08._260_makequestbutton = "Suche Taurean "
gameforge.subquest_08._270_sayReward = "Yu-Rang wird stنndig von Taurean geنrgert.[ENTER]Bestrafe ihn, dann gibt sie dir einen Reiskuchen. "
gameforge.subquest_08._280_npcChat = "Warum نrgerst du Yu-Rang? "
gameforge.subquest_08._290_say = "Was, wen soll ich geنrgert haben? Ach, du meinst[ENTER]das Mنdchen, das die Reiskuchen verkauft?[ENTER]Nein, ich wollte sie nicht نrgern! Mir war nur[ENTER]langweilig und sie sah nett aus und hatte nicht[ENTER]viel zu tun. Da habe ich sie ein paar Mal besucht[ENTER]und wollte mit ihr spielen, aber sie ist nur[ENTER]wütend geworden...[ENTER]Mنdchen sind komisch. Dann besuche ich sie eben[ENTER]nicht mehr, pah! "
gameforge.subquest_08._300_makequestbutton = "Zurück zu Yu-Rang "
gameforge.subquest_08._30_select = "Akzeptieren "
gameforge.subquest_08._310_targetVid = "Reiskuchen "
gameforge.subquest_08._320_sayReward = "Taurean wird Yu-Rang nicht mehr belنstigen. Geh[ENTER]zu ihr und hole dir deinen Reiskuchen ab. "
gameforge.subquest_08._330_say = "Ha, ha! Du hast Taurean bestraft, danke! Jetzt[ENTER]wird er es sich zweimal überlegen, bevor er[ENTER]wieder her kommt.[ENTER]Hier hast du den Reiskuchen. Lass ihn dir[ENTER]schmecken! "
gameforge.subquest_08._340_makequestbutton = "Zurück zu Ah-Yu "
gameforge.subquest_08._350_targetVid = "Reiskuchen für Ah-Yu "
gameforge.subquest_08._360_sayReward = "Du hast von Yu-Rang einen Reiskuchen bekommen.[ENTER]Bringe ihn zu Ah-Yu.[ENTER]Du findest sie und ihr Kind im ersten Dorf. "
gameforge.subquest_08._370_npcChat = "Hier ist der Reiskuchen für dein Kind. "
gameforge.subquest_08._380_say = "Du hast mir den Reiskuchen gebracht! Vielen,[ENTER]vielen Dank. Schau nur, mein Baby hat aufgehِrt[ENTER]zu weinen und knabbert ganz glücklich daran[ENTER]herum. Du hast es geschafft. Danke für deine[ENTER]Hilfe! "
gameforge.subquest_08._390_sayReward = "Du erhنltst 26.000 Erfahrungspunkte.[ENTER]Du erhنltst 10.000 Yang. "
gameforge.subquest_08._40_say = "Aber... Ich kann hier nicht weg und das Baby[ENTER]terrorisiert die gesamte Nachbarschaft...[ENTER]Es dauert auch bestimmt nicht lang! Bist du[ENTER]sicher, dass du keine Zeit hast? "
gameforge.subquest_08._50_say = "Du bist wohl beschنftigt?[ENTER]Bitte komm spنter noch einmal.[ENTER]Nicht weinen, mein Kind. "
gameforge.subquest_08._60_say = "Dann werde ich wohl jemand anderen fragen müssen.[ENTER]Viel Glück auf deinen Reisen! "
gameforge.subquest_08._70_say = "Hab vielen Dank! Das ist für mich eine groكe[ENTER]Erleichterung. "
gameforge.subquest_08._80_makequestbutton = "Reiskuchen "
gameforge.subquest_08._90_targetVid = "Reiskuchen "
gameforge.subquest_09 = {}
gameforge.subquest_09._100_sayReward = "Finde die Weiكer-Eid Soldatin, die dem[ENTER]Schmied die goldene Axt gestohlen hat[ENTER]und bring diese zu ihm zurück. "
gameforge.subquest_09._10_targetVid = "Finde die goldene Axt "
gameforge.subquest_09._110_sendLetter = "Goldene Axt gefunden "
gameforge.subquest_09._120_npcChat = "Hier ist die goldene Axt. "
gameforge.subquest_09._130_say = "Danke! Ich stehe in deiner Schuld. Jetzt muss ich[ENTER]mir keine Gedanken mehr machen, was ich Deokbae[ENTER]sage, wenn ich ihn sehe! "
gameforge.subquest_09._140_sayReward = "Du erhنltst 36.000 Erfahrungspunkte.[ENTER]Du erhنltst 10.000 Yang.[ENTER]Du erhنltst einen Schmuckgegenstand. "
gameforge.subquest_09._20_npcChat = "Die goldene Axt "
gameforge.subquest_09._30_say = "Erinnerst du dich an meinen Freund Deokbae?[ENTER]Ich versprach ihm, eine Axt zu fertigen, aber ich[ENTER]passte einen Augenblick nicht auf und eine[ENTER]Weiكer-Eid Soldatin stahl sie mir.[ENTER]Kannst du mir die Axt wiederholen? Eine[ENTER]Weiكer-Eid Soldatin muss sie haben. Du solltest[ENTER]die Axt erkennen. Es gibt nicht viele davon. Ich[ENTER]werde dich fürstlich belohnen! "
gameforge.subquest_09._40_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_09._50_sayTitle = "Schmied: "
gameforge.subquest_09._60_say = "Ich will die Axt unbedingt![ENTER]Sehen wir uns noch einmal?[ENTER]Auf Wiedersehen. "
gameforge.subquest_09._70_say = "Danke, dass du dich darum kümmerst.[ENTER]Pass auf dich auf, denn der Clan macht viel[ENTER]ؤrger. "
gameforge.subquest_09._80_say = "Danke, dass du dich darum kümmerst.[ENTER]Pass auf dich auf, denn der Clan macht richtig[ENTER]ؤrger. "
