gameforge.subquest_10._100_sayReward = "Frage den Schmied nach dem Verbleib der[ENTER]Haarnadel. "
gameforge.subquest_10._10_targetVid = "Finde die Haarnadel "
gameforge.subquest_10._110_npcChat = "Die gestohlene Haarnadel "
gameforge.subquest_10._120_say = "Was? Sie denkt, dass ich ihre Haarnadel gestohlen[ENTER]habe? Das ist unglaublich! Für wen hنlt sie mich?[ENTER]Ich habe fleiكig in meiner Schmiede gearbeitet![ENTER]Ah, ich sollte dir das nicht erzنhlen, aber der[ENTER]Waffenhنndler war vor einer Weile im Laden der[ENTER]Gemischtwarenhنndlerin. "
gameforge.subquest_10._130_makequestbutton = "Die gestohlene Haarnadel "
gameforge.subquest_10._140_sayReward = "Frage den Waffenhنndler nach dem Verbleib der[ENTER]Haarnadel. "
gameforge.subquest_10._150_say = "Was? Du glaubst, dass ich die Haarnadel der[ENTER]Gemischtwarenhنndlerin gestohlen habe? Nein,[ENTER]nein, das habe ich nicht! Ehrlich! Ich war zwar[ENTER]dort, um der Gemischtwarenhنndlerin einen Besuch[ENTER]abzustatten! Aber sie war nicht da. An ihrer[ENTER]Stelle fand ich eine Weiكer-Eid Bogenschützin.[ENTER]Als sie mich sah, rannte sie weg. Vielleicht hat[ENTER]sie die Haarnadel gestohlen. "
gameforge.subquest_10._160_sayReward = "Hole die Haarnadel von der Weiكer-Eid[ENTER]Bogenschützin zurück! "
gameforge.subquest_10._170_sendLetter = "Haarnadel gefunden "
gameforge.subquest_10._180_targetVid = "Gehe zur Hنndlerin. "
gameforge.subquest_10._190_npcChat = "Ich habe hier deine Haarnadel. "
gameforge.subquest_10._200_say = "Oh, vielen Dank.[ENTER]Ich freue mich. Endlich habe ich meine geliebte[ENTER]Haarnadel wieder![ENTER]Du hast mir schon so oft geholfen. Wie kann ich[ENTER]das nur wieder gut machen? Ich habe eine[ENTER]Reitkarte. Es ist nur eine Kleinigkeit, aber ich[ENTER]brauche sie nicht mehr, da ich meinen Laden nicht[ENTER]mehr so einfach verlassen kann. Nimm sie, als[ENTER]Zeichen meiner Dankbarkeit! "
gameforge.subquest_10._20_say = "Bitte, hِr mich an. Ich bin in einer misslichen[ENTER]Lage. Ich habe für kurze Zeit meinen Laden[ENTER]verlassen, weil ich etwas ganz Wichtiges zu[ENTER]erledigen hatte. Wنhrend meiner Abwesenheit stahl[ENTER]jemand meine Lieblingshaarnadel. "
gameforge.subquest_10._210_sayReward = "Du erhنltst 60.000 Erfahrungspunkte.[ENTER]Du erhنltst 10.000 Yang.[ENTER]Du erhنltst eine Reitkarte. "
gameforge.subquest_10._220_say = "Du hast meine Haarnadel noch nicht gefunden?[ENTER]Ich hoffe, du findest sie noch. "
gameforge.subquest_10._230_select = "Aufhِren "
gameforge.subquest_10._240_say = "Wirklich aufhِren? "
gameforge.subquest_10._250_say = "Ja, sie sind zنhe Gegner...[ENTER]Ruh dich aus und versuch es spنter noch einmal. "
gameforge.subquest_10._260_say = "Wo ist meine Lieblingshaarnadel?[ENTER]Das hat wohl nicht funktioniert... Auf[ENTER]Wiedersehen. "
gameforge.subquest_10._270_say = "Vielen Dank. Sie bedeutet mir wirklich viel. "
gameforge.subquest_10._30_say = "Mein Vater schenkte mir diese schmückende[ENTER]Haarnadel zum Geburtstag und ich liebe sie. Aber[ENTER]natürlich kann ich meinen Laden nicht wieder[ENTER]verlassen, sonst wird mir vielleicht noch etwas[ENTER]Wichtiges gestohlen.[ENTER]Kِnntest du die Haarnadel für mich suchen? Ich[ENTER]verdنchtige den Schmied. Er erwنhnte einmal, dass[ENTER]er nach solchem Haarschmuck sucht. "
gameforge.subquest_10._40_select = "Ich suche sie. "
gameforge.subquest_10._50_say = "Quest wirklich abbrechen? "
gameforge.subquest_10._60_say = "Bis zum nنchsten Mal.[ENTER]Viel Spaك noch. "
gameforge.subquest_10._70_say = "Wo mag meine Haarnadel nur sein?[ENTER]Auf Wiedersehen... "
gameforge.subquest_10._80_say = "Du suchst sie für mich?[ENTER]Oh, vielen Dank! "
gameforge.subquest_10._90_targetVid = "Geh zum Schmied "
