gameforge.subquest_11._100_targetVid = "Frage Yu-Hwan nach Mirines Bruder. "
gameforge.subquest_11._10_targetVid = "Finde meinen Bruder "
gameforge.subquest_11._110_npcChat = "Hast du Mirines Bruder gesehen? "
gameforge.subquest_11._120_say = "Ich habe mich verliebt, ohne zu wissen, was Liebe[ENTER]bedeutet... Lalalaa...[ENTER]Wen suchst du? Mirines Bruder? Wir haben uns kurz[ENTER]unterhalten, bevor er in die Berge ging, um[ENTER]seltene Krنuter zu suchen. Ich weiك nicht, wo er[ENTER]jetzt ist.[ENTER]Der Jنger hier im Dorf geht hنufig in die Berge.[ENTER]Warum fragst du nicht ihn?[ENTER]La, la, la, Liebe ist traurig, aber schِn... "
gameforge.subquest_11._130_targetVid = "Frage Yang-Shin nach Mirines Bruder. "
gameforge.subquest_11._140_say = "Mirines Bruder? Ja, er hat in den Bergen nach[ENTER]Krنutern gesucht.[ENTER]Er hat sich so gefreut, einige wirklich seltene[ENTER]Krنuter gefunden zu haben. Er wollte seiner[ENTER]Schwester aus dem Erlِs der Krنuter neue Kleider[ENTER]kaufen. Er ist wirklich nett.[ENTER]Ich schنtze, er wird in ein paar Tagen zurück[ENTER]sein. Meinst du nicht auch? "
gameforge.subquest_11._150_targetVid = "Erzنhle Mirine die Neuigkeiten. "
gameforge.subquest_11._160_npcChat = "Neuigkeiten über Mirines Bruder. "
gameforge.subquest_11._170_say = "Schau, ich habe einen Brief von meinem Bruder[ENTER]bekommen! Er schreibt, dass er einen Ort mit[ENTER]vielen Krنutern gefunden hat und deshalb lنnger[ENTER]fort bleiben wird.[ENTER]Verzeih. Ich hنtte dich nicht belنstigen sollen.[ENTER]Hier, es ist nicht viel, aber ich hoffe du nimmst[ENTER]es an und verzeihst mir.[ENTER]Danke, dass du den weiten Weg auf dich genommen[ENTER]hast! "
gameforge.subquest_11._180_sayReward = "Du erhنltst 122.000 Erfahrungspunkte.[ENTER]Du erhنltst 5.000 Yang. "
gameforge.subquest_11._20_npcChat = " Finde meinen Bruder. "
gameforge.subquest_11._30_say = "Kann ich dich um einen Gefallen bitten?[ENTER]Mein Bruder ist schon lange weg. Ich habe schon[ENTER]seit einiger Zeit nichts mehr von ihm gehِrt.[ENTER]So langsam mache ich mir Sorgen.[ENTER]Kِnntest du ihn suchen? "
gameforge.subquest_11._40_say = "Mein Bruder wollte den Musiker Yu-Hwan[ENTER]im nنchsten Dorf besuchen.[ENTER]Wenn du zu Yu-Hwan gehst, erfنhrst du[ENTER]sicher Neues über meinen Bruder.[ENTER]Vielen Dank im Voraus. "
gameforge.subquest_11._50_select = "Ja, mach ich. "
gameforge.subquest_11._60_say = "Willst du diese Quest für immer aufgeben? "
gameforge.subquest_11._70_say = "Vielen Dank.[ENTER]Bitte such ihn für mich.[ENTER]Ich mach mir groكe Sorgen.[ENTER]Bis bald. "
gameforge.subquest_11._80_say = "Schade, dass du mir nicht helfen willst.[ENTER]Bis bald. "
gameforge.subquest_11._90_say = "Du wirst ihn für mich suchen?[ENTER]Vielen Dank, ich mache mir groكe Sorgen um ihn.[ENTER]Viel Glück. "
