gameforge.subquest_12._110_sayReward = "Gehe dann zum Wنchter des Dorfplatzes zurück. "
gameforge.subquest_12._120_sayTitle = "Mi-Jung vom Weiكen-Eid "
gameforge.subquest_12._130_sayReward = "Geh und tِte Mi-Jung vom Weiكen-Eid.[ENTER]Kehre dann zum Wنchter des Dorfplatzes zurück. "
gameforge.subquest_12._140_targetVid = "Gehe zum Wنchter des Dorfplatzes. "
gameforge.subquest_12._150_sayTitle = "Mi-Jung vom Weiكen-Eid getِtet "
gameforge.subquest_12._160_sayReward = "Kehre zum Wنchter des Dorfplatzes zurück,[ENTER]um deine Belohnung in Empfang zu nehmen. "
gameforge.subquest_12._170_npcChat = "Ich habe Mi-Jung getِtet. "
gameforge.subquest_12._180_say = "Oh! Du bist wirklich so gut, wie ich gehِrt[ENTER]habe. Ganz erstaunlich. Dank dir wird das Problem[ENTER]mit dem Weiكen-Eid jetzt viel einfacher zu lِsen[ENTER]sein. Gut gemacht! "
gameforge.subquest_12._190_sayReward = "Du erhنltst 122.000 Erfahrungspunkte.[ENTER]Du erhنltst 20.000 Yang.[ENTER]Du erhنltst ein Silberarmband. "
gameforge.subquest_12._20_say = "Komm einen Moment her.[ENTER]Du bist ein guter Kنmpfer. Ich habe vom Hauptmann[ENTER]viel über dich gehِrt. "
gameforge.subquest_12._30_say = "Kannst du dich Mi-Jungs vom Weiكen-Eid annehmen,[ENTER]die so viele Probleme bereitet?[ENTER]Es ist schwer, das Dorf und seine Einwohner[ENTER]vor den hنufigen Angriffen des Weiكen-Eids zu[ENTER]schützen. Wenn wir Mi-Jung, eine der[ENTER]Anführerinnen, tِten, wird sich die Situation[ENTER]نndern. Die Sicherheit unseres Dorfes liegt in[ENTER]deiner Hand. Ich vertraue dir! "
gameforge.subquest_12._40_select = "Ja, werde ich. "
gameforge.subquest_12._50_select = "Jetzt nicht. "
gameforge.subquest_12._60_say = "Du willst uns wirklich nicht helfen? "
gameforge.subquest_12._70_say = "Es ist wohl nicht der richtige Zeitpunkt.[ENTER]Komm spنter wieder. "
gameforge.subquest_12._80_say = "Wenn du nicht willst, kann man nichts machen.[ENTER]Dann geh... "
gameforge.subquest_12._90_say = "Willst du uns wirklich nicht helfen? "
