gameforge.subquest_13._120_sayReward = "Der Waffenhنndler braucht deine Hilfe.[ENTER]Besorge ihm Eisenerz von Uriel und Leinen von[ENTER]Ariyoung. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_13._140_say = "Du brauchst Eisenerz? Ich kِnnte dir welches[ENTER]geben, wenn du mir einen Gefallen tust. "
gameforge.subquest_13._150_say = "Ich habe etwas fallen lassen, als ich vor den[ENTER]Tigern um mein Leben laufen musste: Es ist ein[ENTER]zusammengeschnürtes Bündel, in dem sich wichtige[ENTER]Bücher befinden. Wenn ich sie nicht habe, kann[ENTER]ich die Metinsteine nicht weiter untersuchen.[ENTER]Bring mir dieses Pنckchen und du bekommst etwas[ENTER]Erz von mir. "
gameforge.subquest_13._160_npcChat = "Ich habe dein Pنckchen. "
gameforge.subquest_13._170_say = "Danke![ENTER]Ich bitte dich zu oft um einen Gefallen.[ENTER]Hier! Hier hast du etwas Eisenerz. Ich hoffe, es[ENTER]erfüllt seinen Zweck. "
gameforge.subquest_13._180_say = "Was? Du brauchst noch mehr Eisenerz? Es wنchst[ENTER]nicht auf Bنumen, weiكt du![ENTER]Ich gebe dir etwas Eisenerz, aber du musst mir[ENTER]einen Gefallen tun.[ENTER]Tiger haben mein Pنckchen gestohlen. Ich bin[ENTER]weggerannt, um mein Leben zu retten. In diesem[ENTER]Pنckchen sind viele wichtige Dokumente. Ohne sie[ENTER]kann ich meine Forschung über die Metinsteine[ENTER]nicht fortführen. Bitte finde das Pنckchen, das[ENTER]sie mir gestohlen haben. "
gameforge.subquest_13._190_say = "Das hab ich dir doch schon gegeben.[ENTER]Hast du das vergessen? "
gameforge.subquest_13._200_sayTitle = "Pنckchen gefunden "
gameforge.subquest_13._20_npcChat = "Material für Waffen "
gameforge.subquest_13._210_say = "Du hast das Pنckchen von Uriel gefunden.[ENTER]Gehe zurück zu ihm. "
gameforge.subquest_13._220_npcChat = "Ich brauche Leinen. "
gameforge.subquest_13._230_say = "Du brauchst Leinen? Das habe ich Ah-Yu gegeben.[ENTER]Warte![ENTER]Wenn du sowieso zu ihr gehst, dann kannst du[ENTER]diesen Brief mitnehmen. Wir sind gut befreundet,[ENTER]haben uns aber wegen ihres Kindes lange nicht[ENTER]gesehen. Ich schreibe noch dazu, dass sie dir[ENTER]etwas von dem Leinen geben soll... So, damit ist[ENTER]allen geholfen![ENTER]Und richte ihr meine Grüكe aus. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Du hast doch bestimmt Leinen von Ah-Yu[ENTER]bekommen, oder? "
gameforge.subquest_13._250_npcChat = "Ariyoungs Brief "
gameforge.subquest_13._260_say = "Ein Brief von Ariyoung? Es ist schِn, nach so[ENTER]langer Zeit endlich wieder von ihr zu hِren.[ENTER]Früher haben wir uns oft zum Reden getroffen,[ENTER]aber in letzter Zeit war es schwierig.[ENTER]Hier steht, du brauchst Leinen? Ich habe welches[ENTER]von Ariyoung bekommen, davon kann ich dir etwas[ENTER]abgeben.[ENTER]Vielen Dank, dass du mir den Brief gebracht hast.[ENTER]Ich werde ihr gleich zurückschreiben... "
gameforge.subquest_13._270_qSetTitle = "Auf zum Waffenhنndler "
gameforge.subquest_13._280_targetVid = "Geh zum Waffenhنndler. "
gameforge.subquest_13._290_sayTitle = "Materialien abgeben "
gameforge.subquest_13._300_sayReward = "Ich habe das Material.[ENTER]Auf zum Waffenhنndler. "
gameforge.subquest_13._30_say = "Hey, du musst mir einen Gefallen tun.[ENTER]Ich versuche, neue Waffenarten zu fertigen.[ENTER]Es ist nicht leicht, das passende Material für[ENTER]sie zu finden. Ich habe viele Bestellungen und[ENTER]kann nicht selbst nach den Materialien suchen.[ENTER]Kِnntest du sie für mich besorgen? "
gameforge.subquest_13._310_say = "Gut gemacht. Du bist sehr fنhig und schnell.[ENTER]Lass mich jetzt an den Waffen arbeiten![ENTER]*Hنmmer, hنmmer.*[ENTER]Hier sind sie. Das sind die neuen Waffenarten.[ENTER]Ich habe mein Bestes gegeben. Ich hoffe, die[ENTER]Waffe gefنllt dir. Viel Spaك damit! "
gameforge.subquest_13._320_sayTitle = "Belohung: "
gameforge.subquest_13._330_sayReward = "Du erhنltst 122.000 Erfahrungspunkte.[ENTER]Du erhنltst 20.000 Yang. "
gameforge.subquest_13._340_sayReward = "Du erhنltst ein Breitschwert+3. "
gameforge.subquest_13._350_sayReward = "Du erhنltst einen Scherendolch+3. "
gameforge.subquest_13._360_sayReward = "Du erhنltst einen Pfauenfنcher+3. "
gameforge.subquest_13._40_say = "Natürlich werde ich dich dafür belohnen.[ENTER]Wenn die Waffen fertig sind, werde ich dir[ENTER]eine davon geben.[ENTER]Ich brauche folgende Materialien: Eisenerz und[ENTER]Leinen. Eisenerz erhنltst du bei Uriel, Leinen[ENTER]bei Ariyoung.[ENTER]Lass es mich wissen, wenn du alle Materialien[ENTER]hast. "
gameforge.subquest_13._50_say = "Willst du die Aufgabe wirklich nicht erledigen? "
gameforge.subquest_13._60_say = "Das war wohl zuviel für dich.[ENTER]Komm wieder, wenn du mehr Zeit hast! "
gameforge.subquest_13._70_say = "Wenn du nicht mِchtest, kann man wohl nichts[ENTER]machen. Bis bald. "
gameforge.subquest_13._80_say = "Sehr gut![ENTER]Wenn die Waffen fertig sind, bekommst du[ENTER]auch eine von mir. Viel Glück. "
gameforge.subquest_13._90_sendLetter = "Materialien suchen "
