gameforge.subquest_15._10_targetVid = "Eun-Jung vom Weiكen-Eid "
gameforge.subquest_15._110_sayReward = "Du hast Eun-Jung vom Weiكen-Eid getِtet.[ENTER]Geh zurück zum Wنchter des Dorfplatzes und[ENTER]erstatte ihm Bericht. "
gameforge.subquest_15._120_say = "Du bist groكartig! Sogar noch besser, als ich[ENTER]erwartet habe. Wir konnten gegen diese beiden[ENTER]Anführer des Weiكen-Eids nichts machen. Du aber[ENTER]bist mit beiden ganz leicht fertig geworden. "
gameforge.subquest_15._130_say = "Das ist unglaublich.[ENTER]Du solltest eine angemessene Belohnung erhalten.[ENTER]Bitte nimm dies und arbeite weiterhin für den[ENTER]Frieden des Dorfes! "
gameforge.subquest_15._140_sayReward = "Du erhنltst 150.000 Erfahrungspunkte.[ENTER]Du erhنltst 25.000 Yang.[ENTER]Du erhنltst eine Goldhalskette+4. "
gameforge.subquest_15._20_say = "Komm einen Moment her.[ENTER]Ich habe vom Hauptmann viel über dich gehِrt. Du[ENTER]scheinst furchtlos zu sein. Deshalb brauche ich[ENTER]noch einmal deine Hilfe: Der Weiكe-Eid ist[ENTER]schlimmer als je zuvor. "
gameforge.subquest_15._30_say = "Du hast dich zwar um Mi-Jung, die Anführerin des[ENTER]Weiكen-Eids, gekümmert, aber wir sind immer noch[ENTER]nicht sicher. Die Gefahr durch den Weiكen-Eid ist[ENTER]nicht weniger geworden, sondern grِكer als je[ENTER]zuvor! "
gameforge.subquest_15._40_say = "Um die Sache zu beenden, müssen wir auch noch[ENTER]die Anführerin Eun-Jung vernichten. Der Rest[ENTER]sollte dann einfach sein.[ENTER]Geh und tِte Eun-Jung. Unser Schicksal liegt in[ENTER]deinen Hنnden! "
gameforge.subquest_15._50_sayTitle = "حارس ساحة القرية: "
gameforge.subquest_15._60_say = "Kommst du spنter wieder?[ENTER]Du bist genau richtig für diesen Auftrag. "
gameforge.subquest_15._70_say = "Du kannst nicht? Na gut.[ENTER]Auf bald. "
gameforge.subquest_15._80_say = "Ich wusste, dass du uns helfen würdest.[ENTER]Tِte Eun-Jung. Wir erledigen den Rest.[ENTER]Viel Glück! "
gameforge.subquest_15._90_sayReward = "Tِte die Anführerin Eun-Jung. Hoffentlich gibt[ENTER]der Weiكe-Eid dann Ruhe. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "Frage Yu-Hwan "
gameforge.subquest_16._10_targetVid = "Suche nach der gepanzerten Kavallerie "
gameforge.subquest_16._110_targetVid = "Geh zu Yu-Hwan "
gameforge.subquest_16._120_say = "Das Leben ist so schِn... Oh, die Liebe,[ENTER]wunderschِn... ![ENTER]Du schon wieder. Was willst du jetzt?[ENTER]Informationen über die gepanzerte Kavallerie?[ENTER]Warum fragst du danach?[ENTER]Der Hauptmann hat wohl hochtrabende Plنne? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Es sind zwar kaum Originaltexte aus dieser Zeit[ENTER]erhalten, aber ich kenne einige Lieder über die[ENTER]gepanzerte Kavallerie. Moment, ich stimme kurz[ENTER]mein Instrument...[ENTER]Ach, du hast es eilig? Heutzutage nimmt sich[ENTER]niemand mehr die Zeit zum Zuhِren...[ENTER]Also gut. Grob zusammengefasst war Isups Reiterei[ENTER]beinahe unbesiegbar. Hervorragend ausgebildete[ENTER]Soldaten, schwere Eisenrüstungen und dazu noch[ENTER]schnell und beweglich. "
gameforge.subquest_16._150_say = "Es war die beste Armee, die dieser Kontinent[ENTER]jemals gesehen hat. Damals gingen viele Lنnder[ENTER]unter, weil nichts die Kavallerie aufhalten[ENTER]konnte. Heute sنhe das ganz نhnlich aus.[ENTER]Allerdings braucht man harte Trainingsmethoden[ENTER]und viel hochwertiges Eisen, um solch eine Armee[ENTER]aufzustellen.[ENTER]Du solltest den Fahrenden Hنndler und den[ENTER]Gelehrten Uriel befragen. Sie wissen sicher mehr[ENTER]über die Einzelheiten. "
gameforge.subquest_16._160_makequestbutton = "Zum Fahrenden Hنndler "
gameforge.subquest_16._170_qSetTitle = "Die gepanzerte Kavallerie "
gameforge.subquest_16._180_targetVid = "Fahrender Hنndler "
gameforge.subquest_16._190_sayReward = "Der Musiker Yu-Hwan sagt, dass der Fahrende[ENTER]Hنndler und der Gelehrte Uriel Informationen[ENTER]über die gepanzerte Kavallerie haben kِnnten.[ENTER]Gehe zuerst zum Fahrenden Hنndler. "
gameforge.subquest_16._200_sayTitle = "Fahrender Hنndler: "
gameforge.subquest_16._20_npcChat = "Die gepanzerte Kavallerie "
gameforge.subquest_16._210_say = "Was willst du von einem einfachen fahrenden[ENTER]Hنndler wie mir? Die Eisenrüstungen der[ENTER]gepanzerten Kavallerie? Das sind doch alte[ENTER]Geschichten. Wen interessiert das heute noch? Ich[ENTER]muss meinen Lebensunterhalt verdienen und kann[ENTER]nicht den ganzen Tag plaudern! "
gameforge.subquest_16._220_say = "Es wird immer schwieriger, über die Runden zu[ENTER]kommen. Seit diese Steine vom Himmel fallen,[ENTER]habe ich... Was sagst du?[ENTER]Achja, die Kavallerie.[ENTER]Soweit ich weiك, trugen sie Spezialrüstungen,[ENTER]deren Herstellung einzigartige Fنhigkeiten[ENTER]erforderte. Es sind die besten Rüstungen, die je[ENTER]hergestellt wurden! Gewِhnliche Messer oder[ENTER]sogar Pfeile prallten einfach ab! "
gameforge.subquest_16._230_say = "Dass diese Rüstungen etwas ganz Besonderes waren,[ENTER]sieht man schon an den Geldern, die nِtig waren,[ENTER]um die Kavallerie aufzustellen. Es heiكt,[ENTER]die Schatzkammern ganzer Kِnigreiche habe sie[ENTER]verschlungen! Wenn ich solche Rüstungen verkaufen[ENTER]würde, hنtte ich ausgesorgt! "
gameforge.subquest_16._240_say = "Heute kann man sogar aus Metinsteinen Rüstungen[ENTER]herstellen. Mit dieser neuen Rüstungsart eine[ENTER]gepanzerte Kavallerie wie die damalige[ENTER]aufzustellen, ist mِglicherweise nicht nur ein[ENTER]Traum. Aber ich rede zu viel. Ich muss weiter.[ENTER]Bis bald! "
gameforge.subquest_16._250_sayTitle = "Die gepanzerte Kavallerie "
gameforge.subquest_16._260_say = "Der Fahrende Hنndler wusste etwas über die[ENTER]Eisenrüstungen der gepanzerten Kavallerie.[ENTER]Gehe nun zum Gelehrten Uriel im Nachbardorf und[ENTER]frage ihn nach den Trainingsmethoden. "
gameforge.subquest_16._270_sayTitle = " أوريل : "
gameforge.subquest_16._280_say = "Was führt dich diesmal zu mir? Die gepanzerte[ENTER]Kavallerie? Natürlich weiك ich etwas über sie.[ENTER]Jeder weiك etwas. Man wird sie für alle Zeiten[ENTER]als die beste Armee der Geschichte in Erinnerung[ENTER]behalten! Vieles, was man sich erzنhlt, mag[ENTER]übertrieben sein, aber diese Reiter waren[ENTER]wirklich auكerordentlich gefürchtet. Und das zu[ENTER]Recht. "
gameforge.subquest_16._290_say = "Die gepanzerte Kavallerie war allen anderen[ENTER]Kنmpfern überlegen. Das lag hauptsنchlich an[ENTER]ihrem unmenschlich harten Training. Nur die[ENTER]Allerbesten konnten die Ausbildung abschlieكen,[ENTER]nicht wenige starben dabei. Ich glaube, wenn das[ENTER]gleiche Training heute durchgeführt werden würde,[ENTER]bliebe am Ende kein einziger Soldat übrig. "
gameforge.subquest_16._300_say = "Einige der Trainingsmethoden sind überliefert.[ENTER]Ich gebe dir ein paar Notizen mit, dann kannst du[ENTER]dir selbst ein Bild davon machen.[ENTER]Ich weiك, dass schreckliche Kriege wüten, aber[ENTER]ich bin nicht sicher, ob es eine gute Idee wنre,[ENTER]noch einmal so eine furchterregende Armee[ENTER]aufzustellen. "
gameforge.subquest_16._30_say = "Ich habe einen neuen Auftrag für dich.[ENTER]Du hast den Befehl, Informationen über die[ENTER]gepanzerte Kavallerie zu sammeln. Sie war die[ENTER]wichtigste Einheit der Armee von Isup, dem[ENTER]Gründerkِnig und Vereiniger des Kontinents.[ENTER]Die gepanzerte Kavallerie wurde von den anderen[ENTER]Lنndern wegen ihrer erstaunlichen Schnelligkeit[ENTER]und Angriffskraft gefürchtet. "
gameforge.subquest_16._310_say = "Gehe zum Hauptmann und berichte ihm alles,[ENTER]was du über die gepanzerte Kavallerie erfahren[ENTER]hast. "
gameforge.subquest_16._320_makequestbutton = "Gehe zum Hauptmann "
gameforge.subquest_16._330_npcChat = "Bericht über die gepanzerte Kavallerie "
gameforge.subquest_16._340_sayTitle = "Hauptmann: "
gameforge.subquest_16._350_say = "Hast du etwas herausfinden kِnnen? Erzنhl![ENTER]…[ENTER]Hm, das ist sehr interessant. Es steckt also[ENTER]nicht mehr dahinter als starke Rüstungen und[ENTER]hartes Training? Dann wنre es machbar! Mit solch[ENTER]einer Armee kِnnten die drei Reiche wieder[ENTER]vereint werden! "
gameforge.subquest_16._360_say = "Allerdings brنuchte ich eine ganze Menge Geld.[ENTER]Und viele gute Schmiede. Und Rekruten, die[ENTER]freiwillig durch die Hِlle gehen, um die Besten[ENTER]der Besten zu werden![ENTER]Nein, nein. Schau mich nicht so an. Keine Sorge,[ENTER]du hast vorerst genug getan. "
gameforge.subquest_16._370_say = "Hier, nimm diese Belohnung und ruh dich aus.[ENTER]Wir sehen uns spنter! "
gameforge.subquest_16._380_sayReward = "Du erhنltst 150.000 Erfahrungspunkte.[ENTER]Du erhنltst 30.000 Yang.[ENTER]Du erhنltst Goldohrringe. "
gameforge.subquest_16._40_say = "Mit den von dir gesammelten Informationen[ENTER]kِnnen wir vielleicht unsere eigene militنrische[ENTER]Schlagkraft stنrken. Besuch zuerst den Musiker[ENTER]Yu-Hwan. Ich bin sicher, dass er Einiges über[ENTER]Isups Kavallerie weiك. "
gameforge.subquest_16._50_say = "Hm, wie du meinst. Bis spنter dann! "
gameforge.subquest_16._60_say = "Werde ich jemals so eine Kavallerie bekommen?[ENTER]Sei vorsichtig. "
gameforge.subquest_16._70_say = "Danke, pass auf dich auf. "
gameforge.subquest_16._80_sayTitle = "Die gepanzerte Kavallerie "
gameforge.subquest_16._90_sayReward = "Der Hauptmann sucht nach Informationen über die[ENTER]legendنre Reiterei des Gründerkِnigs Isup.[ENTER]Der Musiker Yu-Hwan weiك vermutlich etwas[ENTER]darüber. Geh und frage ihn. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Rede mit der Gemischtwarenhنndlerin "
gameforge.subquest_17._10_targetVid = "Die Geschichte von Ariyoungs Ehemann "
gameforge.subquest_17._110_say = "Geh zur Gemischtwarenhنndlerin und erkundige[ENTER]dich nach Ariyoungs Ehemann. "
gameforge.subquest_17._120_npcChat = "Ariyoungs Ehemann "
gameforge.subquest_17._130_say = "Das ist eine traurige Geschichte. Sie weiك noch[ENTER]nicht, was mit ihrem Ehemann passiert ist? Er ist[ENTER]an einem Ort, von dem niemand zurückkommt...[ENTER]Er war mit seinen Waren gerade auf dem Weg[ENTER]zum Dorf zurück, als er von der Schwarzwindbande[ENTER]entführt und getِtet wurde. "
gameforge.subquest_17._140_say = "Sie wird sehr verzweifelt sein, wenn du es ihr[ENTER]mitteilst. Die beiden haben sich sehr geliebt.[ENTER]Aber erfahren muss sie es auf jeden Fall. Die[ENTER]Ungewissheit bringt sie sonst um. "
gameforge.subquest_17._150_targetVid = "Die traurige Nachricht "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "Die Gemischtwarenhنndlerin hatte schlechte[ENTER]Neuigkeiten. Geh zu Ariyoung und berichte ihr vom[ENTER]Tod ihres Ehemanns. "
gameforge.subquest_17._180_npcChat = "Dein Ehemann ist tot... "
gameforge.subquest_17._190_say = "Was sagst du da?! Er… er wurde von der[ENTER]Schwarzwindbande getِtet?[ENTER]Oh, nein... er ist tot... Ich weiك nicht, was ich[ENTER]ohne ihn tun soll! "
gameforge.subquest_17._200_say = "Würdest du mir den Leichnam meines Mannes[ENTER]hierher bringen, bitte? Dann kِnnte ich mich von[ENTER]ihm verabschieden. Oder wenigstens ein Andenken?[ENTER]Die Goo-Pae von der Schwarzwindbande haben[ENTER]bestimmt etwas. Bitte, bring mir alles, was du[ENTER]finden kannst, solange es nur von ihm ist! "
gameforge.subquest_17._20_say = "Es ist viel Zeit vergangen, seit ich etwas von[ENTER]meinem Mann gehِrt habe. Ich habe Angst um ihn.[ENTER]Hoffentlich ist ihm nichts passiert.[ENTER]Ich weiك: Es ist unnütz, sich Sorgen zu machen,[ENTER]wenn man doch nichts نndern kann. Aber mein Herz[ENTER]schlنgt so furchtbar stark. Ich kann mich einfach[ENTER]nicht beruhigen. "
gameforge.subquest_17._210_select = "Ja, ich helfe dir. "
gameforge.subquest_17._220_say = "Komm zu mir, wenn du es dir anders überlegt hast.[ENTER]Bitte... "
gameforge.subquest_17._230_say = "Du hast nichts gefunden? Danke trotzdem...[ENTER]Oh, ich Arme! "
gameforge.subquest_17._240_say = "Ich kann gar nicht sagen, wie dankbar ich dir[ENTER]bin. Ich bete für dich. "
gameforge.subquest_17._250_sendLetter = "Tِte Goo-Paes "
gameforge.subquest_17._260_say = "Die Schwarzwindbande hat Ariyoungs Ehemann[ENTER]ermordet und ausgeraubt. Tِte so lange Goo-Paes,[ENTER]bis du ein Andenken an Ariyoungs Ehemann findest. "
gameforge.subquest_17._270_npcChat = "Wegen deines Ehemanns... "
gameforge.subquest_17._280_say = "Wie ist es gelaufen? Konntest du ein Andenken[ENTER]von meinem Ehemann finden?[ENTER]Er war mein Ein und Alles.[ENTER]Irgendetwas? "
gameforge.subquest_17._290_select = "Noch nicht. Ich suche weiter! "
gameforge.subquest_17._300_say = "Die Goo-Pae von der Schwarzwindbande sind keine[ENTER]einfachen Gegner.[ENTER]Ruh dich ein wenig aus.[ENTER]Und hab vielen Dank für deine Hilfe. "
gameforge.subquest_17._30_say = "Ich hoffe, dass die Gemischtwarenhنndlerin etwas[ENTER]über meinen Ehemann gehِrt hat. Sie hat viele[ENTER]Kunden. Vielleicht hat ja jemand etwas erzنhlt. "
gameforge.subquest_17._310_say = "Dann werde ich auf einen anderen Helden warten[ENTER]müssen, der mir hilft.[ENTER]Auf Wiedersehen. "
gameforge.subquest_17._320_say = "Oh, das ist sehr freundlich.[ENTER]Bitte, bring mir ein Andenken meines Ehemannes. "
gameforge.subquest_17._330_sendLetter = "Ariyoungs Ehering "
gameforge.subquest_17._340_targetVid = "Gehe zu Ariyoung "
gameforge.subquest_17._350_sayTitle = "Gehe zu Ariyoung "
gameforge.subquest_17._360_say = "Du hast bei einem der getِteten Goo-Paes den[ENTER]Ehering von Ariyoungs Ehemann gefunden. Ein[ENTER]besseres Andenken ist kaum vorstellbar.[ENTER]Bringe den Ring zu Ariyoung. "
gameforge.subquest_17._370_npcChat = "Ich habe diesen Ring gefunden. "
gameforge.subquest_17._380_say = "Dieser Ring... ist... mein Ehering! Vielen Dank![ENTER]Jetzt kann mein Ehemann in Frieden ruhen.[ENTER]Ich werde diesen Ring zusammen mit einem Brief[ENTER]von mir vergraben![ENTER]Von jetzt an werde ich allein leben.[ENTER]Zumindest habe ich seinen Ehering wieder![ENTER]Das ist ein wunderbares Gefühl. Ich danke dir,[ENTER]ich danke dir so sehr. "
gameforge.subquest_17._390_sendLetter = "Quest abgeschlossen! "
gameforge.subquest_17._400_say = "Deine Taten für Ariyoung sprechen sich herum.[ENTER]Viele Leute würdigen deine Hilfe. "
gameforge.subquest_17._40_select = "Ich gehe zu der Hنndlerin. "
gameforge.subquest_17._410_sayReward = "Du erhنltst 300.000 Erfahrungspunkte. "
gameforge.subquest_17._420_sayReward = "Du erhنltst 10.000 Yang. "
gameforge.subquest_17._50_select = "Nein, keine Zeit. "
gameforge.subquest_17._60_say = "Willst du diese Quest für immer aufgeben? "
gameforge.subquest_17._70_say = "Komm zu mir, wenn du es dir anders überlegt hast.[ENTER]Bitte... "
gameforge.subquest_17._80_say = "Du hast keine Zeit?[ENTER]Keine Zeit für so eine einfache Aufgabe?[ENTER]Tja, dann... "
gameforge.subquest_17._90_say = "Vielen Dank. Du bist wirklich sehr nett.[ENTER]Oh, wo ist bloك mein Ehemann? "
gameforge.subquest_18 = {}
gameforge.subquest_18._100_say = "Such einen Mann, der Gedichte liest und zerlumpte[ENTER]Kleider trنgt, und sprich ihn an. "
gameforge.subquest_18._10_targetVid = "Wo hat er sich versteckt? "
gameforge.subquest_18._110_npcChat = "Wo ist dein Ehemann? "
gameforge.subquest_18._120_say = "Ich weiك nicht, wo er sich versteckt.[ENTER]Er verbirgt sich inzwischen so gut, dass es[ENTER]schwer ist, ihn zu finden. Sollte ich wirklich[ENTER]ein Glِckchen um seinen Hals hنngen, wie es der[ENTER]Ladenbesitzer vorschlug? "
gameforge.subquest_18._130_npcChat = "Finde Soon! "
gameforge.subquest_18._140_say = "Du hِrst ein wunderbares Gedicht. Gefangen von[ENTER]den Worten folgst du dem Klang der Stimme, bis du[ENTER]vor einem Mann in zerlumpten Kleidern stehst.[ENTER]Das muss Aranyos Ehemann sein![ENTER]Du willst dich gerade abwenden, um zu Aranyo[ENTER]zurückzukehren, als er dich an der Schulter packt. "
gameforge.subquest_18._150_say = "Du bist nicht von hier.[ENTER]Hat dich meine Frau geschickt?[ENTER]Oh nein! Er weiك, wer ich bin! Was soll ich nur[ENTER]sagen? "
gameforge.subquest_18._153_select = "Ich kam nur zufنllig vorbei. "
gameforge.subquest_18._157_select = "Nun, eigentlich... "
gameforge.subquest_18._160_say = "Aha. Wie nett, dich kennenzulernen.[ENTER]Wunderbares Wetter, nicht wahr?[ENTER]Hast du in letzter Zeit ein gutes Buch gelesen?[ENTER]Ich lese momentan das Buch von Oja.[ENTER]Kann ich nur empfehlen. "
gameforge.subquest_18._170_say = "Ich habe Recht, nicht wahr?[ENTER]Die Sticheleien meiner Frau sind inzwischen so[ENTER]schlimm, dass ich zu Hause einfach nicht mehr in[ENTER]Ruhe lesen kann. Sie versteht mich einfach nicht.[ENTER]Und jetzt schickt sie mir auch noch Leute[ENTER]hinterher... Du hast mich zwar hier entdeckt,[ENTER]aber ich kann jederzeit woanders hin gehen. Wie[ENTER]wنre es, wenn du ihr nichts verraten würdest?[ENTER]Dafür werde ich dir einen guten Ratschlag geben,[ENTER]der die Jagd betrifft. "
gameforge.subquest_18._180_sendLetter = "Zurück zu Aranyo "
gameforge.subquest_18._190_say = "Kehre zu Aranyo zurück und erzنhle ihr,[ENTER]dass du Soon nicht finden konntest. "
gameforge.subquest_18._200_npcChat = "Soons Geheimnis. "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "Du konntest ihn nicht finden?[ENTER]Ich habe sogar Fallen aufgestellt.[ENTER]Wo zum Teufel hat er sich versteckt?[ENTER]Ich bin so beschنftigt...[ENTER]Was für ein elendes Schicksal. "
gameforge.subquest_18._220_sendLetter = "Zurück zu Soon "
gameforge.subquest_18._230_say = "Gehe zurück zu Soon und teile ihm mit, dass[ENTER]du erfolgreich warst. "
gameforge.subquest_18._240_npcChat = "Hier bin ich. "
gameforge.subquest_18._250_say = "Ging alles gut? Du hast mir das Leben[ENTER]gerettet! Nimm das hier, Abenteurer. Wie[ENTER]versprochen gebe ich dir eine Belohnung. "
gameforge.subquest_18._260_sayReward = "Du erhنltst 7.000 Erfahrungspunkte. "
gameforge.subquest_18._270_sayReward = "Du erhنltst 10.000 Yang. "
gameforge.subquest_18._280_say = "Kehre zu Aranyo zurück und teile ihr Soons[ENTER]Aufenthaltsort mit. "
gameforge.subquest_18._290_npcChat = "Das Versteckspiel ist schwierig. "
gameforge.subquest_18._300_say = "Vielen Dank, dass du mich nicht verraten hast![ENTER]Es ist nicht leicht, sich vor seiner Frau zu[ENTER]verstecken. Ich mِchte doch lediglich in Ruhe[ENTER]studieren... "
gameforge.subquest_18._30_say = "Mein Ehemann ist wirklich meine grِكte Plage.[ENTER]Er bezeichnet sich selbst als einen Gelehrten![ENTER]Wنhrend wir um unser tنgliches Brot kنmpfen,[ENTER]liest er nur Bücher.[ENTER]Hast du ihn gesehen? Wieso habe ich bloك[ENTER]so einen Bücherwurm geheiratet? "
gameforge.subquest_18._310_npcChat = "Soons Aufenthalt "
gameforge.subquest_18._320_say = "Du hast ihn entdeckt?[ENTER]Vielen, vielen Dank! Wenn er bemerkt, dass du ihn[ENTER]gefunden hast, kِnnte er fliehen. Ich mache mich[ENTER]sofort auf den Weg. Dieses Mal erwische ich ihn![ENTER]Und du bekommst das hier, als Zeichen meiner[ENTER]Anerkennung.[ENTER]Na warte, Bürschchen...! "
gameforge.subquest_18._33_select = "Ich helfe dir. "
gameforge.subquest_18._37_select = "Dafür habe ich keine Zeit. "
gameforge.subquest_18._40_say = "Willst du diese Aufgabe beenden? "
gameforge.subquest_18._50_say = "Gut. Vielleicht schaust du spنter nach ihm. "
gameforge.subquest_18._60_say = "Vielleicht findest du ihn doch noch... "
gameforge.subquest_18._70_say = "Dafür wنre ich sehr dankbar.[ENTER]Wenn du einen armen Schreiberling entdeckst, lass[ENTER]es mich wissen. Er ist vermutlich ohnehin der[ENTER]Einzige im Dorf. Vielleicht schreibt er ja gerade[ENTER]ein Gedicht und bleibt deswegen lieber für sich.[ENTER]Wenn er erfنhrt, dass ich ihn suche, kِnnte er[ENTER]weglaufen. Also sei vorsichtig. "
gameforge.subquest_18._80_sendLetter = "Suche Soon "
gameforge.subquest_18._90_sayTitle = "Suche den Bücherwurm "
