gameforge.subquest_19._10_npcChat = "Suche einen Staubwedel "
gameforge.subquest_19._110_sayTitle = "Wolfspelz besorgen "
gameforge.subquest_19._120_sayReward = "Besorge einen Wolfspelz, damit die Alte Frau[ENTER]ihr Haus sنubern kann und nicht mehr husten muss.[ENTER]Du bekommst ihn von den Grauwِlfen. "
gameforge.subquest_19._130_targetVid = "Zurück zur Alten Frau "
gameforge.subquest_19._140_npcChat = "Wolfspelz abliefern "
gameforge.subquest_19._150_say = "Ein Wolfspelz, wie liebenswürdig...[ENTER]Oh, nein! Dieser Wolfpelz taugt leider nichts.[ENTER]Geh noch einmal zu den Wِlfen. Vielleicht findest[ENTER]du diesmal einen besseren. "
gameforge.subquest_19._160_say = "Ich brauche einen richtigen Staubwedel.[ENTER]Entschuldige bitte, aber damit kann ich nichts[ENTER]anfangen. "
gameforge.subquest_19._170_select = "Ich versuche es nochmal. "
gameforge.subquest_19._180_select = "Ich habe keine Lust mehr. "
gameforge.subquest_19._190_say = "Willst du diese Aufgabe wirklich beenden? "
gameforge.subquest_19._200_say = "Komm einfach spنter noch einmal wieder. "
gameforge.subquest_19._20_say = "Hust! Hust! Diese Husterei laugt mich aus. Ich[ENTER]habe nichts zum Abstauben. Deswegen bleibt der[ENTER]ganze Staub im Haus liegen. Oh, warum habe ich[ENTER]keinen Staubwedel? Mein Sohn nahm ihn mit, um[ENTER]irgendeine Waffe zu bearbeiten. Mein eigen[ENTER]Fleisch und Blut bringt mich um! "
gameforge.subquest_19._210_say = "Ich weiك, dass es schwer ist. Aber versuche es[ENTER]bitte trotzdem noch einmal. "
gameforge.subquest_19._220_say = "Danke, dass du dich darum kümmerst. "
gameforge.subquest_19._230_say = "Du bist der Abenteurer von neulich! Wie klingt[ENTER]mein Husten? Hust, hust![ENTER]Wie du hِren kannst, hat sich nicht viel[ENTER]geنndert. Das Haus ist immer noch voller Staub.[ENTER]Oh? Du hast mir einen Wolfspelz gebracht? Was für[ENTER]ein prنchtiges Exemplar, der ist genau richtig![ENTER]Du bist sehr edelmütig. Warte einen Moment, ich[ENTER]bin gleich wieder da... "
gameforge.subquest_19._240_say = "Eins, zwei, eins, zwei. Immer einen Fuك vor den[ENTER]anderen...[ENTER]So, da bin ich wieder. Vielen Dank! Endlich[ENTER]konnte ich mein Haus richtig sنubern. Ich habe[ENTER]dabei etwas gefunden, das ich dir gerne geben[ENTER]mِchte. Ich weiك nicht, ob es etwas wert ist,[ENTER]aber vielleicht kannst du es gebrauchen.[ENTER]Vielen Dank noch einmal. Lebe wohl! "
gameforge.subquest_19._250_sendLetter = "Ein verstaubtes Etwas "
gameforge.subquest_19._260_say = "Dein Lohn besteht aus einem groكen, unhandlichen[ENTER]Gegenstand, der unter seiner jahrzehntealten[ENTER]Staubschicht nicht zu identifizieren ist.[ENTER]Neugierig entstaubst du ihn... "
gameforge.subquest_19._270_say = "Es ist eine alte Rüstung von hoher Qualitنt,[ENTER]das Werk eines guten Schmieds. Welch ein[ENTER]Glück! "
gameforge.subquest_19._280_say = "Es ist eine Rüstung. Alt, aber noch zu[ENTER]gebrauchen. Immerhin etwas! "
gameforge.subquest_19._290_say = "Es handelt sich um eine Rüstung. Deiner Hoffnung[ENTER]zum Trotz stellt sie sich jedoch als so gut wie[ENTER]wertlos heraus. "
