gameforge.subquest_19._30_select = "Ich besorg dir einen. "
gameforge.subquest_19._40_say = "Ist das alles verstaubt![ENTER]Ich brauche unbedingt einen richtigen[ENTER]Staubwedel.[ENTER]Willst du mir helfen? "
gameforge.subquest_19._50_say = "Es ist schon eine ganze Weile her, aber ich[ENTER]glaube, dass mein Ehemann - mِge er in Frieden[ENTER]ruhen - ihn aus einem Wolfspelz fertigte.[ENTER]Hust! Hust![ENTER]Kِnntest du einer armen, alten Frau vielleicht[ENTER]einen Wolfspelz besorgen? Am besten von einem[ENTER]Grauwolf. Du würdest mir damit sehr helfen. "
