gameforge.subquest_19._80_say = "Was für eine Belohnung kann man schon von[ENTER]so einer armen, alten Frau erwarten? "
gameforge.subquest_19._90_say = "Es ist nicht einfach, so einen Wolfspelz zu[ENTER]bekommen. Aber ich werde es versuchen. Denn ich[ENTER]will ja mal ein groكer Held werden! "
