gameforge.subquest_20._300_sayTitle = "Ah-Yu: "
gameforge.subquest_20._30_say = "Oh, bitte weine nicht mehr, mein Liebling. Mama[ENTER]hat auch Sorgen. Wenn du immer[ENTER]weiter weinst, werden wir uns beide nicht[ENTER]beruhigen kِnnen! Bitte, hِr auf. "
gameforge.subquest_20._310_say = "Du hast einen gefunden, das ist gut![ENTER]Aber kannst du bitte auch die übrigen beiden[ENTER]suchen? Sie gehِren doch zusammen.[ENTER]Auكerdem sieht es viel schِner aus, wenn sie[ENTER]gemeinsam an der Wand hنngen...[ENTER]Ich danke dir. "
gameforge.subquest_20._320_select = "Ich versuche es noch einmal. "
gameforge.subquest_20._330_select = "Ich gebe auf. "
gameforge.subquest_20._340_say = "Du hast die Suche nach den Speeren von Ah-Yus[ENTER]Ehemann aufgegeben. "
gameforge.subquest_20._350_say = "Vielen Dank, dass du nicht aufgibst! "
gameforge.subquest_20._360_say = "Oh, da sind sie ja! Ich bin sehr froh, vielen[ENTER]Dank. Hier. Das ist zwar nicht viel Yang, aber[ENTER]nimm es ruhig. "
gameforge.subquest_20._370_sayReward = "Du erhنltst 300.000 Erfahrungspunkte.[ENTER]Du erhنltst 20.000 Yang. "
gameforge.subquest_20._40_say = "So kenne ich dich gar nicht. Du bist doch sonst[ENTER]immer so frِhlich! Ist etwas passiert? "
gameforge.subquest_20._50_say = "Früher hat mein Mann immer für mich gesorgt und[ENTER]aufgepasst, dass mir nichts zustِكt. Dann ist er[ENTER]im Krieg gestorben.[ENTER]Das einzige, was ich jetzt noch von ihm habe,[ENTER]sind unser Baby und seine Speere. "
gameforge.subquest_20._60_say = "Aber heute hat jemand die Speere gestohlen,[ENTER]wنhrend ich arbeiten war. Meine Nachbarin sagt,[ENTER]es seien Wilde Mنnner gewesen. Die Speere waren[ENTER]das letzte Andenken an meinen Ehemann. Und wegen[ENTER]des Babys kann ich nicht suchen gehen. "
gameforge.subquest_20._70_say = "Kannst du mir die Speere wiederbringen? Du[ENTER]findest sie bestimmt bei den Wilden. "
gameforge.subquest_20._80_select = "Ich werde sie suchen. "
gameforge.subquest_20._90_select = "Ich habe keine Zeit. "
