gameforge.subquest_21._20_npcChat = "Es juckt so sehr... "
gameforge.subquest_21._30_sayTitle = "Verrنter Balso: "
gameforge.subquest_21._40_say = "Darf ich dich um einen Gefallen bitten? Wie du[ENTER]wahrscheinlich schon erfahren hast, bin ich als[ENTER]ein Verrنter bekannt. Es ist nun sehr schwierig[ENTER]für mich, mein Leben zu führen. Ich hatte auch[ENTER]gute Zeiten, in denen ich gut lebte. Aber jetzt[ENTER]ist es genau das Gegenteil. Nun bin ich immer auf[ENTER]der Flucht. Dabei komme ich mit vielen[ENTER]Krankheiten in Kontakt. "
gameforge.subquest_21._50_say = "Vor ein paar Tagen war ich am Berg Sohan[ENTER]unterwegs und geriet zwischen einige[ENTER]Plagenmنnner. Zum Glück konnte ich fliehen,[ENTER]aber ich scheine mir bei der Berührung ihrer[ENTER]fauligen Haut irgendeine Krankheit zugezogen zu[ENTER]haben. Kannst du mir helfen, Medizin zu bekommen?[ENTER]Ich vermute, dass sie welche bei sich tragen.[ENTER]Ich mache das nur ungern, aber ich bitte dich[ENTER]sehr, mir zu helfen. "
gameforge.subquest_21._60_select = "Ja, ich helfe dir. "
gameforge.subquest_21._70_say = "Mِchtest du mit der Suche aufhِren? "
gameforge.subquest_21._80_say = "Tja, das passiert mir immer wieder. Um mich[ENTER]herum gibt es nur Leute, die mich nicht mِgen.[ENTER]Falls du es dir anders überlegst, dann komm[ENTER]spنter nochmal wieder. "
gameforge.subquest_21._90_say = "Verschwinde! Und lass dich hier nie wieder[ENTER]blicken! Immer dasselbe... "
