gameforge.subquest_22._30_sayTitle = "Holzfنller Deokbae: "
gameforge.subquest_22._40_say = "Oh nein, oh nein! Ich habe die Axt verloren.[ENTER]Vielleicht weiكt du, welche Axt ich meine?[ENTER]Es ist die goldene Axt, die ich vom Schmied[ENTER]bekommen habe. Ein Wilder hat sie mir gestohlen. "
gameforge.subquest_22._50_say = "Wenn der Schmied dies herausfindet, wird er sehr[ENTER]zornig sein und meine ؤxte nicht mehr reparieren.[ENTER]Auكerdem war es eine wirklich gute Axt. Kannst du[ENTER]sie zurückbringen? "
