gameforge.subquest_23._120_say = "Der نltere Bruder von Mirine ist wieder[ENTER]verschwunden. Er hat vor einiger Zeit einen Brief[ENTER]geschrieben, seitdem aber nichts mehr von sich[ENTER]hِren lassen. Geh zu Yu-Hwan und frage ihn, ob[ENTER]er etwas über Mirines Bruder weiك. "
gameforge.subquest_23._130_npcChat = "Hast du Mirines Bruder gesehen? "
gameforge.subquest_23._140_say = "Mirines Bruder? Nein, ich kann dir leider nicht[ENTER]weiterhelfen. Ich hatte auch schon lنngere Zeit[ENTER]keinen Kontakt mehr mit ihm. Ich kann mich kaum[ENTER]erinnern, wann ich ihn das letzte Mal gesehen[ENTER]habe. Ich mache mir auch Sorgen. Vielleicht ist[ENTER]etwas passiert? Frag doch mal den Jنger[ENTER]Yang-Shin. Er kommt viel herum und ist ihm[ENTER]vielleicht begegnet. "
gameforge.subquest_23._150_sendLetter = "Suche Yang-Shin "
gameforge.subquest_23._160_targetVid = "Gehe zum Jنger Yang-Shin "
gameforge.subquest_23._170_say = "Der Jنger Yang-Shin kommt viel herum. Vielleicht[ENTER]hat er Mirines نlteren Bruder gesehen. "
gameforge.subquest_23._180_npcChat = "Hast du Mirines Bruder gesehen? "
gameforge.subquest_23._190_say = "Mirines نlterer Bruder? Als ich ihn das letzte[ENTER]Mal getroffen habe, war er unterwegs zum Tal von[ENTER]Seungryong, um dort Heilkrنuter zu sammeln. Ich[ENTER]war etwas verwundert, weil es dort sehr[ENTER]gefنhrlich ist, habe mir aber nichts weiter dabei[ENTER]gedacht. "
gameforge.subquest_23._200_say = "Ich hنtte ihn aufhalten sollen. Wenn er sich[ENTER]bisher nicht gemeldet hat, dann ist ihm bestimmt[ENTER]etwas zugestoكen.[ENTER]Am Besten gehst du gleich ins Tal von Seungryong[ENTER]und suchst nach ihm. "
gameforge.subquest_23._20_npcChat = "Warum weinst du? "
gameforge.subquest_23._210_select = "Suche beginnen "
