gameforge.subquest_23._230_say = "Mirine war wirklich sehr traurig.[ENTER]Ich werde spنter wiederkommen. "
gameforge.subquest_23._240_say = "Wenn ein نlterer Bruder sich lنnger nicht[ENTER]meldet, dann muss das noch lange nicht bedeuten,[ENTER]dass ihm etwas zugestoكen ist.[ENTER]Du musst nicht in dieses gefنhrliche Tal gehen,[ENTER]bloك weil ein kleines Mنdchen dich darum bittet. "
gameforge.subquest_23._250_say = "Der Auftrag ist wohl doch nicht so geringfügig,[ENTER]wie es zunنchst aussah. Das Tal von Seungryong[ENTER]ist ein gefنhrlicher Ort. Aber ich habe es[ENTER]versprochen, also mache ich auch weiter. "
gameforge.subquest_23._260_sendLetter = "Der verschollene Bruder "
gameforge.subquest_23._270_targetVid = "Suche nach dem نlteren Bruder im Tal von[ENTER]Seungryong "
