gameforge.subquest_23._290_say = "Mirines نlterer Bruder sucht Heilkrنuter im Tal[ENTER]von Seungryong. Geh dorthin und sieh nach, ob es[ENTER]ihm gut geht. Der Teleporter hilft dir, wenn du[ENTER]eine Abkürzung suchst. "
gameforge.subquest_23._300_npcChat = "Die Leiche! "
gameforge.subquest_23._30_say = "Du hast mir einmal einen Brief von meinem Bruder[ENTER]gebracht, nicht wahr? Da war ich dir sehr[ENTER]dankbar. Seitdem habe ich keinen Kontakt mehr zu[ENTER]ihm. Mein Bruder ist immer noch unterwegs. Er[ENTER]sucht nach Heilkrنutern für mich. "
gameforge.subquest_23._310_say = "Hier liegt ein toter Mann. Er war jung und dünn[ENTER]und hat wohl Ginseng gesammelt. Ich fürchte, es[ENTER]ist der gesuchte نltere Bruder von Mirine.[ENTER]Die Leiche trنgt eine Kette mit einem Anhنnger[ENTER]bei sich. Ich nehme sie mit und bringe sie[ENTER]Mirine. "
gameforge.subquest_23._320_sendLetter = "Gehe zu Mirine "
gameforge.subquest_23._330_sayTitle = "Die traurige Nachricht "
gameforge.subquest_23._340_say = "Du hast an einer Leiche im Tal von Seungryong[ENTER]einen Anhنnger gefunden, auf dem Mirines Name[ENTER]eingraviert ist.[ENTER]Geh zu Mirine und gib ihr Kette und Anhنnger. "
gameforge.subquest_23._350_npcChat = "Kennst du diese Kette? "
gameforge.subquest_23._360_say = "Oh, diese Kette... die hat mein Bruder immer[ENTER]getragen. Ich habe eine نhnliche Kette. Wir haben[ENTER]die Ketten immer getragen, damit wir uns[ENTER]aneinander erinnern und wieder zueinander finden.[ENTER]Aber... mein Bruder ist nun nicht mehr da...[ENTER]Nur seine Kette ist zurückgekommen... "
gameforge.subquest_23._370_say = "Mein armer Bruder...[ENTER]Der Krieg ist schuld daran. Mein Bruder hat[ENTER]Heilkrنuter verkauft, das war das Einzige, das[ENTER]Geld einbrachte. So konnten wir uns ernنhren.[ENTER]Mein Bruder hat immer fleiكig gearbeitet, damit[ENTER]ich genug zu Essen bekomme. Jetzt ist er tot.[ENTER]Wegen mir... "
gameforge.subquest_23._380_say = "Danke, dass du mir die Kette gebracht hast. Jetzt[ENTER]weiك ich wenigstens, was geschehen ist. Hنttest[ENTER]du mir nicht geholfen, hنtte ich das nie[ENTER]erfahren. "
gameforge.subquest_23._390_say = "Den Anhنnger meines نlteren Bruders bewahre ich[ENTER]sorgfنltig auf und die Kette gebe ich dir zum[ENTER]Dank. Sie wird dir sicherlich hilfreich sein.[ENTER]Danke für die Hilfe.[ENTER]Bestimmt ist er jetzt im Himmel, meinst du nicht[ENTER]auch? "
gameforge.subquest_23._400_sayReward = "Du erhنltst 600.000 Erfahrungspunkte.[ENTER]Du erhنltst 35.000 Yang. "
gameforge.subquest_23._40_say = "Aber ich sorge mich schon um ihn,[ENTER]weil ich keinen Kontakt mehr zu ihm habe.[ENTER]Entschuldige, aber kِnntest du[ENTER]bitte noch einmal meinen Bruder suchen?[ENTER]Vielleicht weiك Yu-Hwan etwas. "
gameforge.subquest_23._50_select = "Absagen "
gameforge.subquest_23._60_say = "Mِchtest du die Suche aufgeben? "
gameforge.subquest_23._70_say = "Oh...[ENTER]Ich warte hier.[ENTER]Vielleicht spنter? Bitte? "
gameforge.subquest_23._80_say = "Ich hab keine Zeit![ENTER]Viel Glück für deinen Bruder. "
gameforge.subquest_23._90_say = "Ein weinendes Mنdchen im Stich lassen wنre[ENTER]nicht sehr nett. Und der Auftrag wird auch nicht[ENTER]viel Zeit beanspruchen. Dann mal los! "
