gameforge.subquest_30._140_sayTitle = "Besorge Erz für neue Waffen "
gameforge.subquest_30._150_say = "Der Schmied benِtigt Erz für die Herstellung[ENTER]einer neuen Waffenart. Bringe ihm jeweils 100[ENTER]Golderz, Silbererz und Ebenholzerz.[ENTER]Erzvorkommen sind überall auf der Karte verteilt[ENTER]und kِnnen mit Bergbau bearbeitet werden. Du[ENTER]kannst aber auch mit anderen Spielern handeln und[ENTER]ihnen Erz abkaufen. "
