gameforge.subquest_30._180_select = "Weitersuchen "
gameforge.subquest_30._190_select = "Aufgeben "
gameforge.subquest_30._200_say = "Du willst wirklich für immer aufgeben? "
gameforge.subquest_30._20_say = "Hey, du! Ja, genau dich meine ich! Du bist nun[ENTER]kein Anfنnger mehr. Und warum? Weil ich dir[ENTER]komplizierte Aufgaben gestellt habe! Es war alles[ENTER]nur für dein Wohl, hehehe. Aber jetzt bitte ich[ENTER]dich um einen wirklichen Gefallen. "
gameforge.subquest_30._210_say = "Es ist schwer, Erz zu bekommen, nicht wahr?[ENTER]Doch das Glück kommt erst mit der harten Arbeit.[ENTER]Wie wنre es mit einer kurzen Pause, bevor du es[ENTER]erneut versuchst? "
gameforge.subquest_30._220_say = "Schade. Es war so eine brilliante Idee.[ENTER]Naja, was soll's. Bis bald! "
gameforge.subquest_30._230_say = "Gib dir ein wenig Mühe, dann hast du bald alles[ENTER]zusammen. Viel Glück! "
gameforge.subquest_30._240_say = "Oh, du hast tatsنchlich schon alles beisammen![ENTER]Hahaha! Ich spüre, dass es klappen wird! Warte[ENTER]einen Moment, es wird nicht lange dauern. Und los[ENTER]geht's! "
gameforge.subquest_30._250_say = "So, es ist fertig. Meine Begabung überrascht mich[ENTER]immer wieder. Hier ist deine Waffe. Sie ist neu,[ENTER]also gehe behutsam damit um! "
gameforge.subquest_30._260_sayReward = "Du erhنltst 200.000 Erfahrungspunkte. "
gameforge.subquest_30._270_sayReward = "Du erhنltst 20.000 Yang. "
gameforge.subquest_30._280_sayReward = "Du erhنltst ein Silberschwert+3. "
gameforge.subquest_30._290_sayReward = "Du erhنltst einen Aquatischen Fنcher+3. "
gameforge.subquest_30._30_say = "Ich mِchte versuchen, eine neue Waffe zu[ENTER]schmieden, aber die Materialien sind schwer zu[ENTER]beschaffen. Kِnntest du das für mich erledigen?[ENTER]Als Belohnung werde ich dir das erste fertige[ENTER]Exemplar überlassen. "
gameforge.subquest_30._40_say = "Ich benِtige je 100 Stück Golderz, Silbererz und[ENTER]Ebenholzerz. Das klingt nach mehr, als es ist.[ENTER]Mit Bergbau kannst du viele Rohstoffe auf einmal[ENTER]besorgen, so dass du sie mit Leichtigkeit[ENTER]zusammenbekommen solltest.[ENTER]Wenn es doch zu schwierig für dich ist, dann[ENTER]kannst du sie auch von jemandem erhandeln. Ganz[ENTER]wie du willst. Ich wünsche dir viel Erfolg! "
gameforge.subquest_30._50_select = "Ablehnen "
