gameforge.subquest_31._210_say = "Soviel zu meinem Plan für eine neuartige[ENTER]Rüstung. Diese Idee hنtte unser gesamtes[ENTER]Zeitalter verنndern kِnnen![ENTER]Es ist jammerschade... "
gameforge.subquest_31._220_say = "Sei stark! Ich weiك, dass du es schaffen kannst! "
gameforge.subquest_31._230_say = "Hervorragend. Du bist wirklich gut im Beschaffen[ENTER]von Materialien. Jetzt pass auf![ENTER]Hier... und hier... und noch schnell abgekühlt...[ENTER]So, das ist für dich, als Lohn für deine Mühen.[ENTER]Bis bald! "
gameforge.subquest_31._240_sayReward = "Du erhنltst 200.000 Erfahrungspunkte. "
gameforge.subquest_31._250_sayReward = "Du erhنltst 20.000 Yang. "
gameforge.subquest_31._260_sayReward = "Du erhنltst einen Lِwenplattenpanzer+3. "
gameforge.subquest_31._270_sayReward = "Du erhنltst einen Roten Ameisenanzug+3. "
gameforge.subquest_31._280_sayReward = "Du erhنltst einen Geistplattenpanzer+3. "
gameforge.subquest_31._290_sayReward = "Du erhنltst eine Kleidung der Liebe+3. "
gameforge.subquest_31._30_say = "Hallo, hast du eine Minute Zeit für mich?[ENTER]Ich weiك es sehr zu schنtzen, dass du mir[ENTER]geholfen hast, eine neue Waffe herzustellen.[ENTER]Jetzt mِchte ich gerne noch einmal deine Hilfe in[ENTER]Anspruch nehmen. Diesmal mِchte ich eine neue[ENTER]Rüstung herstellen. Nachdem ich eine gute Waffe[ENTER]hergestellt habe, ist es klar, dass ich jetzt[ENTER]auch eine gute Rüstung brauche. "
gameforge.subquest_31._40_say = "Natürlich brauche ich wieder Materialien für die[ENTER]Herstellung. Kannst du sie mir besorgen? Du[ENTER]bekommst auch wieder die erste fertige Rüstung[ENTER]dafür. Diesmal brauche ich je 100 Stück[ENTER]Kupfererz, Ebenholzerz und Perlen. Du solltest[ENTER]das ja schon kennen. Viel Erfolg! "
gameforge.subquest_31._50_select = "Annehmen "
gameforge.subquest_31._60_say = "Mِchtest du die Quest für immer aufgeben? "
gameforge.subquest_31._70_say = "Warum zِgerst du dann? Komm wieder, wenn du[ENTER]bereit bist, dich im Bergbau zu betنtigen. "
gameforge.subquest_31._80_say = "Das bisschen Erz ist doch nun wirklich nicht[ENTER]zuviel verlangt. Na, wie du meinst. Verschwinde! "
gameforge.subquest_31._90_say = "Du hilfst mir wieder? Du bist ein guter Freund.[ENTER]Und keine Sorge: Die erste Rüstung gehِrt dir! "
gameforge.subquest_32 = {}
gameforge.subquest_32._100_sendLetter = "Hنndleranfrage "
gameforge.subquest_32._10_targetVid = "Auswahl der Hنndler "
gameforge.subquest_32._110_targetVid = "Gehe zu Ah-Yu "
gameforge.subquest_32._120_targetVid = "Gehe zur Gemischtwarenhنndlerin "
gameforge.subquest_32._130_sayReward = "Materialien für den Hنndler "
gameforge.subquest_32._140_sayReward = "Der Fahrende Hنndler braucht einige Materialen[ENTER]für eine Halskette. Besorge ihm 100 Backenzنhne[ENTER]von Stolzen Ork-Zauberern, ein Schmuckstück von[ENTER]der Gemischtwarenhنndlerin und Nنhgarn von[ENTER]Ariyoung. "
gameforge.subquest_32._150_npcChat = "Ich brauche Nنhgarn. "
gameforge.subquest_32._160_say = "Nنhgarn herstellen ist keine groكe Sache.[ENTER]Allerdings kann ich dann meine andere Arbeit[ENTER]nicht machen. Ich habe heute Ah-Yus zerrissene[ENTER]Kleider genنht und wollte sie ihr gerade[ENTER]bringen... "
gameforge.subquest_32._170_say = "Was hنltst du davon: Du bringst Ah-Yu ihre[ENTER]Kleidung zurück und ich stelle inzwischen Nنhgarn[ENTER]für dich her. Einverstanden? "
gameforge.subquest_32._180_say = "Willst du für immer aufgeben? "
gameforge.subquest_32._190_say = "Der Weg ist wirklich nicht sehr weit. Warum[ENTER]zِgerst du noch? Komm wieder her, wenn du[ENTER]bereit bist. "
gameforge.subquest_32._200_say = "Oh, ich hatte so gehofft, dass du Zeit hast. Dann[ENTER]muss ich wohl selber laufen. Leb wohl! "
gameforge.subquest_32._20_npcChat = "Wegen der Halsketten... "
gameforge.subquest_32._210_say = "Herrlich, ich danke dir vielmals! Grüكe Ah-Yu von[ENTER]mir und pass auf, dass du ihre Kleidung unterwegs[ENTER]nicht zerdrückst! Ich warte hier auf dich. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Ich werde dein Nنhgarn fertig haben, wenn du aus[ENTER]dem Nachbardorf zurückkommst. Du hast doch nicht[ENTER]vergessen, Ah-Yu ihre Kleider zu bringen, oder?[ENTER]Das würde sie mir übelnehmen. "
gameforge.subquest_32._240_say = "Ist Ah-Yu mit der Kleidung zufrieden? Dann ist es[ENTER]ein Vergnügen, so hart zu arbeiten. Hier ist[ENTER]dein Nنhgarn. Es ist sehr krنftig und kann für[ENTER]vieles benutzt werden. Bis bald! "
gameforge.subquest_32._250_say = "Ich habe dir bereits Nنhgarn gegeben. Hast du es[ENTER]verloren? "
gameforge.subquest_32._260_npcChat = "Ariyoung schickt dir diese Kleider. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Oh, wie schِn. Das ging wirklich schnell. Gute[ENTER]Freundschaften soll man pflegen, nicht wahr? Wir[ENTER]helfen uns oft gegenseitig...[ENTER]Danke, dass du mir die Kleidung gebracht hast.[ENTER]Bitte übermittle Ariyoung meine Grüكe. "
gameforge.subquest_32._290_npcChat = "Ich brauche ein Schmuckstück. "
gameforge.subquest_32._300_say = "Du suchst Schmuck?[ENTER]Ich kann dir ein Schmuckstück geben, wenn du mir[ENTER]ein wenig hilfst. Zurzeit arbeite ich an einer[ENTER]speziellen Medizin gegen Schmerzen, aber eine[ENTER]Zutat fehlt mir: die Leber eines Tigers. Die sind[ENTER]sehr schwierig zu bekommen. Ich brauche 100[ENTER]Stück. "
gameforge.subquest_32._30_say = "Wir Fahrenden Hنndler haben es im Krieg nicht[ENTER]leicht. Es fehlt zwar überall an Waren, aber der[ENTER]Bedarf wechselt so schnell, dass ich nie weiك, ob[ENTER]ich gerade das Richtige im Angebot habe. Ganz zu[ENTER]schweigen von den langen Wegen durch die Wildnis,[ENTER]wo all diese Monster unachtsamen Wanderern[ENTER]auflauern. Hast du nicht Lust, dir ein paar Yang[ENTER]zu verdienen? Ich kِnnte Hilfe gebrauchen. "
gameforge.subquest_32._310_say = "Auكerdem brauche ich noch bestimmte Krنuter mit[ENTER]heilender Wirkung, aber die bekommst du auch von[ENTER]den Tigern. Sie wنlzen sich gerne darin, weil sie[ENTER]den Geruch lieben. Für die Krنuter und die[ENTER]Tigerlebern gebe ich dir dann ein Schmuckstück. "
gameforge.subquest_32._320_say = "Jage dafür Tiger oder Weiكe Tiger. "
gameforge.subquest_32._330_say = "Was sagst du dazu? Kommen wir ins Geschنft? "
gameforge.subquest_32._340_say = "Ist meine Aufgabe zu schwer für dich? Das kann[ENTER]ich mir nicht vorstellen! Besuch mich wieder,[ENTER]wenn du es dir anders überlegst. "
gameforge.subquest_32._350_say = "Du lنufst also für den Hنndler den weiten Weg[ENTER]hierher und gibst dann auf? Wie du willst...[ENTER]Schِnen Tag noch. "
gameforge.subquest_32._360_say = "Sehr gut. Das wird uns beiden weiterhelfen, nicht[ENTER]wahr? Danke und viel Glück! "
gameforge.subquest_32._370_npcChat = "Bekomme ich jetzt das Schmuckstück? "
gameforge.subquest_32._380_say = "Lass mich nachsehen... 100 Tigerlebern und die[ENTER]Heilkrنuter, es ist alles da. Ich danke dir![ENTER]Bitte sehr, dieses Schmuckstück hast du dir[ENTER]ehrlich verdient. Bis bald! "
gameforge.subquest_32._390_qSetTitle = "Zurück zum Fahrenden Hنndler "
gameforge.subquest_32._400_targetVid = "Zurück zum Fahrenden Hنndler "
gameforge.subquest_32._40_say = "Im Moment sind Halsketten sehr gefragt, die aus[ENTER]den Backenzنhnen von Orks bestehen. Orkzنhne sind[ENTER]groك und hart und eignen sich gut für die[ENTER]Herstellung verschiedener Schmuckstücke. Die[ENTER]Backenzنhne der Ork-Zauberer gelten zudem bei den[ENTER]Soldaten als Talismane. Kِnntest du mir solche[ENTER]Zنhne besorgen? 100 Stück sollten fürs Erste[ENTER]reichen. "
gameforge.subquest_32._410_sayReward = "Zurück zum Fahrenden Hنndler "
gameforge.subquest_32._420_sayReward = "Du hast endlich alle Materialien für die[ENTER]Halskette zusammen. Bringe sie dem Fahrenden[ENTER]Hنndler. "
gameforge.subquest_32._430_npcChat = "Ich habe alle Materialien. "
gameforge.subquest_32._440_sayTitle = "Fahrender Hنndler: "
gameforge.subquest_32._450_say = "Hast du alle Materialien bekommen? Lass sehen...[ENTER]Tatsنchlich, es ist alles da. Dank deiner Hilfe[ENTER]kann ich mein Angebot erweitern, das ist gut.[ENTER]Hier ist dein Anteil. Viel Spaك damit.[ENTER]Kommt heran, Leute! Hier ist für jeden etwas[ENTER]dabei! "
gameforge.subquest_32._460_sayReward = "Du erhنltst 1.100.000 Erfahrungspunkte. "
gameforge.subquest_32._470_sayReward = "Du erhنltst ein Goldarmband, eine Goldhalskette[ENTER]und Goldohrringe. "
gameforge.subquest_32._480_say = "Hmm, tut mir leid, aber da fehlt aber noch etwas.[ENTER]Unvollstنndige Lieferungen kann ich nicht[ENTER]gebrauchen. Versuchst du es weiter? "
gameforge.subquest_32._490_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_32._500_say = "Danke, dass du nicht so leicht aufgibst. Das[ENTER]Glück ist denen hold, die sich bemühen! Ich warte[ENTER]hier auf dich. "
gameforge.subquest_32._50_say = "Zusنtzlich brauche ich noch ein Schmuckstück und[ENTER]Nنhgarn. Das eine bekommst du von der[ENTER]Gemischtwarenhنndlerin, das andere von Ariyoung.[ENTER]So viele Sachen zu beschaffen ist nicht einfach,[ENTER]aber der Verkauf der Ketten ist ein gutes[ENTER]Geschنft und du bekommst eine ordentliche[ENTER]Belohnung für die Materialien. Was meinst du,[ENTER]hِrt sich das interessant an? "
gameforge.subquest_32._510_say = "Die Aufgabe ist wohl zu schwer? Na immerhin hast[ENTER]du es versucht. Wenn ich irgendwann einmal eine[ENTER]einfachere Aufgabe für dich habe, lasse ich es[ENTER]dich wissen. Leb wohl. "
gameforge.subquest_32._520_say = "Du versuchst es noch einmal? Danke.[ENTER]Ich werde hier auf dich warten. "
gameforge.subquest_32._60_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_32._70_say = "Du bist beschنftigt? Das kann ich gut verstehen.[ENTER]Aber komm bitte wieder, wenn du Zeit hast. "
gameforge.subquest_32._80_say = "Oh je, wie soll ich bloك all meine Auftrنge[ENTER]erledigen? Bis bald! "
gameforge.subquest_32._90_say = "Wunderbar. Ich werde hier auf dich warten. "
gameforge.subquest_33 = {}
gameforge.subquest_33._100_sayTitle = "Schatzkarte gefunden "
gameforge.subquest_33._10_targetVid = "Gehe zum Bücherwurm. "
gameforge.subquest_33._110_say = "Du hast die Tiergottheiten vor der Stadt gejagt[ENTER]und die vier Teile der Schatzkarte gefunden.[ENTER]Bringe sie zu Soon. "
gameforge.subquest_33._120_sayTitle = "Jagd auf die Tiergottheiten "
gameforge.subquest_33._130_say = "Sammle für Soon vier Teile einer Schatzkarte,[ENTER]indem du die Tiergottheiten Lykos, Scrofa, Bera[ENTER]und Tigris jagst. "
gameforge.subquest_33._140_sayReward = "(Kartenteile gefunden: %s ) "
gameforge.subquest_33._150_sendLetter = "Die Schatzkarte "
gameforge.subquest_33._160_sayTitle = "Alle Kartenteile gesammelt "
gameforge.subquest_33._170_say = "Geh zurück zu Soon und berichte ihm, dass du[ENTER]die Schatzkartenteile gefunden hast. "
gameforge.subquest_33._175_npcChat = "Ich habe alle Kartenteile. "
gameforge.subquest_33._180_say = "Oh, groكartig! Alle vier Kartenteile beisammen...[ENTER]Ich habe kaum gewagt, davon zu trنumen.[ENTER]Nun noch schnell die Teile zu einer Karte[ENTER]zusammengefügt... so... "
gameforge.subquest_33._190_say = "Hmm, eigenartig. Die Karte sagt, der Schatz sei[ENTER]bei dem Felsen nahe des Alten Mannes versteckt.[ENTER]Ich kann mir nicht vorstellen, dass das stimmt.[ENTER]Er wنre lنngst gefunden worden. Was für eine[ENTER]kindische Spielerei! Willst du trotzdem nachsehen[ENTER]oder soll ich die Karte verbrennen? "
gameforge.subquest_33._200_select = "Ich werde nachsehen. "
gameforge.subquest_33._20_npcChat = "Wegen der Schatzkarte... "
gameforge.subquest_33._210_select = "Verbrenn sie ruhig. "
gameforge.subquest_33._220_say = "Bist du sicher, dass du die Karte nicht mehr[ENTER]brauchst? "
gameforge.subquest_33._230_say = "Was für ein lنcherliches Mنrchen![ENTER]Es tut mir Leid, dass ich dich auf die Suche nach[ENTER]den Kartenteilen geschickt habe. Ich verbrenne[ENTER]sie, damit nicht noch andere Leute darauf[ENTER]hereinfallen. Trotzdem vielen Dank. Leb wohl! "
gameforge.subquest_33._240_say = "Warum noch zِgern? Die Kartenteile hast du[ENTER]bereits gesammelt, dann kannst du auch nachsehen[ENTER]gehen. Hier, nimm die Karte mit. "
gameforge.subquest_33._250_say = "Wie du meinst. Es würde mich zwar sehr[ENTER]überraschen, wenn du wirklich etwas findest, aber[ENTER]ich wünsche dir viel Glück! Hier, nimm die Karte[ENTER]mit. "
gameforge.subquest_33._260_say = "Die Karte wurde in vier Teile zerlegt. Wir[ENTER]brauchen alle vier Teile, um sie wieder[ENTER]zusammensetzen zu kِnnen! "
gameforge.subquest_33._270_select = "Erneut versuchen "
gameforge.subquest_33._280_say = "Du gibst auf? Nun denn, so sei es. Leb wohl. "
gameforge.subquest_33._290_say = "Wie erwartet bist du voller Energie. Ich vertraue[ENTER]dir! "
gameforge.subquest_33._300_targetVid = "Fels beim Alten Mann "
gameforge.subquest_33._30_say = "Hey, ich habe in alten Texten seltsame[ENTER]Informationen entdeckt. Es heiكt, dass es[ENTER]Schatzkarten in diesem Dorf gibt. Kennst du die[ENTER]gِttlichen Tierwنchter - Hundegottheit,[ENTER]Bنrengottheit, Tigergottheit und Schweinegottheit[ENTER]- drauكen vor der Stadt? "
gameforge.subquest_33._310_sayTitle = "Suche nach dem Schatz "
gameforge.subquest_33._320_say = "Hmm, unterhalb der Felsen bei dem Alten Mann...[ENTER]Keine Ahnung. Ich sollte zuerst den Alten Mann[ENTER]fragen. Warum ist der Weg zu ihm so weit? Mist. "
gameforge.subquest_33._330_sayTitle = "Alter Mann: "
gameforge.subquest_33._340_say = "Wonach suchst du? Nach einem Schatz? Haha, da[ENTER]kannst du lange suchen! Zeig mal die Karte...[ENTER]Hm, das müsste dort drüben sein. Viel Glück,[ENTER]hihihi... "
gameforge.subquest_33._350_say = "Das hier muss die Stelle sein. Hau ruck! … und[ENTER]weiter...[ENTER]Verdammt, der Boden ist ganz schِn hart. Hrmpf...[ENTER]Hey, ich kann eine Kiste sehen! "
gameforge.subquest_33._360_sendLetter = "Es gibt den Schatz wirklich! "
gameforge.subquest_33._370_sayTitle = "Zurück zu Soon "
gameforge.subquest_33._380_say = "Du hast an dem Ort gegraben, den die Karte der[ENTER]Tiergottheiten bezeichnete und dort tatsنchlich[ENTER]eine Schatztruhe gefunden! Gehe zu Soon und[ENTER]berichte ihm von dem unerwarteten Erfolg. "
gameforge.subquest_33._390_npcChat = "Ich habe den Schatz gefunden! "
gameforge.subquest_33._400_say = "Oh, das ist eine ـberraschung! Zeig her...[ENTER]Erstaunlich. Genau so wurde die Schatztruhe in[ENTER]den alten Texten beschrieben. Jetzt muss ich nur[ENTER]noch herausfinden, wie man sie ِffnen kann.[ENTER]Aber das soll nicht deine Sorge sein. Ich danke[ENTER]dir! Nimm dies als Zeichen meiner Anerkennung. "
gameforge.subquest_33._40_say = "Eine uralte Mنr überliefert, dass diese vier[ENTER]gِttlichen Monster die Karte in vier Teile[ENTER]geteilt haben und diese beschützen. Ich bin mir[ENTER]nicht sicher, ob es stimmt. Kِnntest du das für[ENTER]mich überprüfen? Oh bitte, diese Ungewissheit[ENTER]bringt mich sonst um... Ich flehe dich an, hilf[ENTER]mir! "
gameforge.subquest_33._410_sayReward = "Du erhنltst 1.400.000 Erfahrungspunkte. "
gameforge.subquest_33._420_sayReward = "Du erhنltst 25.000 Yang. "
gameforge.subquest_33._430_sayReward = "Du erhنltst eine Geistermaskenschaller+1. "
gameforge.subquest_33._440_sayReward = "Du erhنltst einen Burghelm+1. "
gameforge.subquest_33._450_sayReward = "Du erhنltst eine Stahlkapuze+1. "
gameforge.subquest_33._460_sayReward = "Du erhنltst einen Sonnenlichthut+1. "
gameforge.subquest_33._470_say = "Ja, wo ist er denn? Willst du dich über mich[ENTER]lustig machen?! Du hast ihn nicht wirklich[ENTER]gefunden, hab ich Recht? "
gameforge.subquest_33._50_say = "Interessieren alte Schatzkarten dich nicht? Du[ENTER]bist seltsam... Ich werde weiter nach Hinweisen[ENTER]in diesen Texten suchen. Komm zurück, wenn du[ENTER]deine Meinung geنnderst hast. "
gameforge.subquest_33._60_say = "Magst du solche Abenteuer nicht? Wie soll ich nun[ENTER]an die Kartenteile kommen?[ENTER]Naja, wie auch immer. Leb wohl. "
gameforge.subquest_33._70_say = "Du bist ein wahrer Freund. Ich vertraue darauf,[ENTER]dass du sie finden wirst. "
gameforge.subquest_33._80_sendLetter = "Schatzkarte des Bücherwurms "
gameforge.subquest_33._90_targetVid = "Geh zum Bücherwurm "
gameforge.subquest_34 = {}
gameforge.subquest_34._100_say = "Der Hauptmann hat weiterhin Schwierigkeiten, die[ENTER]Schwarzwindkrieger in den Griff zu bekommen.[ENTER]Tِte ihre Generنle Jak-To, To-Su und Gu-Ryung.[ENTER]Vielleicht geben sie dann endlich Ruhe. "
gameforge.subquest_34._10_npcChat = "Was macht die Schwarzwindbande? "
gameforge.subquest_34._110_say = "Die Generنle sind tot! "
gameforge.subquest_34._120_select = "Weiter versuchen "
gameforge.subquest_34._130_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_34._140_say = "Kنmpfen ist eine schwierige Angelegenheit und[ENTER]Siegen erst recht. Vor allem gegen die Generنle.[ENTER]Versuche es noch einmal! "
gameforge.subquest_34._150_say = "Wie gesagt: Es ist eine sehr starke Bande.[ENTER]Auf Wiedersehen. "
gameforge.subquest_34._160_say = "Wie mutig du bist! Ich glaube, du kannst die[ENTER]Schwarzwindbande besiegen! "
gameforge.subquest_34._170_targetVid = "Berichte dem Hauptmann "
gameforge.subquest_34._180_say = "Geh zurück zum Hauptmann und berichte, dass du[ENTER]die Generنle getِtet hast. "
gameforge.subquest_34._185_npcChat = "Ich habe die Generنle getِtet! "
gameforge.subquest_34._190_say = "Hmm... Du hast die Generنle besiegt. Gut.[ENTER]Wir hatten schon Kopfschmerzen wegen der[ENTER]Schwarzwindbande, aber dank deiner Hilfe schaffen[ENTER]wir es nun. Ohne die Generنle wird der Rest ein[ENTER]Kinderspiel.[ENTER]Hier ist eine Belohnung für dich. Ich hoffe, wir[ENTER]sehen uns bald wieder! "
gameforge.subquest_34._200_sayReward = "Du erhنltst 1.000.000 Erfahrungspunkte. "
gameforge.subquest_34._20_sayTitle = "Hauptmann: "
gameforge.subquest_34._210_sayReward = "Du erhنltst einen Sprachenring. "
gameforge.subquest_34._30_say = "Obwohl du der Schwarzwindbande einen[ENTER]empfindlichen Schlag versetzt hast, denken sie[ENTER]nicht daran, sich ruhig zu verhalten und benehmen[ENTER]sich einfach weiter wie die Wilde Horde. Wenn wir[ENTER]sie endgültig besiegen wollen, müssen wir ihre[ENTER]Anführer tِten. "
gameforge.subquest_34._40_say = "Wenn die Anführer erst besiegt sind, wird der[ENTER]Rest der Bande auch bald untergehen. Es wird ein[ENTER]hartes Stück Arbeit, aber wir brauchen einen Sieg[ENTER]über die Schwarzwindgenerنle Jak-To, To-Su und[ENTER]Gu-Ryung. Wenn wir sie besiegen, müssen wir uns[ENTER]über die Schwarzwindbande keine Sorgen mehr[ENTER]machen. Also, viel Glück, ich bete für deinen[ENTER]Sieg! "
gameforge.subquest_34._50_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_34._60_say = "Hmm, na gut.[ENTER]Aber komm bitte wieder, wenn du bereit bist.[ENTER]Es gibt viel zu wenig fنhige Leute wie dich. "
gameforge.subquest_34._70_say = "Du kannst es nicht...? Aber wie sollen wir die[ENTER]Schwarzwindbande dann besiegen? "
gameforge.subquest_34._80_say = "Ich wusste, dass ich mich auf dich verlassen[ENTER]kann! Wenn die Generنle tot sind, sind die[ENTER]anderen Schwarzwindkrieger kein Problem mehr.[ENTER]Viel Glück! "
gameforge.subquest_34._90_sendLetter = "Tِte die Schwarzwindgenerنle "
gameforge.subquest_36 = {}
gameforge.subquest_36._100_sayTitle = "Auf zum Stallburschen "
gameforge.subquest_36._10_targetVid = "Yonah "
gameforge.subquest_36._110_say = "Du hast 10 Ballen Heu zusammengetragen.[ENTER]Bringe sie zum Stallburschen, damit er die Pferde[ENTER]füttern kann. "
gameforge.subquest_36._120_sayTitle = "Heu für die Stنlle "
gameforge.subquest_36._130_say = "Es herrscht Futtermangel bei den Stنllen.[ENTER]Besorge 10 Ballen Heu und bringe sie dem[ENTER]Stallburschen, bevor die Pferde verhungern![ENTER]Heu erhنltst du bei der Jagd. "
gameforge.subquest_36._140_npcChat = "Du brauchst Heu? "
gameforge.subquest_36._150_say = "Du bist wohl hier, weil Yonah dich geschickt hat?[ENTER]Ich habe bereits viel von dir gehِrt.[ENTER]Ach, unsere Pferde leiden an Unterernنhrung. Wir[ENTER]müssen dafür sorgen, dass sie überleben. Hilf mir[ENTER]und besorge Heu für die Pferde! "
gameforge.subquest_36._160_say = "Was man verspricht, das soll man halten.[ENTER]Auكerdem will ich spنter vielleicht auch einmal[ENTER]ein Pferd reiten. Ich muss unbedingt Heu finden! "
gameforge.subquest_36._170_say = "Es tut mir leid. Ich suche ja auch, aber es ist[ENTER]einfach kein Heu zu finden. "
gameforge.subquest_36._180_say = "Ich weiك, es ist nicht sehr nett von mir, dir[ENTER]meine Arbeit aufzudrücken. Trotzdem hatte ich[ENTER]gehofft, du kِnntest es schaffen.[ENTER]Versuchst du es bitte noch einmal? Ich kenne[ENTER]jemanden in einem anderen Reich, eine sehr[ENTER]wichtige Persِnlichkeit. Wenn du mir hilfst,[ENTER]frage ich ihn, ob er etwas für dich tun kann. "
gameforge.subquest_36._190_select = "Weitersuchen "
gameforge.subquest_36._200_say = "Natürlich helfe ich dir. Mal sehen, was ich tun[ENTER]kann. "
gameforge.subquest_36._20_npcChat = "Die Stنlle haben ؤrger "
gameforge.subquest_36._210_say = "Ich kann nicht die Energie dafür aufbringen.[ENTER]Ich will dir wirklich helfen, aber ich kann[ENTER]nicht. Ich bin nicht stark genug. "
gameforge.subquest_36._220_npcChat = "Ich habe Heu für die Pferde. "
gameforge.subquest_36._230_say = "Du hast Heu besorgt? Oh, danke.[ENTER]Das Pferdefutter wurde knapp und ich erzنhlte[ENTER]Yonah davon. Er ist ein guter Freund von mir. Ich[ENTER]dachte mir schon, dass er sich umhِrt, ob jemand[ENTER]helfen kann. Aber dass es so schnell geht, das[ENTER]hنtte ich nicht gedacht. Schau nur, wie[ENTER]begeistert die Pferde fressen! "
gameforge.subquest_36._240_sayReward = "Du erhنltst 1.800.000 Erfahrungspunkte. "
gameforge.subquest_36._250_sendLetter = "Zurück zu Yonah "
gameforge.subquest_36._260_sayTitle = "Zurück zu Yonah "
gameforge.subquest_36._270_say = "Du hast dem Stallburschen 10 Ballen Heu für die[ENTER]hungernden Pferde gebracht. Geh und berichte[ENTER]Yonah von deinem Erfolg. "
gameforge.subquest_36._280_npcChat = "Die Pferde sind versorgt! "
gameforge.subquest_36._290_say = "Hallo, du bist zurück![ENTER]Es war bestimmt nicht leicht, so viel Heu zu[ENTER]sammeln. Danke, dass du nicht aufgegeben hast![ENTER]Hier ist ein kleines Geschenk für dich. "
gameforge.subquest_36._300_sayReward = "Du erhنltst ein Missionsbuch. "
gameforge.subquest_36._30_say = "Hallo, ich habe eine Frage an dich![ENTER]Ich weiك, dass du nicht für die Stنlle[ENTER]verantwortlich bist, aber in letzter Zeit haben[ENTER]wir viel ؤrger und kِnnten deine Hilfe[ENTER]gebrauchen. Die Pferde haben wنhrend des Krieges[ENTER]viel zu tun, aber selbst ein ausgewachsenes,[ENTER]starkes Pferd hat seine Grenzen. "
gameforge.subquest_36._40_say = "Zum Glück haben wir noch genügend Pferde, aber es[ENTER]gibt zu wenig Futter. So sterben viele.[ENTER]Kannst du bitte Futter besorgen, damit die[ENTER]erschِpften Pferde wieder zu Krنften kommen?[ENTER]Ich habe niemand anderen, den ich fragen[ENTER]kِnnte... Sammel 10 Ballen Heu und bring sie dem[ENTER]Stallburschen. Er weiك schon Bescheid. Sag[ENTER]einfach, dass du von mir kommst. "
gameforge.subquest_36._50_select = "Ich gehe sofort los! "
gameforge.subquest_36._60_select = "Nein, das ist niedere Arbeit. "
gameforge.subquest_36._70_say = "Heutzutage mِchten immer mehr Leute Pferde[ENTER]haben. Aber keiner denkt daran, dass das Futter[ENTER]für die Pferde knapp wird. Und jetzt verhungern[ENTER]sie im Stall. Wenn du deine Meinung نnderst, komm[ENTER]zurück. "
gameforge.subquest_36._80_say = "Oh, die armen Pferde! Sie hungern und ich kann[ENTER]nichts dagegen tun. Was soll ich nur machen... "
gameforge.subquest_36._90_say = "Mir ist klar, dass du sehr beschنftigt bist. Um[ENTER]so mehr weiك ich deine Hilfsbereitschaft zu[ENTER]schنtzen. Heutzutage sind Pferde sehr wichtig.[ENTER]Wir brauchen das Heu wirklich dringend. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah gibt sein Bestes, um neues Porzellan[ENTER]herzustellen, kommt aber mit seinen Experimenten[ENTER]nicht weiter. Geh zum Gelehrten Uriel und frage[ENTER]ihn, ob er etwas über Seladon-Porzellan weiك. "
gameforge.subquest_37._10_targetVid = "Das Geheimnis des Seladon-Porzellans "
gameforge.subquest_37._110_npcChat = "Kennst du Seladon-Porzellan? "
gameforge.subquest_37._120_sayTitle = " أوريل : "
gameforge.subquest_37._130_say = "Seladon-Porzellan?[ENTER]Nun, ich habe gute Kenntnisse in Geschichte und[ENTER]Wissenschaft. Kunst aber interessiert mich nicht.[ENTER]Deshalb kann ich dir über das Seladon-Porzellan[ENTER]leider nichts sagen.[ENTER]Aber kِnnte Soon das nicht wissen? Er ist zwar[ENTER]nicht sehr beliebt, aber er liest viele Bücher.[ENTER]Vielleicht weiك er etwas darüber. "
gameforge.subquest_37._140_makequestbutton = "Geh zu Soon "
gameforge.subquest_37._150_targetVid = "Weiter zu Soon "
gameforge.subquest_37._160_say = "Uriel weiك leider nichts über Seladon-Porzellan.[ENTER]Aber der Bücherwurm Soon liest viele Sachen in[ENTER]seinen Büchern. Geh zu ihm und frage ihn, ob er[ENTER]etwas über die Herstellungsmethode weiك. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Was willst du? Stِr mich nicht beim Lesen![ENTER]Hنh? Seladon-Porzellan? Natürlich kenne ich das.[ENTER]Immerhin habe ich annنhernd ein Dutzend Bücher[ENTER]gelesen, die sich nur damit befassen. Warum? Ich[ENTER]werde nicht umsonst 'Bücherwurm' genannt! Ich[ENTER]kann alles verstehen, was in jedem Buch[ENTER]geschrieben steht! "
gameforge.subquest_37._190_say = "Ich kِnnte dir die Herstellungsmethode für das[ENTER]Seladon-Porzellan aus dem Kopf aufschreiben,[ENTER]aber warum sollte ich das tun?[ENTER]Hmm, warte, ich habe eine Idee: Ich habe beim[ENTER]Fahrenden Hنndler im Nachbardorf ein Buch[ENTER]angefordert, das mir noch fehlt, aber ich habe[ENTER]keine Zeit für den langen Weg. Hole es für mich[ENTER]ab, dann helfe ich dir mit dem Porzellan. Los,[ENTER]los! "
gameforge.subquest_37._200_makequestbutton = "Auf zum Fahrenden Hنndler "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Geh zum Fahrenden Hنndler "
gameforge.subquest_37._220_say = "Soon, der Bücherwurm, kennt sich mit[ENTER]Seladon-Porzellan aus. Er will sein Wissen aber[ENTER]nicht ohne Gegenleistung teilen.[ENTER]Geh für Soon zum Fahrenden Hنndler im Nachbardorf[ENTER]und hole das Buch ab, das er bei ihm bestellt[ENTER]hat. "
gameforge.subquest_37._230_npcChat = "Soon schickt mich... "
gameforge.subquest_37._240_say = "Hallo! Kommst du, um mir nochmal zu helfen?[ENTER]Ah, du mِchtest das Buch für Soon. Ich wنre[ENTER]sowieso bald in die Stadt gekommen, aber er ist[ENTER]zu ungeduldig. Bittet andere darum, es für ihn[ENTER]zu holen. Hmm.[ENTER]Hier ist es. Ich verstehe nicht, was Soon immer[ENTER]an diesen Papierstapeln findet. Es ist doch viel[ENTER]wichtiger, schnell Yang zu verdienen! "
gameforge.subquest_37._250_qSetTitle = "Rückkehr zu Soon. "
gameforge.subquest_37._260_targetVid = "Rückkehr zu Soon "
gameforge.subquest_37._270_say = "Du hast Soons Buch beim Fahrenden Hنndler[ENTER]abgeholt. Geh zurück zu Soon und gib es ihm,[ENTER]damit er dir die Herstellungsmethode des[ENTER]Seladon-Porzellans verrنt. "
gameforge.subquest_37._280_npcChat = "Ich habe das Buch. "
gameforge.subquest_37._290_say = "Juhu! Endlich neuer Lesestoff! Ich danke dir.[ENTER]Es gibt nicht viele Bücher, die ich noch nicht[ENTER]kenne...[ENTER]Hier, ich habe dir aufgeschrieben, worauf es beim[ENTER]Herstellen von Seladon-Porzellan ankommt. Halte[ENTER]dich an die Anweisungen, dann wirst du[ENTER]fantastisches Porzellan herstellen.[ENTER]Und nun wird es Zeit, das neue Buch zu lesen.[ENTER]Leb wohl. "
gameforge.subquest_37._300_makequestbutton = "Zurück zu Yonah "
gameforge.subquest_37._30_say = "Hmm... Das hier taugt nichts. Und dieses[ENTER]auch nicht...[ENTER]Oh, hallo! Schaut einmal her: Ich stelle[ENTER]ununterbrochen Porzellan her, aber die meisten[ENTER]Sachen zerbrechen sofort. Ich denke, ich brauche[ENTER]ein neues, wegweisendes Porzellan... "
gameforge.subquest_37._310_targetVid = "Bring die Notizen zu Yonah "
gameforge.subquest_37._320_say = "Soon hat sein Versprechen gehalten und dir eine[ENTER]Anleitung zum Brennen von Seladon-Porzellan[ENTER]geschrieben. Bringe sie zu Yonah. "
gameforge.subquest_37._330_say = "Ooh!!! Hier steht alles über die Herstellung von[ENTER]Seladon-Porzellan. Mit Hilfe dieser[ENTER]Aufzeichnungen werde ich als Meister in die[ENTER]Geschichte eingehen. Danke für deine[ENTER]Hilfsbereitschaft. Schon bald werde ich dir die[ENTER]allerbeste Keramik zeigen kِnnen! Verlass dich[ENTER]auf mich. Mein Porzellan wird die Jahrhunderte[ENTER]überdauern. "
gameforge.subquest_37._340_sayReward = "Du erhنltst 2.500.000 Erfahrungspunkte. "
gameforge.subquest_37._350_sayReward = "Du erhنltst 35.000 Yang. "
gameforge.subquest_37._360_sayReward = "Du erhنltst Jadeschuhe+3. "
gameforge.subquest_37._40_say = "Ich werde eine neue Methode ausprobieren.[ENTER]Seladon-Porzellan ist sehr schwer herzustellen,[ENTER]daher kِnnen es nur sehr wenige. Aber ich werde[ENTER]es für meine Kunstwerke brauchen! Daher...[ENTER]Hmm, der weise Uriel kِnnte es wissen![ENTER]Geh doch bitte zu Uriel und frag ihn nach der[ENTER]Herstellung von Seladon-Porzellan! "
gameforge.subquest_37._50_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_37._60_say = "Hm, du bist wohl zu beschنftigt?[ENTER]Denk daran, mich nochmal zu besuchen, wenn[ENTER]du mehr Zeit hast. "
gameforge.subquest_37._70_say = "Verstehe. Leb wohl... "
gameforge.subquest_37._80_say = "Vielen Dank. Uriel weiك bestimmt weiter. Bis[ENTER]gleich! "
gameforge.subquest_37._90_targetVid = "Auf zu Uriel "
