gameforge.subquest_38._100_say = "Dem Jنger Yang-Shin wurde sein Verzierter Bogen,[ENTER]ein Erbstück der Familie, gestohlen.[ENTER]Geh zum Sangsun Dong und hole den Bogen von den[ENTER]diebischen Affen zurück. "
gameforge.subquest_38._10_targetVid = "Schatz des Jنgers "
gameforge.subquest_38._110_sendLetter = "Verzierten Bogen gefunden "
gameforge.subquest_38._120_targetVid = "Geh zum Jنger Yang-Shin "
gameforge.subquest_38._125_say = "Du hast den Verzierten Bogen des Jنgers gefunden.[ENTER]Bringe ihn zurück zu Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Hier ist der Bogen! "
gameforge.subquest_38._140_say = "Tatsنchlich, das ist er! Mein Bogen! Meine Ehre[ENTER]vor den Ahnen ist gerettet. Puuuh. Wie lange habe[ENTER]ich darunter gelitten, ihn verloren zu haben...[ENTER]Ich bin نuكerst dankbar für deine Hilfe. Es ist[ENTER]mir wahrhaft eine Ehre, dir dies hier zu geben.[ENTER]Es mag nach wenig aussehen, aber es kommt von[ENTER]Herzen. Bitte nimm es. Dank dir kann ich nun in[ENTER]Frieden weiterleben! "
gameforge.subquest_38._150_sayReward = "Du erhنltst 1.500.000 Erfahrungspunkte. "
gameforge.subquest_38._160_sayReward = "Du erhنltst 35.000 Yang. "
gameforge.subquest_38._170_sayReward = "Du erhنltst einen Tapferkeitsumhang. "
gameforge.subquest_38._180_say = "Du hast meinen Bogen gefunden? Aber wo ist er[ENTER]denn? Hast du ihn schon wieder verloren? "
gameforge.subquest_38._190_select = "Ich suche weiter. "
gameforge.subquest_38._200_say = "So sei es.[ENTER]Pass auf dich auf. "
gameforge.subquest_38._20_say = "Hey. Hِrst du mir kurz zu?[ENTER]Wie du sehen kannst, bin ich ein Jنger. Meine[ENTER]Familie jagt seit vielen Generationen. Wir sind[ENTER]alle Jنger, eine Familie mit groكer Ehre.[ENTER]Aber ich habe einen Fehler begangen, der mich vor[ENTER]meiner Familie entehrt... "
gameforge.subquest_38._210_say = "Du versuchst du es noch einmal? Ich danke dir.[ENTER]Ich bin sicher, mit deinen Fنhigkeiten kannst du[ENTER]es schaffen. "
gameforge.subquest_38._30_say = "Es geht um einen Verzierten Bogen, der vor[ENTER]einiger Zeit von Affen gestohlen wurde.[ENTER]Ich habe damals im Affendungeon gejagt und war[ENTER]für einen Moment unaufmerksam. Sie nutzten die[ENTER]Gelegenheit und stahlen ihn mir. "
gameforge.subquest_38._40_say = "Ich war niemals tief im Sangsun Dong, daher kenne[ENTER]ich mich dort nicht aus und benِtige deine[ENTER]Hilfe. Ich habe von einigen Einwohnern gehِrt,[ENTER]du hنttest groكes Talent. Deswegen bitte ich[ENTER]dich um diesen Gefallen.[ENTER]Ich kann meinen Ahnen nicht ohne meinen[ENTER]Verzierten Bogen entgegentreten. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Oh, ich muss ihn schnell zurückhaben...[ENTER]Bitte, komm wieder, wenn du Zeit hast.[ENTER]Leb wohl. "
gameforge.subquest_38._70_say = "Nun denn...[ENTER]Sei wachsam auf deinen Reisen. "
gameforge.subquest_38._80_say = "Er kann leicht gefunden werden, denn er ist ein[ENTER]sehr aufwendig verzierter Bogen. Ich werde dich[ENTER]dafür gut belohnen! "
gameforge.subquest_38._90_sayTitle = "Suche den verzierten Bogen "
