gameforge.subquest_39._110_say = "Der Gesundheitszustand von Verrنter Balso hat[ENTER]sich verschlechtert. Geh zu Baek-Go und frage[ENTER]ihn, wie man Balso helfen kann. "
gameforge.subquest_39._120_makequestbutton = "Geh zu Baek-Go "
gameforge.subquest_39._130_qSetTitle = "Geh zu Baek-Go "
gameforge.subquest_39._140_targetVid = "Auf zu Baek-Go "
gameforge.subquest_39._150_npcChat = "Ich habe einen Patienten... "
gameforge.subquest_39._160_sayTitle = "بايك-غو: "
gameforge.subquest_39._170_say = "Oh, du bist es, wie geht es dir?[ENTER]Du behandelst einen Kranken? Erzنhl mal, was[ENTER]hat er denn... Hmm...[ENTER]Und welche Medizin hat er bisher bekommen?[ENTER]Wie bitte?! Kein Wunder, dass es ihm schlechter[ENTER]geht! Diese Medizin ist vِllig ungeeignet! "
gameforge.subquest_39._180_say = "Er kann froh sein, dass er noch lebt! Es ist sehr[ENTER]gefنhrlich, einen Kranken falsch zu behandeln![ENTER]Aber ich weiك etwas, das ihm helfen wird. Es gibt[ENTER]ein bestimmtes Kraut, das den Kِrper von Giften[ENTER]befreit und ihn bei der Heilung unterstützt.[ENTER]Allerdings ist die Suche danach sehr riskant. "
gameforge.subquest_39._190_say = "Soweit ich weiك, wنchst das Kraut nur im Sangsun[ENTER]Dong. Es wird aber immer für den Affen-Lord[ENTER]abgeerntet, der es gerne isst. Du wirst ihn tِten[ENTER]müssen, um es zu bekommen.[ENTER]Wenn du mir das Kraut bringst, stelle ich dir[ENTER]daraus die richtige Medizin her. "
gameforge.subquest_39._200_select = "Gut, ich hole es. "
gameforge.subquest_39._20_npcChat = "Wegen deiner Medizin... "
gameforge.subquest_39._210_select = "Das kann ich nicht. "
gameforge.subquest_39._220_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_39._230_select = "Ja "
gameforge.subquest_39._240_say = "Naja, dann eben spنter, wenn du Zeit hast.[ENTER]Viele Menschen sind krank, aber nur wenige suchen[ENTER]nach der Medizin. "
gameforge.subquest_39._250_say = "Hmm, so ist das leider. Schade, dass keiner den[ENTER]Mut dazu hat. Wie soll das nur weitergehen... "
gameforge.subquest_39._260_say = "Oh, danke. Es ist eine schwierige Aufgabe, aber[ENTER]du wirst damit vielen Menschen helfen! "
gameforge.subquest_39._270_makequestbutton = "Kraut des Affen-Lords "
gameforge.subquest_39._280_targetVid = "Zurück zu Baek-Go "
gameforge.subquest_39._290_sayTitle = "Kraut des schweren Affen gefunden "
gameforge.subquest_39._300_say = "Du hast dem Affen-Lord das Kraut des schweren[ENTER]Affen abgenommen. Bringe es zu Baek-Go, damit er[ENTER]dir die Medizin für Balso herstellen kann. "
gameforge.subquest_39._30_say = "Danke, dass du mir letztens die Medizin gebracht[ENTER]hast. Aber es gibt da ein Problem... Die Wirkung[ENTER]der Medizin hat in letzter Zeit stark[ENTER]nachgelassen. Ich glaube, dass sie schlecht[ENTER]geworden ist.[ENTER]*Hust* - Ich brauche dringend eine Behandlung. "
gameforge.subquest_39._310_sayTitle = "Hole das Kraut aus dem Sangsun Dong "
gameforge.subquest_39._320_say = "Baek-Go kann eine Medizin für Verrنter Balsos[ENTER]Krankheit herstellen. Er benِtigt dafür das Kraut[ENTER]des schweren Affen. Du erhنltst es vom Affen-Lord[ENTER]im schweren Affendungeon. "
gameforge.subquest_39._330_npcChat = "Das Kraut des schweren Affen... "
gameforge.subquest_39._340_say = "Wir scheinen kurz vor einer Epidemie zu stehen,[ENTER]aber wir wissen nicht, woran es liegt. Zum Glück[ENTER]hat uns die akademische Gesellschaft über eine[ENTER]Heilungsmِglichkeit durch Affenkraut berichtet.[ENTER]Was ist? Hast du das Kraut schon gefunden? "
gameforge.subquest_39._350_select = "Noch nicht. Aber bald! "
gameforge.subquest_39._360_select = "Ich kann das Kraut nicht besorgen. "
gameforge.subquest_39._370_say = "Du willst wirklich aufgeben? Hmm, mehr kannst du[ENTER]wohl nicht tun.[ENTER]Was soll ich nur machen? Dieses Kraut kِnnte ein[ENTER]wahrer Segen sein... "
gameforge.subquest_39._380_select = "Ich schaffe es nicht. "
gameforge.subquest_39._390_select = "Ich will helfen! "
gameforge.subquest_39._400_say = "Die Affen sind zu stark für mich. Ich habe keine[ENTER]Mِglichkeit, an das Kraut heranzukommen. Es tut[ENTER]mir leid. "
gameforge.subquest_39._40_say = "Ich weiك, dass in der nنchsten Stadt ein Arzt[ENTER]lebt. Kannst du zu ihm gehen und ihm meinen[ENTER]Zustand erklنren, damit er dir sagt, wie man mir[ENTER]helfen kann? Wie du sehen kannst, schaffe ich es[ENTER]in meinem Zustand nicht, die Stadt zu verlassen.[ENTER]Ich bin dir sehr dankbar, dass du mir bereits[ENTER]letztes Mal geholfen hast. Ich werde dich auch[ENTER]dieses Mal belohnen. "
gameforge.subquest_39._410_say = "Du verwehrst Menschen, die an einer furchtbaren[ENTER]und mysteriِsen Krankheit leiden, deine Hilfe.[ENTER]Geh mir aus den Augen! "
gameforge.subquest_39._420_say = "Du hast Recht. Jemand muss dieses Kraut besorgen,[ENTER]sonst werden all diese Kranken furchtbar leiden.[ENTER]Ich werde mich darum kümmern. "
gameforge.subquest_39._430_say = "Nun denn. Beeil dich. "
gameforge.subquest_39._440_say = "Oh, du hast das Kraut des Affen besorgt. Sehr[ENTER]gut! Ich hoffe, es kann tatsنchliche diese[ENTER]mysteriِse Krankheit besiegen! Warte kurz, ich[ENTER]werde dir die Medizin herstellen... "
gameforge.subquest_39._450_sayTitle = "بايك-غو: "
gameforge.subquest_39._460_say = "So, hier hast du die Medizin. Nun mach dich[ENTER]schnell auf den Weg zu deinem Patienten und gib[ENTER]sie ihm. Dann sollte es ihm bald besser gehen.[ENTER]Und erinnere ihn daran, dass man lieber einen[ENTER]Arzt fragen sollte, welche Medizin die richtige[ENTER]ist! "
gameforge.subquest_39._470_makequestbutton = "Bring Balso die Medizin "
gameforge.subquest_39._480_targetVid = "Du gibst dem Verrنter Balso die Medizin. "
gameforge.subquest_39._490_sayTitle = "Verrنter Balsos Medizin "
gameforge.subquest_39._500_say = "Baek-Go hat dir aus dem Kraut des schweren Affen[ENTER]eine Medizin hergestellt, die viele seltene[ENTER]Krankheiten zu heilen vermag. Bringe sie zum[ENTER]Verrنter Balso im Nachbardorf. "
gameforge.subquest_39._50_say = "Mِchtest du die Quest für immer aufgeben? "
gameforge.subquest_39._510_npcChat = "Hier ist die Medizin. "
gameforge.subquest_39._520_say = "Bringst du mir neue Medizin? Es gibt also[ENTER]Fortschritte in der Medizinforschung?[ENTER]Entschuldige, dass ich dir solchen ؤrger bereitet[ENTER]habe. Ich hنtte von Anfang an einen Arzt um Rat[ENTER]fragen sollen. Wie dem auch sei, ich werde mich[ENTER]damit abfinden müssen, diese Medizin zu nehmen. "
gameforge.subquest_39._530_say = "Vielen Dank, dass du mir in meinem Elend geholfen[ENTER]hast. Ich habe nicht viele Freunde.[ENTER]Hier, es ist keine groكe Summe, aber es kommt von[ENTER]Herzen. Nimm es bitte. Und wenn ich einmal den[ENTER]groكen Durchbruch schaffen sollte, werde ich[ENTER]dich nicht vergessen! "
gameforge.subquest_39._540_sayReward = "Du erhنltst 4.000.000 Erfahrungspunkte. "
gameforge.subquest_39._550_sayReward = "Du erhنltst 65.000 Yang. "
gameforge.subquest_39._60_say = "Wenn du weiكt, wie man mir helfen kann,[ENTER]treffen wir uns wieder hier. "
gameforge.subquest_39._70_sayTitle = "Verrنter Balso: "
gameforge.subquest_39._80_say = "Ob ich wohl so weiter leben muss?[ENTER]Bis zum nنchsten Mal. "
gameforge.subquest_39._90_say = "Danke. Sei vorsichtig. "
