gameforge.subquest_40._130_say = "Die Armee hat Probleme mit dem Nachschub von[ENTER]Pfeilen. Tِte Plagenbogenschützen auf dem Berg[ENTER]Sohan und sammle ihre Pfeilspitzen für den[ENTER]Hauptmann. 5000 Stück genügen. "
gameforge.subquest_40._140_npcChat = "Wegen den Pfeilspitzen... "
gameforge.subquest_40._150_say = "Diese Plagenbogenschützen haben irgendeine[ENTER]Krankheit, die sich auf dem Kontinent verbreitet[ENTER]hat. Nicht einmal unsere ؤrzte kِnnen sich das[ENTER]erklنren. Noch sind die meisten ihrer[ENTER]Pfeilspitzen unverseucht, aber sie sind immer[ENTER]ِfter giftig. "
gameforge.subquest_40._160_select = "Ich mache dann mal weiter. "
gameforge.subquest_40._170_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_40._180_say = "Du hast Angst vor der Krankheit. Beruhige dich[ENTER]und komm spنter wieder. "
gameforge.subquest_40._190_say = "Bist du sicher, dass du aufgeben willst?[ENTER]Hmm, vielleicht ist der Auftrag wirklich zu[ENTER]schwer für dich. Ich frag jemand anderen.[ENTER]Bis dann! "
gameforge.subquest_40._200_say = "Ich verstehe.[ENTER]Du gibst niemals auf, nicht wahr?[ENTER]Dann los. "
gameforge.subquest_40._20_say = "Achtung, Krieger! Wie du sicher schon bemerkt[ENTER]hast, hنufen sich die Angriffe unserer Feinde.[ENTER]Auكerdem haben wir von Yu-Hwan Informationen[ENTER]erhalten, die sehr alarmierend sind. Kurz gesagt:[ENTER]Wir haben zu wenig Pfeile! "
gameforge.subquest_40._210_npcChat = "Hier sind 5000 Pfeilspitzen! "
gameforge.subquest_40._220_say = "Sehr gute Arbeit! Dank deiner Hilfe kِnnen wir[ENTER]uns jetzt auf den Angriff vorbereiten. Ich werde[ENTER]sofort den Befehl geben, die Pfeile herzustellen.[ENTER]Das war eine wirklich gute Zusammenarbeit. Ich[ENTER]hoffe, dass wir spنter wieder auf dich zنhlen[ENTER]kِnnen. "
gameforge.subquest_40._230_say = "Hier ist deine Belohnung. Wenn ich das nنchste[ENTER]Mal einen wichtigen Auftrag habe, wirst du der[ENTER]erste sein, der davon erfنhrt. Viel Glück und bis[ENTER]bald! "
gameforge.subquest_40._240_sayReward = "Du erhنltst 4.500.000 Erfahrungspunkte. "
gameforge.subquest_40._250_sayReward = "Du erhنltst 50.000 Yang. "
gameforge.subquest_40._260_sayReward = "Du erhنltst 3x Kritischer Kampf.[ENTER]Du erhنltst 3x Durchbohrender Kampf. "
gameforge.subquest_40._30_say = "Bogenschützen sind ein wichtiger strategischer[ENTER]Faktor bei der Kriegsführung. Sobald die Feinde[ENTER]in Reichweite sind, sollten unsere Bogenschützen[ENTER]sie beschieكen. So kِnnen wir sie entweder gleich[ENTER]in die Flucht schlagen oder zumindest ihre Zahl[ENTER]verringern. Wenn aber viele Angriffe in kurzer[ENTER]Zeit stattfinden, gehen uns schnell die Pfeile[ENTER]aus. "
gameforge.subquest_40._40_say = "Deswegen brauchen wir dich! Reise zum Berg Sohan.[ENTER]Dort sollst du Plagenbogenschützen tِten und ihre[ENTER]Pfeilspitzen einsammeln. Diese Pfeilspitzen sind[ENTER]vergiftet. Das kommt uns sehr gelegen, um unsere[ENTER]Feinde zu besiegen.[ENTER]5000 Stück benِtigen wir. Was sagst du? "
gameforge.subquest_40._50_select = "Ich nehme an. "
gameforge.subquest_40._60_select = "Das ist zu hart für mich. "
gameforge.subquest_40._70_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_40._80_say = "Ist es dir etwa zu weit zum Berg Sohah?[ENTER]Denk noch einmal darüber nach. Dieser Auftrag ist[ENTER]von hِchster Wichtigkeit. "
gameforge.subquest_40._90_say = "Hm, du hast Angst vor den Plagenbogenschützen?[ENTER]Dann habe ich dich wohl falsch eingeschنtzt.[ENTER]Ich sehe keine Hoffnung mehr für uns. "
gameforge.subquest_41 = {}
gameforge.subquest_41._015_npcChat = "Was liest du da? "
gameforge.subquest_41._100_say = "Du hast die 100 Spinnenaugen für Octavios neues[ENTER]Spezialrezept gesammelt. Bringe sie schnell zu[ENTER]ihm. "
gameforge.subquest_41._10_targetVid = "Spinnenaugen spezial "
gameforge.subquest_41._110_sayTitle = "Spinnenaugen besorgen "
gameforge.subquest_41._120_say = "Octavio will ein neues Rezept ausprobieren:[ENTER]'Spinnenaugen spezial'. Dazu braucht er[ENTER]einhundert Spinnenaugen von den Spinnen in der[ENTER]Yongbi-Wüste. "
gameforge.subquest_41._130_targetVid = "Zurück zu Octavio "
gameforge.subquest_41._140_npcChat = "Ich habe die Spinnenaugen. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Zeig her. Genau einhundert Augen, sehr gut.[ENTER]Dann wollen wir mal...[ENTER]Mmh, fertig! Willst du auch probieren? Schau[ENTER]nicht so entsetzt. Es wird dich schon nicht[ENTER]umbringen. "
gameforge.subquest_41._170_say = "Hm, hmm... Was für ein Erlebnis! Sehr gehaltvoll,[ENTER]nicht zu süك... atemberaubender Geschmack![ENTER]Ich wusste, der Aufwand lohnt sich. Ohne dich[ENTER]hنtte ich das niemals geschafft. Vielen Dank für[ENTER]die Hilfe! "
gameforge.subquest_41._180_sayReward = "Du erhنltst 2.100.000 Erfahrungspunkte. "
gameforge.subquest_41._190_say = "Was redest du da? Das sind keine hundert Augen,[ENTER]das seh ich doch ohne nachzuzنhlen! Besorge bitte[ENTER]noch weitere. "
gameforge.subquest_41._200_say = "Ich will das unbedingt kochen.[ENTER]Egal, danke. Mach es gut und pass auf dich auf. "
gameforge.subquest_41._20_say = "Hey, wie geht es dir? Ich lese gerade ein[ENTER]Kochbuch, das Soon mir freundlicherweise[ENTER]überlassen hat. Darin habe ich ein Rezept für[ENTER]'Spinnenaugen spezial' gefunden. So etwas habe[ENTER]ich noch nie zuvor gesehen! Hast du? Es scheint[ENTER]sich um eine Spezialitنt aus fernen Lنndern zu[ENTER]handeln. "
gameforge.subquest_41._210_say = "Danke, dass du mich nicht hنngen lنsst. Du bist[ENTER]sehr freundlich! "
gameforge.subquest_41._30_say = "Ich würde dieses Gericht gerne ausprobieren, aber[ENTER]wie soll ich an Spinnenaugen kommen? Deswegen[ENTER]benِtige ich deine Hilfe! Bitte hol mir[ENTER]Spinnenaugen von den Spinnen in der Yongbi-Wüste. "
gameforge.subquest_41._40_say = "Kِnntest du das tun? Ich wنre dir sehr dankbar.[ENTER]Für den ersten Versuch brauche ich einhundert[ENTER]Augen, damit es auch eine ordentliche Portion[ENTER]ergibt. Ich bin schon ganz aufgeregt... "
gameforge.subquest_41._50_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_41._60_say = "Ich will dieses Rezept unbedingt kochen. Falls du[ENTER]mir einen Gefallen tun mِchtest, besuch mich[ENTER]bitte. "
gameforge.subquest_41._70_say = "Hm, woher bekomme ich diese Augen?[ENTER]Ok, bis bald. "
gameforge.subquest_41._80_say = "Danke. Ich wusste, du würdest mir diesen Gefallen[ENTER]tun. Im Gegenzug werde ich dir ein ganz[ENTER]vorzügliches Gericht servieren. "
gameforge.subquest_41._90_sayTitle = "Zurück zu Octavio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Das ist sehr bedauerlich. Ich hِre so[ENTER]viele Stimmen von Toten, die nicht in Frieden[ENTER]ruhen kِnnen. Wir müssen ihnen unbedingt[ENTER]helfen. Ich frage jemand anderen. Leb wohl. "
gameforge.subquest_42._10_targetVid = "Für den Rest des Todes "
gameforge.subquest_42._110_say = "Du bist sehr mutig. Ich bin mir sicher, dass dank[ENTER]deiner Hilfe die jungen toten Krieger bald ins[ENTER]Nirwana gehen kِnnen. "
gameforge.subquest_42._120_say = "Schlimme Kriege tِten immer hنufiger junge[ENTER]Mنnner. Es sind Kنmpfer, die an der Frontlinie[ENTER]für sich selbst, ihre Familie und ihr Land[ENTER]kنmpfen. Aber nach dem Tod kamen einige nicht in[ENTER]das Nirwana. Sie blieben in dieser Welt. "
gameforge.subquest_42._130_say = "Ich hِrte, dass der Stolze dunkle Oberst im[ENTER]Hwang-Tempel einen Tempelschal und eine[ENTER]Tempellehre besitzen soll.[ENTER]Bitte hilf mir und meinen Kameraden, diejenigen[ENTER]zu beruhigen, die für ihr Land gestorben sind. "
gameforge.subquest_42._140_sayTitle = "Zurück zum Lehrer der Drachenmacht "
gameforge.subquest_42._150_say = "Du hast einen Tempelschal und eine Tempellehre[ENTER]gefunden. Bringe sie dem Lehrer der Drachenmacht,[ENTER]damit die Schamanen ihr Ritual zur Besنnftigung[ENTER]der Toten beginnen kِnnen. "
gameforge.subquest_42._160_sayTitle = "Hol den Tempelschal und die Tempellehre "
gameforge.subquest_42._170_say = "Die Schamanen brauchen einen Tempelschal und eine[ENTER]Tempellehre für eine Zeremonie, die die Geister[ENTER]gefallener Soldaten beruhigen soll.[ENTER]Tِte den Stolzen dunklen Oberst im Hwang-Tempel,[ENTER]um diese rituellen Gegenstنnde zu erhalten. "
gameforge.subquest_42._180_npcChat = "Ich habe den Schal und die Lehre. "
gameforge.subquest_42._190_say = "Sehr gut. Nun kِnnen wir die toten Soldaten[ENTER]beruhigen. Sie haben ihr Bestes gegeben, also[ENTER]sollen sie jetzt auch in Frieden ruhen.[ENTER]Lass mich dir eine Belohnung geben für diese[ENTER]noble Tat. "
gameforge.subquest_42._200_sayReward = "Du erhنltst 1.700.000 Erfahrungspunkte. "
gameforge.subquest_42._20_sayTitle = "Lehrer der Drachenmacht: "
gameforge.subquest_42._210_sayReward = "Du erhنltst 30.000 Yang. "
gameforge.subquest_42._220_sayReward = "Du erhنltst 3 Diamanten. "
gameforge.subquest_42._230_say = "Sehr gut. Nun kِnnen wir die toten Soldaten[ENTER]beruhigen. Sie haben ihr Bestes gegeben, also[ENTER]sollen sie jetzt auch in Frieden ruhen.[ENTER]Lass mich dir eine Belohnung geben für diese[ENTER]noble Tat. "
gameforge.subquest_42._30_say = "Schlimme Kriege tِten immer hنufiger junge[ENTER]Mنnner. Es sind Kنmpfer, die an der Frontlinie[ENTER]für sich selbst, ihre Familie und ihr Land[ENTER]kنmpfen. Aber nach dem Tod kamen einige nicht in[ENTER]das Nirwana. Sie blieben in dieser Welt. "
gameforge.subquest_42._40_say = "Man sagt, sie seien wنhrend des Krieges resistent[ENTER]gegen den Tod geworden. Sie glauben, dass sie ihr[ENTER]Land immer noch verteidigen müssen.[ENTER]Unsere Schamanen wollen nun eine Zeremonie[ENTER]abhalten, um diese Geister zu beruhigen. Dafür[ENTER]brauchen wir einen speziellen Tempelschal und[ENTER]eine Tempellehre, aber heutzutage ist es schwer,[ENTER]so etwas zu finden. Kِnntest du diese beiden[ENTER]Sachen für uns holen? "
gameforge.subquest_42._50_say = "Ich hِrte, dass der Stolze dunkle Oberst im[ENTER]Hwang-Tempel einen Tempelschal und eine[ENTER]Tempellehre besitzen soll.[ENTER]Bitte hilf mir und meinen Kameraden, diejenigen[ENTER]zu beruhigen, die für ihr Land gestorben sind. "
gameforge.subquest_42._60_select = "Ich helfe dir. "
