gameforge.subquest_44._100_sendLetter = "Die Spinne mit der Glocke "
gameforge.subquest_44._10_targetVid = "Die Spinne "
gameforge.subquest_44._110_say = "Taurean sagt, er habe einer Spinne ein Glِckchen[ENTER]umgehنngt. Nun mِchte Yu-Rang wissen, ob ihr[ENTER]Freund wirklich so mutig gewesen ist, wie er[ENTER]behauptet.[ENTER]Suche nach dieser Spinne in der Wüste. "
gameforge.subquest_44._120_say = "Hast du die Spinne mit dem Glِckchen schon[ENTER]gefunden? Nein? Wahrscheinlich wirst du sie auch[ENTER]nie finden. Taurean ist ein Angsthase und wollte[ENTER]nur angeben! "
gameforge.subquest_44._130_sendLetter = "Kein Glِckchen zu finden "
gameforge.subquest_44._140_sayTitle = "Viele Spinnen, kein Glِckchen "
gameforge.subquest_44._150_say = "Du hast einige Spinnen getِtet, aber kein[ENTER]Glِckchen bei ihnen gefunden. Du kannst nicht[ENTER]ewig suchen. Wahrscheinlich ist es einfacher,[ENTER]Taurean zu suchen und ihn nach der Wahrheit zu[ENTER]fragen. "
gameforge.subquest_44._160_sendLetter = "Geh zu Taurean "
gameforge.subquest_44._170_targetVid = "Frage Taurean nach dem Glِckchen "
gameforge.subquest_44._180_say = "Es ist kaum anzunehmen, dass Taurean wirklich so[ENTER]mutig ist, einer Spinne ein Glِckchen umzuhنngen.[ENTER]Frage ihn am besten direkt nach der[ENTER]Wahrheit. "
gameforge.subquest_44._190_npcChat = "Sag mal, deine Wette mit Yu-Rang... "
gameforge.subquest_44._200_say = "Du weiكt von der Wette mit Yu-Rang? Sie traut mir[ENTER]nicht und denkt, ich hنtte es nicht geschafft.[ENTER]Sie denkt, ich würde schon tot umfallen, wenn ich[ENTER]eine Riesenspinne nur ansehe. "
gameforge.subquest_44._20_npcChat = "Eine Spinne mit Glِckchen...? "
gameforge.subquest_44._210_say = "Ehrlich gesagt... Also, eigentlich hat sie ja[ENTER]Recht. Ich habe mich nicht getraut, es ihr zu[ENTER]beichten, weil ich zu stolz bin. "
gameforge.subquest_44._220_say = "Aber du siehst sehr stark aus! Kannst du nicht[ENTER]für mich das Glِckchen an eine Babyspinne[ENTER]hنngen und dann sagen, dass ich es war? Bitte,[ENTER]bitte! Sonst wird sie sich für den Rest meines[ENTER]Lebens über mich lustig machen. "
gameforge.subquest_44._230_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_44._240_say = "Du willst es nicht machen? Aber du wirst doch[ENTER]hoffentlich nicht alles Yu-Rang erzنhlen?![ENTER]Bitte, hilf mir. Komm wieder her, wenn du Zeit[ENTER]für mich hast! "
gameforge.subquest_44._250_say = "Jetzt wird Yu-Rang nie mehr mit mir reden.[ENTER]Oder mich nur auslachen... "
gameforge.subquest_44._260_say = "Ah, ich hatte Recht: du bist tatsنchlich so[ENTER]freundlich, wie du aussiehst! Danke für deine[ENTER]Hilfe. Viel Erfolg! "
gameforge.subquest_44._270_sendLetter = "Zurück zu Yu-Rang "
gameforge.subquest_44._280_say = "Geh zurück zu Yu-Rang und berichte ihr von[ENTER]Taureans Lüge. "
gameforge.subquest_44._290_npcChat = "Yu-Rang ist sehr enttنuscht von dir. "
gameforge.subquest_44._300_say = "Du hast es ihr gesagt?![ENTER]Ich kann verstehen, dass sie nicht mehr meine[ENTER]Freundin sein will. Aber es macht mich sehr[ENTER]traurig. Ich hoffe ich kann sie irgendwann[ENTER]umstimmen. Vielleicht fنllt mir etwas Schِnes für[ENTER]sie ein... "
gameforge.subquest_44._30_say = "Hey, kannst du mir einen Gefallen tun? Mein[ENTER]Freund Taurean war sehr verنrgert, weil ich ihn[ENTER]einen Feigling nannte. Er sagte, dass er[ENTER]eigentlich recht tapfer sei. Er hat mit mir eine[ENTER]Wette abgeschlossen, dass er es schaffen würde,[ENTER]ein Glِckchen an eine Babyspinne zu hنngen. Er[ENTER]erzنhlte mir auch, dass er es schon getan hنtte,[ENTER]aber ich kann ihm das einfach nicht glauben. "
gameforge.subquest_44._310_npcChat = "Taurean hat gelogen. "
gameforge.subquest_44._320_say = "Seine Geschichte stimmt also nicht?[ENTER]Hmm, die Lüge an sich finde ich nicht so schlimm.[ENTER]Jeder hat seinen Stolz. Aber dann hنtte er[ENTER]wenigstens versuchen müssen, sie wahr zu machen![ENTER]Mit so einem Angsthasen will ich nicht lنnger[ENTER]befreundet sein. "
gameforge.subquest_44._330_sayReward = "Yu-Rang gibt dir eine Belohnung für deine[ENTER]Ehrlichkeit. "
gameforge.subquest_44._340_sayReward = "Du erhنltst 30.000 Yang. "
gameforge.subquest_44._350_sayReward = "Du erhنltst 350.000 Erfahrungspunkte. "
gameforge.subquest_44._360_sendLetter = "Glِckchen für die Spinne "
gameforge.subquest_44._370_say = "Geh in die Wüste zu den Babyspinnen und versuche,[ENTER]einer von ihnen Taureans Glِckchen umzuhنngen. "
gameforge.subquest_44._380_npcChat = "Wegen des Glِckchens... "
gameforge.subquest_44._390_say = "Du hast das Glِckchen noch nicht angehنngt?[ENTER]Dann mach es bitte bald. Und pass auf, dass[ENTER]Yu-Rang dich nicht erwischt! "
gameforge.subquest_44._400_sendLetter = "Geschafft! "
gameforge.subquest_44._40_say = "Ich weiك, dass ich meinem Freund vertrauen[ENTER]sollte. Ich mِchte aber dennoch wissen, ob er es[ENTER]wirklich getan hat. Für mich ist es zu gefنhrlich[ENTER]in der Wüste. Du siehst sehr stark aus. Es wird[ENTER]sicher leicht für dich. Würdest du gehen und für[ENTER]mich nachsehen? "
gameforge.subquest_44._410_say = "Es war sehr schwierig, aber du hast es endlich[ENTER]geschafft, das Glِckchen einer Babyspinne[ENTER]umzuhنngen. Gehe nun zu Yu-Rang und erzنhle ihr,[ENTER]dass das Taureans Werk sei. "
gameforge.subquest_44._420_npcChat = "Das Glِckchen ist angebracht. "
gameforge.subquest_44._430_say = "Du hast es geschafft? Das ist toll![ENTER]Dann erzنhle schnell Yu-Rang davon, damit sie mir[ENTER]endlich glaubt! "
gameforge.subquest_44._440_npcChat = "Taurean hat die Wahrheit gesagt. "
gameforge.subquest_44._450_say = "Wie bitte? Du hast eine Spinne mit Glِckchen[ENTER]gefunden? Dann hat Taurean es tatsنchlich getan.[ENTER]Das hنtte ich niemals für mِglich gehalten.[ENTER]Vielleicht wird doch noch einmal ein richtiger[ENTER]Mann aus ihm. Danke, dass du das für mich[ENTER]überprüft hast. Hier ist eine Belohnung für deine[ENTER]Hilfe. "
gameforge.subquest_44._460_sendLetter = "Zurück zu Taurean "
gameforge.subquest_44._470_targetVid = "Zurück zu Taurean "
gameforge.subquest_44._480_say = "Du hast Yu-Rang erzنhlt, dass ihr Freund[ENTER]tatsنchlich einer Babyspinne eine Glocke[ENTER]umgehنngt habe.[ENTER]Gehe nun zurück zu Taurean und berichte ihm von[ENTER]der erfolgreichen Tنuschung. "
gameforge.subquest_44._490_npcChat = "Yu-Rang glaubt dir. "
gameforge.subquest_44._500_say = "Danke vielmals. Nun verachtet Yu-Rang mich nicht.[ENTER]Wir müssen das für immer geheimhalten![ENTER]Versprochen? Bis bald! "
gameforge.subquest_44._50_select = "Annehmen "
gameforge.subquest_44._510_sayReward = "Taurean gibt dir eine Belohnung für die[ENTER]Unterstützung bei seiner Lüge:[ENTER]Du erhنltst 30.000 Yang. "
gameforge.subquest_44._520_sayReward = "Du erhنltst 700.000 Erfahrungspunkte. "
gameforge.subquest_44._60_say = "Mِchtest du die Quest für immer aufgeben? "
gameforge.subquest_44._70_say = "Warum nicht? Hast du etwa auch Angst?[ENTER]Besuche mich, wenn du deine Meinung geنndert[ENTER]hast. "
gameforge.subquest_44._80_say = "Oh, hast du etwa auch Angst? Aber du bist doch[ENTER]viel grِكer und stنrker als ich! Haha, du bist[ENTER]feige! Dann muss ich wohl jemand anders fragen. "
gameforge.subquest_44._90_say = "Die Spinnen leben in der Wüste.[ENTER]Du bist stark. Ich bin sicher, du wirst es[ENTER]schaffen. Viel Glück! "
