gameforge.subquest_45._100_sayTitle = "Hole die geheimen Informationen "
gameforge.subquest_45._10_npcChat = "Die Sache mit dem Dunklen Tempel "
gameforge.subquest_45._110_say = "Du hast nun die Tempelehre, den Tempelschal und[ENTER]die ـbersetzung der Fluchsammlung in deinem[ENTER]Besitz. Bringe die Gegenstنnde zu Soon. "
gameforge.subquest_45._120_say = "Wenn du Soon, dem Bücherwurm, hilfst, kann er[ENTER]seine Studien über den Dunklen Tempel fortführen.[ENTER]Dies ist nur mِglich, wenn er in den Besitz von[ENTER]folgenden Sachen kommt: Die Tempellehre, den[ENTER]Tempelschal und die ـbersetzung der[ENTER]Fluchsammlung. Besorge diese Sachen und bringe[ENTER]sie dann zu Soon. Du findest sie im Hwang-Tempel[ENTER]im Tal von Seungryong. "
gameforge.subquest_45._130_npcChat = "Die Sachen aus dem Dunklen Tempel "
gameforge.subquest_45._140_say = "Ah, du hast sie! Vielen Dank.[ENTER]Was die Wesen im Tempel betrifft, nun, das ist[ENTER]einfach: sie sind gefنhrlich. Aber das hast du ja[ENTER]am eigenen Leib erfahren.[ENTER]Auكerdem scheinen sie bِsen Gِttern zu dienen.[ENTER]Ich kenne keine Details, aber ich vermute, sie[ENTER]planen Schlimmes. "
gameforge.subquest_45._150_say = "Jetzt, wo ich einige ihrer heiligen[ENTER]Gegenstنnde besitze, werde ich hoffentlich mehr[ENTER]herausfinden kِnnen. Am besten ich beginne mit[ENTER]der Tempellehre.[ENTER]Mal sehen... Hmmhm... Aha...[ENTER]Warum stehst du noch hier rum? Hast du nichts zu[ENTER]tun? "
gameforge.subquest_45._160_sayReward = "Du erhنltst 7.000.000 Erfahrungspunkte. "
gameforge.subquest_45._170_sayReward = "Du erhنltst 70.000 Yang. "
gameforge.subquest_45._180_sayReward = "Du erhنltst ein Buch des Anführers. "
gameforge.subquest_45._190_say = "Was? Du hast sie nicht?[ENTER]Beeil dich, wenn du einen Auftrag annimmst.[ENTER]Schnell, geh los! "
gameforge.subquest_45._200_select = "Noch einmal versuchen "
gameforge.subquest_45._20_say = "Irgendetwas ist im Dunklen Tempel im Gange. Ich[ENTER]denke, es sind gefنhrliche Wesen, die dort die[ENTER]alten Zauber studieren.[ENTER]Die Geheimnisse des Dunklen Tempels sind schwer[ENTER]zu durchdringen, auch für mich. Aber ich bin[ENTER]sicher, dass die Motive dieser Wesen mehr als[ENTER]zweifelhaft sind. Ich muss mehr darüber[ENTER]herausfinden! "
gameforge.subquest_45._210_say = "Dann werde ich wohl einen stنrkeren Helden fragen[ENTER]müssen. Leb wohl. "
gameforge.subquest_45._220_say = "Danke.[ENTER]Ich hoffe du hast diesmal mehr Erfolg! "
gameforge.subquest_45._30_say = "Ich benِtige Fakten für meine Studien.[ENTER]Ich denke, die Tempellehre, der Tempelschal und[ENTER]die ـbersetzung der Fluchsammlung kِnnten mehr[ENTER]als hilfreich sein.[ENTER]Kannst du mir diese Dinge bringen? Ich wنre dir[ENTER]sehr dankbar. Und trِdle nicht zu lange, ich[ENTER]brauche sie bald! "
gameforge.subquest_45._40_select = "Ich werde sofort gehen. "
gameforge.subquest_45._50_say = "Willst du die Aufgabe annehmen? "
gameforge.subquest_45._60_say = "Ich bitte dich um deine Hilfe![ENTER]Wenn du beschنftigt bist, dann komm spنter[ENTER]wieder. Vielleicht hast du dann mehr Zeit.[ENTER]Ich warte auf dich. "
gameforge.subquest_45._70_say = "Ich bitte um deine Hilfe und du drehst dich[ENTER]einfach um?[ENTER]Ach, wer braucht dich schon... Los, verschwinde! "
gameforge.subquest_45._80_say = "Danke! "
gameforge.subquest_45._90_makequestbutton = "Dunkler Tempel "
