gameforge.subquest_46._40_say = "Den Wüstensand erhنltst du bei den[ENTER]Wüstenbanditen, Kristallerz kannst du aus einer[ENTER]Erzader gewinnen und für das Affenblut musst du[ENTER]Affen im Sangsun Dong tِten. Kannst du mir diese[ENTER]Materialien besorgen? Ich weiك, es wird nicht[ENTER]einfach, aber ich werde dich reich entlohnen. "
gameforge.subquest_46._50_select = "Annehmen "
gameforge.subquest_46._60_select = "Ablehnen "
