gameforge.subquest_48._110_say = "Einer der Spione des Hauptmanns lebt als Fischer[ENTER]im Dorf Pyungmoo im Jinno-Reich. Nimm unauffنllig[ENTER]Kontakt zu ihm auf und überbringe seinen Bericht[ENTER]dem Hauptmann. "
gameforge.subquest_48._120_say = "Einer der Spione des Hauptmanns lebt als Fischer[ENTER]im Dorf Yongan im Shinsoo-Reich. Nimm[ENTER]unauffنllig Kontakt zu ihm auf und überbringe[ENTER]seinen Bericht dem Hauptmann. "
gameforge.subquest_48._130_say = "Einer der Spione des Hauptmanns lebt als Fischer[ENTER]im Dorf Joan im Chunjo-Reich. Nimm[ENTER]unauffنllig Kontakt zu ihm auf und überbringe[ENTER]seinen Bericht dem Hauptmann. "
gameforge.subquest_48._140_npcChat = "Was machst du gerade? "
gameforge.subquest_48._150_say = "Psst, sei leise! Du verscheuchst alle Fische.[ENTER]Was willst du eigentlich hier? Du bist so laut[ENTER]und ungeschickt. Du kannst kaum zum Angeln[ENTER]gekommen sein. "
gameforge.subquest_48._160_say = "Ah, ich verstehe. Ich habe dich schon lنngst[ENTER]erwartet. Du kommst spنt. Es war nicht leicht, an[ENTER]die Informationen zu kommen, ohne entdeckt zu[ENTER]werden. ـberall lauern Feinde und warten nur[ENTER]darauf, dass man sich verrنt. "
gameforge.subquest_48._170_say = "Halten wir uns hier nicht zu lange auf! Nicht,[ENTER]dass uns noch jemand entdeckt. Hier hast du die[ENTER]Dokumente. Mache dich geschwind auf den Weg und[ENTER]überbringe sie direkt dem Hauptmann! "
gameforge.subquest_48._180_say = "Einen kleinen Moment noch! Ich habe hier etwas[ENTER]für dich. Ein kleines Geschenk. So, nun mach dich[ENTER]auf den Weg. "
gameforge.subquest_48._190_sayReward = "Neugierig ِffnest du das Pنckchen, um[ENTER]nachzusehen, was der Spion dir geschenkt hat. "
gameforge.subquest_48._200_say = "Toll! Gegrillte Rotfeder! Offensichtlich versteht[ENTER]der Spion tatsنchlich etwas vom Fischen. "
gameforge.subquest_48._20_say = "Steh bequem, Soldat![ENTER]Da wir mit den Nachbarlنndern in feindlicher[ENTER]Beziehung leben, ist es sehr wichtig, Freunde zu[ENTER]haben, die dort verdeckt kundschaften. So kommen[ENTER]wir an Informationen und kِnnen uns auf[ENTER]mِgliche Angriffe vorbereiten. Es ist von[ENTER]grِكter Wichtigkeit, dass diese Spione nicht[ENTER]enttarnt werden. "
gameforge.subquest_48._210_sayReward = "Du hast 3 gegrillte Rotfedern bekommen. "
gameforge.subquest_48._220_sendLetter = "Zurück zum Hauptmann "
gameforge.subquest_48._230_targetVid = "Der Hauptmann "
gameforge.subquest_48._240_say = "Die gefنhrliche Reise nach Pyungmoo im Reich[ENTER]Jinno war erfolgreich: Du hast den Bericht des[ENTER]als Fischer getarnten Spions erhalten.[ENTER]Kehre nun schnell in dein Reich zurück und bring[ENTER]dem Hauptmann die Informationen. "
gameforge.subquest_48._250_say = "Die gefنhrliche Reise nach Yongan im Reich[ENTER]Shinsoo war erfolgreich: Du hast den Bericht des[ENTER]als Fischer getarnten Spions erhalten.[ENTER]Kehre nun schnell in dein Reich zurück und bring[ENTER]dem Hauptmann die Informationen. "
gameforge.subquest_48._260_say = "Die gefنhrliche Reise nach Joan im Reich Chunjo[ENTER]war erfolgreich: Du hast den Bericht des als[ENTER]Fischer getarnten Spions erhalten.[ENTER]Kehre nun schnell in dein Reich zurück und bring[ENTER]dem Hauptmann die Informationen. "
gameforge.subquest_48._270_npcChat = "Die Mission war erfolgreich! "
gameforge.subquest_48._280_say = "Sind das die Dokumente? Fantastisch! Ich danke[ENTER]dir. Nun kennen wir die Plنne unserer Feinde und[ENTER]kِnnen die richtigen Maكnahmen treffen, um uns zu[ENTER]schützen. Du hast deinem Reich einen groكen[ENTER]Dienst erwiesen! "
gameforge.subquest_48._290_sayReward = "Du erhنltst 5.500.000 Erfahrungspunkte. "
gameforge.subquest_48._300_sayReward = "Du erhنltst 50.000 Yang. "
gameforge.subquest_48._30_say = "Du kennst doch sicherlich Yu-Hwan, den Musiker?[ENTER]Auch er ist ein Spion und arbeitet für unser[ENTER]Land. Aber ein einzelner Spion reicht nicht aus.[ENTER]So haben wir mehrere über die ganze Welt[ENTER]verteilt. Einer von ihnen hنlt sich als Fischer[ENTER]im ersten Dorf auf. "
gameforge.subquest_48._40_say = "Da ich nicht in direkten Kontakt zu ihm treten[ENTER]kann, ohne seine Tarnung zu gefنhrden, bin ich[ENTER]auf die Mithilfe von furchtlosen Soldaten[ENTER]angewiesen. Ja, ich meine dich! Geh für mich zu[ENTER]diesem Fischer und bring mir seinen neuesten[ENTER]Bericht. Es ist von hِchster Wichtigkeit für[ENTER]die Sicherheit des Reiches! "
gameforge.subquest_48._50_say = "Willst du die Quest für immer aufgeben? "
gameforge.subquest_48._60_say = "Du willst dich erst noch vorbereiten? Dann komm[ENTER]spنter wieder vorbei. Ich erwarte dich. Aber[ENTER]zِgere nicht zu lange, ich brauche diesen[ENTER]Bericht! "
gameforge.subquest_48._70_say = "Was ist denn los mit dir? Du hast doch letztes[ENTER]Mal so groكartige Arbeit für uns geleistet! Und[ENTER]jetzt lنsst du dein Reich im Stich? Aber da kann[ENTER]ich wohl nichts machen. Leb wohl. "
gameforge.subquest_48._80_say = "Ich wusste, dass auf dich Verlass ist.[ENTER]Viel Erfolg! Und pass auf dich auf! "
gameforge.subquest_48._90_makequestbutton = "Den Spion treffen "
