gameforge.subquest_49._100_sayTitle = "Was ist Bingsu "
gameforge.subquest_49._10_targetVid = "Bingsu? "
gameforge.subquest_49._110_say = "Taurean hat sich mit Harang gestritten, weil er[ENTER]ihr nicht glaubt, dass man im Sommer Eis[ENTER]herstellen kann. Geh zu Harang und frage sie, was[ENTER]sie über Bingsu weiك. "
gameforge.subquest_49._120_qSetTitle = "Harang fragen "
gameforge.subquest_49._130_targetVid = "Frage Harang "
gameforge.subquest_49._140_npcChat = "Was ist Bingsu? "
gameforge.subquest_49._150_say = "Dieser Taurean tut immer so, als wüsste er alles.[ENTER]Dabei kennt er nicht einmal Bingsu! Wie kann man[ENTER]so etwas Leckeres nicht kennen?[ENTER]Du weiكt es auch nicht?? Dann geh am besten[ENTER]gleich zu Octavio ins Nachbardorf. Er ist ein[ENTER]berühmter Koch und kennt alle guten Rezepte.[ENTER]Einmal hat er mir Bingsu gemacht, mmmmh... Er[ENTER]wird dir beweisen, dass ich Recht habe! "
gameforge.subquest_49._160_makequestbutton = "Auf zu Octavio "
gameforge.subquest_49._170_say = "Taurean mِchte unbedingt wissen, was Bingsu ist.[ENTER]Geh für ihn zum Restaurantbesitzer Octavio. Er[ENTER]kann dir sicherlich weiterhelfen. "
gameforge.subquest_49._180_npcChat = "Weiكt du, was Bingsu ist? "
gameforge.subquest_49._190_say = "Bingsu? Natürlich kenne ich das. Jeder gute Koch[ENTER]weiك, wie man Bingsu herstellt! Zunنchst benِtigt[ENTER]man fein gemahlenes Eis. Darauf kommt dann[ENTER]Zucker, klein geschnittene Reiskuchen und[ENTER]frisches Obst zum Dekorieren. "
gameforge.subquest_49._200_say = "Warum fragst du? Weil Taurean und Harang sich[ENTER]streiten? Das ist ja nichts Neues. Aber Harang[ENTER]hat Recht. Besonders in heiكen Sommern ist[ENTER]Bingsu eine beliebte Speise.[ENTER]Taurean ist ein guter Junge, auch wenn er[ENTER]manchmal etwas engherzig ist. Wenn du mir die[ENTER]Zutaten besorgst, kِnnte ich Bingsu für ihn[ENTER]herstellen. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Ich würde Taurean gerne eine Freude machen und[ENTER]ihm Bingsu servieren. Was meinst du? Kannst du[ENTER]mir Eis vom Berg Sohan holen? "
gameforge.subquest_49._220_say = "Mِchtest du die Quest für immer aufgeben? "
gameforge.subquest_49._230_say = "Magst du kein Eis? Oder hast du schon zu viel[ENTER]gegessen? Es ist für Taurean, also überleg es dir[ENTER]bitte nochmal. "
gameforge.subquest_49._240_say = "Schade. Taurean wird sehr enttنuscht sein.[ENTER]Bis dann. "
gameforge.subquest_49._250_say = "Sehr gut. Ich benِtige Eisklumpen von dem[ENTER]Verzauberten Eis auf dem Berg Sohan. Bring mir 50[ENTER]Stück, dann kann ich leckeres Bingsu machen. "
gameforge.subquest_49._260_targetVid = "Geh zu Octavio "
gameforge.subquest_49._270_say = "%s[ENTER]Du hast die Eisklumpen für Taureans Bingsu.[ENTER]Bringe sie zu Octavio. "
gameforge.subquest_49._275_say = "Eisklumpen besorgt "
gameforge.subquest_49._280_say = "%s[ENTER]Octavio hat sich bereit erklنrt, für Taurean[ENTER]Bingsu herzustellen, braucht aber Eis dafür. Tِte[ENTER]Verzaubertes Eis auf dem Berg Sohan und sammle 50[ENTER]Klumpen Eis. Bringe diese dann zu Octavio. "
gameforge.subquest_49._285_say = "Suche nach dem Eis "
gameforge.subquest_49._290_npcChat = "Hier, ich habe Eisklumpen mitgebracht. "
gameforge.subquest_49._300_say = "Ah, sehr gut! Damit ist der schwierigste Teil der[ENTER]Bingsuherstellung erledigt. Jetzt muss ich nur[ENTER]noch ein bisschen Zucker... und etwas Obst...[ENTER]Bitte sehr! Ein Eis für Taurean. Nimm es gleich[ENTER]mit, dann vergisst er bald seinen ؤrger. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Es tut mir leid, aber das reicht nicht. Du musst[ENTER]noch mehr besorgen, sonst wird es nur eine winzig[ENTER]kleine Portion! "
gameforge.subquest_49._320_select = "Weiter versuchen "
gameforge.subquest_49._330_say = "Ich weiك, der Weg ist weit und die Monster stark.[ENTER]Wenn es dir zu schwierig ist, kann man nichts[ENTER]machen. Bis dann. "
gameforge.subquest_49._340_say = "Versuche es ruhig noch einmal. Mit deinem Mut und[ENTER]deiner Ausdauer kannst du es schaffen! "
gameforge.subquest_49._350_targetVid = "Bingsu! "
gameforge.subquest_49._360_say = "Es ist vollbracht: Octavio hat aus dem Eis vom[ENTER]Berg Sohan Bingsu hergestellt. Jetzt schnell[ENTER]zurück zu Taurean, bevor es schmilzt. "
gameforge.subquest_49._370_npcChat = "Hier ist das Bingsu! "
gameforge.subquest_49._380_say = "Das ist Bingsu? Das schmeckt wirklich gut. Süك[ENTER]und kühl. Sowas habe ich noch nie gegessen,[ENTER]danke! Harang hatte also recht. Jetzt werde ich[ENTER]mich wohl bei ihr entschuldigen müssen... "
gameforge.subquest_49._390_sayReward = "Du erhنltst 6.000.000 Erfahrungspunkte. "
gameforge.subquest_49._400_sayReward = "Du erhنltst 70.000 Yang. "
gameforge.subquest_49._40_say = "Heut habe ich mich mit Harang gestritten.[ENTER]Ich kِnnte sie...[ENTER]Sie behauptet, dass es etwas sehr Leckeres gibt,[ENTER]das aus fein zerkleinertem Eis besteht.[ENTER]Bingsu heiكt es. "
gameforge.subquest_49._410_sayReward = "Du erhنltst eine Schriftrolle des Krieges. "
gameforge.subquest_49._420_say = "Hast daran gedacht, mir Bingsu mitzubringen? "
gameforge.subquest_49._430_say = "Oje, das habe ich ganz vergessen! Hmm, ob ich es[ENTER]noch weiter versuche? Oder soll ich es lieber[ENTER]lassen? "
gameforge.subquest_49._440_select = "Ich mache weiter. "
gameforge.subquest_49._450_select = "Ich gebe auf. "
gameforge.subquest_49._460_say = "Ich schaffe es nicht.[ENTER]Es tut mir leid. "
gameforge.subquest_49._50_say = "So etwas ist eigentlich nur im Winter machbar,[ENTER]wenn es richtig kalt ist. Trotzdem behauptet sie[ENTER]stنndig, dass es geht. Kannst du herausfinden, ob[ENTER]man dieses Bingsu auch im Sommer herstellen kann?[ENTER]Wenn es so etwas überhaupt gibt... "
gameforge.subquest_49._60_say = "Dieses Bingsu ist bestimmt lecker! Bist du[ENTER]sicher, dass du mir niemals helfen willst,[ENTER]welches herzustellen? "
gameforge.subquest_49._70_say = "Wenn du es spنter erledigen[ENTER]mِchtest, sage es mir bitte. "
gameforge.subquest_49._80_say = "Ich würde ja so gerne mal Bingsu probieren...[ENTER]Aber du hast recht. Harang wollte bestimmt bloك[ENTER]angeben und es gibt überhaupt kein Bingsu![ENTER]Mach's gut. "
gameforge.subquest_49._90_say = "Danke, dass du mir hilfst. Lass es mich wissen,[ENTER]wenn du etwas herausfindest. Dann kann ich dieser[ENTER]Harang die Meinung sagen! "
