gameforge.training_grandmaster_skill._30_say = "بما أنك قرأت لفيفة طرد الأرواح الشرير فبإمكانك[ENTER]الآن متابعة التدريب بدون توقف. "
gameforge.training_grandmaster_skill._40_say = "عليك أن ترتاح نصف يوم بعد الانتهاء من التدريب.[ENTER]أعد المحاولة لاحقاً من جديد.أو استخدم اللفيفة[ENTER]التعويذية. "
gameforge.training_grandmaster_skill._50_say = "إنك لم تتعلم حتى الآن لمهارة من المهارات بشكل[ENTER]يمكِّنك من الوصول إلى مستوى الخبير الكبير. "
gameforge.training_grandmaster_skill._60_say = "اختر من فضلك إحدى المهارات، لكي ترتقي إلى مستوى[ENTER]الخبير المحترف. "
gameforge.training_grandmaster_skill._70_chat = "مجموع نقاط الرتب: %s "
gameforge.training_grandmaster_skill._75_chat = "نقاط الرتبة الضرورية: "
gameforge.training_grandmaster_skill._80_stringFormat = "%s تدريب مهارات الخبير المحترف "
gameforge.training_grandmaster_skill._90_say = "إن تدريب مهارات الخبير المحترف تستهلك عدداً[ENTER]كبيراً من النقاط. قد يؤدي هذا بك إلى انخفاض مجموع[ENTER]نقاطك إلى المجال السلبي. "
gameforge.training_mount = {}
gameforge.training_mount._01_say = "يؤسفني أن أخبرك بأنك لا تملك ما يكفي من خبرة[ENTER]الرُّكوب لكي تقوم بتطوير دابتك. سيتوجب عليك قبل[ENTER]ذلك السعي للحصول على رخصة الحصان المُدرع على[ENTER]الأقل. "
gameforge.training_mount._02_say = "آسف، لكنني لا أستطيع مُساعدتك إذا لم تُحضر[ENTER]الوثائق اللازمة. إياك أن تحاول خداعي من جديد![ENTER]ستدفع ثمن خداعك غالياً إذا تجرأت من جديد! "
gameforge.training_mount._03_say = "أين هو ختم الدابة؟ لا يمكنني تحسين دابتك إذا لم[ENTER]تُحضره لي. ألق نظرة يسار أسفل الشاشة وراء القطعة[ENTER]النقدية التي تدور. ستعثر هناك على شهادات يمكنني[ENTER]أن أستبدلها لك مقابل ختم الدابة. "
gameforge.training_mount._04_say = "إنني أرغب في ركوب دابة جديدة! "
gameforge.training_mount._05_say = "يا هذا! يا له من منظر مُضحك، إنك لا زلت تستعمل[ENTER]الحصان كدابة؟ هل هذا معقول؟ لقد أصبح اليوم[ENTER]بإمكاننا ترويض الحيوانات البرية وركوبها. "
gameforge.training_mount._06_say = "يجب أن تكون فارساً ماهراً لترويض الحيوانات البرية[ENTER]لخوض المعارك الشرسة. كما أن ستحتاج إلى البنود[ENTER]التالية: لفيفة التّطور، لتطوير الدابة إلى دابة[ENTER]برية، ولفيفة الطافر لتحويل هذه الأخيرة إلى دابة[ENTER]قوية. "
gameforge.training_mount._07_say = "لا تتردّد في زيارتي إذا كانت لديك بعض الأسئلة.[ENTER]سأبذل قصارى جهدي لمساعدتك. "
gameforge.training_mount._08_say = "إنني أرغب في تطوير دابّتي! "
gameforge.training_mount._09_say = "أنت راغبٌ إذاً في تطوير دابتك؟ هل لديك فكرة كيف[ENTER]يمكنك فعل هذا؟ طيب، سأوضّح لك العملية بالتفصيل. "
gameforge.training_mount._10_say = "عليك أولاً البحث عن لفيفة التطّور، إذا كُنت ترغب[ENTER]في تطوير دابتك إلى دابة برية. أما إذا كُنت ترغب[ENTER]في تدريب دابتك لتحويلها إلى دابة قوية فعليك البحث[ENTER]عن لفيفة الطافر. يُحكى أنها هذه اللفائف أُخفيت في[ENTER]بلاد بعيدة، يسكنها عمالقة أشرار! "
gameforge.training_mount._11_say = "أحضر لي هذه اللفائف وسأقوم بتطوير دابتك. إنك لا[ENTER]تحملها معك الآن، هذا صحيح؟ "
gameforge.training_mount._12_say = "نعم، إنني أرغب في تحسين دابتي! "
gameforge.training_mount._13_say = "لا، ليس الآن. "
gameforge.training_mount._14_say = "آه، لقد أحضرت معك اللفائف. أيهما إذاً؟ سيمكّنك[ENTER]استعمال لفيفة التّطور من تطوير دابتك الصغيرة[ENTER]وتحضيرها لخوض معارك شرسة. أما لفيفة الطافر[ENTER]فاستعمالها يُحول دابتك إلى دابة قوية. "
gameforge.training_mount._15_2_say = "لقد حصلتُ على لفيفة الطافر. "
gameforge.training_mount._15_say = "لقد حصلتُ على لفيفة التّطور. "
gameforge.training_mount._16_say = "إنني لا أحمل معي أية لفيفة من اللفائف. "
gameforge.training_mount._17_say = "آه، وا عجباه، انظر إنها لفيفة التّطور! دعني إذاً[ENTER]ألقي نظرة على ختم الدابة. لقد حاول بعضهم سابقاً[ENTER]التّلاعب بي وخداعي! أعطني إيّاه، سأفحص أولاً[ENTER]أصليته. (اسحب الختم نحو صبي الإسطبل.) "
gameforge.training_mount._18_say = "لفيفة الطافر! لم أشاهدها من قبل، بل سمعت عنها[ENTER]فقط. هيّا أعطني ختم الدابة. سأستبدله لك بختم أكثر[ENTER]قوة، بمجرد تحقُّقي من أصليته. (اسحب الختم نحو صبي[ENTER]الإسطبل.) "
gameforge.training_mount._19_say = "عُد إلي من جديد بِمُجرّد عثورك على إحدى اللفائف.[ENTER]سأعمل حينها على استبدال ختم دابتك القديم بختم[ENTER]جديد أقوى منه. "
gameforge.training_mount._20_say = "لقد أصبح ختم دابتك هذا بالفعل تُحفة يجبُ وضعه في[ENTER]متحف للآثار القديمة! انتظر للحظة، سأستبدله لك[ENTER]بختم جديد. تفضّل. يمكنك الآن مناداة دابتك البرية.[ENTER]عُد إليّ من جديد، بمجرد اكتشافك للفيفة التطّور.[ENTER]سأحضّر لك عندها ختم دابة أقوى بكثير من ختمك[ENTER]القديم. "
gameforge.training_mount._21_say = "آه، يا زمان! إنه ختم الدابة التي حصلت مني عليه[ENTER]منذ زمن بعيد. إن علامات الزمن تظهر عليه جلياً.[ENTER]أعطني إياه وسأعوِّضه لك بختم دابة أقوى منه! "
gameforge.training_mount._22_say = "إن قوة هذا الختم تُحضّر دابّتك المُتحولة. لا[ENTER]تُضيّعه، إن قيمته لا تُقدر بثمن! "
gameforge.training_mount._23_say = "هل بإمكاني استعمال مهارات الرّكوب؟ "
gameforge.training_mount._24_say = "هل ترغب في استعمال مهارات الركوب؟ إنك فعلاً شخص[ENTER]طموح ومُلح! لا عليك، أنا أيضاً أحلُم بنفس[ENTER]الشيء... طيب، تذكر أنك إذا كنت ترغب في تعلم طريقة[ENTER]استعمالها، فسيتوجب عليك احترام بعض القواعد. "
gameforge.training_mount._25_say = "القاعدة الأولى تتمثل في إتقان مهارة الركوب، لأنك[ENTER]قد تُعرّض نفسك لخطر كبير، إن لم تفعل. كما سيتوجب[ENTER]عليك أيضاً تحضير دابتك للقتال، عندها فقط ستتمكن[ENTER]من استعمال مهارات الركوب. "
gameforge.training_mount._26_say = "هل بإمكان دابتك تعلُّم مهارات الرّكوب؟ إذا كان[ENTER]عاجزاً عن ذلك فلن أسمح لك بالتدريب. ما الذي ترغب[ENTER]في عمله الآن؟ "
gameforge.training_mount._27_say = "طيب، فهمتُ قصدك. سأحاول الآن تقييم وتقدير قوتك[ENTER]وخبرتك في الركوب. انتظر لحظة. "
gameforge.training_mount._28_say = "هممم... ظهر صلب وقامة مُعتدلة، وخبرة جيدة في[ENTER]الركوب، وها هي دابتك مُستعدة لخوض أشرس المعارك.[ENTER]يمكنك الآن استعمال مهارات الرّكوب. "
gameforge.training_mount._29_say = "يمكن الآن لدابتك أن تستعمل مهارات الحصان. تذكر[ENTER]بأنه سيتوجب عليك إذا ما حصلت على دابة جديدة،[ENTER]تعلُّم المهارات من جديد. يمكنك حينها العودة[ENTER]لزيارتي من جديد. "
gameforge.training_mount._30_say = "أرأيت، ألم أخبرك بأن الركوب قد يُشكل لك خطراً إذا[ENTER]كنت لا تُتقن مهارة الرّكوب. عُد لزيارتي من جديد[ENTER]عند إتقانها. "
gameforge.training_mount._31_say = "أظن أن دابتك ليست مُستعدة بعد. عُد من جديد إذا[ENTER]ظهر على دابتك تعطُّشها للقتال. "
gameforge.training_mount._32_say = "هلاّ نزلت من فضلك من على ظهر دابتك لكي نتحدث في[ENTER]هدوء؟ لقد ألمني عُنقي من شدة رفع الرأس للنظر إليك[ENTER]أثناء حديثنا. "
gameforge.training_mount._33_say = "إنك لا تملك رخصة الركوب اللازمة من أجل تحسين[ENTER]دابتك. ستحتاج على الأقل لرخصة الحصان المدرع، لكي[ENTER]تتمكن من ترويض الدابة البرية. أم ترويض الدابة[ENTER]القوية فإنه يستلزم رخصة حصان الجيش. "
gameforge.training_mount._34_say = "آه أرى أنك تملك وجبة تقوية. ستمنح هذه النبتة[ENTER]الخارقة دابتك قوة خارقة وتُمدّد من مدة حياتها[ENTER]ببضعة أيام. كيف يمكنني أن أساعدك؟ هل ترغب في أن[ENTER]أمدِّد حياة دابتك أو هل ترغب في تحسينها؟ "
gameforge.training_mount._35_select_1 = "تمديد "
gameforge.training_mount._35_select_2 = "تحسين "
gameforge.training_mount._36_select_1 = "7 أيام "
gameforge.training_mount._36_select_2 = "15 يوماً "
gameforge.training_mount._36_select_3 = "30 يوماً "
gameforge.training_mount._36_select_4 = "لفيفة الطافر + 200 ألف يانغ "
gameforge.training_mount._37_say = "إنك مع الأسف لا تملك وجبة التقوية المناسبة للمدة[ENTER]المُختارة. لكنك ستجدها وراء القطعة النقدية التي[ENTER]تدور. "
gameforge.training_mount._38_say = "تتميز لفيفة الطافر بقوة خارقة! حيث أنه بإمكانها[ENTER]تمديد حياة دابتك القوية لمدة قد تصل 4 أيام.[ENTER]ستكلفك محاولة واحدة 200.000 يانغ. لكن يجب هنا أن[ENTER]تكون دابتك مُنهكة وأن يتبقى لها أقل من يوم واحد[ENTER]للحياة. كما أنك بطبيعة الحال ستحتاج لبعض الحظ![ENTER]يمكنك إذا ما فشلت عملية التمديد إطعامه بوجبة[ENTER]تقوية، تجدها وراء القطعة النقدية التي تدور. "
gameforge.training_mount._39_say = "إن دابّتك لا تزال قوية لذا فلن يكون للفيفة الطافر[ENTER]أي مفعول عليها. عُد من جديد عندما يتبقىّ لها أقل[ENTER]من يوم للحياة. "
gameforge.training_mount._40_say = "لا يمكنني مساعدتك للأسف. إنك إمّا لا تحمل معك[ENTER]لفيفة الطافر أو أن ما تملكه من اليانغ يقل عن[ENTER]200.000 يانغ. "
gameforge.upgrade_refine_scroll = {}
gameforge.upgrade_refine_scroll._100_say = "فشلت محاولتك في صناعة اللفيفة، لأنك لا تملك جميع[ENTER]المواد اللازمة. "
gameforge.upgrade_refine_scroll._10_npcChat = "صناعة لفيفة الحرب "
gameforge.upgrade_refine_scroll._110_npcChat = "صنع لفيفة التنين "
gameforge.upgrade_refine_scroll._120_say = "ترفع لفيفة التنين من معدل نجاح التحسين. وإذا ما[ENTER]فشل هذا الأخير، فكل ما يحصل هو أن المستوى ينخفض،[ENTER]ولا يؤدي الفشل إلى تدمير العدة. إن لفيفة التنين[ENTER]شيء غامض يمكن اعتبارها لفيفة أكثر تطوراً من لفيفة[ENTER]البركة. "
gameforge.upgrade_refine_scroll._130_say = "تحتاج لصناعتها إلى خام حديد سحري. "
gameforge.upgrade_refine_scroll._140_sayItem = "خام حديد سحري "
gameforge.upgrade_refine_scroll._150_say = "يلزمك لفيفة البركة لصناعتها. "
gameforge.upgrade_refine_scroll._160_say = "هل لديك جميع الأشياء اللازمة؟ هل تريد صناعة لفيفة[ENTER]التنين؟ تحتاج لذلك إلى لفيفة البركة وخام حديد[ENTER]سحري. "
gameforge.upgrade_refine_scroll._170_say = "لقد صنعت لفيفة التنين! إنه من السهل صناعة لفيفة[ENTER]التنين عند استخدام خام الحديد السحري! هذا[ENTER]يعجبني! "
gameforge.upgrade_refine_scroll._180_say = "فشلت محاولتك في صناعة اللفيفة، لأنك لا تملك جميع[ENTER]المواد اللازمة. "
gameforge.upgrade_refine_scroll._190_npcChat = "صناعة دليل الحدادة "
gameforge.upgrade_refine_scroll._200_say = "هل سمعت بحجر، يسمى حجر الحداد؟ هذا حجر صنعه[ENTER]الحداد بدمه وعرق جبينه. إذا أحضرت لي هذا الحجر مع[ENTER]لفيفة البركة، فإني سأصنع لك دليل الحدادة الذي[ENTER]يحتوي على معلومات قيمة حول تقنية الحدادة. معرفة[ENTER]وتقنية تتوارثها الأجيال في عائلتنا. لهذا الدليل[ENTER]وظيفة مشابهة للفيفة التنين، غير أن معدل نجاحه[ENTER]أعلى منها. "
gameforge.upgrade_refine_scroll._20_say = "إن لفائف الحرب عبارة عن أشياء غامضة، تحسن الأشياء[ENTER]+0 حتى +3، وهذا بنسبة نجاح تصل إلى 100%. ولكنها[ENTER]لا تؤثر على الأشياء +4 وما فوق. "
gameforge.upgrade_refine_scroll._210_say = "تحتاج إلى حجر الحداد لصناعته. "
gameforge.upgrade_refine_scroll._220_sayItem = "حجر الحداد "
gameforge.upgrade_refine_scroll._230_say = "تحتاج إلى لفيفة البركة لصناعته. "
gameforge.upgrade_refine_scroll._240_say = "هل لديك جميع الأشياء اللازمة؟ إذاً هل تريدني أن[ENTER]أصنع لك الدليل الذي يحتوي معرفة الحدادة المتوارثة[ENTER]عبر الأجيال؟ "
gameforge.upgrade_refine_scroll._250_say = "لقد قمت لك بتحضير دليل الحدادة! إنك الآن تملك[ENTER]معرفة سلالة جد عريقة في مهنة الحدادة. أحسن[ENTER]استعمالها! ها، ها، ها! "
gameforge.upgrade_refine_scroll._260_sayItem = "دليل الحدادة "
gameforge.upgrade_refine_scroll._270_say = "لا يمكنني أن أصنع لك دليل الحدادة، لأنك لا تحمل[ENTER]معك جميع المواد اللازمة. "
gameforge.upgrade_refine_scroll._30_say = "تحتاج إلى نحاس سحري خام لصناعته. "
gameforge.upgrade_refine_scroll._40_sayItem = "نحاس خام سحري "
gameforge.upgrade_refine_scroll._50_say = "تحتاج بالإضافة إلى لفيفة البركة. "
gameforge.upgrade_refine_scroll._60_sayItem = "لفيفة البركة "
gameforge.upgrade_refine_scroll._70_say = "هل لديك جميع الأشياء اللازمة؟[ENTER]كل ما تحتاج إليه إذاً هو 200.000 يانغ.[ENTER]يمكنك صناعة لفيفة الحرب عندما تملك لفيفة البركة[ENTER]وخام النحاس السحري و 200.000 يانغ.[ENTER]هل تريد صناعة اللفيفة؟ "
gameforge.upgrade_refine_scroll._80_say = "لقد صنعت لفيفة! إنه بالفعل من السهل صناعة لفيفة[ENTER]الحرب إذا توفر الحديد الصلب! هذا يعجبني! ها ها[ENTER]ها! "
gameforge.upgrade_refine_scroll._90_sayItem = "لفيفة الحرب "
gameforge.warehouse = {}
gameforge.warehouse._100_say = "أهلاً ومرحباً بك! هل لديك فكرة عن الهدف من[ENTER]استعمال سبيكة الذهب؟ إذا كنت تحمل معك بعض اليانغ،[ENTER]فإن هذا بمثابة عرض مفتوح للصوص، قائلاً لهم:[ENTER]تفضلوا! اقتلوني من فضلكم! لذى فإنني أستبدل للناس[ENTER]اليانغ بسبائك من ذهب. "
gameforge.warehouse._10_npcChat = "إنني أرغب في استخدام المخزن. "
gameforge.warehouse._110_say = "حسناً، إني سأطالبك بنسبة أكبر بقليل من قيمة سبيكة[ENTER]الذهب. ولكن هذا جد عادل، بالمقارنة مع الخدمة التي[ENTER]أقدمها لك، أليس كذلك؟ لا داعي هنا للإحساس بالخدع.[ENTER]فإنك على علم تام بمدى أخطار البرية. "
gameforge.warehouse._120_npcChat = "افتح متجر المعدات. "
gameforge.warehouse._130_say = "لقد نفذ محتوى المناجم من المعادن. إنه من الصعب[ENTER]العثور على الذهب والفضة. طالما أنك لم تكتشف عرق[ENTER]خام بعد، فإنك لن تحصل على ذهب أو[ENTER]فضة. "
gameforge.warehouse._140_say = "مرحباً! هل ترغب في الإطلاع على مخزن متجر العدة؟[ENTER]لِم أتيت عندي إذاً؟ ألقي نظرة على قائمة معداتك،[ENTER]ستجد هناك طريقاً مباشراً للوصول. "
gameforge.warehouse._150_say = "انقر ببساطة على هذا الرمز، للانتقال إلى أي مكان[ENTER]ترغب فيه، وكذا إلى مخزن متجر العدة. إن كلمة السر،[ENTER]طالما أنك لم تقُم بتغييرها من قبل، هي 000000. "
gameforge.warehouse._20_sayTitle = "أمين المستودع: "
gameforge.warehouse._30_say = "عليك أن تدفع بعض المال لاستخدام المخزن. من حُسن[ENTER]الحظ أن مزاجي اليوم جيد، لذا فإنني سأعرض عليك[ENTER]استخدامه مقابل 500 يانغ فقط. ما رأيك؟ رخيص أليس[ENTER]كذلك؟ "
gameforge.warehouse._40_say = "ماذا؟ ليس لديك يانغ كافي؟ عُد لاحقاً إذاً، عندما[ENTER]يتوفر لك بعض المال. "
